statements:
[
-- Create enumerations
CREATE TYPE user_role AS ENUM ('ADMIN', 'KEEPER', 'ACCOUNTANT', 'EMPLOYEE');
CREATE TYPE transaction_type AS ENUM ('IMPORT', 'EXPORT', 'TRANSFER', 'ADJUSTMENT', 'LIQUIDATION');
CREATE TYPE transaction_status AS ENUM ('PENDING', 'APPROVED', 'COMPLETED', 'CANCELLED');
CREATE TYPE request_status AS ENUM ('DRAFT', 'PENDING', 'APPROVED', 'REJECTED', 'IN_TRANSIT', 'COMPLETED');
CREATE TYPE warehouse_type AS ENUM ('GENERAL', 'SITE', 'OFFICE');
CREATE TYPE activity_type AS ENUM ('TRANSACTION', 'INVENTORY', 'REQUEST', 'SYSTEM');
CREATE TYPE activity_status AS ENUM ('SUCCESS', 'WARNING', 'INFO', 'DANGER');

-- Create tables
CREATE TABLE users (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  email TEXT UNIQUE NOT NULL,
  username TEXT UNIQUE NOT NULL,
  phone TEXT,
  role user_role NOT NULL DEFAULT 'EMPLOYEE',
  avatar TEXT,
  assigned_warehouse_id TEXT, -- Will map to UUID later at application level or we can keep it as TEXT for now
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Note: We are not linking to Supabase auth yet for this demo, we'll keep it simple and just use the username field for basic auth,
-- however we add an auth_id mapping just in case we switch to real supabase auth.
ALTER TABLE users ADD COLUMN auth_id UUID REFERENCES auth.users(id);

CREATE TABLE warehouses (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  address TEXT NOT NULL,
  type warehouse_type NOT NULL,
  is_archived BOOLEAN DEFAULT FALSE,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE suppliers (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  contact_person TEXT NOT NULL,
  phone TEXT NOT NULL,
  debt NUMERIC DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE categories (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL
);

CREATE TABLE units (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL
);

CREATE TABLE items (
  id TEXT PRIMARY KEY,
  sku TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  category TEXT NOT NULL,
  unit TEXT NOT NULL,
  price_in NUMERIC NOT NULL,
  price_out NUMERIC NOT NULL,
  min_stock INTEGER NOT NULL,
  supplier_id TEXT REFERENCES suppliers(id),
  image_url TEXT,
  stock_by_warehouse JSONB DEFAULT '{}'::JSONB,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE transactions (
  id TEXT PRIMARY KEY,
  type transaction_type NOT NULL,
  date TIMESTAMPTZ NOT NULL,
  items JSONB NOT NULL,
  source_warehouse_id TEXT REFERENCES warehouses(id),
  target_warehouse_id TEXT REFERENCES warehouses(id),
  supplier_id TEXT REFERENCES suppliers(id),
  requester_id UUID REFERENCES users(id),
  approver_id UUID REFERENCES users(id),
  status transaction_status NOT NULL,
  note TEXT,
  related_request_id TEXT,
  pending_items JSONB,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE requests (
  id TEXT PRIMARY KEY,
  code TEXT UNIQUE NOT NULL,
  site_warehouse_id TEXT REFERENCES warehouses(id) NOT NULL,
  source_warehouse_id TEXT REFERENCES warehouses(id),
  requester_id UUID REFERENCES users(id) NOT NULL,
  status request_status NOT NULL,
  items JSONB NOT NULL,
  created_date TIMESTAMPTZ NOT NULL,
  expected_date TIMESTAMPTZ NOT NULL,
  note TEXT,
  logs JSONB DEFAULT '[]'::JSONB,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE activities (
  id TEXT PRIMARY KEY,
  user_id UUID REFERENCES users(id) NOT NULL,
  user_name TEXT NOT NULL,
  user_avatar TEXT,
  type activity_type NOT NULL,
  action TEXT NOT NULL,
  description TEXT NOT NULL,
  timestamp TIMESTAMPTZ NOT NULL,
  warehouse_id TEXT REFERENCES warehouses(id),
  status activity_status DEFAULT 'INFO',
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE app_settings (
  id INTEGER PRIMARY KEY DEFAULT 1,
  name TEXT NOT NULL,
  logo TEXT
);

-- Enable RLS
ALTER TABLE users ENABLE ROW LEVEL SECURITY;
ALTER TABLE warehouses ENABLE ROW LEVEL SECURITY;
ALTER TABLE suppliers ENABLE ROW LEVEL SECURITY;
ALTER TABLE categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE units ENABLE ROW LEVEL SECURITY;
ALTER TABLE items ENABLE ROW LEVEL SECURITY;
ALTER TABLE transactions ENABLE ROW LEVEL SECURITY;
ALTER TABLE requests ENABLE ROW LEVEL SECURITY;
ALTER TABLE activities ENABLE ROW LEVEL SECURITY;
ALTER TABLE app_settings ENABLE ROW LEVEL SECURITY;

-- Creating permissive policies for simplicity in this demo.
-- In a real app, these should be locked down.
CREATE POLICY "Enable all actions for all users" ON users FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all actions for all warehouses" ON warehouses FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all actions for all suppliers" ON suppliers FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all actions for all categories" ON categories FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all actions for all units" ON units FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all actions for all items" ON items FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all actions for all transactions" ON transactions FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all actions for all requests" ON requests FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all actions for all activities" ON activities FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all actions for app_settings" ON app_settings FOR ALL USING (true) WITH CHECK (true);
]

[CREATE SEQUENCE IF NOT EXISTS employee_code_seq START 1;

CREATE TABLE IF NOT EXISTS public.employees (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    employee_code VARCHAR(20) UNIQUE,
    full_name VARCHAR(255) NOT NULL,
    title VARCHAR(100),
    gender VARCHAR(20) CHECK (gender IN ('Nam', 'Nữ', 'Khác')),
    phone VARCHAR(20),
    email VARCHAR(255) UNIQUE,
    date_of_birth DATE,
    start_date DATE,
    official_date DATE,
    status VARCHAR(50) DEFAULT 'Đang làm việc' CHECK (status IN ('Đang làm việc', 'Đã nghỉ việc')),
    user_id UUID REFERENCES public.users(id) ON DELETE SET NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE OR REPLACE FUNCTION set_employee_code()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.employee_code IS NULL OR NEW.employee_code = '' THEN
        NEW.employee_code := 'TT' || LPAD(nextval('employee_code_seq')::text, 3, '0');
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_set_employee_code ON public.employees;
CREATE TRIGGER trg_set_employee_code
BEFORE INSERT ON public.employees
FOR EACH ROW EXECUTE FUNCTION set_employee_code();

ALTER TABLE public.employees ENABLE ROW LEVEL SECURITY;

-- Allow read/write for all temporarily since the app seems to use anon key or simple auth right now
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_policies WHERE policyname = 'Enable all for anon on employees' AND tablename = 'employees'
    ) THEN
        CREATE POLICY "Enable all for anon on employees" ON public.employees FOR ALL TO anon USING (true) WITH CHECK (true);
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM pg_policies WHERE policyname = 'Enable all for authenticated on employees' AND tablename = 'employees'
    ) THEN
        CREATE POLICY "Enable all for authenticated on employees" ON public.employees FOR ALL TO authenticated USING (true) WITH CHECK (true);
    END IF;
END
$$;
]

[
-- 1. Thêm cột vào bảng items để lưu đơn vị mua hàng (đơn vị phụ)
ALTER TABLE public.items
  ADD COLUMN IF NOT EXISTS purchase_unit TEXT DEFAULT NULL, -- Đơn vị mua (VD: 'KG', 'Tấn')
  ADD COLUMN IF NOT EXISTS location TEXT DEFAULT NULL;       -- Vị trí kho (nếu chưa có)

-- 2. Tạo comment mô tả
COMMENT ON COLUMN public.items.purchase_unit IS 'Đơn vị dùng khi mua hàng từ nhà cung cấp (VD: KG, Tấn). Khác với unit (đơn vị tồn kho/xuất kho như Cây, Cái, Tấm).';
COMMENT ON COLUMN public.items.unit IS 'Đơn vị tính chuẩn dùng để quản lý tồn kho và xuất kho (VD: Cây, Cái, Tấm).';
]

[
-- Enum types for workflow
CREATE TYPE workflow_node_type AS ENUM ('START', 'ACTION', 'APPROVAL', 'END');
CREATE TYPE workflow_instance_status AS ENUM ('RUNNING', 'COMPLETED', 'REJECTED', 'CANCELLED');
CREATE TYPE workflow_instance_action AS ENUM ('SUBMITTED', 'APPROVED', 'REJECTED', 'REVISION_REQUESTED');

-- 1. Workflow Templates
CREATE TABLE workflow_templates (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  description text DEFAULT '',
  created_by uuid NOT NULL REFERENCES users(id),
  is_active boolean DEFAULT true,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

-- 2. Workflow Nodes
CREATE TABLE workflow_nodes (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  template_id uuid NOT NULL REFERENCES workflow_templates(id) ON DELETE CASCADE,
  type workflow_node_type NOT NULL,
  label text NOT NULL,
  config jsonb DEFAULT '{}',
  position_x float DEFAULT 0,
  position_y float DEFAULT 0
);

-- 3. Workflow Edges
CREATE TABLE workflow_edges (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  template_id uuid NOT NULL REFERENCES workflow_templates(id) ON DELETE CASCADE,
  source_node_id uuid NOT NULL REFERENCES workflow_nodes(id) ON DELETE CASCADE,
  target_node_id uuid NOT NULL REFERENCES workflow_nodes(id) ON DELETE CASCADE,
  label text DEFAULT ''
);

-- 4. Workflow Instances
CREATE TABLE workflow_instances (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  template_id uuid NOT NULL REFERENCES workflow_templates(id),
  code text UNIQUE NOT NULL,
  title text NOT NULL,
  created_by uuid NOT NULL REFERENCES users(id),
  current_node_id uuid REFERENCES workflow_nodes(id),
  status workflow_instance_status DEFAULT 'RUNNING',
  form_data jsonb DEFAULT '{}',
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

-- 5. Workflow Instance Logs
CREATE TABLE workflow_instance_logs (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  instance_id uuid NOT NULL REFERENCES workflow_instances(id) ON DELETE CASCADE,
  node_id uuid NOT NULL REFERENCES workflow_nodes(id),
  action workflow_instance_action NOT NULL,
  acted_by uuid NOT NULL REFERENCES users(id),
  comment text DEFAULT '',
  created_at timestamptz DEFAULT now()
);

-- Enable RLS
ALTER TABLE workflow_templates ENABLE ROW LEVEL SECURITY;
ALTER TABLE workflow_nodes ENABLE ROW LEVEL SECURITY;
ALTER TABLE workflow_edges ENABLE ROW LEVEL SECURITY;
ALTER TABLE workflow_instances ENABLE ROW LEVEL SECURITY;
ALTER TABLE workflow_instance_logs ENABLE ROW LEVEL SECURITY;

-- RLS Policies: Allow all authenticated users to read/write (app-level authorization)
CREATE POLICY "Allow all for authenticated" ON workflow_templates FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow all for authenticated" ON workflow_nodes FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow all for authenticated" ON workflow_edges FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow all for authenticated" ON workflow_instances FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow all for authenticated" ON workflow_instance_logs FOR ALL USING (true) WITH CHECK (true);
]

[
-- HRM Master Data: 6 lookup tables

CREATE TABLE hrm_areas (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  description TEXT DEFAULT '',
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE hrm_offices (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  address TEXT DEFAULT '',
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE hrm_employee_types (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE hrm_positions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  level INTEGER DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE hrm_salary_policies (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  description TEXT DEFAULT '',
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE hrm_work_schedules (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  description TEXT DEFAULT '',
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Enable RLS on all new tables
ALTER TABLE hrm_areas ENABLE ROW LEVEL SECURITY;
ALTER TABLE hrm_offices ENABLE ROW LEVEL SECURITY;
ALTER TABLE hrm_employee_types ENABLE ROW LEVEL SECURITY;
ALTER TABLE hrm_positions ENABLE ROW LEVEL SECURITY;
ALTER TABLE hrm_salary_policies ENABLE ROW LEVEL SECURITY;
ALTER TABLE hrm_work_schedules ENABLE ROW LEVEL SECURITY;

-- Allow all authenticated users to read, admins to write
CREATE POLICY "Allow all read on hrm_areas" ON hrm_areas FOR SELECT USING (true);
CREATE POLICY "Allow all write on hrm_areas" ON hrm_areas FOR ALL USING (true);

CREATE POLICY "Allow all read on hrm_offices" ON hrm_offices FOR SELECT USING (true);
CREATE POLICY "Allow all write on hrm_offices" ON hrm_offices FOR ALL USING (true);

CREATE POLICY "Allow all read on hrm_employee_types" ON hrm_employee_types FOR SELECT USING (true);
CREATE POLICY "Allow all write on hrm_employee_types" ON hrm_employee_types FOR ALL USING (true);

CREATE POLICY "Allow all read on hrm_positions" ON hrm_positions FOR SELECT USING (true);
CREATE POLICY "Allow all write on hrm_positions" ON hrm_positions FOR ALL USING (true);

CREATE POLICY "Allow all read on hrm_salary_policies" ON hrm_salary_policies FOR SELECT USING (true);
CREATE POLICY "Allow all write on hrm_salary_policies" ON hrm_salary_policies FOR ALL USING (true);

CREATE POLICY "Allow all read on hrm_work_schedules" ON hrm_work_schedules FOR SELECT USING (true);
CREATE POLICY "Allow all write on hrm_work_schedules" ON hrm_work_schedules FOR ALL USING (true);
]

