CREATE TABLE IF NOT EXISTS public.project_transactions (
  id TEXT PRIMARY KEY,
  "projectFinanceId" TEXT NOT NULL,
  "constructionSiteId" TEXT NOT NULL,
  type TEXT NOT NULL DEFAULT 'expense',
  category TEXT NOT NULL DEFAULT 'materials',
  amount NUMERIC NOT NULL DEFAULT 0,
  description TEXT NOT NULL DEFAULT '',
  date TEXT NOT NULL,
  source TEXT NOT NULL DEFAULT 'manual',
  "sourceRef" TEXT,
  "createdBy" TEXT,
  "createdAt" TIMESTAMPTZ DEFAULT now()
);

ALTER TABLE public.project_transactions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow all access to project_transactions" ON public.project_transactions
  FOR ALL USING (true) WITH CHECK (true);

CREATE INDEX idx_project_tx_finance_id ON public.project_transactions ("projectFinanceId");
CREATE INDEX idx_project_tx_site_id ON public.project_transactions ("constructionSiteId");
]

