ALTER TABLE public.org_units ADD COLUMN IF NOT EXISTS "customTypeLabel" text;
]

[
-- ==========================================
-- Chat Conversations
-- ==========================================
CREATE TABLE IF NOT EXISTS public.chat_conversations (
    id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    type text NOT NULL DEFAULT 'direct' CHECK (type IN ('direct', 'group')),
    name text,
    avatar_url text,
    created_by text,
    created_at timestamptz DEFAULT now()
);

ALTER TABLE public.chat_conversations ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow all for authenticated" ON public.chat_conversations
    FOR ALL USING (true) WITH CHECK (true);

-- ==========================================
-- Chat Members
-- ==========================================
CREATE TABLE IF NOT EXISTS public.chat_members (
    id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    conversation_id uuid NOT NULL REFERENCES public.chat_conversations(id) ON DELETE CASCADE,
    user_id text NOT NULL,
    role text NOT NULL DEFAULT 'member' CHECK (role IN ('admin', 'member')),
    last_read_at timestamptz DEFAULT now(),
    joined_at timestamptz DEFAULT now()
);

ALTER TABLE public.chat_members ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow all for authenticated" ON public.chat_members
    FOR ALL USING (true) WITH CHECK (true);

CREATE INDEX idx_chat_members_conversation ON public.chat_members(conversation_id);
CREATE INDEX idx_chat_members_user ON public.chat_members(user_id);
CREATE UNIQUE INDEX idx_chat_members_unique ON public.chat_members(conversation_id, user_id);

-- ==========================================
-- Chat Messages
-- ==========================================
CREATE TABLE IF NOT EXISTS public.chat_messages (
    id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    conversation_id uuid NOT NULL REFERENCES public.chat_conversations(id) ON DELETE CASCADE,
    sender_id text NOT NULL,
    content text,
    type text NOT NULL DEFAULT 'text' CHECK (type IN ('text', 'image', 'file', 'system')),
    attachments jsonb DEFAULT '[]'::jsonb,
    created_at timestamptz DEFAULT now()
);

ALTER TABLE public.chat_messages ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow all for authenticated" ON public.chat_messages
    FOR ALL USING (true) WITH CHECK (true);

CREATE INDEX idx_chat_messages_conversation ON public.chat_messages(conversation_id);
CREATE INDEX idx_chat_messages_sender ON public.chat_messages(sender_id);
CREATE INDEX idx_chat_messages_created ON public.chat_messages(conversation_id, created_at DESC);

-- Enable realtime for chat_messages
ALTER PUBLICATION supabase_realtime ADD TABLE public.chat_messages;
]

[
-- Add reactions column to chat_messages
-- Format: {"👍": ["userId1"], "❤️": ["userId2", "userId3"]}
ALTER TABLE public.chat_messages
ADD COLUMN IF NOT EXISTS reactions jsonb DEFAULT '{}'::jsonb;
]

[
-- =============================================
-- MODULE QUỸ (CASH FUND) - Database Schema
-- =============================================

-- 1. Bảng quỹ tiền mặt
CREATE TABLE IF NOT EXISTS cash_funds (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  currency text NOT NULL DEFAULT 'VND',
  opening_balance numeric NOT NULL DEFAULT 0,
  description text,
  is_active boolean NOT NULL DEFAULT true,
  created_at timestamptz DEFAULT now()
);

-- 2. Bảng phiếu thu/chi
CREATE TABLE IF NOT EXISTS cash_vouchers (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  code text NOT NULL UNIQUE,
  type text NOT NULL CHECK (type IN ('receipt', 'payment')),
  fund_id uuid NOT NULL REFERENCES cash_funds(id),
  date timestamptz NOT NULL DEFAULT now(),
  amount numeric NOT NULL DEFAULT 0,
  contact_name text,
  contact_type text CHECK (contact_type IN ('supplier', 'customer', 'employee', 'other')),
  contact_id text,
  reason text NOT NULL DEFAULT '',
  status text NOT NULL DEFAULT 'draft' CHECK (status IN ('draft', 'approved', 'cancelled')),
  approved_by uuid REFERENCES users(id),
  approved_at timestamptz,
  note text,
  created_by uuid NOT NULL REFERENCES users(id),
  created_at timestamptz DEFAULT now()
);

-- 3. Bảng chi tiết dòng phiếu
CREATE TABLE IF NOT EXISTS cash_voucher_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  voucher_id uuid NOT NULL REFERENCES cash_vouchers(id) ON DELETE CASCADE,
  description text NOT NULL DEFAULT '',
  amount numeric NOT NULL DEFAULT 0,
  cost_category text
);

-- =============================================
-- RLS Policies
-- =============================================

ALTER TABLE cash_funds ENABLE ROW LEVEL SECURITY;
ALTER TABLE cash_vouchers ENABLE ROW LEVEL SECURITY;
ALTER TABLE cash_voucher_items ENABLE ROW LEVEL SECURITY;

-- cash_funds: Tất cả authenticated users có thể đọc, ADMIN/ACCOUNTANT có thể CRUD
CREATE POLICY "cash_funds_select" ON cash_funds FOR SELECT TO authenticated USING (true);
CREATE POLICY "cash_funds_insert" ON cash_funds FOR INSERT TO authenticated WITH CHECK (true);
CREATE POLICY "cash_funds_update" ON cash_funds FOR UPDATE TO authenticated USING (true);
CREATE POLICY "cash_funds_delete" ON cash_funds FOR DELETE TO authenticated USING (true);

-- cash_vouchers: Tất cả authenticated users có thể đọc, CRUD mở cho authenticated
CREATE POLICY "cash_vouchers_select" ON cash_vouchers FOR SELECT TO authenticated USING (true);
CREATE POLICY "cash_vouchers_insert" ON cash_vouchers FOR INSERT TO authenticated WITH CHECK (true);
CREATE POLICY "cash_vouchers_update" ON cash_vouchers FOR UPDATE TO authenticated USING (true);
CREATE POLICY "cash_vouchers_delete" ON cash_vouchers FOR DELETE TO authenticated USING (true);

-- cash_voucher_items: Linked to voucher access
CREATE POLICY "cash_voucher_items_select" ON cash_voucher_items FOR SELECT TO authenticated USING (true);
CREATE POLICY "cash_voucher_items_insert" ON cash_voucher_items FOR INSERT TO authenticated WITH CHECK (true);
CREATE POLICY "cash_voucher_items_update" ON cash_voucher_items FOR UPDATE TO authenticated USING (true);
CREATE POLICY "cash_voucher_items_delete" ON cash_voucher_items FOR DELETE TO authenticated USING (true);

-- Index cho performance
CREATE INDEX IF NOT EXISTS idx_cash_vouchers_fund_id ON cash_vouchers(fund_id);
CREATE INDEX IF NOT EXISTS idx_cash_vouchers_type ON cash_vouchers(type);
CREATE INDEX IF NOT EXISTS idx_cash_vouchers_status ON cash_vouchers(status);
CREATE INDEX IF NOT EXISTS idx_cash_vouchers_date ON cash_vouchers(date DESC);
CREATE INDEX IF NOT EXISTS idx_cash_voucher_items_voucher_id ON cash_voucher_items(voucher_id);
]

