[
-- Request Categories (templates for request types)
CREATE TABLE IF NOT EXISTS request_categories (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  description TEXT DEFAULT '',
  icon TEXT DEFAULT 'FileText',
  color TEXT DEFAULT 'from-blue-500 to-cyan-500',
  custom_fields JSONB DEFAULT '[]'::jsonb,
  approver_role TEXT,
  approver_user_id UUID,
  is_active BOOLEAN DEFAULT true,
  created_by UUID NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Request Instances (individual requests)
CREATE TABLE IF NOT EXISTS request_instances (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  category_id UUID NOT NULL REFERENCES request_categories(id) ON DELETE CASCADE,
  code TEXT NOT NULL,
  title TEXT NOT NULL,
  description TEXT DEFAULT '',
  priority TEXT DEFAULT 'medium' CHECK (priority IN ('low', 'medium', 'high', 'urgent')),
  form_data JSONB DEFAULT '{}'::jsonb,
  created_by UUID NOT NULL,
  assigned_to UUID,
  status TEXT DEFAULT 'PENDING' CHECK (status IN ('DRAFT', 'PENDING', 'APPROVED', 'IN_PROGRESS', 'DONE', 'REJECTED', 'CANCELLED')),
  due_date TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Request Logs (history)
CREATE TABLE IF NOT EXISTS request_logs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  request_id UUID NOT NULL REFERENCES request_instances(id) ON DELETE CASCADE,
  action TEXT NOT NULL,
  acted_by UUID NOT NULL,
  comment TEXT DEFAULT '',
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Indexes
CREATE INDEX IF NOT EXISTS idx_request_instances_category ON request_instances(category_id);
CREATE INDEX IF NOT EXISTS idx_request_instances_status ON request_instances(status);
CREATE INDEX IF NOT EXISTS idx_request_instances_created_by ON request_instances(created_by);
CREATE INDEX IF NOT EXISTS idx_request_logs_request_id ON request_logs(request_id);

-- Enable RLS
ALTER TABLE request_categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE request_instances ENABLE ROW LEVEL SECURITY;
ALTER TABLE request_logs ENABLE ROW LEVEL SECURITY;

-- RLS Policies (allow all for authenticated users - fine-grained control on frontend)
CREATE POLICY "Allow all for authenticated" ON request_categories FOR ALL USING (true) WITH CHECK (true);
