[
-- ============================================================
-- PHASE 1: RLS Infrastructure + Critical Fixes
-- ============================================================

-- 1. Helper: Is current user ADMIN?
CREATE OR REPLACE FUNCTION public.is_admin()
RETURNS boolean LANGUAGE sql SECURITY DEFINER STABLE
SET search_path = '' AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.users
    WHERE auth_id = (SELECT auth.uid()) AND role = 'ADMIN'
  );
$$;

-- 2. Helper: Get current app user ID (public.users.id)
CREATE OR REPLACE FUNCTION public.current_app_user_id()
RETURNS uuid LANGUAGE sql SECURITY DEFINER STABLE
SET search_path = '' AS $$
  SELECT id FROM public.users
  WHERE auth_id = (SELECT auth.uid()) LIMIT 1;
$$;

-- 3. Remove dangerous anon policy on employees
DROP POLICY IF EXISTS "Enable all for anon on employees" ON public.employees;

-- 4. Fix function search_path
ALTER FUNCTION public.set_employee_code() SET search_path = '';
]

