-- ---- hrm_payrolls ----
DROP POLICY IF EXISTS "Allow all access to hrm_payrolls" ON public.hrm_payrolls;
CREATE POLICY "payrolls_select" ON public.hrm_payrolls FOR SELECT USING (
  public.is_admin() OR "employeeId" IN (
    SELECT e.id FROM public.employees e WHERE e.user_id = public.current_app_user_id()
  )
);
CREATE POLICY "payrolls_insert" ON public.hrm_payrolls FOR INSERT WITH CHECK (public.is_admin());
CREATE POLICY "payrolls_update" ON public.hrm_payrolls FOR UPDATE USING (public.is_admin());
