[
-- RPC function for AI assistant to run read-only SQL queries safely
CREATE OR REPLACE FUNCTION execute_ai_query(query_text TEXT)
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  result JSON;
  upper_query TEXT;
BEGIN
  -- Safety check: only allow SELECT and WITH (CTE)
  upper_query := UPPER(TRIM(query_text));
  IF NOT (upper_query LIKE 'SELECT%' OR upper_query LIKE 'WITH%') THEN
    RETURN json_build_object('error', 'Only SELECT queries are allowed');
  END IF;

  -- Block dangerous keywords
  IF upper_query LIKE '%INSERT%' OR upper_query LIKE '%UPDATE%' OR upper_query LIKE '%DELETE%'
     OR upper_query LIKE '%DROP%' OR upper_query LIKE '%ALTER%' OR upper_query LIKE '%CREATE%'
     OR upper_query LIKE '%TRUNCATE%' OR upper_query LIKE '%GRANT%' OR upper_query LIKE '%REVOKE%' THEN
    RETURN json_build_object('error', 'Dangerous keywords detected');
  END IF;

  -- Execute and return as JSON
  EXECUTE 'SELECT json_agg(row_to_json(t)) FROM (' || query_text || ') t' INTO result;

  -- Handle null result (no rows)
  IF result IS NULL THEN
    result := '[]'::json;
  END IF;

  RETURN result;
EXCEPTION
  WHEN OTHERS THEN
    RETURN json_build_object('error', SQLERRM);
END;
$$;
]

