[-- Grant permissions on employee_code_seq to all relevant roles
GRANT USAGE, SELECT, UPDATE ON SEQUENCE employee_code_seq TO authenticated;
GRANT USAGE, SELECT, UPDATE ON SEQUENCE employee_code_seq TO anon;
GRANT USAGE, SELECT, UPDATE ON SEQUENCE employee_code_seq TO service_role;

-- Also ensure the trigger function can be executed by the roles
GRANT EXECUTE ON FUNCTION set_employee_code() TO authenticated;
GRANT EXECUTE ON FUNCTION set_employee_code() TO anon;
GRANT EXECUTE ON FUNCTION set_employee_code() TO service_role;

-- Make the trigger function run with SECURITY DEFINER so it always has permission
CREATE OR REPLACE FUNCTION set_employee_code()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
    IF NEW.employee_code IS NULL OR NEW.employee_code = '' THEN
        NEW.employee_code := 'TT' || LPAD(nextval('employee_code_seq')::text, 3, '0');
    END IF;
    RETURN NEW;
END;
$$;]

