  file_size bigint,
  storage_path text,                    -- path trên Supabase Storage
  chunk_count int DEFAULT 0,
  status text DEFAULT 'pending',        -- 'pending', 'processing', 'ready', 'error'
  error_message text,
  uploaded_by text,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

-- Bảng lưu chunks + embeddings
CREATE TABLE rag_chunks (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  document_id uuid REFERENCES rag_documents(id) ON DELETE CASCADE,
  chunk_index int NOT NULL,
  content text NOT NULL,
  metadata jsonb DEFAULT '{}',
  embedding vector(768),
  token_count int,
  created_at timestamptz DEFAULT now()
);

-- Index cho vector search
CREATE INDEX rag_chunks_embedding_idx ON rag_chunks USING ivfflat (embedding vector_cosine_ops) WITH (lists = 20);
CREATE INDEX rag_chunks_document_id_idx ON rag_chunks(document_id);
CREATE INDEX rag_documents_status_idx ON rag_documents(status);

-- Function tìm kiếm vector
CREATE OR REPLACE FUNCTION match_rag_chunks(
  query_embedding vector(768),
  match_count int DEFAULT 5,
  match_threshold float DEFAULT 0.3
)
RETURNS TABLE (
  id uuid,
  document_id uuid,
  content text,
  metadata jsonb,
  similarity float
)
LANGUAGE sql STABLE
AS $$
  SELECT
    rc.id, rc.document_id, rc.content, rc.metadata,
    1 - (rc.embedding <=> query_embedding) as similarity
  FROM rag_chunks rc
  JOIN rag_documents rd ON rc.document_id = rd.id
  WHERE rd.status = 'ready'
    AND 1 - (rc.embedding <=> query_embedding) > match_threshold
  ORDER BY rc.embedding <=> query_embedding
  LIMIT match_count;
$$;

