[-- Project master table. A Project is the business object used by DA.
-- HRM construction sites are optional physical/site links, not the project list itself.

CREATE TABLE IF NOT EXISTS public.projects (
  id text PRIMARY KEY DEFAULT gen_random_uuid()::text,
  code text NOT NULL UNIQUE,
  name text NOT NULL,
  description text,
  client_name text,
  project_type text NOT NULL DEFAULT 'construction',
  status text NOT NULL DEFAULT 'planning'
    CHECK (status IN ('planning', 'active', 'paused', 'completed', 'cancelled')),
  construction_site_id uuid REFERENCES public.hrm_construction_sites(id) ON DELETE SET NULL,
  manager_id text,
  start_date date,
  end_date date,
  created_by text,
  source text NOT NULL DEFAULT 'manual' CHECK (source IN ('manual', 'backfill')),
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
) CREATE INDEX IF NOT EXISTS idx_projects_construction_site_id
  ON public.projects(construction_site_id) CREATE INDEX IF NOT EXISTS idx_projects_status
  ON public.projects(status) CREATE INDEX IF NOT EXISTS idx_projects_manager_id
  ON public.projects(manager_id) CREATE OR REPLACE FUNCTION public.set_updated_at()
RETURNS trigger
LANGUAGE plpgsql
SET search_path = public
AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ DROP TRIGGER IF EXISTS trg_projects_updated_at ON public.projects CREATE TRIGGER trg_projects_updated_at
  BEFORE UPDATE ON public.projects
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at() -- Expose the table to Supabase Data API roles. RLS stays enabled below.
GRANT SELECT, INSERT, UPDATE, DELETE ON public.projects TO anon, authenticated ALTER TABLE public.projects ENABLE ROW LEVEL SECURITY DROP POLICY IF EXISTS "projects_select" ON public.projects CREATE POLICY "projects_select" ON public.projects
  FOR SELECT TO public
  USING (auth.role() IN ('anon', 'authenticated')) DROP POLICY IF EXISTS "projects_insert" ON public.projects CREATE POLICY "projects_insert" ON public.projects
  FOR INSERT TO public
  WITH CHECK (auth.role() IN ('anon', 'authenticated')) DROP POLICY IF EXISTS "projects_update" ON public.projects CREATE POLICY "projects_update" ON public.projects
  FOR UPDATE TO public
  USING (auth.role() IN ('anon', 'authenticated'))
  WITH CHECK (auth.role() IN ('anon', 'authenticated')) DROP POLICY IF EXISTS "projects_delete" ON public.projects CREATE POLICY "projects_delete" ON public.projects
  FOR DELETE TO public
  USING (auth.role() IN ('anon', 'authenticated')) -- Backfill one project per existing HRM construction site. Use the site UUID string
-- as the project ID so legacy site-based records can be linked without ambiguity.
INSERT INTO public.projects (
  id,
  code,
  name,
  description,
  status,
  construction_site_id,
  manager_id,
  source,
  created_at,
  updated_at
)
SELECT
  s.id::text,
  'PRJ-' || upper(substr(replace(s.id::text, '-', ''), 1, 8)),
  s.name,
  COALESCE(NULLIF(to_jsonb(s)->>'address', ''), NULLIF(to_jsonb(s)->>'description', '')),
  'active',
  s.id,
  NULLIF(to_jsonb(s)->>'managerId', ''),
  'backfill',
  now(),
  now()
FROM public.hrm_construction_sites s
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  construction_site_id = EXCLUDED.construction_site_id,
  manager_id = COALESCE(public.projects.manager_id, EXCLUDED.manager_id),
  updated_at = now()
WHERE public.projects.source = 'backfill' -- Project-level staff must work even before a project is linked to a HRM site.
DO $$
BEGIN
  IF to_regclass('public.project_staff') IS NOT NULL THEN
    ALTER TABLE public.project_staff
      ADD COLUMN IF NOT EXISTS project_id text REFERENCES public.projects(id) ON DELETE SET NULL;
    ALTER TABLE public.project_staff
      ALTER COLUMN construction_site_id DROP NOT NULL;
    CREATE INDEX IF NOT EXISTS idx_project_staff_project_id
      ON public.project_staff(project_id);
    UPDATE public.project_staff
    SET project_id = construction_site_id
    WHERE project_id IS NULL AND construction_site_id IS NOT NULL;
  END IF;
END;
