    CREATE UNIQUE INDEX IF NOT EXISTS ux_project_staff_permissions_staff_type
      ON public.project_staff_permissions(staff_id, permission_type_id);

    CREATE INDEX IF NOT EXISTS idx_project_staff_permissions_active
      ON public.project_staff_permissions(staff_id, permission_type_id)
