[create or replace function public.ai_database_catalog()
returns jsonb
language sql
stable
security invoker
set search_path = ''
as $$
  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'table', table_name,
        'columns', columns
      )
      order by table_name
    ),
    '[]'::jsonb
  )
  from (
    select
      c.table_name,
      jsonb_agg(
        jsonb_build_object(
          'name', c.column_name,
          'type', c.data_type,
          'nullable', c.is_nullable = 'YES'
        )
        order by c.ordinal_position
      ) as columns
    from information_schema.columns c
    where c.table_schema = 'public'
      and c.table_name not like 'pg_%'
      and c.table_name not in ('app_code_counters')
    group by c.table_name
  ) s;
$$;

create or replace function public.execute_ai_readonly_query(p_query text)
returns jsonb
language plpgsql
security invoker
set search_path = public
as $$
declare
  v_sql text := trim(coalesce(p_query, ''));
  v_lower text;
  v_rows jsonb;
  v_row_count integer;
begin
  v_sql := regexp_replace(v_sql, ';\s*$', '');
  v_lower := lower(v_sql);

  if v_sql = '' or v_lower !~ '^\s*(select|with)\s' then
    raise exception 'AI query must be SELECT-only';
  end if;

  if v_sql like '%;%' then
    raise exception 'AI query must contain a single statement';
  end if;

  if v_sql ~ '(--|/\*)' then
    raise exception 'AI query comments are not allowed';
  end if;

  if v_lower ~ '(^|[^a-z_])(insert|update|delete|drop|alter|truncate|grant|revoke|create|replace|merge|call|copy|do|execute|notify|listen|vacuum|analyze|set|reset|refresh)([^a-z_]|$)' then
    raise exception 'AI query contains a blocked keyword';
  end if;

  if v_lower ~ '(^|[^a-z_])(auth|storage|vault|net|extensions|pg_catalog|information_schema)\s*\.' then
    raise exception 'AI query references a blocked schema';
  end if;

  perform set_config('statement_timeout', '5000', true);

  execute format(
    'select coalesce(jsonb_agg(to_jsonb(ai_limited)), ''[]''::jsonb)
       from (select * from (%s) ai_source limit 500) ai_limited',
    v_sql
  )
  into v_rows;

  v_row_count := coalesce(jsonb_array_length(v_rows), 0);
  return jsonb_build_object(
    'rows', v_rows,
    'rowCount', v_row_count,
    'limited', v_row_count >= 500
  );
end;
$$;

create or replace function public.ai_search_knowledge(p_query text, p_limit integer default 8)
returns table (
  document_id text,
  title text,
  file_name text,
  content text,
  rank real
)
language plpgsql
stable
security invoker
set search_path = public
as $$
declare
  v_content_column text;
  v_limit integer := least(greatest(coalesce(p_limit, 8), 1), 20);
begin
  if to_regclass('public.rag_chunks') is null or to_regclass('public.rag_documents') is null then
    return;
  end if;

  select column_name
    into v_content_column
  from information_schema.columns
  where table_schema = 'public'
    and table_name = 'rag_chunks'
    and column_name in ('content', 'chunk_text', 'text')
  order by case column_name when 'content' then 1 when 'chunk_text' then 2 else 3 end
  limit 1;

  if v_content_column is null then
    return;
  end if;

  return query execute format(
    'select
       c.document_id::text,
       d.title::text,
       d.file_name::text,
       left(c.%1$I::text, 1800) as content,
       ts_rank_cd(to_tsvector(''simple'', coalesce(c.%1$I::text, '''')), plainto_tsquery(''simple'', $1))::real as rank
     from public.rag_chunks c
     join public.rag_documents d on d.id = c.document_id
     where coalesce(d.status, ''ready'') = ''ready''
       and to_tsvector(''simple'', coalesce(c.%1$I::text, '''')) @@ plainto_tsquery(''simple'', $1)
     order by rank desc
     limit $2',
    v_content_column
  )
  using p_query, v_limit;
end;
$$;

revoke all on function public.ai_database_catalog() from public;
revoke all on function public.execute_ai_readonly_query(text) from public;
revoke all on function public.ai_search_knowledge(text, integer) from public;

revoke execute on function public.ai_database_catalog() from anon, authenticated;
revoke execute on function public.execute_ai_readonly_query(text) from anon, authenticated;
revoke execute on function public.ai_search_knowledge(text, integer) from anon, authenticated;

grant execute on function public.ai_database_catalog() to service_role;
grant execute on function public.execute_ai_readonly_query(text) to service_role;
grant execute on function public.ai_search_knowledge(text, integer) to service_role;

notify pgrst, 'reload schema';]

[-- FastCons Integration: BOQ + Payment + Cost Items

-- 1. ALTER project_tasks — thêm BOQ fields
ALTER TABLE project_tasks
  ADD COLUMN IF NOT EXISTS code TEXT,
  ADD COLUMN IF NOT EXISTS quantity NUMERIC,
  ADD COLUMN IF NOT EXISTS unit TEXT,
  ADD COLUMN IF NOT EXISTS unit_price NUMERIC,
  ADD COLUMN IF NOT EXISTS total_price NUMERIC,
  ADD COLUMN IF NOT EXISTS completed_quantity NUMERIC DEFAULT 0,
  ADD COLUMN IF NOT EXISTS contract_item_id UUID;

-- 2. ALTER daily_logs — thêm JSONB columns cho chi tiết nhật ký
ALTER TABLE daily_logs
  ADD COLUMN IF NOT EXISTS volumes JSONB DEFAULT '[]'::jsonb,
  ADD COLUMN IF NOT EXISTS materials JSONB DEFAULT '[]'::jsonb,
  ADD COLUMN IF NOT EXISTS labor_details JSONB DEFAULT '[]'::jsonb,
  ADD COLUMN IF NOT EXISTS machines JSONB DEFAULT '[]'::jsonb;

-- 3. CREATE contract_items
CREATE TABLE IF NOT EXISTS contract_items (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  contract_id UUID NOT NULL,
  contract_type TEXT NOT NULL CHECK (contract_type IN ('customer', 'subcontractor')),
  construction_site_id UUID NOT NULL,
  parent_id UUID REFERENCES contract_items(id) ON DELETE SET NULL,
  code TEXT NOT NULL,
  name TEXT NOT NULL,
  unit TEXT NOT NULL DEFAULT 'm2',
  quantity NUMERIC NOT NULL DEFAULT 0,
  unit_price NUMERIC NOT NULL DEFAULT 0,
  total_price NUMERIC NOT NULL DEFAULT 0,
  completed_quantity NUMERIC DEFAULT 0,
  completed_percent NUMERIC DEFAULT 0,
  "order" INTEGER NOT NULL DEFAULT 0,
  note TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_contract_items_contract ON contract_items(contract_id, contract_type);
CREATE INDEX IF NOT EXISTS idx_contract_items_site ON contract_items(construction_site_id);

-- 4. CREATE payment_certificates
CREATE TABLE IF NOT EXISTS payment_certificates (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  contract_id UUID NOT NULL,
  contract_type TEXT NOT NULL CHECK (contract_type IN ('customer', 'subcontractor')),
  construction_site_id UUID NOT NULL,
  period_number INTEGER NOT NULL,
  period_start DATE NOT NULL,
  period_end DATE NOT NULL,
  description TEXT,
  items JSONB NOT NULL DEFAULT '[]'::jsonb,
  total_contract_value NUMERIC NOT NULL DEFAULT 0,
  total_completed_value NUMERIC NOT NULL DEFAULT 0,
  current_completed_value NUMERIC NOT NULL DEFAULT 0,
  advance_recovery NUMERIC NOT NULL DEFAULT 0,
  retention_percent NUMERIC NOT NULL DEFAULT 5,
  retention_amount NUMERIC NOT NULL DEFAULT 0,
  penalty_amount NUMERIC NOT NULL DEFAULT 0,
  penalty_reason TEXT,
  deduction_amount NUMERIC NOT NULL DEFAULT 0,
  deduction_reason TEXT,
  previous_certified_amount NUMERIC NOT NULL DEFAULT 0,
  current_payable_amount NUMERIC NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft', 'submitted', 'approved', 'paid')),
  submitted_by TEXT,
  submitted_at TIMESTAMPTZ,
  approved_by TEXT,
  approved_at TIMESTAMPTZ,
  paid_at TIMESTAMPTZ,
  note TEXT,
  attachments JSONB DEFAULT '[]'::jsonb,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_payment_certs_contract ON payment_certificates(contract_id, contract_type);
CREATE INDEX IF NOT EXISTS idx_payment_certs_site ON payment_certificates(construction_site_id);
CREATE INDEX IF NOT EXISTS idx_payment_certs_status ON payment_certificates(status);

-- 5. CREATE advance_payments
CREATE TABLE IF NOT EXISTS advance_payments (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  contract_id UUID NOT NULL,
  contract_type TEXT NOT NULL CHECK (contract_type IN ('customer', 'subcontractor')),
  construction_site_id UUID NOT NULL,
  amount NUMERIC NOT NULL DEFAULT 0,
  date DATE NOT NULL,
  recovery_percent NUMERIC NOT NULL DEFAULT 30,
  recovered_amount NUMERIC NOT NULL DEFAULT 0,
  remaining_amount NUMERIC NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'fully_recovered', 'cancelled')),
  note TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_advance_payments_contract ON advance_payments(contract_id, contract_type);

-- 6. CREATE project_cost_items
CREATE TABLE IF NOT EXISTS project_cost_items (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  construction_site_id UUID NOT NULL,
  code TEXT NOT NULL,
  name TEXT NOT NULL,
  parent_id UUID REFERENCES project_cost_items(id) ON DELETE SET NULL,
  "order" INTEGER NOT NULL DEFAULT 0,
  budget_amount NUMERIC NOT NULL DEFAULT 0,
  actual_amount NUMERIC NOT NULL DEFAULT 0,
  variance_amount NUMERIC DEFAULT 0,
  variance_percent NUMERIC DEFAULT 0,
  formula TEXT,
  warning_threshold NUMERIC DEFAULT 90,
  source TEXT NOT NULL DEFAULT 'manual' CHECK (source IN ('manual', 'contract', 'dailylog', 'payment')),
  is_auto_calculated BOOLEAN DEFAULT false,
  note TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_cost_items_site ON project_cost_items(construction_site_id);

-- 7. RLS Policies (enable + drop-if-exists trước khi tạo)
ALTER TABLE contract_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE payment_certificates ENABLE ROW LEVEL SECURITY;
ALTER TABLE advance_payments ENABLE ROW LEVEL SECURITY;
