create or replace function public.process_transaction_status(
  p_transaction_id text,
  p_status public.transaction_status,
  p_approver_id uuid
)
returns public.transactions
language plpgsql
security definer
set search_path = public
as $$
declare
  v_tx public.transactions%rowtype;
  v_user public.users%rowtype;
  v_line jsonb;
  v_pending jsonb;
  v_item_id text;
  v_qty integer;
  v_can_approve boolean := false;
  v_can_complete boolean := false;
begin
  select * into v_tx
  from public.transactions
  where id = p_transaction_id
  for update;
  if not found then
    raise exception 'transaction not found: %', p_transaction_id;
  end if;

  select * into v_user from public.users where id = public.current_app_user_id();
  if v_user.id is null then
    raise exception 'authentication required';
  end if;

  v_can_approve :=
    public.is_module_admin('WMS')
    or (
      v_user.role = 'WAREHOUSE_KEEPER'
      and (
        (v_tx.type = 'IMPORT'::public.transaction_type and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id)
        or (v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
            and v_user.assigned_warehouse_id is not distinct from v_tx.source_warehouse_id)
      )
    );

  v_can_complete :=
    public.is_module_admin('WMS')
    or (
      v_user.role = 'WAREHOUSE_KEEPER'
      and (
        (v_tx.type in ('IMPORT'::public.transaction_type, 'TRANSFER'::public.transaction_type)
            and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id)
        or (v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type)
            and v_user.assigned_warehouse_id is not distinct from v_tx.source_warehouse_id)
      )
    );

  if p_status = 'APPROVED'::public.transaction_status and not v_can_approve then
    raise exception 'insufficient privilege to approve transaction';
  end if;

  if p_status = 'CANCELLED'::public.transaction_status
     and not v_can_approve
     and v_tx.requester_id is distinct from v_user.id then
    raise exception 'insufficient privilege to cancel transaction';
  end if;

  if p_status = 'COMPLETED'::public.transaction_status and not v_can_complete then
    raise exception 'insufficient privilege to complete transaction';
  end if;

  if v_tx.status = p_status then
    return v_tx;
  end if;
  if v_tx.status = 'CANCELLED'::public.transaction_status then
    raise exception 'cancelled transaction cannot be changed';
  end if;
  if v_tx.status = 'COMPLETED'::public.transaction_status then
    raise exception 'completed transaction cannot be changed';
  end if;

  if p_status in ('APPROVED'::public.transaction_status, 'COMPLETED'::public.transaction_status) then
    for v_pending in
      select value from jsonb_array_elements(coalesce(v_tx.pending_items, '[]'::jsonb))
    loop
      insert into public.items (
        id, sku, name, category, unit, purchase_unit,
        price_in, price_out, min_stock, supplier_id, image_url,
        stock_by_warehouse, location
      )
      values (
        v_pending->>'id',
        v_pending->>'sku',
        v_pending->>'name',
        coalesce(nullif(v_pending->>'category', ''), 'Khác'),
        coalesce(nullif(v_pending->>'unit', ''), 'Cái'),
        nullif(v_pending->>'purchaseUnit', ''),
        coalesce(nullif(v_pending->>'priceIn', '')::numeric, 0),
        coalesce(nullif(v_pending->>'priceOut', '')::numeric, 0),
        coalesce(nullif(v_pending->>'minStock', '')::integer, 0),
        nullif(v_pending->>'supplierId', ''),
        nullif(v_pending->>'imageUrl', ''),
        coalesce(v_pending->'stockByWarehouse', '{}'::jsonb),
        nullif(v_pending->>'location', '')
      )
      on conflict (id) do nothing;
    end loop;
  end if;

  if p_status = 'COMPLETED'::public.transaction_status then
    for v_line in
      select value from jsonb_array_elements(v_tx.items)
    loop
      v_item_id := v_line->>'itemId';
      v_qty := coalesce(nullif(v_line->>'quantity', '')::numeric, 0)::integer;
      if v_item_id is null or v_qty <= 0 then
        raise exception 'invalid transaction item payload';
      end if;

      if v_tx.type = 'IMPORT'::public.transaction_type then
        perform public.apply_stock_change(v_item_id, v_tx.target_warehouse_id, v_qty);
      elsif v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type) then
        perform public.apply_stock_change(v_item_id, v_tx.source_warehouse_id, -v_qty);
      elsif v_tx.type = 'TRANSFER'::public.transaction_type then
        perform public.apply_stock_change(v_item_id, v_tx.source_warehouse_id, -v_qty);
        perform public.apply_stock_change(v_item_id, v_tx.target_warehouse_id, v_qty);
      elsif v_tx.type = 'ADJUSTMENT'::public.transaction_type then
        perform public.apply_stock_change(v_item_id, v_tx.target_warehouse_id, v_qty);
      end if;
    end loop;
  end if;

  update public.transactions
  set status = p_status,
      approver_id = p_approver_id
  where id = p_transaction_id
  returning * into v_tx;

  return v_tx;
end;
$$;

revoke all on function public.process_transaction_status(text, public.transaction_status, uuid) from public;
grant execute on function public.process_transaction_status(text, public.transaction_status, uuid) to authenticated;

notify pgrst, 'reload schema';]

[-- Fix workflow processing RPC ambiguity introduced by RETURNS TABLE output names.
-- This is cloud-only: apply with `npx supabase db query --linked -f ...`.

alter type public.workflow_instance_action add value if not exists 'REOPENED' create or replace function public.process_workflow_instance_fast(
  p_instance_id uuid,
  p_action public.workflow_instance_action,
  p_user_id uuid,
  p_comment text default '',
  p_next_assignee_user_id uuid default null
)
returns table (
  id uuid,
  template_id uuid,
  code text,
  title text,
  created_by uuid,
  current_node_id uuid,
  status public.workflow_instance_status,
  watchers text[],
  step_assignees jsonb,
  created_at timestamptz,
  updated_at timestamptz
)
language plpgsql
security definer
set search_path = public
as $$
declare
  v_inst public.workflow_instances%rowtype;
  v_current_user uuid := public.current_app_user_id();
  v_actor public.users%rowtype;
  v_template public.workflow_templates%rowtype;
  v_current_node public.workflow_nodes%rowtype;
  v_next_node_id uuid;
  v_next_node_type public.workflow_node_type;
  v_prev_node_id uuid;
  v_prev_node_type public.workflow_node_type;
  v_start_node_id uuid;
  v_first_task_node_id uuid;
  v_can_act boolean := false;
begin
  if v_current_user is null then
    raise exception 'authentication required';
  end if;

  if p_user_id is distinct from v_current_user and not public.is_module_admin('WF') then
    raise exception 'cannot act as another user';
  end if;

  select u.* into v_actor
  from public.users u
  where u.id = p_user_id;

  select wi.* into v_inst
  from public.workflow_instances wi
  where wi.id = p_instance_id
  for update;

  if not found then
    raise exception 'workflow instance not found: %', p_instance_id;
  end if;

  if v_inst.status <> 'RUNNING'::public.workflow_instance_status then
    raise exception 'workflow instance is not running';
  end if;

  if v_inst.current_node_id is null then
    raise exception 'workflow instance has no current node';
  end if;

  select wn.* into v_current_node
  from public.workflow_nodes wn
  where wn.id = v_inst.current_node_id;

  if not found then
    raise exception 'workflow current node not found: %', v_inst.current_node_id;
  end if;

  select wt.* into v_template
  from public.workflow_templates wt
  where wt.id = v_inst.template_id;

  if not found then
    raise exception 'workflow template not found: %', v_inst.template_id;
  end if;

  select n.id into v_start_node_id
  from public.workflow_nodes n
  where n.template_id = v_inst.template_id
    and n.type = 'START'::public.workflow_node_type
  limit 1;

  select e.target_node_id into v_first_task_node_id
  from public.workflow_edges e
  where e.source_node_id = v_start_node_id
  limit 1;

  v_can_act :=
    public.is_module_admin('WF')
    or coalesce(v_inst.step_assignees ->> v_inst.current_node_id::text, '') = p_user_id::text
    or coalesce(v_current_node.config ->> 'assigneeUserId', '') = p_user_id::text
    or (
      v_actor.id is not null
      and coalesce(v_current_node.config ->> 'assigneeRole', '') = v_actor.role::text
    )
    or p_user_id::text = any(coalesce(v_template.managers, '{}'::text[]))
    or (
      v_inst.created_by = p_user_id
      and v_inst.current_node_id = v_first_task_node_id
      and exists (
        select 1
        from public.workflow_instance_logs wil
        where wil.instance_id = p_instance_id
          and wil.action = 'REVISION_REQUESTED'::public.workflow_instance_action
      )
    );

  if not v_can_act then
    raise exception 'user is not allowed to process current workflow step';
  end if;

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (p_instance_id, v_inst.current_node_id, p_action, p_user_id, coalesce(p_comment, ''));

  if p_action = 'APPROVED'::public.workflow_instance_action then
    select e.target_node_id, n.type
      into v_next_node_id, v_next_node_type
    from public.workflow_edges e
    join public.workflow_nodes n on n.id = e.target_node_id
    where e.source_node_id = v_inst.current_node_id
    limit 1;

    if v_next_node_id is null then
      raise exception 'no next workflow node found';
    end if;

    update public.workflow_instances wi
    set current_node_id = v_next_node_id,
        status = case
          when v_next_node_type = 'END'::public.workflow_node_type
          then 'COMPLETED'::public.workflow_instance_status
          else wi.status
        end,
        step_assignees = case
          when p_next_assignee_user_id is not null and v_next_node_type <> 'END'::public.workflow_node_type
          then coalesce(wi.step_assignees, '{}'::jsonb) || jsonb_build_object(v_next_node_id::text, p_next_assignee_user_id::text)
          else coalesce(wi.step_assignees, '{}'::jsonb)
        end,
        updated_at = now()
    where wi.id = p_instance_id
    returning wi.* into v_inst;
  elsif p_action = 'REJECTED'::public.workflow_instance_action then
    update public.workflow_instances wi
    set status = 'REJECTED'::public.workflow_instance_status,
        updated_at = now()
    where wi.id = p_instance_id
    returning wi.* into v_inst;
  elsif p_action = 'REVISION_REQUESTED'::public.workflow_instance_action then
    select e.source_node_id, n.type
      into v_prev_node_id, v_prev_node_type
    from public.workflow_edges e
    join public.workflow_nodes n on n.id = e.source_node_id
    where e.target_node_id = v_inst.current_node_id
    limit 1;

    if v_prev_node_id is not null and v_prev_node_type = 'START'::public.workflow_node_type then
      select e.target_node_id
        into v_prev_node_id
      from public.workflow_edges e
      where e.source_node_id = v_prev_node_id
      limit 1;
    end if;

    if v_prev_node_id is not null then
      update public.workflow_instances wi
      set current_node_id = v_prev_node_id,
          step_assignees = case
            when p_next_assignee_user_id is not null
            then coalesce(wi.step_assignees, '{}'::jsonb) || jsonb_build_object(v_prev_node_id::text, p_next_assignee_user_id::text)
            else coalesce(wi.step_assignees, '{}'::jsonb)
          end,
          updated_at = now()
      where wi.id = p_instance_id
      returning wi.* into v_inst;
    end if;
  end if;

  return query select
    v_inst.id,
    v_inst.template_id,
    v_inst.code,
    v_inst.title,
    v_inst.created_by,
    v_inst.current_node_id,
    v_inst.status,
    coalesce(v_inst.watchers, '{}'::text[]),
    coalesce(v_inst.step_assignees, '{}'::jsonb),
    v_inst.created_at,
    v_inst.updated_at;
end;
$$ revoke execute on function public.process_workflow_instance_fast(uuid, public.workflow_instance_action, uuid, text, uuid) from anon revoke execute on function public.process_workflow_instance_fast(uuid, public.workflow_instance_action, uuid, text, uuid) from public grant execute on function public.process_workflow_instance_fast(uuid, public.workflow_instance_action, uuid, text, uuid) to authenticated notify pgrst, 'reload schema']

[-- Tighten direct role grants for daily-log progress and catalog tables.
-- RLS remains the enforcement layer; anon/public should not have direct table grants.

do $$
declare
  table_name text;
begin
  foreach table_name in array array[
    'public.contract_labor_catalogs',
    'public.daily_log_volumes',
    'public.daily_log_labor',
    'public.daily_log_machines'
  ]
  loop
    if to_regclass(table_name) is not null then
      execute format('revoke all privileges on table %s from anon', table_name);
      execute format('revoke all privileges on table %s from public', table_name);
      execute format('grant select, insert, update, delete on table %s to authenticated', table_name);
    end if;
  end loop;
end;
$$ notify pgrst, 'reload schema']

[-- 1. Pinned messages per conversation
CREATE TABLE IF NOT EXISTS chat_pins (
    id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    conversation_id UUID NOT NULL REFERENCES chat_conversations(id) ON DELETE CASCADE,
    message_id   UUID NOT NULL REFERENCES chat_messages(id) ON DELETE CASCADE,
    pinned_by    UUID NOT NULL REFERENCES users(id),
    pinned_at    TIMESTAMPTZ DEFAULT now(),
    UNIQUE(conversation_id, message_id)
);

-- 2. Server channels (text/voice channels)
CREATE TABLE IF NOT EXISTS chat_server_channels (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    server_id       TEXT NOT NULL,           -- e.g. 'fc-erp', 'rico', etc.
    name            TEXT NOT NULL,
    type            TEXT DEFAULT 'text',     -- 'text' | 'voice'
    conversation_id UUID REFERENCES chat_conversations(id) ON DELETE SET NULL,
    position        INT DEFAULT 0,
    created_at      TIMESTAMPTZ DEFAULT now()
);

-- 3. Call session logs
CREATE TABLE IF NOT EXISTS chat_call_logs (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    conversation_id UUID NOT NULL REFERENCES chat_conversations(id) ON DELETE CASCADE,
    initiator_id    UUID NOT NULL REFERENCES users(id),
    call_type       TEXT NOT NULL,           -- 'audio' | 'video'
    status          TEXT NOT NULL DEFAULT 'ringing',  -- 'ringing'|'answered'|'missed'|'ended'
    started_at      TIMESTAMPTZ DEFAULT now(),
    ended_at        TIMESTAMPTZ,
    duration_secs   INT
);

-- 4. Add reply_to support to messages
ALTER TABLE chat_messages
    ADD COLUMN IF NOT EXISTS reply_to_id UUID REFERENCES chat_messages(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS reply_to_preview JSONB;

-- 5. Add file/attachment metadata
ALTER TABLE chat_messages
    ADD COLUMN IF NOT EXISTS file_urls JSONB DEFAULT '[]'::jsonb;

-- Enable RLS on new tables
ALTER TABLE chat_pins ENABLE ROW LEVEL SECURITY;
ALTER TABLE chat_call_logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE chat_server_channels ENABLE ROW LEVEL SECURITY;

-- Setup RLS Policies safely with cast to avoid TEXT = UUID comparison issues
DROP POLICY IF EXISTS "Members can pin" ON chat_pins;
CREATE POLICY "Members can pin" ON chat_pins
    FOR ALL USING (
        EXISTS (SELECT 1 FROM chat_members
                WHERE conversation_id = chat_pins.conversation_id
                AND (user_id = auth.uid()::text OR user_id::text = auth.uid()::text))
    );

DROP POLICY IF EXISTS "Members can see call logs" ON chat_call_logs;
CREATE POLICY "Members can see call logs" ON chat_call_logs
    FOR ALL USING (
        EXISTS (SELECT 1 FROM chat_members
                WHERE conversation_id = chat_call_logs.conversation_id
                AND (user_id = auth.uid()::text OR user_id::text = auth.uid()::text))
    );

DROP POLICY IF EXISTS "All authenticated can see channels" ON chat_server_channels;
CREATE POLICY "All authenticated can see channels" ON chat_server_channels
    FOR SELECT USING (auth.uid() IS NOT NULL);
]

[do $$
declare
  table_name text;
begin
  foreach table_name in array array[
    'approval_rules',
    'project_permission_types',
    'project_staff',
    'project_staff_permissions'
  ]
  loop
    if to_regclass(format('public.%I', table_name)) is null then
      continue;
    end if;

    execute format('revoke all on table public.%I from anon', table_name);
    execute format('revoke all on table public.%I from authenticated', table_name);
    execute format('grant select, insert, update, delete on table public.%I to authenticated', table_name);

    execute format('alter table public.%I enable row level security', table_name);

    execute format('drop policy if exists %I on public.%I', table_name || '_select', table_name);
    execute format('drop policy if exists %I on public.%I', table_name || '_insert', table_name);
    execute format('drop policy if exists %I on public.%I', table_name || '_update', table_name);
    execute format('drop policy if exists %I on public.%I', table_name || '_delete', table_name);

    execute format(
      'create policy %I on public.%I for select to authenticated using (true)',
      table_name || '_select',
      table_name
    );
    execute format(
      'create policy %I on public.%I for insert to authenticated with check (public.is_module_admin(%L))',
      table_name || '_insert',
      table_name,
      'DA'
    );
    execute format(
      'create policy %I on public.%I for update to authenticated using (public.is_module_admin(%L)) with check (public.is_module_admin(%L))',
      table_name || '_update',
      table_name,
      'DA',
      'DA'
    );
    execute format(
      'create policy %I on public.%I for delete to authenticated using (public.is_module_admin(%L))',
      table_name || '_delete',
      table_name,
      'DA'
    );
  end loop;
end $$ notify pgrst, 'reload schema']

[-- Allow destination warehouse keepers to record the checked/received
-- quantities on an in-flight WMS transaction before changing status.
-- This is intentionally exposed through an RPC instead of direct UPDATE RLS
-- so callers can only adjust quantities on rows they are allowed to process.

create or replace function public.update_transaction_items_for_receipt(
  p_transaction_id text,
  p_items jsonb
)
returns public.transactions
language plpgsql
security definer
set search_path = public
as $$
declare
  v_tx public.transactions%rowtype;
  v_user public.users%rowtype;
  v_item_count integer;
  v_idx integer;
  v_old_item jsonb;
  v_new_item jsonb;
  v_old_qty numeric;
  v_new_qty numeric;
  v_is_fulfillment_transfer boolean := false;
  v_can_adjust boolean := false;
begin
  select * into v_tx
  from public.transactions
  where id = p_transaction_id
  for update;
  if not found then
    raise exception 'transaction not found: %', p_transaction_id;
  end if;

  select * into v_user from public.users where id = public.current_app_user_id();
  if v_user.id is null then
    raise exception 'authentication required';
  end if;

  if v_tx.status not in ('PENDING'::public.transaction_status, 'APPROVED'::public.transaction_status) then
    raise exception 'Chỉ được điều chỉnh số lượng ở bước chờ duyệt hoặc chờ xác nhận nhập.';
  end if;

  if jsonb_typeof(p_items) <> 'array' then
    raise exception 'invalid transaction items payload';
  end if;

  v_item_count := jsonb_array_length(coalesce(v_tx.items, '[]'::jsonb));
  if v_item_count = 0 then
    raise exception 'Phiếu kho không có dòng vật tư để điều chỉnh.';
  end if;
  if jsonb_array_length(p_items) <> v_item_count then
    raise exception 'Không được thêm/xóa dòng vật tư khi duyệt phiếu kho.';
  end if;

  select exists (
    select 1
    from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) line(value)
    where nullif(line.value->>'fulfillmentBatchId', '') is not null
  )
  into v_is_fulfillment_transfer;

  v_is_fulfillment_transfer := v_is_fulfillment_transfer
    and v_tx.type = 'TRANSFER'::public.transaction_type
    and nullif(v_tx.target_warehouse_id, '') is not null;

  v_can_adjust :=
    public.is_module_admin('WMS')
    or (
      v_user.role = 'WAREHOUSE_KEEPER'
      and (
        v_user.assigned_warehouse_id is null
        or (v_tx.type = 'IMPORT'::public.transaction_type and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id)
        or (v_is_fulfillment_transfer and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id)
        or (
          v_tx.status = 'APPROVED'::public.transaction_status
          and v_tx.type = 'TRANSFER'::public.transaction_type
          and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id
        )
      )
    );

  if not v_can_adjust then
    raise exception 'insufficient privilege to adjust transaction quantities';
  end if;

  for v_idx in 0..(v_item_count - 1) loop
    v_old_item := v_tx.items -> v_idx;
    v_new_item := p_items -> v_idx;

    if v_old_item is null or v_new_item is null then
      raise exception 'invalid transaction items payload';
    end if;

    if coalesce(v_old_item->>'itemId', '') is distinct from coalesce(v_new_item->>'itemId', '')
       or coalesce(v_old_item->>'requestLineId', '') is distinct from coalesce(v_new_item->>'requestLineId', '')
       or coalesce(v_old_item->>'fulfillmentBatchId', '') is distinct from coalesce(v_new_item->>'fulfillmentBatchId', '') then
      raise exception 'Không được đổi vật tư/dòng đề xuất khi duyệt phiếu kho.';
    end if;

    v_old_qty := coalesce(nullif(v_old_item->>'quantity', '')::numeric, 0);
    v_new_qty := coalesce(nullif(v_new_item->>'quantity', '')::numeric, 0);

    if v_new_qty < 0 then
      raise exception 'Số lượng thực nhận không được âm.';
    end if;
    if v_new_qty > v_old_qty then
      raise exception 'Số lượng thực nhận không được lớn hơn số lượng trên phiếu. Vui lòng tạo bổ sung/điều chỉnh PO nếu có giao vượt.';
    end if;
  end loop;

  update public.transactions
  set items = p_items
  where id = p_transaction_id
  returning * into v_tx;

  return v_tx;
end;
$$ revoke all on function public.update_transaction_items_for_receipt(text, jsonb) from public grant execute on function public.update_transaction_items_for_receipt(text, jsonb) to authenticated notify pgrst, 'reload schema']

[-- Keep WMS transaction completion and project fulfillment receipt in sync.
-- The client may be allowed to complete a transaction through the RPC while
-- RLS prevents it from reading/updating the fulfillment batch afterwards. This
-- RPC performs the receipt sync with the same trusted status-transition path.

create or replace function public.sync_fulfillment_receipt_for_transaction(
  p_transaction_id text,
  p_actor_user_id uuid default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_tx public.transactions%rowtype;
  v_user public.users%rowtype;
  v_batch public.material_request_fulfillment_batches%rowtype;
  v_actor_user_id uuid;
  v_can_sync boolean := false;
  v_line record;
  v_received_qty numeric;
  v_reason text;
  v_has_variance boolean := false;
  v_po_id text;
  v_po public.purchase_orders%rowtype;
  v_next_items jsonb;
  v_is_delivered boolean;
  v_already_recorded boolean;
begin
  select * into v_tx
  from public.transactions
  where id = p_transaction_id
  for update;
  if not found then
    raise exception 'transaction not found: %', p_transaction_id;
  end if;

  select * into v_user
  from public.users
  where id = public.current_app_user_id();
  if v_user.id is null then
    raise exception 'authentication required';
  end if;

  v_actor_user_id := coalesce(p_actor_user_id, v_user.id);

  v_can_sync :=
    public.is_admin()
    or public.is_module_admin('WMS')
    or (
      v_user.role = 'WAREHOUSE_KEEPER'
      and (
        v_user.assigned_warehouse_id is null
        or (
          v_tx.type in ('IMPORT'::public.transaction_type, 'TRANSFER'::public.transaction_type)
          and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id
        )
      )
    );

  if not v_can_sync then
    raise exception 'insufficient privilege to sync fulfillment receipt';
  end if;

  if v_tx.status <> 'COMPLETED'::public.transaction_status then
    raise exception 'Chỉ đồng bộ nhận hàng cho phiếu kho đã hoàn tất.';
  end if;

  select * into v_batch
  from public.material_request_fulfillment_batches
  where transaction_id = p_transaction_id
  for update;
  if not found then
    return jsonb_build_object('synced', false, 'reason', 'batch_not_found');
  end if;

  if v_batch.status not in ('issued', 'received') then
    return jsonb_build_object('synced', false, 'reason', 'batch_not_receivable', 'batchStatus', v_batch.status);
  end if;

  for v_line in
    select *
    from public.material_request_fulfillment_lines
    where batch_id = v_batch.id
    order by created_at asc
    for update
  loop
    select
      coalesce(sum(coalesce(nullif(item.value->>'quantity', '')::numeric, 0)), 0),
      max(nullif(item.value->>'varianceReason', ''))
    into v_received_qty, v_reason
    from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) item(value)
    where coalesce(item.value->>'fulfillmentBatchId', '') = v_batch.id::text
      and item.value->>'requestLineId' = v_line.request_line_id;

    if coalesce(v_received_qty, 0) = 0 then
      select
        coalesce(sum(coalesce(nullif(item.value->>'quantity', '')::numeric, 0)), 0),
        max(nullif(item.value->>'varianceReason', ''))
      into v_received_qty, v_reason
      from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) item(value)
      where coalesce(item.value->>'fulfillmentBatchId', '') = v_batch.id::text
        and item.value->>'itemId' = v_line.item_id;
    end if;

    if coalesce(v_received_qty, 0) <> coalesce(v_line.issued_qty, 0) then
      v_has_variance := true;
    end if;

    update public.material_request_fulfillment_lines
    set
      received_qty = coalesce(v_received_qty, 0),
      variance_reason = coalesce(
        nullif(v_reason, ''),
        variance_reason,
        case
          when coalesce(v_received_qty, 0) <> coalesce(v_line.issued_qty, 0)
            then 'Thủ kho công trường xác nhận số lượng thực nhận lệch phiếu kho.'
          else null
        end
      )
    where id = v_line.id;
  end loop;

  if v_batch.status = 'issued' then
    update public.material_request_fulfillment_batches
    set
      status = 'received',
      received_by = v_actor_user_id,
      received_at = now(),
      reason = coalesce(
        reason,
        case when v_has_variance then 'Thủ kho công trường xác nhận nhận lệch theo thực tế.' else null end
      )
    where id = v_batch.id
    returning * into v_batch;
  end if;

  for v_po_id in
    select distinct po_id
    from public.material_request_fulfillment_lines
    where batch_id = v_batch.id
      and po_id is not null
  loop
    select * into v_po
    from public.purchase_orders
    where id = v_po_id
    for update;
    if not found then
      continue;
    end if;

    select exists (
      select 1
      from jsonb_array_elements_text(coalesce(v_po.received_transaction_ids, '[]'::jsonb)) existing(id)
      where existing.id = v_tx.id
    )
    into v_already_recorded;
    if v_already_recorded then
      continue;
    end if;

    with receipt_by_line as (
      select po_line_id, sum(coalesce(received_qty, 0)) as received_qty
      from public.material_request_fulfillment_lines
      where batch_id = v_batch.id
        and po_id = v_po_id
        and po_line_id is not null
      group by po_line_id
    ),
    item_rows as (
      select
        item.value as item,
        item.ordinality,
        coalesce(item.value->>'lineId', item.value->>'line_id', item.value->>'itemId', item.value->>'item_id') as line_key,
        coalesce(nullif(item.value->>'qty', '')::numeric, 0) as ordered_qty,
        coalesce(nullif(item.value->>'receivedQty', '')::numeric, 0) as current_received_qty
      from jsonb_array_elements(coalesce(v_po.items, '[]'::jsonb)) with ordinality item(value, ordinality)
    ),
    next_rows as (
      select
        case
          when coalesce(r.received_qty, 0) > 0 then
            jsonb_set(
              ir.item,
              '{receivedQty}',
              to_jsonb(least(ir.ordered_qty, ir.current_received_qty + coalesce(r.received_qty, 0))),
              true
            )
          else ir.item
        end as item,
        ir.ordinality
      from item_rows ir
      left join receipt_by_line r on r.po_line_id = ir.line_key
    )
    select coalesce(jsonb_agg(item order by ordinality), '[]'::jsonb)
    into v_next_items
    from next_rows;

    select coalesce(bool_and(
      coalesce(nullif(item.value->>'qty', '')::numeric, 0) <= coalesce(nullif(item.value->>'receivedQty', '')::numeric, 0)
    ), false)
    into v_is_delivered
    from jsonb_array_elements(coalesce(v_next_items, '[]'::jsonb)) item(value);

    update public.purchase_orders
    set
      items = v_next_items,
      status = case when v_is_delivered then 'delivered' else 'partial' end,
      actual_delivery_date = case when v_is_delivered then current_date else actual_delivery_date end,
      received_transaction_ids = coalesce(received_transaction_ids, '[]'::jsonb) || jsonb_build_array(v_tx.id)
    where id = v_po_id;
  end loop;

  return jsonb_build_object(
    'synced', true,
    'batchId', v_batch.id,
    'batchStatus', v_batch.status,
    'hasVariance', v_has_variance
  );
end;
$$ revoke all on function public.sync_fulfillment_receipt_for_transaction(text, uuid) from public grant execute on function public.sync_fulfillment_receipt_for_transaction(text, uuid) to authenticated notify pgrst, 'reload schema']

[-- Keep delete policies aligned with the client-side delete guards.
-- Before this migration, rejected/returned project material requests and
-- returned-stock PO rows could be blocked by RLS while the client still
-- received a successful 204 response from PostgREST.

create schema if not exists app_private create or replace function app_private.material_request_can_delete_v2(
  p_request_origin text,
  p_project_id text,
  p_status text,
  p_ever_submitted boolean,
  p_requester_id uuid,
  p_submitted_to_user_id text,
  p_source_warehouse_id text,
  p_site_warehouse_id text,
  p_workflow_step text
)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select case
    when coalesce(p_request_origin, 'wms') = 'project' then (
      public.is_admin()
      or app_private.project_user_has_permission(p_project_id, null, 'delete')
      or (
        p_requester_id = public.current_app_user_id()
        and (
          coalesce(p_status, 'DRAFT') = 'REJECTED'
          or coalesce(p_workflow_step, '') = 'returned_to_creator'
          or (
            coalesce(p_status, 'DRAFT') = 'DRAFT'
            and not coalesce(p_ever_submitted, false)
          )
        )
      )
    )
    else (
      public.is_admin()
      or public.is_module_admin('WMS')
      or (
        coalesce(p_status, 'DRAFT') in ('DRAFT', 'REJECTED')
        and p_requester_id = public.current_app_user_id()
      )
      or app_private.current_user_is_global_wms_keeper()
      or app_private.current_user_is_wms_keeper_for(p_source_warehouse_id)
      or app_private.current_user_is_wms_keeper_for(p_site_warehouse_id)
      or (
        p_submitted_to_user_id is not null
        and p_submitted_to_user_id = public.current_app_user_id()::text
      )
    )
  end;
$$ drop policy if exists requests_delete on public.requests create policy requests_delete
  on public.requests
  for delete
  to authenticated
  using (
    app_private.material_request_can_delete_v2(
      request_origin,
      project_id,
      status::text,
      ever_submitted,
      requester_id,
      submitted_to_user_id,
      source_warehouse_id,
      site_warehouse_id,
      workflow_step::text
    )
  ) create or replace function app_private.project_po_stock_cleanup_ok(
  p_po_id text,
  p_received_transaction_ids jsonb
)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_has_received_batch_qty boolean := false;
  v_has_active_batches boolean := false;
  v_has_returned_batch boolean := false;
  v_has_unfinished_transactions boolean := false;
  v_missing_return_transaction boolean := false;
  v_has_insufficient_return_qty boolean := false;
  v_return_transaction_ids text[] := '{}';
  v_receipt_transaction_ids text[] := '{}';
  v_all_transaction_ids text[] := '{}';
begin
  if to_regclass('public.material_request_fulfillment_lines') is null then
    return false;
  end if;

  select coalesce(bool_or(coalesce(received_qty, 0) > 0), false)
    into v_has_received_batch_qty
  from public.material_request_fulfillment_lines
  where po_id = p_po_id;

  if not v_has_received_batch_qty then
    return false;
  end if;

  if to_regclass('public.material_request_fulfillment_batches') is null then
    return false;
  end if;

  select
    coalesce(bool_or(lower(coalesce(b.status::text, '')) not in ('returned', 'cancelled')), false),
    coalesce(bool_or(lower(coalesce(b.status::text, '')) = 'returned'), false)
    into v_has_active_batches, v_has_returned_batch
  from public.material_request_fulfillment_batches b
  where b.id in (
    select distinct batch_id
    from public.material_request_fulfillment_lines
    where po_id = p_po_id
      and batch_id is not null
  );

  select coalesce(array_agg(distinct m.match[1]), '{}')
    into v_return_transaction_ids
  from public.material_request_fulfillment_batches b
  cross join lateral regexp_matches(coalesce(b.note, ''), '(tx-[a-z0-9-]+)', 'gi') as m(match)
  where b.id in (
    select distinct batch_id
    from public.material_request_fulfillment_lines
    where po_id = p_po_id
      and batch_id is not null
  );

  select coalesce(array_agg(distinct tx_id), '{}')
    into v_receipt_transaction_ids
  from (
    select jsonb_array_elements_text(coalesce(p_received_transaction_ids, '[]'::jsonb)) as tx_id
    union
    select b.transaction_id::text as tx_id
    from public.material_request_fulfillment_batches b
    where b.id in (
      select distinct batch_id
      from public.material_request_fulfillment_lines
      where po_id = p_po_id
        and batch_id is not null
    )
  ) tx
  where nullif(tx_id, '') is not null;

  select coalesce(array_agg(distinct tx_id), '{}')
    into v_all_transaction_ids
  from (
    select unnest(v_return_transaction_ids) as tx_id
    union
    select unnest(v_receipt_transaction_ids) as tx_id
  ) tx
  where nullif(tx_id, '') is not null;

  if coalesce(array_length(v_all_transaction_ids, 1), 0) > 0 then
    select coalesce(bool_or(upper(coalesce(t.status::text, '')) not in ('COMPLETED', 'CANCELLED')), false)
      into v_has_unfinished_transactions
    from public.transactions t
    where t.id::text = any(v_all_transaction_ids);
  end if;

  if v_has_received_batch_qty and v_has_returned_batch then
    if coalesce(array_length(v_return_transaction_ids, 1), 0) = 0 then
      v_missing_return_transaction := true;
    else
      select exists (
        select 1
        from unnest(v_return_transaction_ids) as r(tx_id)
        left join public.transactions t
          on t.id::text = r.tx_id
         and upper(coalesce(t.status::text, '')) = 'COMPLETED'
        where t.id is null
      )
        into v_missing_return_transaction;
    end if;
  end if;

  if coalesce(array_length(v_return_transaction_ids, 1), 0) > 0 then
    select exists (
      with received as (
        select item_id::text as item_id, sum(coalesce(received_qty, 0))::numeric as qty
        from public.material_request_fulfillment_lines
        where po_id = p_po_id
          and item_id is not null
          and coalesce(received_qty, 0) > 0
        group by item_id::text
      ),
      returned as (
        select
          elem->>'itemId' as item_id,
          sum(coalesce(nullif(elem->>'quantity', '')::numeric, 0))::numeric as qty
        from public.transactions t
        cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) as elem
        where t.id::text = any(v_return_transaction_ids)
          and upper(coalesce(t.status::text, '')) = 'COMPLETED'
          and nullif(elem->>'itemId', '') is not null
        group by elem->>'itemId'
      )
      select 1
      from received r
      left join returned ret on ret.item_id = r.item_id
      where coalesce(ret.qty, 0) + 0.000000001 < r.qty
      limit 1
    )
      into v_has_insufficient_return_qty;
  else
    v_has_insufficient_return_qty := true;
  end if;

  return not v_has_active_batches
    and not v_has_unfinished_transactions
    and not v_missing_return_transaction
    and not v_has_insufficient_return_qty;
end;
$$ create or replace function app_private.project_po_can_delete_v2(
  p_po_id text,
  p_project_id text,
  p_construction_site_id text,
  p_status text,
  p_ever_submitted boolean,
  p_received_transaction_ids jsonb,
  p_items jsonb
)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_status text := lower(coalesce(p_status, 'draft'));
  v_has_permission boolean := false;
  v_has_received_batch_qty boolean := false;
  v_received_item_qty numeric := 0;
  v_no_receipt boolean := false;
  v_stock_cleanup_ok boolean := false;
begin
  v_has_permission := public.is_admin()
    or app_private.project_user_has_permission(p_project_id, p_construction_site_id, 'delete');

  if not v_has_permission then
    return false;
  end if;

  if v_status = 'draft' and not coalesce(p_ever_submitted, false) then
    return true;
  end if;

  select coalesce(sum(coalesce(nullif(elem->>'receivedQty', '')::numeric, 0)), 0)
    into v_received_item_qty
  from jsonb_array_elements(coalesce(p_items, '[]'::jsonb)) as elem;

  if to_regclass('public.material_request_fulfillment_lines') is not null then
    select coalesce(bool_or(coalesce(received_qty, 0) > 0), false)
      into v_has_received_batch_qty
    from public.material_request_fulfillment_lines
    where po_id = p_po_id;
  end if;

  v_no_receipt := v_received_item_qty <= 0
    and jsonb_array_length(coalesce(p_received_transaction_ids, '[]'::jsonb)) = 0
    and not v_has_received_batch_qty;

  if v_status in ('returned', 'cancelled', 'partial', 'delivered', 'closed') then
    v_stock_cleanup_ok := app_private.project_po_stock_cleanup_ok(
      p_po_id,
      p_received_transaction_ids
    );
  end if;

  return (
    v_status in ('returned', 'cancelled')
    and (v_no_receipt or v_stock_cleanup_ok)
  )
  or (
    v_status in ('partial', 'delivered', 'closed')
    and v_has_received_batch_qty
    and v_stock_cleanup_ok
  );
end;
$$ drop policy if exists purchase_orders_delete on public.purchase_orders create policy purchase_orders_delete
  on public.purchase_orders
  for delete
  to authenticated
  using (
    app_private.project_po_can_delete_v2(
      id::text,
      project_id::text,
      construction_site_id::text,
      status::text,
      ever_submitted,
      received_transaction_ids,
      items
    )
  )]

[-- WMS stock quantities must support decimal units such as m3 and kg.
-- The previous RPC cast stock_by_warehouse values to integer, which fails for
-- existing decimal stock like 20.5 m3 when confirming a transfer receipt.

drop function if exists public.apply_stock_change(text, text, integer) create or replace function public.apply_stock_change(
  p_item_id text,
  p_warehouse_id text,
  p_delta numeric
)
returns jsonb
language plpgsql
security definer
set search_path = 'public'
as $$
declare
  v_stock jsonb;
  v_current numeric;
  v_next numeric;
begin
  if public.current_app_user_id() is null then
    raise exception 'authentication required';
  end if;
  if nullif(p_warehouse_id, '') is null then
    raise exception 'warehouse id is required';
  end if;

  select coalesce(stock_by_warehouse, '{}'::jsonb)
    into v_stock
  from public.items
  where id = p_item_id
  for update;
  if not found then
    raise exception 'item not found: %', p_item_id;
  end if;

  v_current := coalesce((v_stock ->> p_warehouse_id)::numeric, 0);
  v_next := v_current + coalesce(p_delta, 0);
  if v_next < -0.000000001 then
    raise exception 'insufficient stock for item %, warehouse %: available %, delta %',
      p_item_id, p_warehouse_id, v_current, p_delta;
  end if;
  if abs(v_next) < 0.000000001 then
    v_next := 0;
  end if;

  v_stock := jsonb_set(v_stock, array[p_warehouse_id], to_jsonb(v_next), true);

  update public.items
  set stock_by_warehouse = v_stock
  where id = p_item_id;

  return v_stock;
end;
$$ create or replace function public.process_transaction_status(
  p_transaction_id text,
  p_status public.transaction_status,
  p_approver_id uuid
)
returns public.transactions
language plpgsql
security definer
set search_path = 'public'
as $$
declare
  v_tx public.transactions%rowtype;
  v_user public.users%rowtype;
  v_line jsonb;
  v_pending jsonb;
  v_check record;
  v_item_id text;
  v_qty numeric;
  v_on_hand numeric;
  v_tx_reserved numeric;
  v_request_reserved numeric;
  v_reserved numeric;
  v_available numeric;
  v_item_name text;
  v_warehouse_name text;
  v_stock_warehouse_id text;
  v_is_fulfillment_transfer boolean := false;
  v_can_approve boolean := false;
  v_can_complete boolean := false;
begin
  select * into v_tx
  from public.transactions
  where id = p_transaction_id
  for update;
  if not found then
    raise exception 'transaction not found: %', p_transaction_id;
  end if;

  select * into v_user from public.users where id = public.current_app_user_id();
  if v_user.id is null then
    raise exception 'authentication required';
  end if;

  select exists (
    select 1
    from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) line(value)
    where nullif(line.value->>'fulfillmentBatchId', '') is not null
  )
  into v_is_fulfillment_transfer;

  v_is_fulfillment_transfer := v_is_fulfillment_transfer
    and v_tx.type = 'TRANSFER'::public.transaction_type
    and nullif(v_tx.target_warehouse_id, '') is not null;

  v_can_approve :=
    public.is_module_admin('WMS')
    or (
      v_user.role = 'WAREHOUSE_KEEPER'
      and (
        v_user.assigned_warehouse_id is null
        or (v_tx.type = 'IMPORT'::public.transaction_type and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id)
        or (v_is_fulfillment_transfer and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id)
        or (
          not v_is_fulfillment_transfer
          and v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
          and v_user.assigned_warehouse_id is not distinct from v_tx.source_warehouse_id
        )
      )
    );

  v_can_complete :=
    public.is_module_admin('WMS')
    or (
      v_user.role = 'WAREHOUSE_KEEPER'
      and (
        v_user.assigned_warehouse_id is null
        or (v_tx.type in ('IMPORT'::public.transaction_type, 'TRANSFER'::public.transaction_type)
            and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id)
        or (v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type)
            and v_user.assigned_warehouse_id is not distinct from v_tx.source_warehouse_id)
      )
    );

  if p_status = 'APPROVED'::public.transaction_status and not v_can_approve then
    raise exception 'insufficient privilege to approve transaction';
  end if;

  if p_status = 'CANCELLED'::public.transaction_status
     and not v_can_approve
     and v_tx.requester_id is distinct from v_user.id then
    raise exception 'insufficient privilege to cancel transaction';
  end if;

  if p_status = 'COMPLETED'::public.transaction_status and not v_can_complete then
    raise exception 'insufficient privilege to complete transaction';
  end if;

  if v_tx.status = p_status then
    return v_tx;
  end if;
  if v_tx.status = 'CANCELLED'::public.transaction_status then
    raise exception 'cancelled transaction cannot be changed';
  end if;
  if v_tx.status = 'COMPLETED'::public.transaction_status then
    raise exception 'completed transaction cannot be changed';
  end if;

  if p_status = 'COMPLETED'::public.transaction_status
     and v_is_fulfillment_transfer
     and v_tx.status <> 'APPROVED'::public.transaction_status then
    raise exception 'Đợt cấp cần được thủ kho công trường duyệt số lượng/chất lượng trước khi xác nhận nhập kho.';
  end if;

  if p_status in ('APPROVED'::public.transaction_status, 'COMPLETED'::public.transaction_status)
     and v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type, 'ADJUSTMENT'::public.transaction_type) then
    v_stock_warehouse_id := case
      when v_tx.type = 'ADJUSTMENT'::public.transaction_type then v_tx.target_warehouse_id
      else v_tx.source_warehouse_id
    end;
    if nullif(v_stock_warehouse_id, '') is null then
      raise exception 'source warehouse is required for stock-out transaction';
    end if;

    for v_check in
      select
        line.value->>'itemId' as item_id,
        sum(
          case
            when v_tx.type = 'ADJUSTMENT'::public.transaction_type
              then abs(least(0, coalesce(nullif(line.value->>'quantity', '')::numeric, 0)))
            else coalesce(nullif(line.value->>'quantity', '')::numeric, 0)
          end
        ) as qty
      from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) line(value)
      group by line.value->>'itemId'
    loop
      v_item_id := v_check.item_id;
      v_qty := coalesce(v_check.qty, 0);
      if v_item_id is null then
        raise exception 'invalid transaction item payload';
      end if;
      if v_qty <= 0 then
        if v_tx.type = 'ADJUSTMENT'::public.transaction_type then
          continue;
        end if;
        raise exception 'invalid transaction item payload';
      end if;

      select
        coalesce((coalesce(i.stock_by_warehouse, '{}'::jsonb) ->> v_stock_warehouse_id)::numeric, 0),
        i.name
      into v_on_hand, v_item_name
      from public.items i
      where i.id = v_item_id
      for update;
      if not found then
        raise exception 'item not found: %', v_item_id;
      end if;

      select coalesce(sum(coalesce(nullif(line.value->>'quantity', '')::numeric, 0)), 0)
      into v_tx_reserved
      from public.transactions t
      cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) line(value)
      where t.id <> v_tx.id
        and t.source_warehouse_id = v_stock_warehouse_id
        and t.status in ('PENDING'::public.transaction_status, 'APPROVED'::public.transaction_status)
        and t.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
        and line.value->>'itemId' = v_item_id;

      select coalesce(sum(
        case
          when r.status = 'PENDING'::public.request_status
            then coalesce(nullif(line.value->>'requestQty', '')::numeric, 0)
          else coalesce(nullif(line.value->>'approvedQty', '')::numeric, 0)
        end
      ), 0)
      into v_request_reserved
      from public.requests r
      cross join lateral jsonb_array_elements(coalesce(r.items, '[]'::jsonb)) line(value)
      where r.source_warehouse_id = v_stock_warehouse_id
        and (v_tx.related_request_id is null or r.id <> v_tx.related_request_id)
        and r.status in ('PENDING'::public.request_status, 'APPROVED'::public.request_status, 'IN_TRANSIT'::public.request_status)
        and not (
          (coalesce(r.request_origin, 'wms') = 'project' or r.project_id is not null or r.construction_site_id is not null)
          and r.status <> 'PENDING'::public.request_status
        )
        and line.value->>'itemId' = v_item_id;

      v_reserved := coalesce(v_tx_reserved, 0) + coalesce(v_request_reserved, 0);
      v_available := greatest(0, v_on_hand - v_reserved);
      if v_qty > v_available then
        select name into v_warehouse_name from public.warehouses where id = v_stock_warehouse_id;
        raise exception 'Không đủ tồn khả dụng tại kho "%": vật tư "%"; cần %, tồn thực %, đang giữ %, khả dụng %. Vui lòng xử lý phiếu pending/giữ chỗ trước.',
          coalesce(v_warehouse_name, v_stock_warehouse_id),
          coalesce(v_item_name, v_item_id),
          v_qty,
          v_on_hand,
          v_reserved,
          v_available;
      end if;
    end loop;
  end if;

  if p_status in ('APPROVED'::public.transaction_status, 'COMPLETED'::public.transaction_status) then
    for v_pending in
      select value from jsonb_array_elements(coalesce(v_tx.pending_items, '[]'::jsonb))
    loop
      insert into public.items (
        id, sku, name, category, unit, purchase_unit,
        price_in, price_out, min_stock, supplier_id, image_url,
        stock_by_warehouse, location
      )
      values (
        v_pending->>'id',
        v_pending->>'sku',
        v_pending->>'name',
        coalesce(nullif(v_pending->>'category', ''), 'Khác'),
        coalesce(nullif(v_pending->>'unit', ''), 'Cái'),
        nullif(v_pending->>'purchaseUnit', ''),
        coalesce(nullif(v_pending->>'priceIn', '')::numeric, 0),
        coalesce(nullif(v_pending->>'priceOut', '')::numeric, 0),
        coalesce(nullif(v_pending->>'minStock', '')::integer, 0),
        nullif(v_pending->>'supplierId', ''),
        nullif(v_pending->>'imageUrl', ''),
        coalesce(v_pending->'stockByWarehouse', '{}'::jsonb),
        nullif(v_pending->>'location', '')
      )
      on conflict (id) do nothing;
    end loop;
  end if;

  if p_status = 'COMPLETED'::public.transaction_status then
    for v_line in
      select value from jsonb_array_elements(v_tx.items)
    loop
      v_item_id := v_line->>'itemId';
      v_qty := coalesce(nullif(v_line->>'quantity', '')::numeric, 0);
      if v_item_id is null
         or (v_tx.type = 'ADJUSTMENT'::public.transaction_type and v_qty = 0)
         or (v_tx.type <> 'ADJUSTMENT'::public.transaction_type and v_qty <= 0) then
        raise exception 'invalid transaction item payload';
      end if;

      if v_tx.type = 'IMPORT'::public.transaction_type then
        perform public.apply_stock_change(v_item_id, v_tx.target_warehouse_id, v_qty);
      elsif v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type) then
        perform public.apply_stock_change(v_item_id, v_tx.source_warehouse_id, -v_qty);
      elsif v_tx.type = 'TRANSFER'::public.transaction_type then
        perform public.apply_stock_change(v_item_id, v_tx.source_warehouse_id, -v_qty);
        perform public.apply_stock_change(v_item_id, v_tx.target_warehouse_id, v_qty);
      elsif v_tx.type = 'ADJUSTMENT'::public.transaction_type then
        perform public.apply_stock_change(v_item_id, v_tx.target_warehouse_id, v_qty);
      end if;
    end loop;
  end if;

  update public.transactions
  set status = p_status,
      approver_id = p_approver_id
  where id = p_transaction_id
  returning * into v_tx;

  return v_tx;
end;
$$ revoke all on function public.apply_stock_change(text, text, numeric) from public revoke execute on function public.apply_stock_change(text, text, numeric) from anon grant execute on function public.apply_stock_change(text, text, numeric) to authenticated]

[-- Complete the project material-request workflow runtime.
-- Existing Phase 1-2 public RPC signatures remain compatible, while project
-- workflow behavior is made authoritative from the instance snapshot.

create extension if not exists pgcrypto create extension if not exists pg_cron create schema if not exists app_private alter table public.workflow_subjects
  add column if not exists return_to_instance_node_id uuid references public.workflow_instance_nodes(id) on delete set null,
  add column if not exists last_action_instance_node_id uuid references public.workflow_instance_nodes(id) on delete set null alter table public.workflow_step_assignments
  add column if not exists assignment_round_id uuid create index if not exists idx_workflow_step_assignments_round
  on public.workflow_step_assignments(workflow_subject_id, assignment_round_id)
  where assignment_round_id is not null create table if not exists public.workflow_sla_notifications (
  id uuid primary key default gen_random_uuid(),
  workflow_step_assignment_id uuid not null references public.workflow_step_assignments(id) on delete cascade,
  workflow_subject_id uuid not null references public.workflow_subjects(id) on delete cascade,
  user_id uuid not null references public.users(id) on delete cascade,
  notification_kind text not null check (notification_kind in ('DUE_SOON', 'OVERDUE')),
  notified_at timestamptz not null default now(),
  unique(workflow_step_assignment_id, notification_kind)
) create index if not exists idx_workflow_sla_notifications_subject
  on public.workflow_sla_notifications(workflow_subject_id, notified_at desc) alter table public.workflow_sla_notifications enable row level security create or replace function app_private.project_workflow_template_manager(
  p_template_id uuid,
  p_actor uuid default public.current_app_user_id()
)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select coalesce(
    public.is_admin()
    or public.is_module_admin('WF')
    or exists (
      select 1
      from public.workflow_templates wt
      where wt.id = p_template_id
        and p_actor::text = any(coalesce(wt.managers, '{}'::text[]))
    ),
    false
  );
$$ create or replace function app_private.project_user_has_permission(
  p_project_id text,
  p_construction_site_id text,
  p_permission_code text,
  p_user_id uuid
)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select coalesce(
    exists (
      select 1
      from public.project_staff ps
      join public.project_staff_permissions psp
        on psp.staff_id = ps.id
       and coalesce(psp.is_active, true)
      join public.project_permission_types ppt
        on ppt.id = psp.permission_type_id
       and ppt.code = p_permission_code
       and coalesce(ppt.is_active, true)
      where ps.user_id::text = p_user_id::text
        and ps.end_date is null
        and (
          (p_project_id is not null and ps.project_id::text = p_project_id)
          or (p_construction_site_id is not null and ps.construction_site_id::text = p_construction_site_id)
        )
    ),
    false
  );
$$ create or replace function app_private.project_workflow_binding_can_manage(
  p_project_id text,
  p_construction_site_id text,
  p_template_id uuid default null
)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select coalesce(
    public.is_admin()
    or public.is_module_admin('WF')
    or (
      p_project_id is not null
      and (
        public.is_module_admin('DA')
        or (
          (
            (p_template_id is not null and app_private.project_workflow_template_manager(p_template_id, public.current_app_user_id()))
            or (
              p_template_id is null
              and exists (
                select 1
                from public.workflow_templates wt
                where public.current_app_user_id()::text = any(coalesce(wt.managers, '{}'::text[]))
              )
            )
          )
          and app_private.project_user_has_permission(p_project_id, p_construction_site_id, 'edit')
        )
      )
    ),
    false
  );
$$ drop function if exists app_private.project_workflow_binding_can_manage(text, text) cascade create or replace function app_private.project_workflow_validate_template(p_template_id uuid)
returns jsonb
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_template_active boolean := false;
  v_start_count integer := 0;
  v_end_count integer := 0;
  v_task_count integer := 0;
  v_path_reaches_end boolean := false;
  v_invalid_step_count integer := 0;
  v_errors text[] := '{}'::text[];
begin
  select coalesce(wt.is_active, true)
    into v_template_active
  from public.workflow_templates wt
  where wt.id = p_template_id;

  if not found then
    return jsonb_build_object('valid', false, 'errors', jsonb_build_array('Không tìm thấy mẫu workflow.'));
  end if;

  if not v_template_active then
    v_errors := array_append(v_errors, 'Mẫu workflow đang ngừng hoạt động.');
  end if;

  select
    count(*) filter (where wn.type = 'START'::public.workflow_node_type),
    count(*) filter (where wn.type = 'END'::public.workflow_node_type),
    count(*) filter (where wn.type not in ('START'::public.workflow_node_type, 'END'::public.workflow_node_type)),
    count(*) filter (
      where wn.type not in ('START'::public.workflow_node_type, 'END'::public.workflow_node_type)
        and (
          coalesce(nullif(wn.label, ''), '') = ''
          or coalesce(nullif(wn.config ->> 'approvalPolicy', ''), 'ANY_ONE') <> 'ANY_ONE'
        )
    )
  into v_start_count, v_end_count, v_task_count, v_invalid_step_count
  from public.workflow_nodes wn
  where wn.template_id = p_template_id;

  if v_start_count <> 1 then
    v_errors := array_append(v_errors, 'Workflow phải có đúng một bước Bắt đầu.');
  end if;
  if v_end_count <> 1 then
    v_errors := array_append(v_errors, 'Workflow phải có đúng một bước Kết thúc.');
  end if;
  if v_task_count < 1 then
    v_errors := array_append(v_errors, 'Workflow phải có ít nhất một bước xử lý.');
  end if;
  if v_invalid_step_count > 0 then
    v_errors := array_append(v_errors, 'Có bước xử lý thiếu tên hoặc dùng approval policy chưa được hỗ trợ.');
  end if;

  with recursive walk(node_id, visited) as (
    select wn.id, array[wn.id]
    from public.workflow_nodes wn
    where wn.template_id = p_template_id
      and wn.type = 'START'::public.workflow_node_type
    union all
    select we.target_node_id, walk.visited || we.target_node_id
    from walk
    join public.workflow_edges we on we.source_node_id = walk.node_id
    where not (we.target_node_id = any(walk.visited))
  )
  select exists (
    select 1
    from walk
    join public.workflow_nodes wn on wn.id = walk.node_id
    where wn.type = 'END'::public.workflow_node_type
  ) into v_path_reaches_end;

  if not v_path_reaches_end then
    v_errors := array_append(v_errors, 'Không có đường đi hợp lệ từ Bắt đầu tới Kết thúc.');
  end if;

  return jsonb_build_object(
    'valid', coalesce(array_length(v_errors, 1), 0) = 0,
    'errors', to_jsonb(v_errors),
    'startCount', v_start_count,
    'endCount', v_end_count,
    'taskCount', v_task_count
  );
end;
$$ create or replace function public.get_project_workflow_configuration(
  p_subject_type text,
  p_project_id text default null,
  p_construction_site_id text default null
)
returns jsonb
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_binding public.project_workflow_bindings%rowtype;
  v_scope text;
  v_validation jsonb;
begin
  if public.current_app_user_id() is null then
    raise exception 'authentication required';
  end if;
  if p_subject_type <> 'material_request' then
    raise exception 'unsupported project workflow subject type: %', p_subject_type;
  end if;

  select pwb.*
    into v_binding
  from public.project_workflow_bindings pwb
  join public.workflow_templates wt on wt.id = pwb.workflow_template_id
  where pwb.subject_type = p_subject_type
    and pwb.is_active
    and pwb.is_default
    and (
      (p_construction_site_id is not null and pwb.project_id is not distinct from p_project_id and pwb.construction_site_id = p_construction_site_id)
      or (p_project_id is not null and pwb.project_id = p_project_id and pwb.construction_site_id is null)
      or (pwb.project_id is null and pwb.construction_site_id is null)
    )
  order by
    case
      when p_construction_site_id is not null and pwb.construction_site_id = p_construction_site_id then 1
      when p_project_id is not null and pwb.project_id = p_project_id and pwb.construction_site_id is null then 2
      else 3
    end
  limit 1;

  if not found then
    return jsonb_build_object(
      'subjectType', p_subject_type,
      'projectId', p_project_id,
      'constructionSiteId', p_construction_site_id,
      'binding', null,
      'scope', null,
      'valid', false,
      'errors', jsonb_build_array('Chưa cấu hình workflow cho đề xuất vật tư.'),
      'canManage', app_private.project_workflow_binding_can_manage(p_project_id, p_construction_site_id)
    );
  end if;

  v_scope := case
    when v_binding.construction_site_id is not null then 'site'
    when v_binding.project_id is not null then 'project'
    else 'global'
  end;
  v_validation := app_private.project_workflow_validate_template(v_binding.workflow_template_id);

  return jsonb_build_object(
    'subjectType', p_subject_type,
    'projectId', p_project_id,
    'constructionSiteId', p_construction_site_id,
    'binding', to_jsonb(v_binding),
    'scope', v_scope,
    'valid', coalesce((v_validation ->> 'valid')::boolean, false),
    'errors', coalesce(v_validation -> 'errors', '[]'::jsonb),
    'validation', v_validation,
    'canManage', app_private.project_workflow_binding_can_manage(
      p_project_id, p_construction_site_id, v_binding.workflow_template_id
    )
  );
end;
$$ create or replace function public.set_project_workflow_binding(
  p_subject_type text,
  p_workflow_template_id uuid,
  p_project_id text default null,
  p_construction_site_id text default null
)
returns public.project_workflow_bindings
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_validation jsonb;
  v_binding public.project_workflow_bindings%rowtype;
begin
  if v_actor is null then
    raise exception 'authentication required';
  end if;
  if p_subject_type <> 'material_request' then
    raise exception 'unsupported project workflow subject type: %', p_subject_type;
  end if;
  if p_construction_site_id is not null and p_project_id is null then
    raise exception 'site binding requires project id';
  end if;
  if not app_private.project_workflow_binding_can_manage(p_project_id, p_construction_site_id, p_workflow_template_id) then
    raise exception 'user cannot manage this project workflow binding';
  end if;

  v_validation := app_private.project_workflow_validate_template(p_workflow_template_id);
  if not coalesce((v_validation ->> 'valid')::boolean, false) then
    raise exception 'workflow template is invalid: %', v_validation;
  end if;

  update public.project_workflow_bindings pwb
  set is_active = false,
      updated_at = now()
  where pwb.subject_type = p_subject_type
    and pwb.is_default
    and pwb.is_active
    and pwb.project_id is not distinct from p_project_id
    and pwb.construction_site_id is not distinct from p_construction_site_id;

  insert into public.project_workflow_bindings(
    subject_type, project_id, construction_site_id, workflow_template_id,
    is_default, is_active, created_by
  )
  values (
    p_subject_type, p_project_id, p_construction_site_id, p_workflow_template_id,
    true, true, v_actor
  )
  returning * into v_binding;

  return v_binding;
end;
$$ create or replace function public.remove_project_workflow_binding(
  p_subject_type text,
  p_project_id text default null,
  p_construction_site_id text default null
)
returns integer
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_count integer;
  v_template_id uuid;
begin
  if public.current_app_user_id() is null then
    raise exception 'authentication required';
  end if;
  select pwb.workflow_template_id into v_template_id
  from public.project_workflow_bindings pwb
  where pwb.subject_type = p_subject_type
    and pwb.project_id is not distinct from p_project_id
    and pwb.construction_site_id is not distinct from p_construction_site_id
    and pwb.is_active
  order by pwb.updated_at desc
  limit 1;

  if not app_private.project_workflow_binding_can_manage(p_project_id, p_construction_site_id, v_template_id) then
    raise exception 'user cannot manage this project workflow binding';
  end if;

  update public.project_workflow_bindings pwb
  set is_active = false,
      updated_at = now()
  where pwb.subject_type = p_subject_type
    and pwb.project_id is not distinct from p_project_id
    and pwb.construction_site_id is not distinct from p_construction_site_id
    and pwb.is_active;
  get diagnostics v_count = row_count;
  return v_count;
end;
$$ create or replace function app_private.project_workflow_runtime_node_config(p_instance_node_id uuid)
returns jsonb
language sql
stable
security definer
set search_path = ''
as $$
  select coalesce(win.config, '{}'::jsonb)
  from public.workflow_instance_nodes win
  where win.id = p_instance_node_id;
$$ create or replace function app_private.project_workflow_runtime_sla_hours(p_instance_node_id uuid)
returns integer
language sql
stable
security definer
set search_path = ''
as $$
  select nullif(win.config ->> 'slaHours', '')::integer
  from public.workflow_instance_nodes win
  where win.id = p_instance_node_id
    and (win.config ->> 'slaHours') ~ '^[0-9]+$';
$$ create or replace function app_private.project_workflow_runtime_sla_due_at(p_instance_node_id uuid)
returns timestamptz
language sql
stable
security definer
set search_path = ''
as $$
  select case
    when app_private.project_workflow_runtime_sla_hours(p_instance_node_id) is null then null
    else now() + make_interval(hours => app_private.project_workflow_runtime_sla_hours(p_instance_node_id))
  end;
$$ create or replace function app_private.project_workflow_runtime_primary_permission(p_instance_node_id uuid)
returns text
language sql
stable
security definer
set search_path = ''
as $$
  select coalesce(
    (
      select value
      from jsonb_array_elements_text(coalesce(win.config -> 'eligiblePermissionCodes', '[]'::jsonb)) as code(value)
      limit 1
    ),
    nullif(win.config ->> 'eligiblePermissionCode', ''),
    nullif(win.config ->> 'requiredPermissionCode', ''),
    nullif(win.config ->> 'assigneePermissionCode', '')
  )
  from public.workflow_instance_nodes win
  where win.id = p_instance_node_id;
$$ create or replace function app_private.project_workflow_runtime_to_coarse_step(
  p_workflow_instance_id uuid,
  p_instance_node_id uuid
)
returns text
language sql
stable
security definer
set search_path = ''
as $$
  select case
    when p_instance_node_id is null then null
    when p_instance_node_id = (
      select wie.target_instance_node_id
      from public.workflow_instance_nodes start_node
      join public.workflow_instance_edges wie
        on wie.workflow_instance_id = start_node.workflow_instance_id
       and wie.source_instance_node_id = start_node.id
      join public.workflow_instance_nodes target_node
        on target_node.id = wie.target_instance_node_id
      where start_node.workflow_instance_id = p_workflow_instance_id
        and start_node.type = 'START'::public.workflow_node_type
        and target_node.type <> 'END'::public.workflow_node_type
      order by target_node.position_y, target_node.position_x
      limit 1
    ) then 'site_manager_review'
    else 'material_department_review'
  end;
$$ create or replace function app_private.project_workflow_runtime_assignee_is_eligible(
  p_subject_type text,
  p_subject_id text,
  p_instance_node_id uuid,
  p_assignee_user_id uuid
)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_node public.workflow_instance_nodes%rowtype;
  v_request public.requests%rowtype;
  v_mode text;
  v_fixed_user text;
  v_role text;
  v_code_count integer := 0;
  v_target_count integer := 0;
begin
  if p_subject_type <> 'material_request' or p_assignee_user_id is null then
    return false;
  end if;

  select * into v_node
  from public.workflow_instance_nodes win
  where win.id = p_instance_node_id;
  if not found or v_node.type = 'END'::public.workflow_node_type then
    return false;
  end if;

  select * into v_request from public.requests r where r.id = p_subject_id;
  if not found then return false; end if;

  if not exists (
    select 1 from public.users u
    where u.id = p_assignee_user_id and coalesce(u.is_active, true)
  ) then
    return false;
  end if;

  v_mode := coalesce(nullif(v_node.config ->> 'assignmentMode', ''), 'select_on_transition');
  v_fixed_user := nullif(v_node.config ->> 'assigneeUserId', '');
  v_role := nullif(v_node.config ->> 'assigneeRole', '');

  if v_fixed_user is not null then
    return v_fixed_user = p_assignee_user_id::text;
  end if;
  if v_mode = 'creator' then
    return v_request.requester_id = p_assignee_user_id;
  end if;
  if v_role is not null and not exists (
    select 1 from public.users u
    where u.id = p_assignee_user_id and u.role::text = v_role and coalesce(u.is_active, true)
  ) then
    return false;
  end if;

  select count(*) into v_target_count
  from jsonb_array_elements(coalesce(v_node.config -> 'assignmentTargets', '[]'::jsonb)) target(value);

  if v_target_count > 0 then
    return exists (
      select 1
      from jsonb_array_elements(coalesce(v_node.config -> 'assignmentTargets', '[]'::jsonb)) target(value)
      where (
        target.value ->> 'type' = 'user'
        and target.value ->> 'userId' = p_assignee_user_id::text
      ) or (
        target.value ->> 'type' = 'creator'
        and v_request.requester_id = p_assignee_user_id
      ) or (
        target.value ->> 'type' = 'department'
        and exists (
          select 1
          from public.employees e
          where e.user_id = p_assignee_user_id
            and coalesce(e.status, 'Đang làm việc') = 'Đang làm việc'
            and (
              e.department_id::text = target.value ->> 'orgUnitId'
              or e.org_unit_id::text = target.value ->> 'orgUnitId'
            )
        )
      ) or (
        target.value ->> 'type' = 'project_permission'
        and app_private.project_user_has_permission(
          v_request.project_id,
          v_request.construction_site_id,
          target.value ->> 'permissionCode',
          p_assignee_user_id
        )
      )
    );
  end if;

  select count(*) into v_code_count
  from jsonb_array_elements_text(coalesce(v_node.config -> 'eligiblePermissionCodes', '[]'::jsonb)) code(value);

  if v_code_count > 0 then
    return exists (
      select 1
      from jsonb_array_elements_text(coalesce(v_node.config -> 'eligiblePermissionCodes', '[]'::jsonb)) code(value)
      where app_private.project_user_has_permission(
        v_request.project_id,
        v_request.construction_site_id,
        code.value,
        p_assignee_user_id
      )
    );
  end if;

  return exists (
    select 1
    from public.project_staff ps
    where ps.user_id::text = p_assignee_user_id::text
      and ps.end_date is null
      and (
        (v_request.project_id is not null and ps.project_id::text = v_request.project_id)
        or (v_request.construction_site_id is not null and ps.construction_site_id::text = v_request.construction_site_id)
      )
  );
end;
$$ create or replace function app_private.project_workflow_runtime_assignees_are_eligible(
  p_subject_type text,
  p_subject_id text,
  p_instance_node_id uuid,
  p_assignee_user_ids uuid[]
)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_ids uuid[] := app_private.project_workflow_distinct_uuid_array(p_assignee_user_ids);
  v_id uuid;
begin
  if coalesce(array_length(v_ids, 1), 0) = 0 then return false; end if;
  foreach v_id in array v_ids loop
    if not app_private.project_workflow_runtime_assignee_is_eligible(
      p_subject_type, p_subject_id, p_instance_node_id, v_id
    ) then
      return false;
    end if;
  end loop;
  return true;
end;
$$ create or replace function app_private.project_workflow_assignee_is_eligible(
  p_subject_type text,
  p_subject_id text,
  p_node_id uuid,
  p_assignee_user_id uuid
)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_node public.workflow_nodes%rowtype;
  v_request public.requests%rowtype;
  v_mode text;
  v_fixed_user text;
  v_role text;
  v_code_count integer := 0;
  v_target_count integer := 0;
begin
  if p_subject_type <> 'material_request' or p_assignee_user_id is null then return false; end if;
  select * into v_node from public.workflow_nodes wn where wn.id = p_node_id;
  if not found or v_node.type = 'END'::public.workflow_node_type then return false; end if;
  select * into v_request from public.requests r where r.id = p_subject_id;
  if not found then return false; end if;

  if not exists (
    select 1 from public.users u
    where u.id = p_assignee_user_id and coalesce(u.is_active, true)
  ) then return false; end if;

  v_mode := coalesce(nullif(v_node.config ->> 'assignmentMode', ''), 'select_on_transition');
  v_fixed_user := nullif(v_node.config ->> 'assigneeUserId', '');
  v_role := nullif(v_node.config ->> 'assigneeRole', '');
  if v_fixed_user is not null then return v_fixed_user = p_assignee_user_id::text; end if;
  if v_mode = 'creator' then return v_request.requester_id = p_assignee_user_id; end if;
  if v_role is not null and not exists (
    select 1 from public.users u
    where u.id = p_assignee_user_id and u.role::text = v_role and coalesce(u.is_active, true)
  ) then return false; end if;

  select count(*) into v_target_count
  from jsonb_array_elements(coalesce(v_node.config -> 'assignmentTargets', '[]'::jsonb)) target(value);
  if v_target_count > 0 then
    return exists (
      select 1
      from jsonb_array_elements(coalesce(v_node.config -> 'assignmentTargets', '[]'::jsonb)) target(value)
      where (
        target.value ->> 'type' = 'user'
        and target.value ->> 'userId' = p_assignee_user_id::text
      ) or (
        target.value ->> 'type' = 'creator'
        and v_request.requester_id = p_assignee_user_id
      ) or (
        target.value ->> 'type' = 'department'
        and exists (
          select 1 from public.employees e
          where e.user_id = p_assignee_user_id
            and coalesce(e.status, 'Đang làm việc') = 'Đang làm việc'
            and (
              e.department_id::text = target.value ->> 'orgUnitId'
              or e.org_unit_id::text = target.value ->> 'orgUnitId'
            )
        )
      ) or (
        target.value ->> 'type' = 'project_permission'
        and app_private.project_user_has_permission(
          v_request.project_id, v_request.construction_site_id,
          target.value ->> 'permissionCode', p_assignee_user_id
        )
      )
    );
  end if;

  select count(*) into v_code_count
  from jsonb_array_elements_text(coalesce(v_node.config -> 'eligiblePermissionCodes', '[]'::jsonb)) code(value);
  if v_code_count > 0 then
    return exists (
      select 1
      from jsonb_array_elements_text(coalesce(v_node.config -> 'eligiblePermissionCodes', '[]'::jsonb)) code(value)
      where app_private.project_user_has_permission(
        v_request.project_id, v_request.construction_site_id, code.value, p_assignee_user_id
      )
    );
  end if;

  return exists (
    select 1 from public.project_staff ps
    where ps.user_id::text = p_assignee_user_id::text
      and ps.end_date is null
      and (
        (v_request.project_id is not null and ps.project_id::text = v_request.project_id)
        or (v_request.construction_site_id is not null and ps.construction_site_id::text = v_request.construction_site_id)
      )
  );
end;
$$ create or replace function app_private.project_workflow_actor_can_act(
  p_workflow_subject_id uuid,
  p_actor uuid
)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select coalesce(
    app_private.project_workflow_actor_is_admin(p_workflow_subject_id, p_actor)
    or exists (
      select 1
      from public.workflow_subjects ws
      join public.workflow_step_assignments wsa
        on wsa.workflow_subject_id = ws.id
       and wsa.workflow_instance_id = ws.workflow_instance_id
       and wsa.instance_node_id = ws.current_instance_node_id
       and wsa.assignee_user_id = p_actor
       and wsa.status = 'PENDING'
      where ws.id = p_workflow_subject_id
        and ws.status = 'RUNNING'
    ),
    false
  );
$$ create or replace function app_private.project_workflow_pending_assignee_ids(
  p_workflow_subject_id uuid,
  p_node_id uuid
)
returns uuid[]
language sql
stable
security definer
set search_path = ''
as $$
  select coalesce(array_agg(wsa.assignee_user_id order by wsa.assigned_at, wsa.assignee_user_id), '{}'::uuid[])
  from public.workflow_step_assignments wsa
  join public.workflow_subjects ws on ws.id = wsa.workflow_subject_id
  where wsa.workflow_subject_id = p_workflow_subject_id
    and wsa.workflow_instance_id = ws.workflow_instance_id
    and (
      (ws.current_instance_node_id is not null and wsa.instance_node_id = ws.current_instance_node_id)
      or (ws.current_instance_node_id is null and wsa.node_id = p_node_id)
    )
    and wsa.status = 'PENDING'
    and wsa.assignee_user_id is not null;
$$ create or replace function app_private.project_workflow_insert_assignment_pool(
  p_workflow_subject_id uuid,
  p_workflow_instance_id uuid,
  p_node_id uuid,
  p_instance_node_id uuid,
  p_assignee_user_ids uuid[],
  p_assigned_by uuid,
  p_comment text default null,
  p_metadata jsonb default '{}'::jsonb,
  p_assignment_source text default 'manual',
  p_assignment_group_type text default null,
  p_assignment_group_id text default null
)
returns void
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_ids uuid[] := app_private.project_workflow_distinct_uuid_array(p_assignee_user_ids);
  v_id uuid;
  v_sla_hours integer := app_private.project_workflow_runtime_sla_hours(p_instance_node_id);
  v_due_at timestamptz := app_private.project_workflow_runtime_sla_due_at(p_instance_node_id);
  v_node_config jsonb := app_private.project_workflow_runtime_node_config(p_instance_node_id);
  v_target jsonb;
  v_watcher_user_id uuid;
  v_round_id uuid := gen_random_uuid();
begin
  foreach v_id in array v_ids loop
    insert into public.workflow_step_assignments(
      workflow_subject_id, workflow_instance_id, node_id, instance_node_id,
      assignee_user_id, assigned_by, status, assigned_at, action_comment,
      metadata, due_at, sla_hours, assignment_source, assignment_group_type,
      assignment_group_id
    )
    values (
      p_workflow_subject_id, p_workflow_instance_id, p_node_id, p_instance_node_id,
      v_id, p_assigned_by, 'PENDING', now(), nullif(coalesce(p_comment, ''), ''),
      coalesce(p_metadata, '{}'::jsonb) || jsonb_build_object('assignmentRoundId', v_round_id),
      v_due_at, v_sla_hours,
      p_assignment_source, p_assignment_group_type, p_assignment_group_id
    );

    update public.workflow_step_assignments
    set assignment_round_id = v_round_id
    where id = (
      select wsa.id
      from public.workflow_step_assignments wsa
      where wsa.workflow_subject_id = p_workflow_subject_id
        and wsa.workflow_instance_id = p_workflow_instance_id
        and wsa.assignee_user_id = v_id
        and wsa.status = 'PENDING'
      order by wsa.assigned_at desc
      limit 1
    );

    perform app_private.project_workflow_register_participant(
      p_workflow_subject_id, p_workflow_instance_id, v_id, 'ASSIGNEE',
      p_assignment_source, p_assignment_group_id, p_node_id, p_instance_node_id, p_assigned_by
    );
  end loop;

  for v_target in
    select value
    from jsonb_array_elements(coalesce(v_node_config -> 'stepWatcherTargets', '[]'::jsonb)) target(value)
  loop
    if coalesce(v_target ->> 'type', '') = 'user' and nullif(v_target ->> 'userId', '') is not null then
      perform app_private.project_workflow_register_participant(
        p_workflow_subject_id, p_workflow_instance_id, (v_target ->> 'userId')::uuid,
        'WATCHER', 'step_watcher', p_instance_node_id::text, p_node_id,
        p_instance_node_id, p_assigned_by
      );
    elsif coalesce(v_target ->> 'type', '') = 'department' and nullif(v_target ->> 'orgUnitId', '') is not null then
      for v_watcher_user_id in
        select distinct e.user_id
        from public.employees e
        where e.user_id is not null
          and coalesce(e.status, 'Đang làm việc') = 'Đang làm việc'
          and (
            e.department_id::text = v_target ->> 'orgUnitId'
            or e.org_unit_id::text = v_target ->> 'orgUnitId'
          )
      loop
        perform app_private.project_workflow_register_participant(
          p_workflow_subject_id, p_workflow_instance_id, v_watcher_user_id,
          'WATCHER', 'step_watcher_department', v_target ->> 'orgUnitId',
          p_node_id, p_instance_node_id, p_assigned_by
        );
      end loop;
    end if;
  end loop;
end;
$$ do $$
begin
  if to_regprocedure('public.start_project_workflow_v2(text,text,uuid,uuid[],text)') is not null
     and to_regprocedure('public.start_project_workflow_v2_legacy(text,text,uuid,uuid[],text)') is null then
    alter function public.start_project_workflow_v2(text, text, uuid, uuid[], text)
      rename to start_project_workflow_v2_legacy;
  end if;
end $$ create or replace function public.start_project_workflow_v2(
  p_subject_type text,
  p_subject_id text,
  p_template_id uuid default null,
  p_first_assignee_user_ids uuid[] default '{}'::uuid[],
  p_comment text default ''
)
returns public.workflow_subjects
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_request public.requests%rowtype;
  v_config jsonb;
  v_effective_template_id uuid;
  v_subject public.workflow_subjects%rowtype;
  v_pending public.workflow_step_assignments%rowtype;
begin
  if public.current_app_user_id() is null then raise exception 'authentication required'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;

  v_config := public.get_project_workflow_configuration(
    p_subject_type, v_request.project_id, v_request.construction_site_id
  );
  if not coalesce((v_config ->> 'valid')::boolean, false) then
    raise exception 'material request workflow is not configured or invalid: %', v_config -> 'errors';
  end if;
  v_effective_template_id := (v_config -> 'binding' ->> 'workflow_template_id')::uuid;
  if p_template_id is not null and p_template_id <> v_effective_template_id then
    raise exception 'selected workflow template is not the effective project binding';
  end if;

  v_subject := public.start_project_workflow_v2_legacy(
    p_subject_type, p_subject_id, v_effective_template_id,
    p_first_assignee_user_ids, p_comment
  );

  select * into v_pending
  from public.workflow_step_assignments wsa
  where wsa.workflow_subject_id = v_subject.id
    and wsa.instance_node_id = v_subject.current_instance_node_id
    and wsa.status = 'PENDING'
  order by wsa.assigned_at desc
  limit 1;

  update public.requests
  set submitted_to_permission = app_private.project_workflow_runtime_primary_permission(v_subject.current_instance_node_id),
      workflow_step_due_at = v_pending.due_at,
      workflow_step_sla_hours = v_pending.sla_hours
  where id = p_subject_id;

  return v_subject;
end;
$$ create or replace function public.advance_project_workflow_v2(
  p_subject_type text,
  p_subject_id text,
  p_next_assignee_user_ids uuid[] default '{}'::uuid[],
  p_comment text default ''
)
returns public.workflow_subjects
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_request public.requests%rowtype;
  v_current_node public.workflow_instance_nodes%rowtype;
  v_next_node public.workflow_instance_nodes%rowtype;
  v_next_assignee_ids uuid[] := app_private.project_workflow_distinct_uuid_array(p_next_assignee_user_ids);
  v_first_next_assignee uuid;
  v_next_assignee_name text;
  v_sla_hours integer;
  v_due_at timestamptz;
  v_to_step text;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if p_subject_type <> 'material_request' then
    raise exception 'unsupported project workflow subject type: %', p_subject_type;
  end if;

  select * into v_subject
  from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id
  for update;
  if not found then raise exception 'workflow subject not found'; end if;

  select * into v_request from public.requests r where r.id = p_subject_id for update;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;
  if v_subject.status <> 'RUNNING' then raise exception 'workflow subject is not running'; end if;
  if not app_private.project_workflow_actor_can_act(v_subject.id, v_actor) then
    raise exception 'user is not assigned to current workflow step';
  end if;

  select * into v_current_node
  from public.workflow_instance_nodes win
  where win.id = v_subject.current_instance_node_id
    and win.workflow_instance_id = v_subject.workflow_instance_id;
  if not found then raise exception 'current runtime workflow node not found'; end if;

  select target_node.* into v_next_node
  from public.workflow_instance_edges wie
  join public.workflow_instance_nodes target_node on target_node.id = wie.target_instance_node_id
  where wie.workflow_instance_id = v_subject.workflow_instance_id
    and wie.source_instance_node_id = v_subject.current_instance_node_id
  order by wie.sort_order, target_node.position_y, target_node.position_x
  limit 1;
  if not found then raise exception 'next runtime workflow node not found'; end if;

  update public.workflow_step_assignments
  set status = 'APPROVED', acted_at = now(),
      action_comment = nullif(coalesce(p_comment, ''), ''),
      metadata = coalesce(metadata, '{}'::jsonb)
        || jsonb_build_object('approvedByUserId', v_actor, 'approvalPolicy', 'ANY_ONE')
  where workflow_subject_id = v_subject.id
    and workflow_instance_id = v_subject.workflow_instance_id
    and instance_node_id = v_subject.current_instance_node_id
    and assignee_user_id = v_actor
    and status = 'PENDING';

  update public.workflow_step_assignments
  set status = 'SKIPPED', acted_at = now(),
      action_comment = 'Skipped because another assignee approved this step',
      metadata = coalesce(metadata, '{}'::jsonb)
        || jsonb_build_object('skippedByPolicy', 'ANY_ONE', 'approvedByUserId', v_actor)
  where workflow_subject_id = v_subject.id
    and workflow_instance_id = v_subject.workflow_instance_id
    and instance_node_id = v_subject.current_instance_node_id
    and status = 'PENDING';

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_subject.workflow_instance_id, v_current_node.template_node_id,
    'APPROVED'::public.workflow_instance_action, v_actor, coalesce(p_comment, ''));

  if v_next_node.type = 'END'::public.workflow_node_type then
    update public.workflow_instances
    set current_node_id = v_next_node.template_node_id,
        current_instance_node_id = v_next_node.id,
        status = 'COMPLETED'::public.workflow_instance_status,
        updated_at = now()
    where id = v_subject.workflow_instance_id;

    update public.workflow_subjects
    set current_assignee_user_id = null,
        current_assignee_user_ids = '{}'::uuid[],
        current_node_id = v_next_node.template_node_id,
        current_instance_node_id = v_next_node.id,
        last_action_instance_node_id = v_current_node.id,
        status = 'COMPLETED',
        updated_at = now()
    where id = v_subject.id
    returning * into v_subject;

    update public.requests
    set status = 'APPROVED'::public.request_status,
        submitted_to_user_id = null, submitted_to_name = null,
        submitted_to_permission = null,
        submission_note = nullif(coalesce(p_comment, ''), ''),
        last_action_by = v_actor, last_action_at = now(),
        workflow_step = 'batch_planning', workflow_step_started_at = now(),
        workflow_step_due_at = null, workflow_step_sla_hours = null,
        workflow_step_actor_user_id = v_actor::text
    where id = p_subject_id;

    insert into public.material_request_events(
      request_id, project_id, from_step, to_step, action, actor_user_id, note, metadata
    )
    values (
      p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'material_department_review'),
      'batch_planning', 'APPROVED', v_actor::text, nullif(coalesce(p_comment, ''), ''),
      jsonb_build_object(
        'workflowInstanceId', v_subject.workflow_instance_id,
        'workflowSubjectId', v_subject.id,
        'fromInstanceNodeId', v_current_node.id,
        'toInstanceNodeId', v_next_node.id
      )
    );
    return v_subject;
  end if;

  if not app_private.project_workflow_runtime_assignees_are_eligible(
    p_subject_type, p_subject_id, v_next_node.id, v_next_assignee_ids
  ) then
    raise exception 'next assignee pool is not eligible for this runtime workflow step';
  end if;

  perform app_private.project_workflow_insert_assignment_pool(
    v_subject.id, v_subject.workflow_instance_id, v_next_node.template_node_id, v_next_node.id,
    v_next_assignee_ids, v_actor, p_comment,
    jsonb_build_object('approvedFromInstanceNodeId', v_current_node.id, 'approvalPolicy', 'ANY_ONE'),
    'transition'
  );

  v_first_next_assignee := v_next_assignee_ids[1];
  v_next_assignee_name := app_private.project_workflow_first_assignee_name(v_next_assignee_ids);
  v_sla_hours := app_private.project_workflow_runtime_sla_hours(v_next_node.id);
  v_due_at := app_private.project_workflow_runtime_sla_due_at(v_next_node.id);
  v_to_step := app_private.project_workflow_runtime_to_coarse_step(v_subject.workflow_instance_id, v_next_node.id);

  update public.workflow_instances
  set current_node_id = v_next_node.template_node_id,
      current_instance_node_id = v_next_node.id,
      step_assignees = coalesce(step_assignees, '{}'::jsonb)
        || app_private.project_workflow_step_assignees_json(v_next_node.template_node_id, v_next_assignee_ids),
      updated_at = now()
  where id = v_subject.workflow_instance_id;

  update public.workflow_subjects
  set current_assignee_user_id = v_first_next_assignee,
      current_assignee_user_ids = v_next_assignee_ids,
      current_node_id = v_next_node.template_node_id,
      current_instance_node_id = v_next_node.id,
      last_action_instance_node_id = v_current_node.id,
      status = 'RUNNING', updated_at = now()
  where id = v_subject.id
  returning * into v_subject;

  update public.requests
  set status = 'PENDING'::public.request_status,
      submitted_to_user_id = v_first_next_assignee::text,
      submitted_to_name = v_next_assignee_name,
      submitted_to_permission = app_private.project_workflow_runtime_primary_permission(v_next_node.id),
      submission_note = nullif(coalesce(p_comment, ''), ''),
      last_action_by = v_actor, last_action_at = now(),
      workflow_step = v_to_step, workflow_step_started_at = now(),
      workflow_step_due_at = v_due_at, workflow_step_sla_hours = v_sla_hours,
      workflow_step_actor_user_id = v_actor::text
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id, project_id, from_step, to_step, action, actor_user_id,
    target_user_id, target_permission, note, sla_hours, due_at, metadata
  )
  values (
    p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'material_department_review'),
    v_to_step, 'APPROVED', v_actor::text, v_first_next_assignee::text,
    app_private.project_workflow_runtime_primary_permission(v_next_node.id),
    nullif(coalesce(p_comment, ''), ''), v_sla_hours, v_due_at,
    jsonb_build_object(
      'workflowInstanceId', v_subject.workflow_instance_id,
      'workflowSubjectId', v_subject.id,
      'fromInstanceNodeId', v_current_node.id,
      'toInstanceNodeId', v_next_node.id,
      'assigneeUserIds', v_next_assignee_ids
    )
  );
  return v_subject;
end;
$$ create or replace function public.return_project_workflow_v2(
  p_subject_type text,
  p_subject_id text,
  p_comment text default ''
)
returns public.workflow_subjects
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_request public.requests%rowtype;
  v_requester_id uuid;
  v_requester_name text;
  v_return_assignee_ids uuid[];
  v_round_id uuid := gen_random_uuid();
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if nullif(coalesce(p_comment, ''), '') is null then raise exception 'return reason is required'; end if;

  select * into v_subject from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id for update;
  if not found then raise exception 'workflow subject not found'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id for update;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;
  if v_subject.status <> 'RUNNING' then raise exception 'workflow subject is not running'; end if;
  if not app_private.project_workflow_actor_can_act(v_subject.id, v_actor) then
    raise exception 'user is not assigned to current workflow step';
  end if;

  v_requester_id := v_request.requester_id::uuid;
  v_return_assignee_ids := app_private.project_workflow_pending_assignee_ids(v_subject.id, v_subject.current_node_id);

  update public.workflow_step_assignments
  set status = case when assignee_user_id = v_actor then 'RETURNED' else 'SKIPPED' end,
      acted_at = now(), action_comment = p_comment, return_to_node_id = v_subject.current_node_id,
      metadata = coalesce(metadata, '{}'::jsonb) || jsonb_build_object(
        'returnedToCreator', true, 'returnedByUserId', v_actor,
        'returnToInstanceNodeId', v_subject.current_instance_node_id,
        'returnToAssigneeUserIds', v_return_assignee_ids
      )
  where workflow_subject_id = v_subject.id
    and workflow_instance_id = v_subject.workflow_instance_id
    and instance_node_id = v_subject.current_instance_node_id
    and status = 'PENDING';

  insert into public.workflow_step_assignments(
    workflow_subject_id, workflow_instance_id, node_id, instance_node_id,
    assignee_user_id, assigned_by, status, assigned_at, action_comment,
    assignment_source, assignment_round_id, metadata
  )
  values (
    v_subject.id, v_subject.workflow_instance_id, v_subject.current_node_id,
    v_subject.current_instance_node_id, v_requester_id, v_actor, 'PENDING', now(),
    p_comment, 'return_to_creator', v_round_id,
    jsonb_build_object(
      'returnedToCreator', true, 'returnToInstanceNodeId', v_subject.current_instance_node_id,
      'returnToAssigneeUserIds', v_return_assignee_ids, 'assignmentRoundId', v_round_id
    )
  );

  perform app_private.project_workflow_register_participant(
    v_subject.id, v_subject.workflow_instance_id, v_requester_id, 'CREATOR',
    'return_to_creator', p_subject_id, v_subject.current_node_id,
    v_subject.current_instance_node_id, v_actor
  );

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_subject.workflow_instance_id, v_subject.current_node_id,
    'REVISION_REQUESTED'::public.workflow_instance_action, v_actor, p_comment);

  select u.name into v_requester_name from public.users u where u.id = v_requester_id;

  update public.workflow_subjects
  set current_assignee_user_id = v_requester_id,
      current_assignee_user_ids = array[v_requester_id],
      status = 'RETURNED',
      return_to_node_id = v_subject.current_node_id,
      return_to_instance_node_id = v_subject.current_instance_node_id,
      return_to_assignee_user_id = v_return_assignee_ids[1],
      return_to_assignee_user_ids = v_return_assignee_ids,
      returned_by_user_id = v_actor, returned_at = now(), updated_at = now()
  where id = v_subject.id
  returning * into v_subject;

  update public.requests
  set status = 'DRAFT'::public.request_status,
      submitted_to_user_id = v_requester_id::text, submitted_to_name = v_requester_name,
      submitted_to_permission = 'edit', submission_note = p_comment,
      last_action_by = v_actor, last_action_at = now(),
      workflow_step = 'returned_to_creator', workflow_step_started_at = now(),
      workflow_step_due_at = null, workflow_step_sla_hours = null,
      workflow_step_actor_user_id = v_actor::text
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id, project_id, from_step, to_step, action, actor_user_id,
    target_user_id, target_permission, note, metadata
  )
  values (
    p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'material_department_review'),
    'returned_to_creator', 'RETURNED', v_actor::text, v_requester_id::text, 'edit',
    p_comment, jsonb_build_object(
      'workflowInstanceId', v_subject.workflow_instance_id,
      'workflowSubjectId', v_subject.id,
      'returnToInstanceNodeId', v_subject.return_to_instance_node_id,
      'returnToAssigneeUserIds', v_return_assignee_ids
    )
  );
  return v_subject;
end;
$$ create or replace function public.resubmit_project_workflow_v2(
  p_subject_type text,
  p_subject_id text,
  p_assignee_user_ids uuid[] default null,
  p_comment text default ''
)
returns public.workflow_subjects
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_request public.requests%rowtype;
  v_target_node public.workflow_instance_nodes%rowtype;
  v_target_assignee_ids uuid[];
  v_first_assignee uuid;
  v_assignee_name text;
  v_sla_hours integer;
  v_due_at timestamptz;
  v_to_step text;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  select * into v_subject from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id for update;
  if not found then raise exception 'workflow subject not found'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id for update;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;
  if v_subject.status <> 'RETURNED' then raise exception 'workflow subject is not returned'; end if;
  if not (
    public.is_admin() or public.is_module_admin('WF')
    or v_request.requester_id::uuid = v_actor
    or app_private.project_workflow_actor_is_admin(v_subject.id, v_actor)
  ) then
    raise exception 'only requester or workflow admin can resubmit this material request';
  end if;

  select * into v_target_node
  from public.workflow_instance_nodes win
  where win.id = coalesce(v_subject.return_to_instance_node_id, v_subject.current_instance_node_id)
    and win.workflow_instance_id = v_subject.workflow_instance_id;
  if not found or v_target_node.type = 'END'::public.workflow_node_type then
    raise exception 'return runtime workflow node not found';
  end if;

  v_target_assignee_ids := app_private.project_workflow_distinct_uuid_array(
    coalesce(p_assignee_user_ids, v_subject.return_to_assignee_user_ids)
  );
  if not app_private.project_workflow_runtime_assignees_are_eligible(
    p_subject_type, p_subject_id, v_target_node.id, v_target_assignee_ids
  ) then
    raise exception 'resubmit assignee pool is not eligible for this runtime workflow step';
  end if;

  update public.workflow_step_assignments
  set status = 'APPROVED', acted_at = now(),
      action_comment = nullif(coalesce(p_comment, ''), ''),
      metadata = coalesce(metadata, '{}'::jsonb) || jsonb_build_object('resubmittedByCreator', true)
  where workflow_subject_id = v_subject.id
    and workflow_instance_id = v_subject.workflow_instance_id
    and assignee_user_id = v_request.requester_id::uuid
    and status = 'PENDING'
    and assignment_source = 'return_to_creator';

  perform app_private.project_workflow_insert_assignment_pool(
    v_subject.id, v_subject.workflow_instance_id, v_target_node.template_node_id, v_target_node.id,
    v_target_assignee_ids, v_actor, p_comment,
    jsonb_build_object('resubmitted', true, 'approvalPolicy', 'ANY_ONE'), 'resubmit'
  );

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_subject.workflow_instance_id, v_target_node.template_node_id,
    'REOPENED'::public.workflow_instance_action, v_actor, coalesce(p_comment, ''));

  v_first_assignee := v_target_assignee_ids[1];
  v_assignee_name := app_private.project_workflow_first_assignee_name(v_target_assignee_ids);
  v_sla_hours := app_private.project_workflow_runtime_sla_hours(v_target_node.id);
  v_due_at := app_private.project_workflow_runtime_sla_due_at(v_target_node.id);
  v_to_step := app_private.project_workflow_runtime_to_coarse_step(v_subject.workflow_instance_id, v_target_node.id);

  update public.workflow_instances
  set current_node_id = v_target_node.template_node_id,
      current_instance_node_id = v_target_node.id,
      status = 'RUNNING'::public.workflow_instance_status,
      step_assignees = coalesce(step_assignees, '{}'::jsonb)
        || app_private.project_workflow_step_assignees_json(v_target_node.template_node_id, v_target_assignee_ids),
      updated_at = now()
  where id = v_subject.workflow_instance_id;

  update public.workflow_subjects
  set current_assignee_user_id = v_first_assignee,
      current_assignee_user_ids = v_target_assignee_ids,
      current_node_id = v_target_node.template_node_id,
      current_instance_node_id = v_target_node.id,
      status = 'RUNNING',
      return_to_node_id = null, return_to_instance_node_id = null,
      return_to_assignee_user_id = null, return_to_assignee_user_ids = '{}'::uuid[],
      returned_by_user_id = null, returned_at = null, updated_at = now()
  where id = v_subject.id
  returning * into v_subject;

  update public.requests
  set status = 'PENDING'::public.request_status,
      submitted_to_user_id = v_first_assignee::text, submitted_to_name = v_assignee_name,
      submitted_to_permission = app_private.project_workflow_runtime_primary_permission(v_target_node.id),
      submission_note = nullif(coalesce(p_comment, ''), ''), ever_submitted = true,
      last_action_by = v_actor, last_action_at = now(),
      workflow_step = v_to_step, workflow_step_started_at = now(),
      workflow_step_due_at = v_due_at, workflow_step_sla_hours = v_sla_hours,
      workflow_step_actor_user_id = v_actor::text
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id, project_id, from_step, to_step, action, actor_user_id,
    target_user_id, target_permission, note, sla_hours, due_at, metadata
  )
  values (
    p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'returned_to_creator'),
    v_to_step, 'RESUBMITTED', v_actor::text, v_first_assignee::text,
    app_private.project_workflow_runtime_primary_permission(v_target_node.id),
    nullif(coalesce(p_comment, ''), ''), v_sla_hours, v_due_at,
    jsonb_build_object(
      'workflowInstanceId', v_subject.workflow_instance_id,
      'workflowSubjectId', v_subject.id,
      'toInstanceNodeId', v_target_node.id,
      'assigneeUserIds', v_target_assignee_ids
    )
  );
  return v_subject;
end;
$$ create or replace function public.reassign_project_workflow_v2(
  p_subject_type text,
  p_subject_id text,
  p_new_assignee_user_ids uuid[],
  p_comment text default ''
)
returns public.workflow_subjects
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_request public.requests%rowtype;
  v_node public.workflow_instance_nodes%rowtype;
  v_new_assignee_ids uuid[] := app_private.project_workflow_distinct_uuid_array(p_new_assignee_user_ids);
  v_first_assignee uuid;
  v_assignee_name text;
  v_sla_hours integer;
  v_due_at timestamptz;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  select * into v_subject from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id for update;
  if not found then raise exception 'workflow subject not found'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id for update;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;
  if v_subject.status <> 'RUNNING' then raise exception 'workflow subject is not running'; end if;
  if not app_private.project_workflow_actor_can_act(v_subject.id, v_actor) then
    raise exception 'user cannot reassign this workflow step';
  end if;

  select * into v_node from public.workflow_instance_nodes win
  where win.id = v_subject.current_instance_node_id;
  if not found or v_node.type = 'END'::public.workflow_node_type then
    raise exception 'current runtime workflow node cannot be reassigned';
  end if;
  if coalesce((v_node.config ->> 'allowReassign')::boolean, true) = false then
    raise exception 'workflow step does not allow reassign';
  end if;
  if not app_private.project_workflow_runtime_assignees_are_eligible(
    p_subject_type, p_subject_id, v_node.id, v_new_assignee_ids
  ) then
    raise exception 'new assignee pool is not eligible for this runtime workflow step';
  end if;

  update public.workflow_step_assignments
  set status = 'SKIPPED', acted_at = now(),
      action_comment = nullif(coalesce(p_comment, ''), ''),
      metadata = coalesce(metadata, '{}'::jsonb) || jsonb_build_object('reassignedToUserIds', v_new_assignee_ids)
  where workflow_subject_id = v_subject.id
    and workflow_instance_id = v_subject.workflow_instance_id
    and instance_node_id = v_node.id
    and status = 'PENDING';

  perform app_private.project_workflow_insert_assignment_pool(
    v_subject.id, v_subject.workflow_instance_id, v_node.template_node_id, v_node.id,
    v_new_assignee_ids, v_actor, p_comment,
    jsonb_build_object('reassigned', true, 'fromAssigneeUserIds', v_subject.current_assignee_user_ids),
    'reassign'
  );

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_subject.workflow_instance_id, v_node.template_node_id,
    'REOPENED'::public.workflow_instance_action, v_actor,
    coalesce(nullif(p_comment, ''), 'Reassigned workflow step'));

  v_first_assignee := v_new_assignee_ids[1];
  v_assignee_name := app_private.project_workflow_first_assignee_name(v_new_assignee_ids);
  v_sla_hours := app_private.project_workflow_runtime_sla_hours(v_node.id);
  v_due_at := app_private.project_workflow_runtime_sla_due_at(v_node.id);

  update public.workflow_subjects
  set current_assignee_user_id = v_first_assignee,
      current_assignee_user_ids = v_new_assignee_ids, updated_at = now()
  where id = v_subject.id
  returning * into v_subject;

  update public.requests
  set submitted_to_user_id = v_first_assignee::text, submitted_to_name = v_assignee_name,
      submitted_to_permission = app_private.project_workflow_runtime_primary_permission(v_node.id),
      submission_note = nullif(coalesce(p_comment, ''), ''),
      last_action_by = v_actor, last_action_at = now(),
      workflow_step_due_at = v_due_at, workflow_step_sla_hours = v_sla_hours,
      workflow_step_actor_user_id = v_actor::text
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id, project_id, from_step, to_step, action, actor_user_id,
    target_user_id, target_permission, note, sla_hours, due_at, metadata
  )
  values (
    p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'material_department_review'),
    coalesce(v_request.workflow_step, 'material_department_review'), 'REASSIGNED', v_actor::text,
    v_first_assignee::text, app_private.project_workflow_runtime_primary_permission(v_node.id),
    nullif(coalesce(p_comment, ''), ''), v_sla_hours, v_due_at,
    jsonb_build_object(
      'workflowInstanceId', v_subject.workflow_instance_id,
      'workflowSubjectId', v_subject.id,
      'instanceNodeId', v_node.id,
      'fromAssigneeUserIds', v_subject.current_assignee_user_ids,
      'assigneeUserIds', v_new_assignee_ids
    )
  );
  return v_subject;
end;
$$ create or replace function public.reject_project_workflow(
  p_subject_type text,
  p_subject_id text,
  p_comment text default ''
)
returns public.workflow_subjects
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_request public.requests%rowtype;
  v_node public.workflow_instance_nodes%rowtype;
  v_dependency jsonb;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if nullif(coalesce(p_comment, ''), '') is null then raise exception 'reject reason is required'; end if;
  select * into v_subject from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id for update;
  if not found then raise exception 'workflow subject not found'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id for update;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;
  if v_subject.status <> 'RUNNING' then raise exception 'workflow subject can only be rejected while running'; end if;
  if not app_private.project_workflow_actor_can_act(v_subject.id, v_actor) then
    raise exception 'user is not allowed to reject this workflow';
  end if;

  select * into v_node from public.workflow_instance_nodes win where win.id = v_subject.current_instance_node_id;
  if not found or coalesce((v_node.config ->> 'allowReject')::boolean, true) = false then
    raise exception 'runtime workflow step does not allow reject';
  end if;
  v_dependency := public.get_project_workflow_rollback_dependencies(p_subject_type, p_subject_id);
  if not coalesce((v_dependency ->> 'allowed')::boolean, false) then
    raise exception 'reject is locked by active downstream dependencies: %', v_dependency;
  end if;

  update public.workflow_step_assignments
  set status = case when assignee_user_id = v_actor then 'REJECTED' else 'SKIPPED' end,
      acted_at = now(), action_comment = p_comment,
      metadata = coalesce(metadata, '{}'::jsonb) || jsonb_build_object('rejectedByUserId', v_actor)
  where workflow_subject_id = v_subject.id
    and workflow_instance_id = v_subject.workflow_instance_id
    and instance_node_id = v_node.id
    and status = 'PENDING';

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_subject.workflow_instance_id, v_node.template_node_id,
    'REJECTED'::public.workflow_instance_action, v_actor, p_comment);

  update public.workflow_instances
  set status = 'REJECTED'::public.workflow_instance_status, updated_at = now()
  where id = v_subject.workflow_instance_id;
  update public.workflow_subjects
  set current_assignee_user_id = null, current_assignee_user_ids = '{}'::uuid[],
      last_action_instance_node_id = v_node.id, status = 'REJECTED', updated_at = now()
  where id = v_subject.id
  returning * into v_subject;
  update public.requests
  set status = 'REJECTED'::public.request_status,
      submitted_to_user_id = null, submitted_to_name = null, submitted_to_permission = null,
      submission_note = p_comment, last_action_by = v_actor, last_action_at = now(),
      workflow_step = 'rejected', workflow_step_started_at = now(),
      workflow_step_due_at = null, workflow_step_sla_hours = null,
      workflow_step_actor_user_id = v_actor::text
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id, project_id, from_step, to_step, action, actor_user_id, note, metadata
  )
  values (
    p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'material_department_review'),
    'rejected', 'REJECTED', v_actor::text, p_comment,
    jsonb_build_object(
      'workflowInstanceId', v_subject.workflow_instance_id,
      'workflowSubjectId', v_subject.id,
      'instanceNodeId', v_node.id,
      'rollbackDependencies', v_dependency
    )
  );
  return v_subject;
end;
$$ create or replace function public.rollback_completed_project_workflow(
  p_subject_type text,
  p_subject_id text,
  p_comment text
)
returns public.workflow_subjects
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_subject public.workflow_subjects%rowtype;
  v_request public.requests%rowtype;
  v_target_node public.workflow_instance_nodes%rowtype;
  v_dependency jsonb;
  v_round_id uuid;
  v_assignee_ids uuid[];
  v_first_assignee uuid;
  v_assignee_name text;
  v_sla_hours integer;
  v_due_at timestamptz;
  v_to_step text;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if nullif(coalesce(p_comment, ''), '') is null then raise exception 'rollback reason is required'; end if;

  select * into v_subject from public.workflow_subjects ws
  where ws.subject_type = p_subject_type and ws.subject_id = p_subject_id for update;
  if not found then raise exception 'workflow subject not found'; end if;
  select * into v_request from public.requests r where r.id = p_subject_id for update;
  if not found then raise exception 'material request not found: %', p_subject_id; end if;
  if v_subject.status <> 'COMPLETED' then raise exception 'only completed workflow can be rolled back'; end if;
  if not app_private.project_workflow_actor_is_admin(v_subject.id, v_actor) then
    raise exception 'only workflow admin can rollback a completed workflow';
  end if;

  v_dependency := public.get_project_workflow_rollback_dependencies(p_subject_type, p_subject_id);
  if not coalesce((v_dependency ->> 'allowed')::boolean, false) then
    raise exception 'rollback is locked by active downstream dependencies: %', v_dependency;
  end if;

  select * into v_target_node
  from public.workflow_instance_nodes win
  where win.id = v_subject.last_action_instance_node_id
    and win.workflow_instance_id = v_subject.workflow_instance_id;

  if not found then
    select win.* into v_target_node
    from public.workflow_step_assignments wsa
    join public.workflow_instance_nodes win on win.id = wsa.instance_node_id
    where wsa.workflow_subject_id = v_subject.id
      and win.type <> 'END'::public.workflow_node_type
      and wsa.status in ('APPROVED', 'SKIPPED')
    order by wsa.acted_at desc nulls last, wsa.assigned_at desc
    limit 1;
  end if;
  if not found then raise exception 'last actionable runtime workflow step not found'; end if;

  select wsa.assignment_round_id into v_round_id
  from public.workflow_step_assignments wsa
  where wsa.workflow_subject_id = v_subject.id
    and wsa.instance_node_id = v_target_node.id
    and wsa.assignment_round_id is not null
    and wsa.assignment_source not in ('return_to_creator', 'rollback')
  order by wsa.assigned_at desc
  limit 1;

  if v_round_id is not null then
    select coalesce(array_agg(distinct wsa.assignee_user_id), '{}'::uuid[])
      into v_assignee_ids
    from public.workflow_step_assignments wsa
    where wsa.workflow_subject_id = v_subject.id
      and wsa.assignment_round_id = v_round_id
      and wsa.assignee_user_id is not null;
  else
    select coalesce(array_agg(distinct wsa.assignee_user_id), '{}'::uuid[])
      into v_assignee_ids
    from public.workflow_step_assignments wsa
    where wsa.workflow_subject_id = v_subject.id
      and wsa.instance_node_id = v_target_node.id
      and wsa.assignment_source not in ('return_to_creator', 'rollback')
      and wsa.assignee_user_id is not null;
  end if;

  if not app_private.project_workflow_runtime_assignees_are_eligible(
    p_subject_type, p_subject_id, v_target_node.id, v_assignee_ids
  ) then
    raise exception 'previous assignee pool is no longer eligible; reassign before rollback is required';
  end if;

  perform app_private.project_workflow_insert_assignment_pool(
    v_subject.id, v_subject.workflow_instance_id, v_target_node.template_node_id, v_target_node.id,
    v_assignee_ids, v_actor, p_comment,
    jsonb_build_object('rollbackCompletedWorkflow', true, 'rollbackDependencies', v_dependency),
    'rollback'
  );

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (v_subject.workflow_instance_id, v_target_node.template_node_id,
    'REOPENED'::public.workflow_instance_action, v_actor, p_comment);

  v_first_assignee := v_assignee_ids[1];
  v_assignee_name := app_private.project_workflow_first_assignee_name(v_assignee_ids);
  v_sla_hours := app_private.project_workflow_runtime_sla_hours(v_target_node.id);
  v_due_at := app_private.project_workflow_runtime_sla_due_at(v_target_node.id);
  v_to_step := app_private.project_workflow_runtime_to_coarse_step(v_subject.workflow_instance_id, v_target_node.id);

  update public.workflow_instances
  set current_node_id = v_target_node.template_node_id,
      current_instance_node_id = v_target_node.id,
      status = 'RUNNING'::public.workflow_instance_status,
      step_assignees = coalesce(step_assignees, '{}'::jsonb)
        || app_private.project_workflow_step_assignees_json(v_target_node.template_node_id, v_assignee_ids),
      updated_at = now()
  where id = v_subject.workflow_instance_id;

  update public.workflow_subjects
  set current_assignee_user_id = v_first_assignee,
      current_assignee_user_ids = v_assignee_ids,
      current_node_id = v_target_node.template_node_id,
      current_instance_node_id = v_target_node.id,
      status = 'RUNNING', updated_at = now()
  where id = v_subject.id
  returning * into v_subject;

  update public.requests
  set status = 'PENDING'::public.request_status,
      submitted_to_user_id = v_first_assignee::text, submitted_to_name = v_assignee_name,
      submitted_to_permission = app_private.project_workflow_runtime_primary_permission(v_target_node.id),
      submission_note = p_comment, last_action_by = v_actor, last_action_at = now(),
      workflow_step = v_to_step, workflow_step_started_at = now(),
      workflow_step_due_at = v_due_at, workflow_step_sla_hours = v_sla_hours,
      workflow_step_actor_user_id = v_actor::text
  where id = p_subject_id;

  insert into public.material_request_events(
    request_id, project_id, from_step, to_step, action, actor_user_id,
    target_user_id, target_permission, note, sla_hours, due_at, metadata
  )
  values (
    p_subject_id, v_request.project_id, coalesce(v_request.workflow_step, 'batch_planning'),
    v_to_step, 'ROLLED_BACK', v_actor::text, v_first_assignee::text,
    app_private.project_workflow_runtime_primary_permission(v_target_node.id),
    p_comment, v_sla_hours, v_due_at,
    jsonb_build_object(
      'workflowInstanceId', v_subject.workflow_instance_id,
      'workflowSubjectId', v_subject.id,
      'toInstanceNodeId', v_target_node.id,
      'assigneeUserIds', v_assignee_ids,
      'rollbackDependencies', v_dependency
    )
  );
  return v_subject;
end;
$$ create or replace function public.save_workflow_template_structure(
  p_template_id uuid,
  p_template jsonb,
  p_nodes jsonb,
  p_edges jsonb
)
returns jsonb
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_validation jsonb;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if not app_private.project_workflow_template_manager(p_template_id, v_actor) then
    raise exception 'user cannot edit this workflow template';
  end if;
  if jsonb_typeof(coalesce(p_nodes, '[]'::jsonb)) <> 'array'
     or jsonb_typeof(coalesce(p_edges, '[]'::jsonb)) <> 'array' then
    raise exception 'nodes and edges must be arrays';
  end if;

  update public.workflow_templates
  set name = coalesce(nullif(p_template ->> 'name', ''), name),
      description = coalesce(p_template ->> 'description', description),
      is_active = coalesce((p_template ->> 'is_active')::boolean, is_active),
      custom_fields = coalesce(p_template -> 'custom_fields', custom_fields, '[]'::jsonb),
      managers = coalesce(array(select jsonb_array_elements_text(p_template -> 'managers')), managers, '{}'::text[]),
      default_watchers = coalesce(array(select jsonb_array_elements_text(p_template -> 'default_watchers')), default_watchers, '{}'::text[]),
      updated_at = now()
  where id = p_template_id;
  if not found then raise exception 'workflow template not found'; end if;

  delete from public.workflow_edges we where we.template_id = p_template_id;

  delete from public.workflow_nodes wn
  where wn.template_id = p_template_id
    and not exists (
      select 1
      from jsonb_array_elements(p_nodes) node(value)
      where node.value ->> 'id' = wn.id::text
    );

  insert into public.workflow_nodes(id, template_id, type, label, config, position_x, position_y)
  select
    (node.value ->> 'id')::uuid,
    p_template_id,
    (node.value ->> 'type')::public.workflow_node_type,
    node.value ->> 'label',
    coalesce(node.value -> 'config', '{}'::jsonb),
    coalesce((node.value ->> 'position_x')::double precision, 0),
    coalesce((node.value ->> 'position_y')::double precision, 0)
  from jsonb_array_elements(p_nodes) node(value)
  on conflict (id) do update
  set type = excluded.type, label = excluded.label, config = excluded.config,
      position_x = excluded.position_x, position_y = excluded.position_y;

  insert into public.workflow_edges(id, template_id, source_node_id, target_node_id, label)
  select
    (edge.value ->> 'id')::uuid,
    p_template_id,
    (edge.value ->> 'source_node_id')::uuid,
    (edge.value ->> 'target_node_id')::uuid,
    coalesce(edge.value ->> 'label', '')
  from jsonb_array_elements(p_edges) edge(value);

  v_validation := app_private.project_workflow_validate_template(p_template_id);
  if not coalesce((v_validation ->> 'valid')::boolean, false) then
    raise exception 'invalid workflow template structure: %', v_validation;
  end if;
  return v_validation;
end;
$$ create or replace function app_private.prevent_used_workflow_template_delete()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if exists (select 1 from public.project_workflow_bindings b where b.workflow_template_id = old.id)
     or exists (select 1 from public.workflow_template_versions v where v.template_id = old.id)
     or exists (select 1 from public.workflow_instances i where i.template_id = old.id) then
    raise exception 'workflow template has bindings/versions/instances and must be deactivated instead of deleted';
  end if;
  return old;
end;
$$ drop trigger if exists trg_prevent_used_workflow_template_delete on public.workflow_templates create trigger trg_prevent_used_workflow_template_delete
before delete on public.workflow_templates
for each row execute function app_private.prevent_used_workflow_template_delete() create or replace function app_private.material_request_workflow_participant_can_select(p_request_id text)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select exists (
    select 1
    from public.workflow_subjects ws
    where ws.subject_type = 'material_request'
      and ws.subject_id = p_request_id
      and app_private.project_workflow_actor_can_select(ws.id)
  );
$$ create or replace function app_private.project_workflow_instance_can_select(p_instance_id uuid)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select not exists (
    select 1 from public.workflow_subjects ws where ws.workflow_instance_id = p_instance_id
  ) or exists (
    select 1
    from public.workflow_subjects ws
    where ws.workflow_instance_id = p_instance_id
      and app_private.project_workflow_actor_can_select(ws.id)
  );
$$ create or replace function app_private.prevent_project_workflow_instance_delete()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if exists (
    select 1 from public.workflow_subjects ws where ws.workflow_instance_id = old.id
  ) then
    raise exception 'project-linked workflow instances cannot be deleted';
  end if;
  return old;
end;
$$ drop trigger if exists trg_prevent_project_workflow_instance_delete on public.workflow_instances create trigger trg_prevent_project_workflow_instance_delete
before delete on public.workflow_instances
for each row execute function app_private.prevent_project_workflow_instance_delete() create or replace function app_private.sync_material_request_downstream_link()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_request_id text;
  v_target_type text;
  v_target_id text;
  v_project_id text;
  v_status text;
begin
  if tg_table_name = 'material_request_fulfillment_batches' then
    v_request_id := new.material_request_id;
    v_target_type := 'fulfillment_batch';
    v_target_id := new.id::text;
    v_project_id := new.project_id;
    v_status := case
      when lower(coalesce(new.status::text, '')) in ('cancelled', 'canceled', 'returned', 'reversed', 'void')
        then 'reversed' else 'active' end;
  elsif tg_table_name = 'purchase_order_request_lines' then
    v_request_id := coalesce(new.material_request_id, old.material_request_id);
    v_target_type := 'purchase_order';
    v_target_id := coalesce(new.purchase_order_id, old.purchase_order_id);
    v_project_id := coalesce(new.project_id, old.project_id);
    v_status := case when tg_op = 'DELETE' then 'void' else 'active' end;
  elsif tg_table_name = 'transactions' then
    v_request_id := new.related_request_id;
    v_target_type := 'transaction';
    v_target_id := new.id::text;
    select r.project_id into v_project_id from public.requests r where r.id = v_request_id;
    v_status := case
      when lower(coalesce(new.status::text, '')) in ('cancelled', 'canceled', 'returned', 'reversed', 'void')
        then 'reversed' else 'active' end;
  else
    if tg_op = 'DELETE' then return old; end if;
    return new;
  end if;

  if coalesce(v_request_id, '') <> '' then
    insert into public.project_document_links(
      source_type, source_id, target_type, target_id, project_id,
      relation_type, status, metadata
    )
    values (
      'material_request', v_request_id, v_target_type, v_target_id, v_project_id,
      'downstream', v_status, jsonb_build_object('syncedFrom', tg_table_name)
    )
    on conflict (source_type, source_id, target_type, target_id, relation_type)
    do update set status = excluded.status, project_id = excluded.project_id,
      metadata = coalesce(public.project_document_links.metadata, '{}'::jsonb) || excluded.metadata,
      updated_at = now();
  end if;
  if tg_op = 'DELETE' then return old; end if;
  return new;
end;
$$ create or replace function app_private.sync_purchase_order_request_dependencies()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  update public.project_document_links pdl
  set status = case
        when lower(coalesce(new.status::text, '')) in ('cancelled', 'canceled', 'returned', 'reversed', 'void')
          then 'reversed' else 'active' end,
      updated_at = now(),
      metadata = coalesce(pdl.metadata, '{}'::jsonb) || jsonb_build_object('syncedFrom', 'purchase_orders')
  where pdl.source_type = 'material_request'
    and pdl.target_type = 'purchase_order'
    and pdl.target_id = new.id::text
    and pdl.relation_type = 'downstream';
  return new;
end;
