    execute format('drop policy if exists %I on public.%I', v_policy.policyname, v_policy.tablename);
  end loop;
end $$ alter table public.workflow_templates enable row level security alter table public.workflow_nodes enable row level security alter table public.workflow_edges enable row level security create policy workflow_templates_select
  on public.workflow_templates for select to authenticated using (true) create policy workflow_templates_insert
