  with check (app_private.project_workflow_template_manager(template_id, public.current_app_user_id())) create policy workflow_nodes_delete
  on public.workflow_nodes for delete to authenticated
  using (app_private.project_workflow_template_manager(template_id, public.current_app_user_id())) create policy workflow_edges_select
  on public.workflow_edges for select to authenticated using (true) create policy workflow_edges_insert
  on public.workflow_edges for insert to authenticated
  with check (app_private.project_workflow_template_manager(template_id, public.current_app_user_id())) create policy workflow_edges_update
  on public.workflow_edges for update to authenticated
  using (app_private.project_workflow_template_manager(template_id, public.current_app_user_id()))
  with check (app_private.project_workflow_template_manager(template_id, public.current_app_user_id())) create policy workflow_edges_delete
  on public.workflow_edges for delete to authenticated
  using (app_private.project_workflow_template_manager(template_id, public.current_app_user_id())) drop policy if exists requests_select on public.requests create policy requests_select
  on public.requests for select to authenticated
  using (
    app_private.material_request_can_select(
      request_origin, project_id, requester_id, submitted_to_user_id,
      source_warehouse_id, site_warehouse_id
    )
    or app_private.material_request_workflow_participant_can_select(id)
  ) drop policy if exists wf_inst_select on public.workflow_instances create policy wf_inst_select
  on public.workflow_instances for select to authenticated
  using (app_private.project_workflow_instance_can_select(id)) drop policy if exists wf_logs_select on public.workflow_instance_logs create policy wf_logs_select
  on public.workflow_instance_logs for select to authenticated
  using (app_private.project_workflow_instance_can_select(instance_id)) drop policy if exists wf_inst_delete on public.workflow_instances create policy wf_inst_delete
  on public.workflow_instances for delete to authenticated
  using (
    not exists (
      select 1 from public.workflow_subjects ws where ws.workflow_instance_id = workflow_instances.id
    )
    and (
      public.is_module_admin('WF')
      or created_by = public.current_app_user_id()
      or app_private.project_workflow_template_manager(template_id, public.current_app_user_id())
    )
  ) drop policy if exists workflow_sla_notifications_select on public.workflow_sla_notifications create policy workflow_sla_notifications_select
  on public.workflow_sla_notifications for select to authenticated
  using (app_private.project_workflow_actor_can_select(workflow_subject_id)) revoke all on table public.workflow_sla_notifications from anon revoke all on table public.workflow_sla_notifications from public revoke all on table public.workflow_sla_notifications from authenticated grant select on table public.workflow_sla_notifications to authenticated revoke insert, update, delete on table public.project_workflow_bindings from authenticated grant select on table public.project_workflow_bindings to authenticated -- Runtime state and assignment history are write-only through the guarded RPCs.
-- This also guarantees workflow managers cannot delete instance/audit data.
