cute on function public.get_project_workflow_rollback_dependencies(text, text) to authenticated revoke execute on function public.get_project_workflow_configuration(text, text, text) from public revoke execute on function public.get_project_workflow_configuration(text, text, text) from anon grant execute on function public.get_project_workflow_configuration(text, text, text) to authenticated revoke execute on function public.set_project_workflow_binding(text, uuid, text, text) from public revoke execute on function public.set_project_workflow_binding(text, uuid, text, text) from anon grant execute on function public.set_project_workflow_binding(text, uuid, text, text) to authenticated revoke execute on function public.remove_project_workflow_binding(text, text, text) from public revoke execute on function public.remove_project_workflow_binding(text, text, text) from anon grant execute on function public.remove_project_workflow_binding(text, text, text) to authenticated revoke execute on function public.save_workflow_template_structure(uuid, jsonb, jsonb, jsonb) from public revoke execute on function public.save_workflow_template_structure(uuid, jsonb, jsonb, jsonb) from anon grant execute on function public.save_workflow_template_structure(uuid, jsonb, jsonb, jsonb) to authenticated revoke execute on function public.rollback_completed_project_workflow(text, text, text) from public revoke execute on function public.rollback_completed_project_workflow(text, text, text) from anon grant execute on function public.rollback_completed_project_workflow(text, text, text) to authenticated revoke execute on function public.process_project_workflow_sla_reminders() from public revoke execute on function public.process_project_workflow_sla_reminders() from anon revoke execute on function public.process_project_workflow_sla_reminders() from authenticated revoke execute on function public.start_project_workflow_v2(text, text, uuid, uuid[], text) from public revoke execute on function public.start_project_workflow_v2(text, text, uuid, uuid[], text) from anon grant execute on function public.start_project_workflow_v2(text, text, uuid, uuid[], text) to authenticated revoke execute on function public.advance_project_workflow_v2(text, text, uuid[], text) from public revoke execute on function public.advance_project_workflow_v2(text, text, uuid[], text) from anon grant execute on function public.advance_project_workflow_v2(text, text, uuid[], text) to authenticated revoke execute on function public.return_project_workflow_v2(text, text, text) from public revoke execute on function public.return_project_workflow_v2(text, text, text) from anon grant execute on function public.return_project_workflow_v2(text, text, text) to authenticated revoke execute on function public.resubmit_project_workflow_v2(text, text, uuid[], text) from public revoke execute on function public.resubmit_project_workflow_v2(text, text, uuid[], text) from anon grant execute on function public.resubmit_project_workflow_v2(text, text, uuid[], text) to authenticated revoke execute on function public.reassign_project_workflow_v2(text, text, uuid[], text) from public revoke execute on function public.reassign_project_workflow_v2(text, text, uuid[], text) from anon grant execute on function public.reassign_project_workflow_v2(text, text, uuid[], text) to authenticated revoke execute on function public.reject_project_workflow(text, text, text) from public revoke execute on function public.reject_project_workflow(text, text, text) from anon grant execute on function public.reject_project_workflow(text, text, text) to authenticated notify pgrst, 'reload schema']

[-- Project opening balance automation is temporarily dormant. Keep its data for
-- later use, but treat status as informational text and remove the one-lock-per-
