      construction_site_id,
      'edit',
      public.current_app_user_id()
    )
  ) create policy project_finances_delete
  on public.project_finances
  for delete
  to authenticated
  using (
    public.is_module_admin('DA')
    or app_private.project_user_has_permission(
      project_id,
      construction_site_id,
      'delete',
      public.current_app_user_id()
    )
  ) revoke all on table public.project_transactions from anon revoke all on table public.project_transactions from public revoke all on table public.project_transactions from authenticated grant select, insert, update, delete on table public.project_transactions to authenticated drop policy if exists project_tx_select on public.project_transactions drop policy if exists project_tx_write on public.project_transactions drop policy if exists project_tx_insert on public.project_transactions drop policy if exists project_tx_update on public.project_transactions drop policy if exists project_tx_delete on public.project_transactions create policy project_tx_select
