  using (true) create policy project_tx_insert
  on public.project_transactions
  for insert
  to authenticated
  with check (
    public.is_module_admin('DA')
    or app_private.project_user_has_permission(
      project_id,
      construction_site_id,
      'edit',
      public.current_app_user_id()
    )
  ) create policy project_tx_update
  on public.project_transactions
  for update
  to authenticated
  using (
    public.is_module_admin('DA')
    or app_private.project_user_has_permission(
      project_id,
      construction_site_id,
      'edit',
      public.current_app_user_id()
    )
  )
  with check (
    public.is_module_admin('DA')
    or app_private.project_user_has_permission(
      project_id,
      construction_site_id,
      'edit',
      public.current_app_user_id()
    )
  ) create policy project_tx_delete
  on public.project_transactions
  for delete
  to authenticated
  using (
    public.is_module_admin('DA')
    or app_private.project_user_has_permission(
      project_id,
      construction_site_id,
      'delete',
      public.current_app_user_id()
    )
  ) notify pgrst, 'reload schema']

[alter table if exists public.items
  add column if not exists purchase_conversion_factor numeric default 1 update public.items
set purchase_conversion_factor = 1
where purchase_conversion_factor is null
   or purchase_conversion_factor <= 0 alter table if exists public.items
  alter column purchase_conversion_factor set not null alter table if exists public.items
  drop constraint if exists items_purchase_conversion_factor_positive alter table if exists public.items
  add constraint items_purchase_conversion_factor_positive
  check (purchase_conversion_factor > 0) create or replace function public.create_purchase_order_supplier_return(
  p_purchase_order_id text,
  p_source_warehouse_id text,
  p_lines jsonb,
  p_reason text,
  p_note text default null
)
returns public.purchase_order_supplier_returns
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_po public.purchase_orders%rowtype;
  v_return public.purchase_order_supplier_returns%rowtype;
  v_return_id uuid := gen_random_uuid();
  v_transaction_id text := 'tx-supplier-return-' || replace(gen_random_uuid()::text, '-', '');
  v_return_no text;
  v_line jsonb;
  v_po_item jsonb;
  v_po_line_id text;
  v_item_id text;
  v_qty numeric;
  v_stock_qty numeric;
  v_received_qty numeric;
  v_returned_qty numeric;
  v_on_hand numeric;
  v_reserved numeric;
  v_purchase_unit text;
  v_stock_unit text;
  v_conversion_factor numeric;
  v_purchase_unit_price numeric;
  v_stock_unit_price numeric;
  v_is_converted boolean;
  v_transaction_items jsonb := '[]'::jsonb;
  v_return_line_rows jsonb := '[]'::jsonb;
  v_item_total record;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if not (
    public.is_admin()
    or public.is_module_admin('WMS')
    or app_private.current_user_is_global_wms_keeper()
  ) then
    raise exception 'Chỉ Admin, quản trị WMS hoặc thủ kho tổng được tạo phiếu trả hàng NCC.';
  end if;
  if coalesce(trim(p_reason), '') = '' then
    raise exception 'Bắt buộc nhập lý do trả hàng NCC.';
  end if;
  if coalesce(p_source_warehouse_id, '') = '' then
    raise exception 'Chưa chọn kho xuất trả NCC.';
  end if;
  if jsonb_typeof(p_lines) <> 'array' or jsonb_array_length(p_lines) = 0 then
    raise exception 'Phiếu trả NCC chưa có dòng vật tư.';
  end if;

  select * into v_po
  from public.purchase_orders
  where id = p_purchase_order_id
  for update;
  if not found then raise exception 'Không tìm thấy PO cần trả hàng.'; end if;
  if lower(coalesce(v_po.status::text, '')) not in ('partial', 'delivered', 'closed') then
    raise exception 'Chỉ trả NCC cho PO đã phát sinh nhận hàng và đang ở trạng thái giao một phần, hoàn thành hoặc đã đóng.';
  end if;
  if not exists (select 1 from public.warehouses w where w.id = p_source_warehouse_id) then
    raise exception 'Kho xuất trả NCC không tồn tại.';
  end if;

  v_return_no := 'SR-' || regexp_replace(coalesce(v_po.po_number, 'PO'), '[^A-Za-z0-9]+', '-', 'g')
    || '-' || upper(substr(replace(v_return_id::text, '-', ''), 1, 6));

  for v_line in
    select value from jsonb_array_elements(p_lines)
  loop
    v_po_line_id := coalesce(v_line ->> 'purchaseOrderLineId', v_line ->> 'poLineId', v_line ->> 'lineId');
    v_qty := coalesce(nullif(v_line ->> 'quantity', '')::numeric, 0);
    if coalesce(v_po_line_id, '') = '' or v_qty <= 0 then
      raise exception 'Dòng trả NCC không hợp lệ.';
    end if;

    select item.value into v_po_item
    from jsonb_array_elements(coalesce(v_po.items, '[]'::jsonb)) item(value)
    where coalesce(item.value ->> 'lineId', item.value ->> 'itemId') = v_po_line_id
    limit 1;
    if v_po_item is null then raise exception 'Dòng PO không tồn tại: %', v_po_line_id; end if;

    v_item_id := v_po_item ->> 'itemId';
    v_received_qty := coalesce(nullif(v_po_item ->> 'receivedQty', '')::numeric, 0);
    v_purchase_unit_price := coalesce(nullif(v_po_item ->> 'unitPrice', '')::numeric, 0);

    select coalesce(sum(line.return_qty), 0)
    into v_returned_qty
    from public.purchase_order_supplier_return_lines line
    join public.purchase_order_supplier_returns r on r.id = line.supplier_return_id
    where r.purchase_order_id = p_purchase_order_id
      and line.purchase_order_line_id = v_po_line_id
      and r.status in ('pending', 'completed');

    if v_qty > greatest(0, v_received_qty - v_returned_qty) then
      raise exception 'Số lượng trả của dòng % vượt khối lượng đã nhận còn có thể trả. Đã nhận %, đã/đang trả %, yêu cầu trả %.',
        v_po_line_id, v_received_qty, v_returned_qty, v_qty;
    end if;

    select
      coalesce((coalesce(i.stock_by_warehouse, '{}'::jsonb) ->> p_source_warehouse_id)::numeric, 0),
      coalesce(nullif(v_po_item ->> 'stockUnitSnapshot', ''), nullif(v_po_item ->> 'unitSnapshot', ''), i.unit, nullif(v_po_item ->> 'unit', '')),
      coalesce(nullif(v_po_item ->> 'purchaseUnitSnapshot', ''), nullif(v_po_item ->> 'unit', ''), i.purchase_unit, i.unit),
      coalesce(nullif(v_po_item ->> 'purchaseConversionFactor', '')::numeric, i.purchase_conversion_factor, 1)
    into v_on_hand, v_stock_unit, v_purchase_unit, v_conversion_factor
    from public.items i
    where i.id = v_item_id;
    if not found then raise exception 'Không tìm thấy vật tư: %', v_item_id; end if;

    v_conversion_factor := case when coalesce(v_conversion_factor, 0) > 0 then v_conversion_factor else 1 end;
    v_is_converted := coalesce(trim(v_stock_unit), '') <> ''
      and coalesce(trim(v_purchase_unit), '') <> ''
      and lower(trim(v_stock_unit)) <> lower(trim(v_purchase_unit));
    v_stock_qty := case when v_is_converted then v_qty * v_conversion_factor else v_qty end;
    v_stock_unit_price := case when v_is_converted then v_purchase_unit_price / v_conversion_factor else v_purchase_unit_price end;

    select coalesce(sum(coalesce(nullif(item.value ->> 'quantity', '')::numeric, 0)), 0)
    into v_reserved
    from public.transactions t
    cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) item(value)
    where t.source_warehouse_id = p_source_warehouse_id
      and t.status in ('PENDING'::public.transaction_status, 'APPROVED'::public.transaction_status)
      and t.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
      and item.value ->> 'itemId' = v_item_id;

    if v_stock_qty > greatest(0, v_on_hand - v_reserved) then
      raise exception 'Kho xuất trả không đủ tồn khả dụng cho vật tư %. Tồn %, đang giữ %, khả dụng %, cần trả %.',
        coalesce(v_po_item ->> 'name', v_item_id), v_on_hand, v_reserved, greatest(0, v_on_hand - v_reserved), v_stock_qty;
    end if;

    v_transaction_items := v_transaction_items || jsonb_build_array(
      jsonb_build_object(
        'itemId', v_item_id,
        'quantity', v_stock_qty,
        'price', v_stock_unit_price,
        'supplierReturnId', v_return_id::text,
        'purchaseOrderId', p_purchase_order_id,
        'purchaseOrderLineId', v_po_line_id
      )
      || case when v_is_converted then jsonb_build_object(
        'accountingQty', v_qty,
        'accountingUnit', v_purchase_unit,
        'accountingPrice', v_purchase_unit_price
      ) else '{}'::jsonb end
    );

    v_return_line_rows := v_return_line_rows || jsonb_build_array(jsonb_build_object(
      'purchaseOrderLineId', v_po_line_id,
      'itemId', v_item_id,
      'receivedQtySnapshot', v_received_qty,
      'previouslyReturnedQtySnapshot', v_returned_qty,
      'returnQty', v_qty,
      'unit', v_purchase_unit,
      'unitPrice', v_purchase_unit_price
    ));
  end loop;

  for v_item_total in
    select
      item.value ->> 'itemId' as item_id,
      sum(coalesce(nullif(item.value ->> 'quantity', '')::numeric, 0)) as quantity
    from jsonb_array_elements(v_transaction_items) item(value)
    group by item.value ->> 'itemId'
  loop
    select coalesce((coalesce(i.stock_by_warehouse, '{}'::jsonb) ->> p_source_warehouse_id)::numeric, 0)
    into v_on_hand
    from public.items i
    where i.id = v_item_total.item_id
    for update;

    select coalesce(sum(coalesce(nullif(item.value ->> 'quantity', '')::numeric, 0)), 0)
    into v_reserved
    from public.transactions t
    cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) item(value)
    where t.source_warehouse_id = p_source_warehouse_id
      and t.status in ('PENDING'::public.transaction_status, 'APPROVED'::public.transaction_status)
      and t.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
      and item.value ->> 'itemId' = v_item_total.item_id;

    if v_item_total.quantity > greatest(0, v_on_hand - v_reserved) then
      raise exception 'Tổng số lượng trả NCC vượt tồn khả dụng của vật tư %. Tồn %, đang giữ %, khả dụng %, cần trả %.',
        v_item_total.item_id, v_on_hand, v_reserved, greatest(0, v_on_hand - v_reserved), v_item_total.quantity;
    end if;
  end loop;

  insert into public.transactions(
    id, type, date, items, source_warehouse_id, requester_id,
    status, note
  ) values (
    v_transaction_id,
    'EXPORT'::public.transaction_type,
    now(),
    v_transaction_items,
    p_source_warehouse_id,
    v_actor,
    'PENDING'::public.transaction_status,
    'Trả hàng NCC ' || v_return_no || ' theo PO ' || coalesce(v_po.po_number, p_purchase_order_id)
      || case when coalesce(v_po.vendor_name, '') <> '' then ' - ' || v_po.vendor_name else '' end
  );

  insert into public.purchase_order_supplier_returns(
    id, return_no, purchase_order_id, project_id, construction_site_id,
    vendor_id, source_warehouse_id, status, transaction_id,
    reason, note, created_by
  ) values (
    v_return_id, v_return_no, v_po.id, v_po.project_id, v_po.construction_site_id,
    v_po.vendor_id, p_source_warehouse_id, 'pending', v_transaction_id,
    trim(p_reason), nullif(trim(coalesce(p_note, '')), ''), v_actor
  )
  returning * into v_return;

  insert into public.purchase_order_supplier_return_lines(
    supplier_return_id, purchase_order_line_id, item_id,
    received_qty_snapshot, previously_returned_qty_snapshot,
    return_qty, unit, unit_price
  )
  select
    v_return_id,
    line.value ->> 'purchaseOrderLineId',
    line.value ->> 'itemId',
    coalesce(nullif(line.value ->> 'receivedQtySnapshot', '')::numeric, 0),
    coalesce(nullif(line.value ->> 'previouslyReturnedQtySnapshot', '')::numeric, 0),
    coalesce(nullif(line.value ->> 'returnQty', '')::numeric, 0),
    nullif(line.value ->> 'unit', ''),
    coalesce(nullif(line.value ->> 'unitPrice', '')::numeric, 0)
  from jsonb_array_elements(v_return_line_rows) line(value);

  return v_return;
end;
$$]

[-- Inventory Ledger zero-quantity tolerance
-- Zero-quantity historical WMS documents are documents without stock movement.
-- They should not block sync, and they should not create ledger entries.

create or replace function app_private.sync_wms_transaction_to_inventory_ledger(p_transaction_id text)
returns uuid
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_tx public.transactions%rowtype;
  v_existing_id uuid;
  v_inventory_transaction_id uuid;
  v_has_in boolean := false;
  v_has_out boolean := false;
  v_in_code text;
  v_out_code text;
  v_header_code text;
  v_header_type text;
  v_line jsonb;
  v_entry_no integer := 0;
  v_tx_date timestamptz;
  v_item_id text;
  v_qty numeric;
  v_price numeric;
  v_project_id text;
  v_construction_site_id text;
  v_source_line_id text;
  v_metadata jsonb;
begin
  select * into v_tx
  from public.transactions
  where id = p_transaction_id
  for update;
  if not found then
    raise exception 'transaction not found: %', p_transaction_id;
  end if;

  if v_tx.status::text <> 'COMPLETED' then
    return null;
  end if;
  v_tx_date := coalesce(nullif(v_tx.date::text, '')::timestamptz, now());

  select id into v_existing_id
  from public.inventory_transactions
  where source_type = 'wms_transaction'
    and source_id = v_tx.id
  limit 1;
  if v_existing_id is not null then
    return v_existing_id;
  end if;

  v_has_in := v_tx.type::text in ('IMPORT', 'TRANSFER')
    and exists (
      select 1
      from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) item(value)
      where coalesce(nullif(item.value->>'quantity', '')::numeric, 0) > 0
    )
    or exists (
      select 1
      from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) item(value)
      where v_tx.type::text = 'ADJUSTMENT'
        and coalesce(nullif(item.value->>'quantity', '')::numeric, 0) > 0
    );
  v_has_out := v_tx.type::text in ('EXPORT', 'TRANSFER', 'LIQUIDATION')
    and exists (
      select 1
      from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) item(value)
      where coalesce(nullif(item.value->>'quantity', '')::numeric, 0) > 0
    )
    or exists (
      select 1
      from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb)) item(value)
      where v_tx.type::text = 'ADJUSTMENT'
        and coalesce(nullif(item.value->>'quantity', '')::numeric, 0) < 0
    );

  if not v_has_in and not v_has_out then
    return null;
  end if;

  if v_has_in then
    v_in_code := app_private.next_inventory_ledger_code('in');
  end if;
  if v_has_out then
    v_out_code := app_private.next_inventory_ledger_code('out');
  end if;
  v_header_code := coalesce(v_out_code, v_in_code);
  v_header_type := app_private.inventory_transaction_type_for_entry(
    v_tx.type::text,
    case when v_has_out and not v_has_in then 'out' else 'in' end,
    v_tx.related_request_id is not null
  );

  v_metadata := jsonb_build_object(
    'wmsTransactionId', v_tx.id,
    'wmsType', v_tx.type::text,
    'wmsStatus', v_tx.status::text,
    'sourceWarehouseId', v_tx.source_warehouse_id,
    'targetWarehouseId', v_tx.target_warehouse_id,
    'supplierId', v_tx.supplier_id,
    'items', coalesce(v_tx.items, '[]'::jsonb)
  );

  insert into public.inventory_transactions (
    code, transaction_type, status, transaction_date,
    source_type, source_id, source_code,
    related_request_id, project_id, construction_site_id,
    description, metadata, created_by, approved_by, posted_at
  )
  values (
    v_header_code, v_header_type, 'posted', v_tx_date,
    'wms_transaction', v_tx.id, v_tx.id,
    v_tx.related_request_id, null, null,
    v_tx.note, v_metadata, v_tx.requester_id, v_tx.approver_id, now()
  )
  returning id into v_inventory_transaction_id;

  for v_line in
    select value from jsonb_array_elements(coalesce(v_tx.items, '[]'::jsonb))
  loop
    v_item_id := v_line->>'itemId';
    v_qty := coalesce(nullif(v_line->>'quantity', '')::numeric, 0);
    v_price := coalesce(nullif(v_line->>'price', '')::numeric, 0);
    v_project_id := nullif(coalesce(v_line->>'projectId', v_line->>'project_id'), '');
    v_construction_site_id := nullif(coalesce(v_line->>'constructionSiteId', v_line->>'construction_site_id'), '');
    v_source_line_id := nullif(coalesce(v_line->>'requestLineId', v_line->>'materialIssueLineId', v_line->>'lineId'), '');

    if v_item_id is null then
      raise exception 'invalid transaction item payload';
    end if;
    if v_qty = 0 then
      continue;
    end if;

    if v_tx.type::text = 'IMPORT' then
      if v_qty < 0 then raise exception 'invalid import quantity'; end if;
      v_entry_no := v_entry_no + 1;
      perform app_private.post_inventory_ledger_entry(
        v_inventory_transaction_id, v_entry_no, v_in_code,
        v_tx_date, 'purchase_receipt', 'in',
        v_item_id, v_tx.target_warehouse_id, v_project_id, v_construction_site_id,
        'wms_transaction', v_tx.id, v_tx.id, v_source_line_id, v_tx.related_request_id,
        v_qty, v_price, v_tx.note, v_line, v_tx.requester_id, v_tx.approver_id
      );
    elsif v_tx.type::text = 'EXPORT' then
      if v_qty < 0 then raise exception 'invalid export quantity'; end if;
      v_entry_no := v_entry_no + 1;
      perform app_private.post_inventory_ledger_entry(
        v_inventory_transaction_id, v_entry_no, v_out_code,
        v_tx_date, 'project_issue', 'out',
        v_item_id, v_tx.source_warehouse_id, v_project_id, v_construction_site_id,
        'wms_transaction', v_tx.id, v_tx.id, v_source_line_id, v_tx.related_request_id,
        v_qty, v_price, v_tx.note, v_line, v_tx.requester_id, v_tx.approver_id
      );
    elsif v_tx.type::text = 'TRANSFER' then
      if v_qty < 0 then raise exception 'invalid transfer quantity'; end if;
      v_entry_no := v_entry_no + 1;
      perform app_private.post_inventory_ledger_entry(
        v_inventory_transaction_id, v_entry_no, v_out_code,
        v_tx_date, 'transfer_issue', 'out',
        v_item_id, v_tx.source_warehouse_id, v_project_id, v_construction_site_id,
        'wms_transaction', v_tx.id, v_tx.id, v_source_line_id, v_tx.related_request_id,
        v_qty, v_price, v_tx.note, v_line, v_tx.requester_id, v_tx.approver_id
      );
      v_entry_no := v_entry_no + 1;
      perform app_private.post_inventory_ledger_entry(
        v_inventory_transaction_id, v_entry_no, v_in_code,
        v_tx_date, 'transfer_receipt', 'in',
        v_item_id, v_tx.target_warehouse_id, v_project_id, v_construction_site_id,
        'wms_transaction', v_tx.id, v_tx.id, v_source_line_id, v_tx.related_request_id,
        v_qty, v_price, v_tx.note, v_line, v_tx.requester_id, v_tx.approver_id
      );
    elsif v_tx.type::text = 'LIQUIDATION' then
      if v_qty < 0 then raise exception 'invalid liquidation quantity'; end if;
      v_entry_no := v_entry_no + 1;
      perform app_private.post_inventory_ledger_entry(
        v_inventory_transaction_id, v_entry_no, v_out_code,
        v_tx_date, 'loss_issue', 'out',
        v_item_id, v_tx.source_warehouse_id, v_project_id, v_construction_site_id,
        'wms_transaction', v_tx.id, v_tx.id, v_source_line_id, v_tx.related_request_id,
        v_qty, v_price, v_tx.note, v_line, v_tx.requester_id, v_tx.approver_id
      );
    elsif v_tx.type::text = 'ADJUSTMENT' then
      v_entry_no := v_entry_no + 1;
      perform app_private.post_inventory_ledger_entry(
        v_inventory_transaction_id, v_entry_no,
        case when v_qty > 0 then v_in_code else v_out_code end,
        v_tx_date,
        case when v_qty > 0 then 'adjustment_in' else 'adjustment_out' end,
        case when v_qty > 0 then 'in' else 'out' end,
        v_item_id, coalesce(v_tx.target_warehouse_id, v_tx.source_warehouse_id), v_project_id, v_construction_site_id,
        'wms_transaction', v_tx.id, v_tx.id, v_source_line_id, v_tx.related_request_id,
        abs(v_qty), v_price, v_tx.note, v_line, v_tx.requester_id, v_tx.approver_id
      );
    end if;
  end loop;

  if v_entry_no = 0 then
    delete from public.inventory_transactions
    where id = v_inventory_transaction_id;
    return null;
  end if;

  return v_inventory_transaction_id;
end;
$$ notify pgrst, 'reload schema']

[-- Payment schedule workbench V1
-- Keep payment_schedules as the single source of truth for manual contract
-- payment plans, then enrich it with planned WBS scope and lightweight dossier
-- / quality status fields.

alter table if exists public.payment_schedules
  add column if not exists sequence_no integer not null default 1,
  add column if not exists milestone_type text not null default 'progress',
  add column if not exists planned_task_ids text[] not null default '{}'::text[],
  add column if not exists planned_scope_note text,
  add column if not exists dossier_status text not null default 'not_started',
  add column if not exists quality_status text not null default 'not_confirmed',
  add column if not exists quality_confirmed_by text,
  add column if not exists quality_confirmed_name text,
  add column if not exists quality_confirmed_at timestamptz,
  add column if not exists quality_note text do $$
begin
  if to_regclass('public.payment_schedules') is null then
    return;
  end if;

  if not exists (
    select 1 from pg_constraint
    where conname = 'payment_schedules_milestone_type_check'
      and conrelid = 'public.payment_schedules'::regclass
  ) then
    alter table public.payment_schedules
      add constraint payment_schedules_milestone_type_check
      check (milestone_type in ('advance', 'progress', 'settlement', 'retention', 'other'));
  end if;

  if not exists (
    select 1 from pg_constraint
    where conname = 'payment_schedules_dossier_status_check'
      and conrelid = 'public.payment_schedules'::regclass
  ) then
    alter table public.payment_schedules
      add constraint payment_schedules_dossier_status_check
      check (dossier_status in ('not_started', 'preparing', 'submitted', 'approved'));
  end if;

  if not exists (
    select 1 from pg_constraint
    where conname = 'payment_schedules_quality_status_check'
      and conrelid = 'public.payment_schedules'::regclass
  ) then
    alter table public.payment_schedules
      add constraint payment_schedules_quality_status_check
      check (quality_status in ('not_applicable', 'not_confirmed', 'passed', 'failed'));
  end if;
end $$ create index if not exists idx_payment_schedules_due_status
  on public.payment_schedules(due_date, status) create index if not exists idx_payment_schedules_milestone_type
  on public.payment_schedules(milestone_type) create index if not exists idx_payment_schedules_planned_task_ids
  on public.payment_schedules using gin(planned_task_ids) alter table public.payment_schedules enable row level security drop policy if exists payment_schedules_project_insert on public.payment_schedules drop policy if exists payment_schedules_project_update on public.payment_schedules drop policy if exists payment_schedules_project_delete on public.payment_schedules create policy payment_schedules_project_insert
  on public.payment_schedules
  for insert
  to authenticated
  with check (
    public.is_admin()
    or app_private.project_user_has_permission(project_id::text, construction_site_id::text, 'edit')
    or app_private.project_user_has_permission(project_id::text, construction_site_id::text, 'confirm')
  ) create policy payment_schedules_project_update
  on public.payment_schedules
  for update
  to authenticated
  using (
    public.is_admin()
    or app_private.project_user_has_permission(project_id::text, construction_site_id::text, 'edit')
    or app_private.project_user_has_permission(project_id::text, construction_site_id::text, 'confirm')
  )
  with check (
    public.is_admin()
    or app_private.project_user_has_permission(project_id::text, construction_site_id::text, 'edit')
    or app_private.project_user_has_permission(project_id::text, construction_site_id::text, 'confirm')
  ) create policy payment_schedules_project_delete
  on public.payment_schedules
  for delete
  to authenticated
  using (
    public.is_admin()
    or app_private.project_user_has_permission(project_id::text, construction_site_id::text, 'delete')
  )]

