[-- Feedback Hub RLS fix: make create flow use the authenticated app user.
-- This keeps browser inserts from failing when local UI state carries a stale
-- or auth-user id instead of public.users.id.

create or replace function app_private.prepare_feedback_item_insert()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
begin
  if v_actor is not null then
    new.created_by := v_actor;
  end if;

  new.status := 'new';
  new.priority := 'medium';
  new.assigned_to := null;
  new.rejected_reason := null;
  new.completed_at := null;
  new.closed_by := null;
  new.due_at := null;
  new.target_release := null;
  new.roadmap_stage := null;
  new.tags := '{}'::text[];
  new.device_info := coalesce(new.device_info, '{}'::jsonb);
  new.metadata := coalesce(new.metadata, '{}'::jsonb);

  return new;
end;
$$ revoke all on function app_private.prepare_feedback_item_insert() from public drop trigger if exists trg_feedback_items_prepare_insert on public.feedback_items create trigger trg_feedback_items_prepare_insert
before insert on public.feedback_items
for each row execute function app_private.prepare_feedback_item_insert() drop policy if exists feedback_items_insert on public.feedback_items create policy feedback_items_insert
on public.feedback_items
for insert
to authenticated
with check (
  created_by = (select public.current_app_user_id())
  and status = 'new'
  and priority = 'medium'
  and assigned_to is null
  and rejected_reason is null
  and completed_at is null
  and closed_by is null
  and due_at is null
  and target_release is null
  and roadmap_stage is null
  and coalesce(array_length(tags, 1), 0) = 0
  and visibility in ('public', 'private')
) notify pgrst, 'reload schema']

[-- Feedback Hub create RLS hardening:
-- let the BEFORE INSERT trigger be the single authority for actor/default fields.

create or replace function app_private.prepare_feedback_item_insert()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
begin
  if v_actor is null then
    raise exception 'feedback actor profile not found for current auth session'
      using errcode = '28000';
  end if;

  new.created_by := v_actor;
  new.status := 'new';
  new.priority := 'medium';
  new.assigned_to := null;
  new.rejected_reason := null;
  new.completed_at := null;
  new.closed_by := null;
  new.due_at := null;
  new.target_release := null;
  new.roadmap_stage := null;
  new.tags := '{}'::text[];
  new.device_info := coalesce(new.device_info, '{}'::jsonb);
  new.metadata := coalesce(new.metadata, '{}'::jsonb);

  return new;
end;
$$ revoke all on function app_private.prepare_feedback_item_insert() from public drop policy if exists feedback_items_insert on public.feedback_items create policy feedback_items_insert
on public.feedback_items
for insert
to authenticated
with check (
  (select auth.uid()) is not null
  and created_by is not null
  and status = 'new'
  and priority = 'medium'
  and assigned_to is null
  and rejected_reason is null
  and completed_at is null
  and closed_by is null
  and due_at is null
  and target_release is null
  and roadmap_stage is null
  and coalesce(array_length(tags, 1), 0) = 0
  and visibility in ('public', 'private')
) notify pgrst, 'reload schema']

[-- Allow a daily log submitter to choose themself as verifier when they already
-- have the project "verify" permission. The permission check remains enforced
-- by daily_log_user_has_project_permission().

create or replace function public.transition_daily_log_status(
  p_log_id text,
  p_status text,
  p_requested_verifier_id text default null,
  p_requested_verifier_name text default null,
  p_rejection_reason text default null
)
returns void
language plpgsql
security definer
set search_path = public
as $$
declare
  v_log public.daily_logs%rowtype;
  v_user_id text := public.current_app_user_id()::text;
  v_is_admin boolean := public.is_admin();
  v_actor_name text;
  v_owner_id text;
  v_target_verifier_id text;
  v_can_verify boolean;
begin
  if v_user_id is null then
    raise exception 'Không xác định được người dùng đang thao tác.';
  end if;

  if p_status not in ('submitted', 'verified', 'rejected') then
    raise exception 'Trạng thái nhật ký không hợp lệ: %', p_status;
  end if;

  select *
  into v_log
  from public.daily_logs
  where id = p_log_id
  for update;

  if not found then
    raise exception 'Không tìm thấy nhật ký công trường.';
  end if;

  select coalesce(u.name, u.username, u.email, u.id::text)
  into v_actor_name
  from public.users u
  where u.id::text = v_user_id;

  v_owner_id := coalesce(v_log.created_by_id, v_log.submitted_by_id, v_log.submitted_by);
  v_target_verifier_id := coalesce(v_log.requested_verifier_id, v_log.submitted_to_user_id);

  if p_status = 'submitted' then
    if coalesce(v_log.status, 'draft') not in ('draft', 'rejected') then
      raise exception 'Chỉ nhật ký nháp hoặc bị trả lại mới được gửi xác nhận.';
    end if;

    if not v_is_admin and coalesce(v_owner_id, '') <> v_user_id then
      raise exception 'Chỉ người lập nhật ký mới được gửi xác nhận.';
    end if;

    if nullif(p_requested_verifier_id, '') is null then
      raise exception 'Vui lòng chọn người xác nhận nhật ký.';
    end if;

    if not public.daily_log_user_has_project_permission(
      p_requested_verifier_id,
      v_log.project_id::text,
      v_log.construction_site_id::text,
      'verify'
    ) then
      raise exception 'Người được chọn chưa có quyền verify trong Tổ chức dự án.';
    end if;

    update public.daily_logs
    set
      status = 'submitted',
      verified = false,
      submitted_by = v_user_id,
      submitted_by_id = v_user_id,
      submitted_at = now(),
      requested_verifier_id = p_requested_verifier_id,
      submitted_to_user_id = p_requested_verifier_id,
      requested_verifier_name = nullif(p_requested_verifier_name, ''),
      rejected_by = null,
      rejected_by_id = null,
      rejected_at = null,
      rejection_reason = null
    where id = p_log_id;

    return;
  end if;

  if coalesce(v_log.status, 'draft') <> 'submitted' then
    raise exception 'Chỉ nhật ký đang chờ xác nhận mới được duyệt hoặc trả lại.';
  end if;

  v_can_verify := v_is_admin
    or (
      nullif(v_target_verifier_id, '') is not null
      and v_target_verifier_id = v_user_id
      and public.daily_log_user_has_project_permission(
        v_user_id,
        v_log.project_id::text,
        v_log.construction_site_id::text,
        'verify'
      )
    )
    or (
      nullif(v_target_verifier_id, '') is null
      and public.daily_log_user_has_project_permission(
        v_user_id,
        v_log.project_id::text,
        v_log.construction_site_id::text,
        'verify'
      )
    );

  if not v_can_verify then
    raise exception 'Bạn không phải người được giao xác nhận nhật ký này.';
  end if;

  if p_status = 'verified' then
    update public.daily_logs
    set
      status = 'verified',
      verified = true,
      verified_by = coalesce(v_actor_name, v_user_id),
      verified_by_id = v_user_id,
      verified_at = now(),
      rejected_by = null,
      rejected_by_id = null,
      rejected_at = null,
      rejection_reason = null
    where id = p_log_id;
  else
    update public.daily_logs
    set
      status = 'rejected',
      verified = false,
      rejected_by = coalesce(v_actor_name, v_user_id),
      rejected_by_id = v_user_id,
      rejected_at = now(),
      rejection_reason = coalesce(nullif(p_rejection_reason, ''), 'Cần bổ sung/kiểm tra lại')
    where id = p_log_id;
  end if;
end;
$$ revoke all on function public.transition_daily_log_status(text, text, text, text, text) from public grant execute on function public.transition_daily_log_status(text, text, text, text, text) to authenticated notify pgrst, 'reload schema']

[-- Fix material issue returns failing with material_issue_returns_transaction_id_fkey.
-- The return row has a required FK to transactions(id), so the transaction must
-- exist before material_issue_returns is inserted.

create or replace function public.create_material_issue_return(
  p_order_id uuid,
  p_target_warehouse_id text,
  p_lines jsonb,
  p_reason text,
  p_note text default null
)
returns public.material_issue_returns
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_order public.material_issue_orders%rowtype;
  v_return public.material_issue_returns%rowtype;
  v_return_id uuid := gen_random_uuid();
  v_transaction_id text := 'tx-material-return-' || replace(gen_random_uuid()::text, '-', '');
  v_return_no text;
  v_items jsonb := '[]'::jsonb;
  v_return_lines jsonb := '[]'::jsonb;
  v_line jsonb;
  v_issue_line public.material_issue_lines%rowtype;
  v_qty numeric;
  v_available numeric;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if coalesce(trim(p_reason), '') = '' then raise exception 'Bắt buộc nhập lý do hoàn trả.'; end if;

  select * into v_order from public.material_issue_orders where id = p_order_id for update;
  if not found then raise exception 'Không tìm thấy phiếu xuất cấp.'; end if;

  if v_order.status not in ('issued', 'partially_received', 'received', 'settling', 'partially_returned') then
    raise exception 'Phiếu chưa sẵn sàng hoàn trả.';
  end if;

  if not app_private.material_issue_can_process(v_order.source_warehouse_id, v_order.created_by, v_order.responsible_user_id, v_order.recipient_type, v_order.recipient_id) then
    raise exception 'Bạn không có quyền tạo phiếu hoàn trả.';
  end if;

  v_return_no := 'MRET-' || to_char(now(), 'YYYYMMDD') || '-' || upper(substr(replace(v_return_id::text, '-', ''), 1, 6));

  for v_line in select value from jsonb_array_elements(coalesce(p_lines, '[]'::jsonb))
  loop
    v_qty := coalesce(nullif(v_line ->> 'returnQty', '')::numeric, 0);
    if v_qty <= 0 then raise exception 'Số lượng hoàn trả phải lớn hơn 0.'; end if;

    select * into v_issue_line
    from public.material_issue_lines
    where id = (v_line ->> 'issueLineId')::uuid
      and issue_order_id = p_order_id
    for update;
    if not found then raise exception 'Không tìm thấy dòng phiếu xuất cấp.'; end if;

    v_available := greatest(v_issue_line.issued_qty - v_issue_line.returned_qty - v_issue_line.consumed_qty - v_issue_line.lost_qty, 0);
    if v_qty > v_available then raise exception 'Số lượng hoàn trả vượt số lượng còn quyết toán.'; end if;

    v_items := v_items || jsonb_build_array(jsonb_build_object(
      'itemId', v_issue_line.item_id,
      'quantity', v_qty,
      'price', v_issue_line.unit_price,
      'materialIssueOrderId', p_order_id,
      'materialIssueLineId', v_issue_line.id,
      'materialIssueReturnId', v_return_id,
      'recipientType', v_order.recipient_type,
      'recipientNameSnapshot', v_order.recipient_name
    ));

    v_return_lines := v_return_lines || jsonb_build_array(jsonb_build_object(
      'issueLineId', v_issue_line.id,
      'itemId', v_issue_line.item_id,
      'returnQty', v_qty,
      'unit', v_issue_line.unit,
      'reason', nullif(trim(coalesce(v_line ->> 'reason', '')), '')
    ));
  end loop;

  if jsonb_array_length(v_items) = 0 then raise exception 'Phiếu hoàn trả chưa có dòng vật tư.'; end if;

  insert into public.transactions(
    id, type, date, items, source_warehouse_id, target_warehouse_id,
    requester_id, approver_id, status, note, related_request_id, pending_items
  ) values (
    v_transaction_id, 'IMPORT', now(), v_items, null, p_target_warehouse_id,
    v_actor, null, 'PENDING',
    'Hoàn trả vật tư từ ' || v_order.recipient_name || ' theo phiếu ' || v_order.issue_no,
    v_order.material_request_id, '[]'::jsonb
  );

  insert into public.material_issue_returns(
    id, issue_order_id, return_no, target_warehouse_id, status,
    transaction_id, reason, note, created_by
  ) values (
    v_return_id, p_order_id, v_return_no, p_target_warehouse_id, 'pending',
    v_transaction_id, trim(p_reason), nullif(trim(coalesce(p_note, '')), ''), v_actor
  )
  returning * into v_return;

  for v_line in select value from jsonb_array_elements(v_return_lines)
  loop
    insert into public.material_issue_return_lines(
      issue_return_id, issue_line_id, item_id, return_qty, unit, reason
    ) values (
      v_return_id,
      (v_line ->> 'issueLineId')::uuid,
      v_line ->> 'itemId',
      coalesce(nullif(v_line ->> 'returnQty', '')::numeric, 0),
      nullif(v_line ->> 'unit', ''),
      nullif(v_line ->> 'reason', '')
    );
  end loop;

  if to_regclass('public.project_document_links') is not null then
    insert into public.project_document_links(source_type, source_id, target_type, target_id, project_id, relation_type, status, metadata)
    values ('material_issue_order', v_order.id::text, 'material_issue_return', v_return_id::text, v_order.project_id, 'downstream', 'active', jsonb_build_object('returnNo', v_return_no, 'transactionId', v_transaction_id))
    on conflict (source_type, source_id, target_type, target_id, relation_type)
    do update set status = excluded.status, metadata = excluded.metadata, updated_at = now();

    insert into public.project_document_links(source_type, source_id, target_type, target_id, project_id, relation_type, status, metadata)
    values ('material_issue_order', v_order.id::text, 'transaction', v_transaction_id, v_order.project_id, 'downstream', 'active', jsonb_build_object('kind', 'material_issue_return', 'returnId', v_return_id))
    on conflict (source_type, source_id, target_type, target_id, relation_type)
    do update set status = excluded.status, metadata = excluded.metadata, updated_at = now();
  end if;

  return v_return;
end;
