[-- Soft-archive purchase orders instead of physically deleting returned stock documents.

create schema if not exists app_private alter table if exists public.purchase_orders
  add column if not exists archived_at timestamptz,
  add column if not exists archived_by uuid references public.users(id) on delete set null,
  add column if not exists archive_reason text create index if not exists idx_purchase_orders_active_scope_created
  on public.purchase_orders(project_id, construction_site_id, created_at desc, id desc)
  where archived_at is null create index if not exists idx_purchase_orders_active_stock_created
  on public.purchase_orders(source_mode, created_at desc, id desc)
  where archived_at is null create or replace function app_private.project_po_direct_supplier_return_cleanup_ok(
  p_po_id text,
  p_received_transaction_ids jsonb
)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_receipt_transaction_ids text[] := array[]::text[];
  v_has_received_qty boolean := false;
  v_has_unfinished_receipts boolean := false;
  v_has_active_supplier_returns boolean := false;
  v_has_unfinished_return_transactions boolean := false;
  v_has_insufficient_return_qty boolean := true;
begin
  if to_regclass('public.purchase_order_supplier_returns') is null
    or to_regclass('public.transactions') is null
  then
    return false;
  end if;

  select coalesce(array_agg(distinct tx_id), array[]::text[])
    into v_receipt_transaction_ids
  from (
    select jsonb_array_elements_text(coalesce(p_received_transaction_ids, '[]'::jsonb)) as tx_id
  ) tx
  where nullif(tx_id, '') is not null;

  if coalesce(array_length(v_receipt_transaction_ids, 1), 0) = 0 then
    return false;
  end if;

  select coalesce(bool_or(upper(coalesce(t.status::text, '')) not in ('COMPLETED', 'CANCELLED')), false)
    into v_has_unfinished_receipts
  from public.transactions t
  where t.id::text = any(v_receipt_transaction_ids);

  if v_has_unfinished_receipts then
    return false;
  end if;

  select exists (
    select 1
    from public.transactions t
    cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) elem
    where t.id::text = any(v_receipt_transaction_ids)
      and upper(coalesce(t.status::text, '')) = 'COMPLETED'
      and nullif(elem->>'itemId', '') is not null
      and coalesce(nullif(elem->>'quantity', '')::numeric, 0) > 0
  )
    into v_has_received_qty;

  if not v_has_received_qty then
    return false;
  end if;

  select exists (
    select 1
    from public.purchase_order_supplier_returns r
    where r.purchase_order_id = p_po_id
      and lower(coalesce(r.status, '')) not in ('completed', 'cancelled')
  )
    into v_has_active_supplier_returns;

  if v_has_active_supplier_returns then
    return false;
  end if;

  select exists (
    select 1
    from public.purchase_order_supplier_returns r
    left join public.transactions t on t.id::text = r.transaction_id::text
    where r.purchase_order_id = p_po_id
      and lower(coalesce(r.status, '')) = 'completed'
      and (t.id is null or upper(coalesce(t.status::text, '')) <> 'COMPLETED')
  )
    into v_has_unfinished_return_transactions;

  if v_has_unfinished_return_transactions then
    return false;
  end if;

  select exists (
    with received as (
      select
        elem->>'itemId' as item_id,
        sum(coalesce(nullif(elem->>'quantity', '')::numeric, 0))::numeric as qty
      from public.transactions t
      cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) elem
      where t.id::text = any(v_receipt_transaction_ids)
        and upper(coalesce(t.status::text, '')) = 'COMPLETED'
        and nullif(elem->>'itemId', '') is not null
      group by elem->>'itemId'
    ),
    returned as (
      select
        elem->>'itemId' as item_id,
        sum(coalesce(nullif(elem->>'quantity', '')::numeric, 0))::numeric as qty
      from public.purchase_order_supplier_returns r
      join public.transactions t on t.id::text = r.transaction_id::text
      cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) elem
      where r.purchase_order_id = p_po_id
        and lower(coalesce(r.status, '')) = 'completed'
        and upper(coalesce(t.status::text, '')) = 'COMPLETED'
        and nullif(elem->>'itemId', '') is not null
      group by elem->>'itemId'
    )
    select 1
    from received r
    left join returned ret on ret.item_id = r.item_id
    where coalesce(ret.qty, 0) + 0.000000001 < r.qty
    limit 1
  )
    into v_has_insufficient_return_qty;

  return not v_has_insufficient_return_qty;
end;
$$ create or replace function app_private.project_po_can_archive_v1(
  p_po_id text,
  p_project_id text,
  p_construction_site_id text,
  p_status text,
  p_ever_submitted boolean,
  p_received_transaction_ids jsonb,
  p_items jsonb
)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_status text := lower(coalesce(p_status, 'draft'));
  v_has_permission boolean := false;
  v_received_item_qty numeric := 0;
  v_has_received_batch_qty boolean := false;
  v_no_receipt boolean := false;
  v_stock_cleanup_ok boolean := false;
  v_direct_supplier_return_cleanup_ok boolean := false;
begin
  v_has_permission := public.is_admin()
    or app_private.project_user_has_permission(p_project_id, p_construction_site_id, 'delete');

  if not v_has_permission then
    return false;
  end if;

  select coalesce(sum(coalesce(nullif(elem->>'receivedQty', '')::numeric, 0)), 0)
    into v_received_item_qty
  from jsonb_array_elements(coalesce(p_items, '[]'::jsonb)) as elem;

  if to_regclass('public.material_request_fulfillment_lines') is not null then
    select coalesce(bool_or(coalesce(received_qty, 0) > 0), false)
      into v_has_received_batch_qty
    from public.material_request_fulfillment_lines
    where po_id = p_po_id;
  end if;

  v_no_receipt := v_received_item_qty <= 0
    and jsonb_array_length(coalesce(p_received_transaction_ids, '[]'::jsonb)) = 0
    and not v_has_received_batch_qty;

  if v_status in ('returned', 'cancelled', 'partial', 'delivered', 'closed') then
    v_stock_cleanup_ok := app_private.project_po_stock_cleanup_ok(p_po_id, p_received_transaction_ids);
    v_direct_supplier_return_cleanup_ok := app_private.project_po_direct_supplier_return_cleanup_ok(p_po_id, p_received_transaction_ids);
  end if;

  return
    (v_status = 'draft' and not coalesce(p_ever_submitted, false) and v_no_receipt)
    or (
      v_status in ('returned', 'cancelled')
      and (v_no_receipt or v_stock_cleanup_ok or v_direct_supplier_return_cleanup_ok)
    )
    or (
      v_status in ('partial', 'delivered', 'closed')
      and (v_stock_cleanup_ok or v_direct_supplier_return_cleanup_ok)
    );
end;
$$ create or replace function app_private.enforce_purchase_order_archive_update()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_old_payload jsonb;
  v_new_payload jsonb;
begin
  if old.archived_at is not null then
    raise exception 'PO đã lưu trữ không thể chỉnh sửa.';
  end if;

  if new.archived_at is null then
    return new;
  end if;

  if not app_private.project_po_can_archive_v1(
    old.id::text,
    old.project_id::text,
    old.construction_site_id::text,
    old.status::text,
    old.ever_submitted,
    old.received_transaction_ids,
    old.items
  ) then
    raise exception 'Chỉ lưu trữ PO nháp chưa gửi duyệt, hoặc PO đã hoàn trả đủ/không còn giao dịch kho dang dở.';
  end if;

  new.archived_at := coalesce(new.archived_at, now());
  new.archived_by := coalesce(new.archived_by, public.current_app_user_id());
  new.archive_reason := nullif(trim(coalesce(new.archive_reason, '')), '');

  v_old_payload := to_jsonb(old) - 'archived_at' - 'archived_by' - 'archive_reason';
  v_new_payload := to_jsonb(new) - 'archived_at' - 'archived_by' - 'archive_reason';

  if v_old_payload <> v_new_payload then
    raise exception 'Thao tác lưu trữ PO chỉ được cập nhật các trường lưu trữ.';
  end if;

  return new;
end;
$$ drop trigger if exists trg_enforce_purchase_order_archive_update on public.purchase_orders create trigger trg_enforce_purchase_order_archive_update
before update on public.purchase_orders
for each row execute function app_private.enforce_purchase_order_archive_update() create or replace function app_private.sync_purchase_order_archive_dependencies()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if old.archived_at is null
    and new.archived_at is not null
    and to_regclass('public.project_document_links') is not null
  then
    update public.project_document_links
    set status = case when status = 'active' then 'archived' else status end,
        metadata = coalesce(metadata, '{}'::jsonb)
          || jsonb_build_object(
            'purchaseOrderArchivedAt', new.archived_at,
            'purchaseOrderArchiveReason', new.archive_reason
          ),
        updated_at = now()
    where (source_type = 'purchase_order' and source_id = new.id)
       or (target_type = 'purchase_order' and target_id = new.id);
  end if;

  return new;
end;
$$ drop trigger if exists trg_sync_purchase_order_archive_dependencies on public.purchase_orders create trigger trg_sync_purchase_order_archive_dependencies
after update of archived_at on public.purchase_orders
for each row execute function app_private.sync_purchase_order_archive_dependencies() drop policy if exists purchase_orders_select on public.purchase_orders create policy purchase_orders_select
  on public.purchase_orders
  for select
  to authenticated
  using (
    archived_at is null
    and (
      app_private.project_doc_can_view(project_id, construction_site_id, submitted_to_user_id)
      or app_private.current_user_is_global_wms_keeper()
      or app_private.current_user_is_wms_keeper_for(target_warehouse_id)
    )
  ) drop policy if exists purchase_orders_update on public.purchase_orders create policy purchase_orders_update
  on public.purchase_orders
  for update
  to authenticated
  using (
    archived_at is null
    and (
      app_private.project_po_can_update(project_id, construction_site_id, status, submitted_to_user_id)
      or (
        status in ('in_transit', 'partial')
        and (
          app_private.current_user_is_global_wms_keeper()
          or app_private.current_user_is_wms_keeper_for(target_warehouse_id)
        )
      )
    )
  )
  with check (
    archived_at is null
    and (
      project_id is not null
      or construction_site_id is not null
      or public.is_admin()
    )
    and (
      app_private.project_po_can_update(project_id, construction_site_id, status, submitted_to_user_id)
      or app_private.current_user_is_global_wms_keeper()
      or app_private.current_user_is_wms_keeper_for(target_warehouse_id)
    )
  ) drop policy if exists purchase_orders_archive_update on public.purchase_orders create policy purchase_orders_archive_update
  on public.purchase_orders
  for update
  to authenticated
  using (
    archived_at is null
  )
  with check (
    archived_at is not null
  ) drop policy if exists purchase_orders_delete on public.purchase_orders create policy purchase_orders_delete
  on public.purchase_orders
  for delete
  to authenticated
  using (false) revoke all on function app_private.project_po_direct_supplier_return_cleanup_ok(text, jsonb) from public, anon, authenticated revoke all on function app_private.project_po_can_archive_v1(text, text, text, text, boolean, jsonb, jsonb) from public, anon, authenticated revoke all on function app_private.enforce_purchase_order_archive_update() from public, anon, authenticated revoke all on function app_private.sync_purchase_order_archive_dependencies() from public, anon, authenticated grant execute on function app_private.project_po_can_archive_v1(text, text, text, text, boolean, jsonb, jsonb) to authenticated notify pgrst, 'reload schema']

[-- Purchase order removal workflow v2.
-- PO rows without any stock movement can be physically deleted. PO rows that
-- already touched stock stay as auditable records and can only be archived.

create schema if not exists app_private create or replace function app_private.project_po_status_marks_submitted(p_status text)
returns boolean
language sql
immutable
set search_path = ''
as $$
  select lower(coalesce(p_status, 'draft')) in (
    'sent',
    'confirmed',
    'in_transit',
    'partial',
    'delivered',
    'closed',
    'returned'
  );
$$ create or replace function app_private.project_doc_touch()
returns trigger
language plpgsql
set search_path = ''
as $$
declare
  v_marks_submitted boolean := false;
begin
  if tg_table_name = 'purchase_orders' then
    v_marks_submitted := app_private.project_po_status_marks_submitted(new.status::text);

    if tg_op = 'UPDATE'
       and old.archived_at is null
       and new.archived_at is not null
       and old.status is not distinct from new.status
       and old.submitted_to_user_id is not distinct from new.submitted_to_user_id
    then
      return new;
    end if;
  else
    v_marks_submitted := coalesce(new.status::text, 'draft') <> 'draft';
  end if;

  if tg_op = 'INSERT' then
    new.ever_submitted := coalesce(new.ever_submitted, false) or v_marks_submitted;
    new.last_action_by := coalesce(new.last_action_by, public.current_app_user_id()::text);
    new.last_action_at := coalesce(new.last_action_at, now());
    return new;
  end if;

  if old.status is distinct from new.status
     or old.submitted_to_user_id is distinct from new.submitted_to_user_id then
    new.last_action_by := coalesce(new.last_action_by, public.current_app_user_id()::text);
    new.last_action_at := coalesce(new.last_action_at, now());
  end if;

  new.ever_submitted := coalesce(old.ever_submitted, false)
    or coalesce(new.ever_submitted, false)
    or v_marks_submitted;

  return new;
end;
$$ create or replace function app_private.project_po_has_stock_impact_v1(
  p_po_id text,
  p_received_transaction_ids jsonb,
  p_items jsonb
)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_received_transaction_ids text[] := array[]::text[];
  v_has_stock_impact boolean := false;
begin
  select coalesce(array_agg(distinct tx_id), array[]::text[])
    into v_received_transaction_ids
  from (
    select jsonb_array_elements_text(
      case
        when jsonb_typeof(coalesce(p_received_transaction_ids, '[]'::jsonb)) = 'array'
          then coalesce(p_received_transaction_ids, '[]'::jsonb)
        else '[]'::jsonb
      end
    ) as tx_id
  ) tx
  where nullif(tx_id, '') is not null;

  select exists (
    select 1
    from jsonb_array_elements(
      case
        when jsonb_typeof(coalesce(p_items, '[]'::jsonb)) = 'array'
          then coalesce(p_items, '[]'::jsonb)
        else '[]'::jsonb
      end
    ) item(value)
    where coalesce(nullif(item.value->>'receivedQty', '')::numeric, 0) > 0
  )
    into v_has_stock_impact;

  if v_has_stock_impact then
    return true;
  end if;

  if to_regclass('public.material_request_fulfillment_lines') is not null then
    select exists (
      select 1
      from public.material_request_fulfillment_lines line
      where line.po_id = p_po_id
        and coalesce(line.received_qty, 0) > 0
    )
      into v_has_stock_impact;

    if v_has_stock_impact then
      return true;
    end if;
  end if;

  if coalesce(array_length(v_received_transaction_ids, 1), 0) > 0 then
    select exists (
      select 1
      from public.transactions t
      where t.id::text = any(v_received_transaction_ids)
        and upper(coalesce(t.status::text, '')) = 'COMPLETED'
        and exists (
          select 1
          from jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) tx_item(value)
          where coalesce(nullif(tx_item.value->>'quantity', '')::numeric, 0) <> 0
        )
    )
      into v_has_stock_impact;

    if v_has_stock_impact then
      return true;
    end if;

    if to_regclass('public.inventory_ledger_entries') is not null then
      select exists (
        select 1
        from public.inventory_ledger_entries entry
        where entry.source_type = 'wms_transaction'
          and entry.source_id = any(v_received_transaction_ids)
      )
      into v_has_stock_impact;

      if v_has_stock_impact then
        return true;
      end if;
    end if;
  end if;

  if to_regclass('public.material_request_fulfillment_batches') is not null
     and to_regclass('public.material_request_fulfillment_lines') is not null then
    select exists (
      select 1
      from public.material_request_fulfillment_lines line
      join public.material_request_fulfillment_batches batch
        on batch.id = line.batch_id
      left join public.transactions t
        on t.id::text = batch.transaction_id::text
      where line.po_id = p_po_id
        and batch.transaction_id is not null
        and (
          upper(coalesce(t.status::text, '')) = 'COMPLETED'
          or (
            to_regclass('public.inventory_ledger_entries') is not null
            and exists (
              select 1
              from public.inventory_ledger_entries entry
              where entry.source_type = 'wms_transaction'
                and entry.source_id = batch.transaction_id::text
            )
          )
        )
    )
      into v_has_stock_impact;

    if v_has_stock_impact then
      return true;
    end if;
  end if;

  if to_regclass('public.purchase_order_supplier_returns') is not null then
    select exists (
      select 1
      from public.purchase_order_supplier_returns r
      left join public.transactions t
        on t.id::text = r.transaction_id::text
      where r.purchase_order_id = p_po_id
        and (
          lower(coalesce(r.status, '')) = 'completed'
          or upper(coalesce(t.status::text, '')) = 'COMPLETED'
          or (
            to_regclass('public.inventory_ledger_entries') is not null
            and exists (
              select 1
              from public.inventory_ledger_entries entry
              where entry.source_type = 'wms_transaction'
                and entry.source_id = r.transaction_id::text
            )
          )
        )
    )
      into v_has_stock_impact;

    if v_has_stock_impact then
      return true;
    end if;
  end if;

  return false;
end;
$$ create or replace function public.remove_purchase_order_v1(p_po_id text)
returns table(action text, id text, po_number text)
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_po public.purchase_orders%rowtype;
  v_has_permission boolean := false;
  v_has_stock_impact boolean := false;
  v_received_transaction_ids text[] := array[]::text[];
  v_fulfillment_transaction_ids text[] := array[]::text[];
  v_supplier_return_transaction_ids text[] := array[]::text[];
  v_supplier_return_ids uuid[] := array[]::uuid[];
  v_supplier_return_text_ids text[] := array[]::text[];
  v_cleanup_transaction_ids text[] := array[]::text[];
begin
  select *
    into v_po
  from public.purchase_orders
  where public.purchase_orders.id = p_po_id
  for update;

  if not found then
    raise exception 'Không tìm thấy PO cần xoá/lưu trữ.';
  end if;

  if v_po.archived_at is not null then
    raise exception 'PO đã được lưu trữ.';
  end if;

  v_has_permission := public.is_admin()
    or app_private.project_user_has_permission(
      v_po.project_id::text,
      v_po.construction_site_id::text,
      'delete'
    );

  if not v_has_permission then
    raise exception 'Bạn cần quyền xoá dữ liệu để xoá/lưu trữ PO này.'
      using errcode = '42501';
  end if;

  v_has_stock_impact := app_private.project_po_has_stock_impact_v1(
    v_po.id::text,
    v_po.received_transaction_ids,
    v_po.items
  );

  if not v_has_stock_impact then
    select coalesce(array_agg(distinct tx_id), array[]::text[])
      into v_received_transaction_ids
    from (
      select jsonb_array_elements_text(
        case
          when jsonb_typeof(coalesce(v_po.received_transaction_ids, '[]'::jsonb)) = 'array'
            then coalesce(v_po.received_transaction_ids, '[]'::jsonb)
          else '[]'::jsonb
        end
      ) as tx_id
    ) tx
    where nullif(tx_id, '') is not null;

    if to_regclass('public.material_request_fulfillment_batches') is not null
       and to_regclass('public.material_request_fulfillment_lines') is not null then
      select coalesce(array_agg(distinct batch.transaction_id::text), array[]::text[])
        into v_fulfillment_transaction_ids
      from public.material_request_fulfillment_lines line
      join public.material_request_fulfillment_batches batch
        on batch.id = line.batch_id
      where line.po_id = v_po.id::text
        and batch.transaction_id is not null;
    end if;

    if to_regclass('public.purchase_order_supplier_returns') is not null then
      select coalesce(array_agg(distinct r.id), array[]::uuid[]),
             coalesce(array_agg(distinct r.transaction_id::text) filter (where r.transaction_id is not null), array[]::text[])
        into v_supplier_return_ids, v_supplier_return_transaction_ids
      from public.purchase_order_supplier_returns r
      where r.purchase_order_id = v_po.id::text;

      select coalesce(array_agg(ids.return_id::text), array[]::text[])
        into v_supplier_return_text_ids
      from unnest(v_supplier_return_ids) as ids(return_id);
    end if;

    select coalesce(array_agg(distinct tx_id), array[]::text[])
      into v_cleanup_transaction_ids
    from (
      select unnest(v_received_transaction_ids) as tx_id
      union
      select unnest(v_fulfillment_transaction_ids) as tx_id
      union
      select unnest(v_supplier_return_transaction_ids) as tx_id
    ) tx
    where nullif(tx_id, '') is not null;

    if to_regclass('public.project_document_links') is not null then
      delete from public.project_document_links link
      where (link.source_type = 'purchase_order' and link.source_id = v_po.id::text)
         or (link.target_type = 'purchase_order' and link.target_id = v_po.id::text)
         or (
           link.source_type = 'transaction'
           and link.source_id = any(v_cleanup_transaction_ids)
         )
         or (
           link.target_type = 'transaction'
           and link.target_id = any(v_cleanup_transaction_ids)
         )
         or (
           link.source_type = 'supplier_return'
           and link.source_id = any(v_supplier_return_text_ids)
         )
         or (
           link.target_type = 'supplier_return'
           and link.target_id = any(v_supplier_return_text_ids)
         );
    end if;

    if to_regclass('public.purchase_order_supplier_return_lines') is not null
       and coalesce(array_length(v_supplier_return_ids, 1), 0) > 0 then
      delete from public.purchase_order_supplier_return_lines line
      where line.supplier_return_id = any(v_supplier_return_ids);
    end if;

    if to_regclass('public.purchase_order_supplier_returns') is not null then
      delete from public.purchase_order_supplier_returns r
      where r.purchase_order_id = v_po.id::text;
    end if;

    if to_regclass('public.material_request_fulfillment_batches') is not null
       and to_regclass('public.material_request_fulfillment_lines') is not null then
      delete from public.material_request_fulfillment_batches batch
      where exists (
        select 1
        from public.material_request_fulfillment_lines line
        where line.batch_id = batch.id
          and line.po_id = v_po.id::text
      );
    end if;

    if coalesce(array_length(v_cleanup_transaction_ids, 1), 0) > 0 then
      delete from public.transactions t
      where t.id::text = any(v_cleanup_transaction_ids)
        and upper(coalesce(t.status::text, '')) <> 'COMPLETED'
        and not exists (
          select 1
          from public.inventory_ledger_entries entry
          where entry.source_type = 'wms_transaction'
            and entry.source_id = t.id::text
        )
        and (
          to_regclass('public.material_request_fulfillment_batches') is null
          or not exists (
            select 1
            from public.material_request_fulfillment_batches batch
            where batch.transaction_id::text = t.id::text
          )
        )
        and (
          to_regclass('public.purchase_order_supplier_returns') is null
          or not exists (
            select 1
            from public.purchase_order_supplier_returns r
            where r.transaction_id::text = t.id::text
          )
        );
    end if;

    delete from public.purchase_orders
    where public.purchase_orders.id = v_po.id;

    if to_regclass('public.project_document_links') is not null then
      delete from public.project_document_links link
      where (link.source_type = 'purchase_order' and link.source_id = v_po.id::text)
         or (link.target_type = 'purchase_order' and link.target_id = v_po.id::text);
    end if;

    action := 'deleted';
    id := v_po.id::text;
    po_number := v_po.po_number::text;
    return next;
    return;
  end if;

  if not app_private.project_po_can_archive_v1(
    v_po.id::text,
    v_po.project_id::text,
    v_po.construction_site_id::text,
    v_po.status::text,
    v_po.ever_submitted,
    v_po.received_transaction_ids,
    v_po.items
  ) then
    raise exception 'PO đã phát sinh kho và chưa đủ điều kiện lưu trữ. Vui lòng hoàn trả/đối soát đủ trước.';
  end if;

  update public.purchase_orders
  set archived_at = now(),
      archived_by = public.current_app_user_id(),
      archive_reason = 'Người dùng lưu trữ PO từ tab Cung ứng'
  where public.purchase_orders.id = v_po.id;

  action := 'archived';
  id := v_po.id::text;
  po_number := v_po.po_number::text;
  return next;
end;
$$ revoke all on function app_private.project_po_status_marks_submitted(text) from public, anon, authenticated revoke all on function app_private.project_po_has_stock_impact_v1(text, jsonb, jsonb) from public, anon, authenticated revoke all on function public.remove_purchase_order_v1(text) from public, anon grant execute on function public.remove_purchase_order_v1(text) to authenticated notify pgrst, 'reload schema']

[-- Fix PO creation after the removal workflow changed project_doc_touch to call
-- a private helper, and make PO numbers non-reusable within each project/site.

create schema if not exists app_private create or replace function app_private.project_doc_touch()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_marks_submitted boolean := false;
begin
  if tg_table_name = 'purchase_orders' then
    v_marks_submitted := app_private.project_po_status_marks_submitted(new.status::text);

    if tg_op = 'UPDATE'
       and old.archived_at is null
       and new.archived_at is not null
       and old.status is not distinct from new.status
       and old.submitted_to_user_id is not distinct from new.submitted_to_user_id
    then
      return new;
    end if;
  else
    v_marks_submitted := coalesce(new.status::text, 'draft') <> 'draft';
  end if;

  if tg_op = 'INSERT' then
    new.ever_submitted := coalesce(new.ever_submitted, false) or v_marks_submitted;
    new.last_action_by := coalesce(new.last_action_by, public.current_app_user_id()::text);
    new.last_action_at := coalesce(new.last_action_at, now());
    return new;
  end if;

  if old.status is distinct from new.status
     or old.submitted_to_user_id is distinct from new.submitted_to_user_id then
    new.last_action_by := coalesce(new.last_action_by, public.current_app_user_id()::text);
    new.last_action_at := coalesce(new.last_action_at, now());
  end if;

  new.ever_submitted := coalesce(old.ever_submitted, false)
    or coalesce(new.ever_submitted, false)
    or v_marks_submitted;

  return new;
end;
$$ revoke all on function app_private.project_doc_touch() from public, anon, authenticated create unique index if not exists idx_purchase_orders_scope_po_number_unique
on public.purchase_orders (
  coalesce(project_id, ''),
  coalesce(construction_site_id, ''),
  po_number
) create or replace function public.next_purchase_order_number_v1(
  p_project_id text default null,
  p_construction_site_id text default null,
  p_prefix text default 'PO'
)
returns text
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_prefix text := upper(nullif(regexp_replace(trim(coalesce(p_prefix, 'PO')), '[^A-Za-z0-9]+', '-', 'g'), ''));
  v_next integer := 1;
begin
  v_prefix := coalesce(v_prefix, 'PO');

  select coalesce(max((regexp_match(po.po_number, '^' || v_prefix || '-([0-9]+)(?:$|-)'))[1]::integer), 0) + 1
    into v_next
  from public.purchase_orders po
  where coalesce(po.project_id, '') = coalesce(p_project_id, '')
    and coalesce(po.construction_site_id, '') = coalesce(p_construction_site_id, '')
    and po.po_number ~ ('^' || v_prefix || '-[0-9]+($|-)');

  return v_prefix || '-' || lpad(v_next::text, 3, '0');
end;
$$ revoke all on function public.next_purchase_order_number_v1(text, text, text) from public, anon grant execute on function public.next_purchase_order_number_v1(text, text, text) to authenticated notify pgrst, 'reload schema']

[-- PO delivery schedule v1 + supplier return net quantities.
-- One PO can have many planned delivery batches. Each batch may create its own
-- WMS receipt transaction while the original PO receipt history remains gross.

create schema if not exists app_private create table if not exists public.purchase_order_delivery_batches (
  id uuid primary key default gen_random_uuid(),
  purchase_order_id text not null references public.purchase_orders(id) on delete cascade,
  project_id text references public.projects(id) on delete set null,
  construction_site_id text,
  delivery_no integer not null default 1 check (delivery_no > 0),
  planned_delivery_date date,
  status text not null default 'planned'
    check (status in ('planned', 'wms_pending', 'received', 'cancelled')),
  fulfillment_batch_ids text[] not null default '{}',
  note text,
  created_by uuid references public.users(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique(purchase_order_id, delivery_no)
) create table if not exists public.purchase_order_delivery_lines (
  id uuid primary key default gen_random_uuid(),
  delivery_batch_id uuid not null references public.purchase_order_delivery_batches(id) on delete cascade,
  purchase_order_id text not null references public.purchase_orders(id) on delete cascade,
  purchase_order_line_id text not null,
  item_id text not null references public.items(id) on delete restrict,
  planned_qty numeric not null check (planned_qty > 0),
  unit text,
  stock_planned_qty numeric not null default 0 check (stock_planned_qty >= 0),
  stock_unit text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique(delivery_batch_id, purchase_order_line_id)
) alter table if exists public.material_request_fulfillment_batches
  add column if not exists po_delivery_batch_id uuid references public.purchase_order_delivery_batches(id) on delete set null alter table if exists public.material_request_fulfillment_lines
  add column if not exists po_delivery_line_id uuid references public.purchase_order_delivery_lines(id) on delete set null alter table if exists public.purchase_order_supplier_return_lines
  add column if not exists stock_return_qty numeric not null default 0 check (stock_return_qty >= 0),
  add column if not exists stock_unit text create index if not exists idx_po_delivery_batches_po_no
  on public.purchase_order_delivery_batches(purchase_order_id, delivery_no) create index if not exists idx_po_delivery_batches_project_date
  on public.purchase_order_delivery_batches(project_id, planned_delivery_date, delivery_no)
  where project_id is not null create index if not exists idx_po_delivery_batches_site_date
  on public.purchase_order_delivery_batches(construction_site_id, planned_delivery_date, delivery_no)
  where construction_site_id is not null create index if not exists idx_po_delivery_lines_batch
  on public.purchase_order_delivery_lines(delivery_batch_id) create index if not exists idx_po_delivery_lines_po_line
  on public.purchase_order_delivery_lines(purchase_order_id, purchase_order_line_id) create index if not exists idx_mrf_batches_po_delivery_batch
  on public.material_request_fulfillment_batches(po_delivery_batch_id)
  where po_delivery_batch_id is not null create index if not exists idx_mrf_lines_po_delivery_line
  on public.material_request_fulfillment_lines(po_delivery_line_id)
  where po_delivery_line_id is not null create or replace function app_private.set_po_delivery_batch_updated_at()
returns trigger
language plpgsql
set search_path = ''
as $$
begin
  new.updated_at := now();
  return new;
end;
$$ create or replace function app_private.set_po_delivery_line_updated_at()
returns trigger
language plpgsql
set search_path = ''
as $$
begin
  new.updated_at := now();
  return new;
end;
$$ drop trigger if exists trg_po_delivery_batches_updated_at on public.purchase_order_delivery_batches create trigger trg_po_delivery_batches_updated_at
before update on public.purchase_order_delivery_batches
for each row execute function app_private.set_po_delivery_batch_updated_at() drop trigger if exists trg_po_delivery_lines_updated_at on public.purchase_order_delivery_lines create trigger trg_po_delivery_lines_updated_at
before update on public.purchase_order_delivery_lines
for each row execute function app_private.set_po_delivery_line_updated_at() create or replace function app_private.purchase_order_delivery_can_view(p_purchase_order_id text)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select
    public.is_admin()
    or public.is_module_admin('WMS')
    or app_private.current_user_is_global_wms_keeper()
    or exists (
      select 1
      from public.purchase_orders po
      where po.id = p_purchase_order_id
        and (
          app_private.current_user_is_wms_keeper_for(po.target_warehouse_id)
          or app_private.project_doc_can_view(
            po.project_id::text,
            po.construction_site_id::text,
            po.submitted_to_user_id
          )
        )
    );
$$ create or replace function app_private.purchase_order_delivery_can_mutate(p_purchase_order_id text)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select
    public.is_admin()
    or public.is_module_admin('WMS')
    or app_private.current_user_is_global_wms_keeper()
    or exists (
      select 1
      from public.purchase_orders po
      where po.id = p_purchase_order_id
        and (
          app_private.current_user_is_wms_keeper_for(po.target_warehouse_id)
          or app_private.project_doc_can_view(
            po.project_id::text,
            po.construction_site_id::text,
            po.submitted_to_user_id
          )
        )
    );
$$ alter table public.purchase_order_delivery_batches enable row level security alter table public.purchase_order_delivery_lines enable row level security drop policy if exists po_delivery_batches_select on public.purchase_order_delivery_batches create policy po_delivery_batches_select
on public.purchase_order_delivery_batches
for select to authenticated
using (app_private.purchase_order_delivery_can_view(purchase_order_id)) drop policy if exists po_delivery_batches_insert on public.purchase_order_delivery_batches create policy po_delivery_batches_insert
on public.purchase_order_delivery_batches
for insert to authenticated
with check (app_private.purchase_order_delivery_can_mutate(purchase_order_id)) drop policy if exists po_delivery_batches_update on public.purchase_order_delivery_batches create policy po_delivery_batches_update
on public.purchase_order_delivery_batches
for update to authenticated
using (app_private.purchase_order_delivery_can_mutate(purchase_order_id))
with check (app_private.purchase_order_delivery_can_mutate(purchase_order_id)) drop policy if exists po_delivery_batches_delete on public.purchase_order_delivery_batches create policy po_delivery_batches_delete
on public.purchase_order_delivery_batches
for delete to authenticated
using (app_private.purchase_order_delivery_can_mutate(purchase_order_id)) drop policy if exists po_delivery_lines_select on public.purchase_order_delivery_lines create policy po_delivery_lines_select
on public.purchase_order_delivery_lines
for select to authenticated
using (app_private.purchase_order_delivery_can_view(purchase_order_id)) drop policy if exists po_delivery_lines_insert on public.purchase_order_delivery_lines create policy po_delivery_lines_insert
on public.purchase_order_delivery_lines
for insert to authenticated
with check (app_private.purchase_order_delivery_can_mutate(purchase_order_id)) drop policy if exists po_delivery_lines_update on public.purchase_order_delivery_lines create policy po_delivery_lines_update
on public.purchase_order_delivery_lines
for update to authenticated
using (app_private.purchase_order_delivery_can_mutate(purchase_order_id))
with check (app_private.purchase_order_delivery_can_mutate(purchase_order_id)) drop policy if exists po_delivery_lines_delete on public.purchase_order_delivery_lines create policy po_delivery_lines_delete
on public.purchase_order_delivery_lines
for delete to authenticated
using (app_private.purchase_order_delivery_can_mutate(purchase_order_id)) revoke all on table public.purchase_order_delivery_batches from anon revoke all on table public.purchase_order_delivery_batches from public revoke all on table public.purchase_order_delivery_batches from authenticated grant select, insert, update, delete on table public.purchase_order_delivery_batches to authenticated revoke all on table public.purchase_order_delivery_lines from anon revoke all on table public.purchase_order_delivery_lines from public revoke all on table public.purchase_order_delivery_lines from authenticated grant select, insert, update, delete on table public.purchase_order_delivery_lines to authenticated create or replace function public.create_purchase_order_supplier_return(
  p_purchase_order_id text,
  p_source_warehouse_id text,
  p_lines jsonb,
  p_reason text,
  p_note text default null
)
returns public.purchase_order_supplier_returns
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_po public.purchase_orders%rowtype;
  v_return public.purchase_order_supplier_returns%rowtype;
  v_return_id uuid := gen_random_uuid();
  v_transaction_id text := 'tx-supplier-return-' || replace(gen_random_uuid()::text, '-', '');
  v_return_no text;
  v_line jsonb;
  v_po_item jsonb;
  v_po_line_id text;
  v_item_id text;
  v_qty numeric;
  v_stock_qty numeric;
  v_received_qty numeric;
  v_returned_qty numeric;
  v_on_hand numeric;
  v_reserved numeric;
  v_purchase_unit text;
  v_stock_unit text;
  v_conversion_factor numeric;
  v_purchase_unit_price numeric;
  v_stock_unit_price numeric;
  v_is_converted boolean;
  v_transaction_items jsonb := '[]'::jsonb;
  v_return_line_rows jsonb := '[]'::jsonb;
  v_item_total record;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if not (
    public.is_admin()
    or public.is_module_admin('WMS')
    or app_private.current_user_is_global_wms_keeper()
  ) then
    raise exception 'Chỉ Admin, quản trị WMS hoặc thủ kho tổng được tạo phiếu trả hàng NCC.';
  end if;
  if coalesce(trim(p_reason), '') = '' then
    raise exception 'Bắt buộc nhập lý do trả hàng NCC.';
  end if;
  if coalesce(p_source_warehouse_id, '') = '' then
    raise exception 'Chưa chọn kho xuất trả NCC.';
  end if;
  if jsonb_typeof(p_lines) <> 'array' or jsonb_array_length(p_lines) = 0 then
    raise exception 'Phiếu trả NCC chưa có dòng vật tư.';
  end if;

  select * into v_po
  from public.purchase_orders
  where id = p_purchase_order_id
  for update;
  if not found then raise exception 'Không tìm thấy PO cần trả hàng.'; end if;
  if lower(coalesce(v_po.status::text, '')) not in ('partial', 'delivered', 'closed') then
    raise exception 'Chỉ trả NCC cho PO đã phát sinh nhận hàng và đang ở trạng thái giao một phần, hoàn thành hoặc đã đóng.';
  end if;
  if not exists (select 1 from public.warehouses w where w.id = p_source_warehouse_id) then
    raise exception 'Kho xuất trả NCC không tồn tại.';
  end if;

  v_return_no := 'SR-' || regexp_replace(coalesce(v_po.po_number, 'PO'), '[^A-Za-z0-9]+', '-', 'g')
    || '-' || upper(substr(replace(v_return_id::text, '-', ''), 1, 6));

  for v_line in
    select value from jsonb_array_elements(p_lines)
  loop
    v_po_line_id := coalesce(v_line ->> 'purchaseOrderLineId', v_line ->> 'poLineId', v_line ->> 'lineId');
    v_qty := coalesce(nullif(v_line ->> 'quantity', '')::numeric, 0);
    if coalesce(v_po_line_id, '') = '' or v_qty <= 0 then
      raise exception 'Dòng trả NCC không hợp lệ.';
    end if;

    select item.value into v_po_item
    from jsonb_array_elements(coalesce(v_po.items, '[]'::jsonb)) item(value)
    where coalesce(item.value ->> 'lineId', item.value ->> 'itemId') = v_po_line_id
    limit 1;
    if v_po_item is null then raise exception 'Dòng PO không tồn tại: %', v_po_line_id; end if;

    v_item_id := v_po_item ->> 'itemId';
    v_received_qty := coalesce(nullif(v_po_item ->> 'receivedQty', '')::numeric, 0);
    v_purchase_unit_price := coalesce(nullif(v_po_item ->> 'unitPrice', '')::numeric, 0);

    select coalesce(sum(line.return_qty), 0)
    into v_returned_qty
    from public.purchase_order_supplier_return_lines line
    join public.purchase_order_supplier_returns r on r.id = line.supplier_return_id
    where r.purchase_order_id = p_purchase_order_id
      and line.purchase_order_line_id = v_po_line_id
      and r.status in ('pending', 'completed');

    if v_qty > greatest(0, v_received_qty - v_returned_qty) then
      raise exception 'Số lượng trả của dòng % vượt khối lượng đã nhận còn có thể trả. Đã nhận %, đã/đang trả %, yêu cầu trả %.',
        v_po_line_id, v_received_qty, v_returned_qty, v_qty;
    end if;

    select
      coalesce((coalesce(i.stock_by_warehouse, '{}'::jsonb) ->> p_source_warehouse_id)::numeric, 0),
      coalesce(nullif(v_po_item ->> 'stockUnitSnapshot', ''), nullif(v_po_item ->> 'unitSnapshot', ''), i.unit, nullif(v_po_item ->> 'unit', '')),
      coalesce(nullif(v_po_item ->> 'purchaseUnitSnapshot', ''), nullif(v_po_item ->> 'unit', ''), i.purchase_unit, i.unit),
      coalesce(nullif(v_po_item ->> 'purchaseConversionFactor', '')::numeric, i.purchase_conversion_factor, 1)
    into v_on_hand, v_stock_unit, v_purchase_unit, v_conversion_factor
    from public.items i
    where i.id = v_item_id;
    if not found then raise exception 'Không tìm thấy vật tư: %', v_item_id; end if;

    v_conversion_factor := case when coalesce(v_conversion_factor, 0) > 0 then v_conversion_factor else 1 end;
    v_is_converted := coalesce(trim(v_stock_unit), '') <> ''
      and coalesce(trim(v_purchase_unit), '') <> ''
      and lower(trim(v_stock_unit)) <> lower(trim(v_purchase_unit));
    v_stock_qty := case when v_is_converted then v_qty * v_conversion_factor else v_qty end;
    v_stock_unit_price := case when v_is_converted then v_purchase_unit_price / v_conversion_factor else v_purchase_unit_price end;

    select coalesce(sum(coalesce(nullif(item.value ->> 'quantity', '')::numeric, 0)), 0)
    into v_reserved
    from public.transactions t
    cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) item(value)
    where t.source_warehouse_id = p_source_warehouse_id
      and t.status in ('PENDING'::public.transaction_status, 'APPROVED'::public.transaction_status)
      and t.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
      and item.value ->> 'itemId' = v_item_id;

    if v_stock_qty > greatest(0, v_on_hand - v_reserved) then
      raise exception 'Kho xuất trả không đủ tồn khả dụng cho vật tư %. Tồn %, đang giữ %, khả dụng %, cần trả %.',
        coalesce(v_po_item ->> 'name', v_item_id), v_on_hand, v_reserved, greatest(0, v_on_hand - v_reserved), v_stock_qty;
    end if;

    v_transaction_items := v_transaction_items || jsonb_build_array(
      jsonb_build_object(
        'itemId', v_item_id,
        'quantity', v_stock_qty,
        'price', v_stock_unit_price,
        'supplierReturnId', v_return_id::text,
        'purchaseOrderId', p_purchase_order_id,
        'purchaseOrderLineId', v_po_line_id
      )
      || case when v_is_converted then jsonb_build_object(
        'accountingQty', v_qty,
        'accountingUnit', v_purchase_unit,
        'accountingPrice', v_purchase_unit_price
      ) else '{}'::jsonb end
    );

    v_return_line_rows := v_return_line_rows || jsonb_build_array(jsonb_build_object(
      'purchaseOrderLineId', v_po_line_id,
      'itemId', v_item_id,
      'receivedQtySnapshot', v_received_qty,
      'previouslyReturnedQtySnapshot', v_returned_qty,
      'returnQty', v_qty,
      'unit', v_purchase_unit,
      'unitPrice', v_purchase_unit_price,
      'stockReturnQty', v_stock_qty,
      'stockUnit', v_stock_unit
    ));
  end loop;

  for v_item_total in
    select
      item.value ->> 'itemId' as item_id,
      sum(coalesce(nullif(item.value ->> 'quantity', '')::numeric, 0)) as quantity
    from jsonb_array_elements(v_transaction_items) item(value)
    group by item.value ->> 'itemId'
  loop
    select coalesce((coalesce(i.stock_by_warehouse, '{}'::jsonb) ->> p_source_warehouse_id)::numeric, 0)
    into v_on_hand
    from public.items i
    where i.id = v_item_total.item_id
    for update;

    select coalesce(sum(coalesce(nullif(item.value ->> 'quantity', '')::numeric, 0)), 0)
    into v_reserved
    from public.transactions t
    cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) item(value)
    where t.source_warehouse_id = p_source_warehouse_id
      and t.status in ('PENDING'::public.transaction_status, 'APPROVED'::public.transaction_status)
      and t.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
      and item.value ->> 'itemId' = v_item_total.item_id;

    if v_item_total.quantity > greatest(0, v_on_hand - v_reserved) then
      raise exception 'Tổng số lượng trả NCC vượt tồn khả dụng của vật tư %. Tồn %, đang giữ %, khả dụng %, cần trả %.',
        v_item_total.item_id, v_on_hand, v_reserved, greatest(0, v_on_hand - v_reserved), v_item_total.quantity;
    end if;
  end loop;

  insert into public.transactions(
    id, type, date, items, source_warehouse_id, requester_id,
    status, note
  ) values (
    v_transaction_id,
    'EXPORT'::public.transaction_type,
    now(),
    v_transaction_items,
    p_source_warehouse_id,
    v_actor,
    'PENDING'::public.transaction_status,
    'Trả hàng NCC ' || v_return_no || ' theo PO ' || coalesce(v_po.po_number, p_purchase_order_id)
      || case when coalesce(v_po.vendor_name, '') <> '' then ' - ' || v_po.vendor_name else '' end
  );

  insert into public.purchase_order_supplier_returns(
    id, return_no, purchase_order_id, project_id, construction_site_id,
    vendor_id, source_warehouse_id, status, transaction_id,
    reason, note, created_by
  ) values (
    v_return_id, v_return_no, v_po.id, v_po.project_id, v_po.construction_site_id,
    v_po.vendor_id, p_source_warehouse_id, 'pending', v_transaction_id,
    trim(p_reason), nullif(trim(coalesce(p_note, '')), ''), v_actor
  )
  returning * into v_return;

  insert into public.purchase_order_supplier_return_lines(
    supplier_return_id, purchase_order_line_id, item_id,
    received_qty_snapshot, previously_returned_qty_snapshot,
    return_qty, unit, unit_price, stock_return_qty, stock_unit
  )
  select
    v_return_id,
    line.value ->> 'purchaseOrderLineId',
    line.value ->> 'itemId',
    coalesce(nullif(line.value ->> 'receivedQtySnapshot', '')::numeric, 0),
    coalesce(nullif(line.value ->> 'previouslyReturnedQtySnapshot', '')::numeric, 0),
    coalesce(nullif(line.value ->> 'returnQty', '')::numeric, 0),
    nullif(line.value ->> 'unit', ''),
    coalesce(nullif(line.value ->> 'unitPrice', '')::numeric, 0),
    coalesce(nullif(line.value ->> 'stockReturnQty', '')::numeric, 0),
    nullif(line.value ->> 'stockUnit', '')
  from jsonb_array_elements(v_return_line_rows) line(value);

  return v_return;
end;
$$ create or replace function app_private.sync_purchase_order_supplier_return_from_transaction()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_return public.purchase_order_supplier_returns%rowtype;
  v_po public.purchase_orders%rowtype;
  v_next_items jsonb;
  v_is_fully_returned boolean := false;
begin
  if new.status not in ('COMPLETED'::public.transaction_status, 'CANCELLED'::public.transaction_status) then
    return new;
  end if;

  select * into v_return
  from public.purchase_order_supplier_returns r
  where r.transaction_id = new.id
  for update;
  if not found or v_return.status <> 'pending' then return new; end if;

  if new.status = 'CANCELLED'::public.transaction_status then
    update public.purchase_order_supplier_returns
    set status = 'cancelled', cancelled_at = now()
    where id = v_return.id;
    return new;
  end if;

  update public.purchase_order_supplier_returns
  set status = 'completed', completed_by = new.approver_id, completed_at = now()
  where id = v_return.id;

  select * into v_po
  from public.purchase_orders po
  where po.id = v_return.purchase_order_id
  for update;

  with returned_by_line as (
    select line.purchase_order_line_id, sum(line.return_qty) as returned_qty
    from public.purchase_order_supplier_return_lines line
    join public.purchase_order_supplier_returns r on r.id = line.supplier_return_id
    where r.purchase_order_id = v_return.purchase_order_id
      and r.status = 'completed'
    group by line.purchase_order_line_id
  ),
  po_items as (
    select item.value, item.ordinality,
      coalesce(item.value ->> 'lineId', item.value ->> 'itemId') as line_id
    from jsonb_array_elements(coalesce(v_po.items, '[]'::jsonb)) with ordinality item(value, ordinality)
  )
  select coalesce(jsonb_agg(
    jsonb_set(p.value, '{returnedQty}', to_jsonb(coalesce(r.returned_qty, 0)), true)
    order by p.ordinality
  ), '[]'::jsonb)
  into v_next_items
  from po_items p
  left join returned_by_line r on r.purchase_order_line_id = p.line_id;

  select
    coalesce(bool_and(
      coalesce(nullif(item.value ->> 'receivedQty', '')::numeric, 0) <=
      coalesce(nullif(item.value ->> 'returnedQty', '')::numeric, 0)
    ), false)
    and coalesce(sum(coalesce(nullif(item.value ->> 'receivedQty', '')::numeric, 0)), 0) > 0
  into v_is_fully_returned
  from jsonb_array_elements(v_next_items) item(value);

  update public.purchase_orders
  set items = v_next_items,
      status = case when v_is_fully_returned then 'returned' else status end,
      delivery_note = concat_ws(
        ' | ',
        nullif(delivery_note, ''),
        case when v_is_fully_returned
          then 'Đã hoàn trả đủ hàng cho NCC qua phiếu ' || v_return.return_no
          else 'Đã hoàn trả một phần cho NCC qua phiếu ' || v_return.return_no
        end
      )
  where id = v_return.purchase_order_id;

  -- Do not mutate historical PO receipt fulfillment batches here.
  -- Gross received stays gross; return quantities are displayed beside it.

  return new;
end;
$$ drop trigger if exists trg_sync_po_supplier_return_transaction on public.transactions create trigger trg_sync_po_supplier_return_transaction
after update of status on public.transactions
for each row execute function app_private.sync_purchase_order_supplier_return_from_transaction() revoke all on function public.create_purchase_order_supplier_return(text, text, jsonb, text, text) from public revoke all on function public.create_purchase_order_supplier_return(text, text, jsonb, text, text) from anon grant execute on function public.create_purchase_order_supplier_return(text, text, jsonb, text, text) to authenticated notify pgrst, 'reload schema']

[-- Allocate PO numbers globally and keep every issued number reserved forever.
-- Existing duplicate historical codes remain readable, but no new duplicate can
-- be inserted and an existing PO number cannot be edited.

create schema if not exists app_private create sequence if not exists app_private.purchase_order_number_seq
  as bigint
  increment by 1
  minvalue 1
  start with 1
  no cycle create table if not exists app_private.purchase_order_number_registry (
  po_number text primary key,
  purchase_order_id text,
  issued_at timestamptz not null default now()
) insert into app_private.purchase_order_number_registry(po_number, purchase_order_id, issued_at)
select distinct on (po.po_number)
  po.po_number,
  po.id::text,
  coalesce(po.created_at, now())
from public.purchase_orders po
where nullif(trim(po.po_number), '') is not null
order by po.po_number, po.created_at, po.id
on conflict (po_number) do nothing do $$
declare
  v_max_existing bigint := 0;
  v_last_sequence bigint := 1;
begin
  select coalesce(max(substring(po.po_number from '^PO-([0-9]+)')::bigint), 0)
    into v_max_existing
  from public.purchase_orders po
  where po.po_number ~ '^PO-[0-9]+';

  select last_value
    into v_last_sequence
  from app_private.purchase_order_number_seq;

  if greatest(v_max_existing, v_last_sequence) <= 1 and v_max_existing = 0 then
    perform setval('app_private.purchase_order_number_seq', 1, false);
  else
    perform setval(
      'app_private.purchase_order_number_seq',
      greatest(v_max_existing, v_last_sequence),
      true
    );
  end if;
end;
$$ create or replace function public.next_purchase_order_number_v2()
returns text
language plpgsql
volatile
security definer
set search_path = ''
as $$
declare
  v_number bigint;
  v_po_number text;
begin
  loop
    v_number := nextval('app_private.purchase_order_number_seq');
    v_po_number := 'PO-' || lpad(v_number::text, 3, '0');

    insert into app_private.purchase_order_number_registry(po_number)
    values (v_po_number)
    on conflict (po_number) do nothing;

    if found and not exists (
      select 1
      from public.purchase_orders po
      where po.po_number = v_po_number
    ) then
      return v_po_number;
    end if;
  end loop;
end;
$$ -- Keep older clients safe: their scoped v1 call now uses the same global allocator.
create or replace function public.next_purchase_order_number_v1(
  p_project_id text default null,
  p_construction_site_id text default null,
  p_prefix text default 'PO'
)
returns text
language sql
volatile
security definer
set search_path = ''
as $$
  select public.next_purchase_order_number_v2();
$$ create or replace function app_private.enforce_purchase_order_number_v2()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_base_number text;
begin
  if tg_op = 'UPDATE' then
    if old.po_number is distinct from new.po_number then
      raise exception 'Số PO được hệ thống tự sinh và không thể chỉnh sửa.'
        using errcode = '23514';
    end if;
    return new;
  end if;

  -- Supabase upsert executes the INSERT trigger before resolving an existing id.
  -- Allow that existing row to continue through its normal UPDATE path.
  if exists (
    select 1
    from public.purchase_orders po
    where po.id = new.id
      and po.po_number = new.po_number
  ) then
    return new;
  end if;

  if new.po_number !~ '^PO-[0-9]{3,}(-[0-9]{2})?$' then
    raise exception 'Số PO không hợp lệ. Hệ thống phải tự cấp số PO.'
      using errcode = '23514';
  end if;

  v_base_number := regexp_replace(new.po_number, '-[0-9]{2}$', '');

  if new.po_number = v_base_number then
    update app_private.purchase_order_number_registry registry
    set purchase_order_id = new.id::text
    where registry.po_number = new.po_number
      and registry.purchase_order_id is null;

    if not found then
      raise exception 'Số PO % chưa được cấp hoặc đã được sử dụng.', new.po_number
        using errcode = '23505';
    end if;
  else
    if not exists (
      select 1
      from app_private.purchase_order_number_registry registry
      where registry.po_number = v_base_number
    ) then
      raise exception 'Nhóm số PO % chưa được hệ thống cấp.', v_base_number
        using errcode = '23505';
    end if;

    insert into app_private.purchase_order_number_registry(po_number, purchase_order_id)
    values (new.po_number, new.id::text)
    on conflict (po_number) do nothing;

    if not found then
      raise exception 'Số PO % đã được sử dụng.', new.po_number
        using errcode = '23505';
    end if;
  end if;

  return new;
end;
$$ drop trigger if exists trg_enforce_purchase_order_number_v2 on public.purchase_orders create trigger trg_enforce_purchase_order_number_v2
  before insert or update of po_number on public.purchase_orders
  for each row execute function app_private.enforce_purchase_order_number_v2() revoke all on sequence app_private.purchase_order_number_seq from public, anon, authenticated revoke all on table app_private.purchase_order_number_registry from public, anon, authenticated revoke all on function public.next_purchase_order_number_v2() from public, anon grant execute on function public.next_purchase_order_number_v2() to authenticated revoke all on function public.next_purchase_order_number_v1(text, text, text) from public, anon grant execute on function public.next_purchase_order_number_v1(text, text, text) to authenticated revoke all on function app_private.enforce_purchase_order_number_v2() from public, anon, authenticated notify pgrst, 'reload schema']

[create schema if not exists app_private alter table if exists public.purchase_orders
  add column if not exists created_by_id text alter table if exists public.purchase_order_delivery_lines
  add column if not exists delivery_unit_price numeric not null default 0 update public.purchase_orders
set created_by_id = nullif(last_action_by, '')
where nullif(created_by_id, '') is null
  and archived_at is null
  and nullif(last_action_by, '') is not null create index if not exists idx_purchase_orders_created_by_id
  on public.purchase_orders(created_by_id, created_at desc)
  where created_by_id is not null create or replace function app_private.project_doc_touch()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_marks_submitted boolean := false;
begin
  if tg_table_name = 'purchase_orders' then
    v_marks_submitted := app_private.project_po_status_marks_submitted(new.status::text);

    if tg_op = 'UPDATE'
       and old.archived_at is null
       and new.archived_at is not null
       and old.status is not distinct from new.status
       and old.submitted_to_user_id is not distinct from new.submitted_to_user_id
    then
      return new;
    end if;
  else
    v_marks_submitted := coalesce(new.status::text, 'draft') <> 'draft';
  end if;

  if tg_op = 'INSERT' then
    if tg_table_name = 'purchase_orders' then
      new.created_by_id := coalesce(nullif(new.created_by_id, ''), public.current_app_user_id()::text, nullif(new.last_action_by, ''));
    end if;
    new.ever_submitted := coalesce(new.ever_submitted, false) or v_marks_submitted;
    new.last_action_by := coalesce(new.last_action_by, public.current_app_user_id()::text);
    new.last_action_at := coalesce(new.last_action_at, now());
    return new;
  end if;

  if old.status is distinct from new.status
     or old.submitted_to_user_id is distinct from new.submitted_to_user_id then
    new.last_action_by := coalesce(new.last_action_by, public.current_app_user_id()::text);
    new.last_action_at := coalesce(new.last_action_at, now());
  end if;

  new.ever_submitted := coalesce(old.ever_submitted, false)
    or coalesce(new.ever_submitted, false)
    or v_marks_submitted;

  return new;
end;
$$ create or replace function app_private.project_po_has_pending_work_v1(p_po_id text)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_has_pending boolean := false;
begin
  if to_regclass('public.material_request_fulfillment_batches') is not null
     and to_regclass('public.material_request_fulfillment_lines') is not null then
    select exists (
      select 1
      from public.material_request_fulfillment_lines line
      join public.material_request_fulfillment_batches batch on batch.id = line.batch_id
      where line.po_id = p_po_id
        and lower(coalesce(batch.status::text, '')) in ('issued', 'variance_pending')
    )
      into v_has_pending;

    if v_has_pending then
      return true;
    end if;
  end if;

  if to_regclass('public.purchase_order_delivery_batches') is not null then
    select exists (
      select 1
      from public.purchase_order_delivery_batches batch
      where batch.purchase_order_id = p_po_id
        and lower(coalesce(batch.status::text, '')) = 'wms_pending'
    )
      into v_has_pending;

    if v_has_pending then
      return true;
    end if;
  end if;

  if to_regclass('public.purchase_order_supplier_returns') is not null then
    select exists (
      select 1
      from public.purchase_order_supplier_returns r
      where r.purchase_order_id = p_po_id
        and lower(coalesce(r.status::text, '')) not in ('completed', 'cancelled')
    )
      into v_has_pending;
  end if;

  return coalesce(v_has_pending, false);
end;
$$ create or replace function app_private.project_po_can_archive_v1(
  p_po_id text,
  p_project_id text,
  p_construction_site_id text,
  p_status text,
  p_ever_submitted boolean,
  p_received_transaction_ids jsonb,
  p_items jsonb
)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_status text := lower(coalesce(p_status, 'draft'));
  v_has_permission boolean := false;
  v_received_item_qty numeric := 0;
  v_has_received_batch_qty boolean := false;
  v_no_receipt boolean := false;
  v_stock_cleanup_ok boolean := false;
  v_direct_supplier_return_cleanup_ok boolean := false;
begin
  v_has_permission := public.is_admin()
    or exists (
      select 1
      from public.purchase_orders po
      where po.id = p_po_id
        and nullif(po.created_by_id, '') = public.current_app_user_id()::text
    );

  if not v_has_permission then
    return false;
  end if;

  select coalesce(sum(coalesce(nullif(elem->>'receivedQty', '')::numeric, 0)), 0)
    into v_received_item_qty
  from jsonb_array_elements(coalesce(p_items, '[]'::jsonb)) as elem;

  if to_regclass('public.material_request_fulfillment_lines') is not null then
    select coalesce(bool_or(coalesce(received_qty, 0) > 0), false)
      into v_has_received_batch_qty
    from public.material_request_fulfillment_lines
    where po_id = p_po_id;
  end if;

  v_no_receipt := v_received_item_qty <= 0
    and jsonb_array_length(coalesce(p_received_transaction_ids, '[]'::jsonb)) = 0
    and not v_has_received_batch_qty;

  if v_status in ('returned', 'cancelled', 'partial', 'delivered', 'closed') then
    v_stock_cleanup_ok := app_private.project_po_stock_cleanup_ok(p_po_id, p_received_transaction_ids);
    v_direct_supplier_return_cleanup_ok := app_private.project_po_direct_supplier_return_cleanup_ok(p_po_id, p_received_transaction_ids);
  end if;

  return
    (v_status = 'draft' and not coalesce(p_ever_submitted, false) and v_no_receipt)
    or (
      v_status in ('returned', 'cancelled')
      and (v_no_receipt or v_stock_cleanup_ok or v_direct_supplier_return_cleanup_ok)
    )
    or (
      v_status in ('partial', 'delivered', 'closed')
      and (v_stock_cleanup_ok or v_direct_supplier_return_cleanup_ok)
    );
end;
$$ create or replace function public.remove_purchase_order_v1(p_po_id text)
returns table(action text, id text, po_number text)
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_po public.purchase_orders%rowtype;
  v_has_permission boolean := false;
  v_has_stock_impact boolean := false;
  v_received_transaction_ids text[] := array[]::text[];
  v_fulfillment_transaction_ids text[] := array[]::text[];
  v_supplier_return_transaction_ids text[] := array[]::text[];
  v_supplier_return_ids uuid[] := array[]::uuid[];
  v_supplier_return_text_ids text[] := array[]::text[];
  v_cleanup_transaction_ids text[] := array[]::text[];
begin
  select *
    into v_po
  from public.purchase_orders
  where public.purchase_orders.id = p_po_id
  for update;

  if not found then
    raise exception 'Không tìm thấy PO cần xoá/lưu trữ.';
  end if;

  if v_po.archived_at is not null then
    raise exception 'PO đã được lưu trữ.';
  end if;

  v_has_permission := public.is_admin()
    or nullif(v_po.created_by_id, '') = public.current_app_user_id()::text;

  if not v_has_permission then
    raise exception 'Chỉ Admin hoặc người tạo PO được xoá/lưu trữ PO này.'
      using errcode = '42501';
  end if;

  if app_private.project_po_has_pending_work_v1(v_po.id::text) then
    raise exception 'PO đang có đợt giao/giao dịch chờ xử lý. Vui lòng huỷ hoặc xử lý xong trước khi xoá.';
  end if;

  v_has_stock_impact := app_private.project_po_has_stock_impact_v1(
    v_po.id::text,
    v_po.received_transaction_ids,
    v_po.items
  );

  if not v_has_stock_impact then
    select coalesce(array_agg(distinct tx_id), array[]::text[])
      into v_received_transaction_ids
    from (
      select jsonb_array_elements_text(
        case
          when jsonb_typeof(coalesce(v_po.received_transaction_ids, '[]'::jsonb)) = 'array'
            then coalesce(v_po.received_transaction_ids, '[]'::jsonb)
          else '[]'::jsonb
        end
      ) as tx_id
    ) tx
    where nullif(tx_id, '') is not null;

    if to_regclass('public.material_request_fulfillment_batches') is not null
       and to_regclass('public.material_request_fulfillment_lines') is not null then
      select coalesce(array_agg(distinct batch.transaction_id::text), array[]::text[])
        into v_fulfillment_transaction_ids
      from public.material_request_fulfillment_lines line
      join public.material_request_fulfillment_batches batch
        on batch.id = line.batch_id
      where line.po_id = v_po.id::text
        and batch.transaction_id is not null;
    end if;

    if to_regclass('public.purchase_order_supplier_returns') is not null then
      select coalesce(array_agg(distinct r.id), array[]::uuid[]),
             coalesce(array_agg(distinct r.transaction_id::text) filter (where r.transaction_id is not null), array[]::text[])
        into v_supplier_return_ids, v_supplier_return_transaction_ids
      from public.purchase_order_supplier_returns r
      where r.purchase_order_id = v_po.id::text;

      select coalesce(array_agg(ids.return_id::text), array[]::text[])
        into v_supplier_return_text_ids
      from unnest(v_supplier_return_ids) as ids(return_id);
    end if;

    select coalesce(array_agg(distinct tx_id), array[]::text[])
      into v_cleanup_transaction_ids
    from (
      select unnest(v_received_transaction_ids) as tx_id
      union
      select unnest(v_fulfillment_transaction_ids) as tx_id
      union
      select unnest(v_supplier_return_transaction_ids) as tx_id
    ) tx
    where nullif(tx_id, '') is not null;

    if to_regclass('public.project_document_links') is not null then
      delete from public.project_document_links link
      where (link.source_type = 'purchase_order' and link.source_id = v_po.id::text)
         or (link.target_type = 'purchase_order' and link.target_id = v_po.id::text)
         or (link.source_type = 'transaction' and link.source_id = any(v_cleanup_transaction_ids))
         or (link.target_type = 'transaction' and link.target_id = any(v_cleanup_transaction_ids))
         or (link.source_type = 'supplier_return' and link.source_id = any(v_supplier_return_text_ids))
         or (link.target_type = 'supplier_return' and link.target_id = any(v_supplier_return_text_ids));
    end if;

    if to_regclass('public.purchase_order_supplier_return_lines') is not null
       and coalesce(array_length(v_supplier_return_ids, 1), 0) > 0 then
      delete from public.purchase_order_supplier_return_lines line
      where line.supplier_return_id = any(v_supplier_return_ids);
    end if;

    if to_regclass('public.purchase_order_supplier_returns') is not null then
      delete from public.purchase_order_supplier_returns r
      where r.purchase_order_id = v_po.id::text;
    end if;

    if to_regclass('public.material_request_fulfillment_batches') is not null
       and to_regclass('public.material_request_fulfillment_lines') is not null then
      delete from public.material_request_fulfillment_batches batch
      where exists (
        select 1
        from public.material_request_fulfillment_lines line
        where line.batch_id = batch.id
          and line.po_id = v_po.id::text
      );
    end if;

    if coalesce(array_length(v_cleanup_transaction_ids, 1), 0) > 0 then
      delete from public.transactions t
      where t.id::text = any(v_cleanup_transaction_ids)
        and upper(coalesce(t.status::text, '')) <> 'COMPLETED'
        and not exists (
          select 1
          from public.inventory_ledger_entries entry
          where entry.source_type = 'wms_transaction'
            and entry.source_id = t.id::text
        )
        and (
          to_regclass('public.material_request_fulfillment_batches') is null
          or not exists (
            select 1
            from public.material_request_fulfillment_batches batch
            where batch.transaction_id::text = t.id::text
          )
        )
        and (
          to_regclass('public.purchase_order_supplier_returns') is null
          or not exists (
            select 1
            from public.purchase_order_supplier_returns r
            where r.transaction_id::text = t.id::text
          )
        );
    end if;

    delete from public.purchase_orders
    where public.purchase_orders.id = v_po.id;

    if to_regclass('public.project_document_links') is not null then
      delete from public.project_document_links link
      where (link.source_type = 'purchase_order' and link.source_id = v_po.id::text)
         or (link.target_type = 'purchase_order' and link.target_id = v_po.id::text);
    end if;

    action := 'deleted';
    id := v_po.id::text;
    po_number := v_po.po_number::text;
    return next;
    return;
  end if;

  if not app_private.project_po_can_archive_v1(
    v_po.id::text,
    v_po.project_id::text,
    v_po.construction_site_id::text,
    v_po.status::text,
    v_po.ever_submitted,
    v_po.received_transaction_ids,
    v_po.items
  ) then
    raise exception 'PO đã phát sinh kho và chưa đủ điều kiện lưu trữ. Vui lòng hoàn trả/đối soát đủ trước.';
  end if;

  update public.purchase_orders
  set archived_at = now(),
      archived_by = public.current_app_user_id(),
      archive_reason = 'Người dùng lưu trữ PO từ tab Cung ứng'
  where public.purchase_orders.id = v_po.id;

  action := 'archived';
  id := v_po.id::text;
  po_number := v_po.po_number::text;
  return next;
end;
$$ revoke all on function app_private.project_doc_touch() from public, anon, authenticated revoke all on function app_private.project_po_has_pending_work_v1(text) from public, anon, authenticated revoke all on function app_private.project_po_can_archive_v1(text, text, text, text, boolean, jsonb, jsonb) from public, anon, authenticated revoke all on function public.remove_purchase_order_v1(text) from public, anon grant execute on function public.remove_purchase_order_v1(text) to authenticated notify pgrst, 'reload schema']

[create schema if not exists app_private create or replace function app_private.project_po_delivery_batch_refresh_status_v1(
  p_delivery_batch_id uuid
)
returns void
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_has_rows boolean := false;
  v_has_open boolean := false;
  v_has_received boolean := false;
  v_all_rejected boolean := false;
  v_next_status text;
begin
  if p_delivery_batch_id is null
     or to_regclass('public.purchase_order_delivery_batches') is null
     or to_regclass('public.material_request_fulfillment_batches') is null
     or to_regclass('public.material_request_fulfillment_lines') is null then
    return;
  end if;

  select
    count(*) > 0,
    coalesce(bool_or(lower(coalesce(batch.status::text, '')) in ('issued', 'variance_pending')), false),
    coalesce(bool_or(lower(coalesce(batch.status::text, '')) = 'received' or coalesce(line_totals.received_qty, 0) > 0), false),
    count(*) > 0
      and coalesce(bool_and(lower(coalesce(batch.status::text, '')) in ('returned', 'cancelled')), false)
      and not coalesce(bool_or(coalesce(line_totals.received_qty, 0) > 0), false)
  into v_has_rows, v_has_open, v_has_received, v_all_rejected
  from public.material_request_fulfillment_batches batch
  left join lateral (
    select coalesce(sum(coalesce(line.received_qty, 0)), 0) as received_qty
    from public.material_request_fulfillment_lines line
    where line.batch_id = batch.id
  ) line_totals on true
  where batch.po_delivery_batch_id = p_delivery_batch_id;

  if not v_has_rows then
    return;
  end if;

  v_next_status := case
    when v_all_rejected then 'cancelled'
    when v_has_open then 'wms_pending'
    when v_has_received then 'received'
    else 'wms_pending'
  end;

  update public.purchase_order_delivery_batches
  set status = v_next_status
  where id = p_delivery_batch_id
    and status is distinct from v_next_status;
end;
$$ create or replace function app_private.project_po_delivery_group_refresh_status_v1(
  p_delivery_group_id uuid
)
returns void
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_has_rows boolean := false;
  v_has_open boolean := false;
  v_has_received boolean := false;
  v_all_rejected boolean := false;
  v_next_status text;
begin
  if p_delivery_group_id is null
     or to_regclass('public.purchase_order_delivery_groups') is null
     or to_regclass('public.material_request_fulfillment_batches') is null
     or to_regclass('public.material_request_fulfillment_lines') is null then
    return;
  end if;

  select
    count(*) > 0,
    coalesce(bool_or(lower(coalesce(batch.status::text, '')) in ('issued', 'variance_pending')), false),
    coalesce(bool_or(lower(coalesce(batch.status::text, '')) = 'received' or coalesce(line_totals.received_qty, 0) > 0), false),
    count(*) > 0
      and coalesce(bool_and(lower(coalesce(batch.status::text, '')) in ('returned', 'cancelled')), false)
      and not coalesce(bool_or(coalesce(line_totals.received_qty, 0) > 0), false)
  into v_has_rows, v_has_open, v_has_received, v_all_rejected
  from public.material_request_fulfillment_batches batch
  left join lateral (
    select coalesce(sum(coalesce(line.received_qty, 0)), 0) as received_qty
    from public.material_request_fulfillment_lines line
    where line.batch_id = batch.id
  ) line_totals on true
  where batch.po_delivery_group_id = p_delivery_group_id;

  if not v_has_rows then
    return;
  end if;

  v_next_status := case
    when v_all_rejected then 'cancelled'
    when v_has_open then 'issued'
    when v_has_received then 'received'
    else 'issued'
  end;

  update public.purchase_order_delivery_groups
  set status = v_next_status
  where id = p_delivery_group_id
    and status is distinct from v_next_status;
end;
$$ create or replace function app_private.project_po_sync_cancelled_receipt_transaction_v1(
  p_transaction_id text,
  p_reason text default null
)
returns jsonb
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_tx public.transactions%rowtype;
  v_reason text := coalesce(nullif(trim(p_reason), ''), 'Phiếu kho nhập PO đã bị từ chối trước khi nhập kho.');
  v_batch_ids uuid[] := array[]::uuid[];
  v_delivery_batch_ids uuid[] := array[]::uuid[];
  v_delivery_group_ids uuid[] := array[]::uuid[];
  v_id uuid;
begin
  if p_transaction_id is null
     or to_regclass('public.material_request_fulfillment_batches') is null
     or to_regclass('public.material_request_fulfillment_lines') is null then
    return jsonb_build_object('synced', false, 'reason', 'missing_input_or_tables');
  end if;

  select *
    into v_tx
  from public.transactions
  where id = p_transaction_id
  for update;

  if not found then
    return jsonb_build_object('synced', false, 'reason', 'transaction_not_found');
  end if;

  if v_tx.status <> 'CANCELLED'::public.transaction_status then
    return jsonb_build_object('synced', false, 'reason', 'transaction_not_cancelled');
  end if;

  if to_regclass('public.inventory_ledger_entries') is not null
     and exists (
       select 1
       from public.inventory_ledger_entries entry
       where entry.source_type = 'wms_transaction'
         and entry.source_id = v_tx.id::text
     ) then
    return jsonb_build_object('synced', false, 'reason', 'stock_ledger_exists');
  end if;

  select coalesce(array_agg(distinct batch.id), array[]::uuid[])
    into v_batch_ids
  from public.material_request_fulfillment_batches batch
  where batch.transaction_id::text = v_tx.id::text
    and lower(coalesce(batch.source_type::text, '')) = 'po_receipt'
    and lower(coalesce(batch.status::text, '')) in ('issued', 'variance_pending')
    and not exists (
      select 1
      from public.material_request_fulfillment_lines line
      where line.batch_id = batch.id
        and coalesce(line.received_qty, 0) > 0
    );

  if coalesce(array_length(v_batch_ids, 1), 0) = 0 then
    return jsonb_build_object('synced', false, 'reason', 'no_receipt_batches_to_return');
  end if;

  update public.material_request_fulfillment_batches batch
  set status = 'returned',
      cancel_reason = coalesce(nullif(batch.cancel_reason, ''), v_reason),
      reason = coalesce(nullif(batch.reason, ''), v_reason)
  where batch.id = any(v_batch_ids);

  select coalesce(array_agg(distinct batch.po_delivery_batch_id) filter (where batch.po_delivery_batch_id is not null), array[]::uuid[]),
         coalesce(array_agg(distinct batch.po_delivery_group_id) filter (where batch.po_delivery_group_id is not null), array[]::uuid[])
    into v_delivery_batch_ids, v_delivery_group_ids
  from public.material_request_fulfillment_batches batch
  where batch.id = any(v_batch_ids);

  foreach v_id in array v_delivery_batch_ids loop
    perform app_private.project_po_delivery_batch_refresh_status_v1(v_id);
  end loop;

  foreach v_id in array v_delivery_group_ids loop
    perform app_private.project_po_delivery_group_refresh_status_v1(v_id);
  end loop;

  return jsonb_build_object(
    'synced', true,
    'transactionId', v_tx.id,
    'returnedBatchCount', coalesce(array_length(v_batch_ids, 1), 0)
  );
end;
$$ create or replace function app_private.project_po_sync_cancelled_receipt_transaction_trigger_v1()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if tg_op = 'UPDATE'
     and new.status = 'CANCELLED'::public.transaction_status
     and old.status is distinct from new.status then
    perform app_private.project_po_sync_cancelled_receipt_transaction_v1(
      new.id::text,
      'Phiếu kho nhập PO đã bị từ chối trước khi nhập kho.'
    );
  end if;

  return new;
end;
$$ drop trigger if exists trg_project_po_sync_cancelled_receipt_transaction
  on public.transactions create trigger trg_project_po_sync_cancelled_receipt_transaction
after update of status on public.transactions
for each row
execute function app_private.project_po_sync_cancelled_receipt_transaction_trigger_v1() create or replace function app_private.project_po_has_failed_delivery_work_v1(p_po_id text)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_has_failed boolean := false;
begin
  if to_regclass('public.material_request_fulfillment_batches') is not null
     and to_regclass('public.material_request_fulfillment_lines') is not null then
    select exists (
      select 1
      from public.material_request_fulfillment_lines line
      join public.material_request_fulfillment_batches batch on batch.id = line.batch_id
      left join public.transactions tx on tx.id::text = batch.transaction_id::text
      where line.po_id = p_po_id
        and coalesce(line.received_qty, 0) <= 0
        and (
          lower(coalesce(batch.status::text, '')) in ('returned', 'cancelled')
          or (
            lower(coalesce(batch.status::text, '')) in ('issued', 'variance_pending')
            and tx.status = 'CANCELLED'::public.transaction_status
          )
        )
    )
      into v_has_failed;

    if v_has_failed then
      return true;
    end if;
  end if;

  if to_regclass('public.purchase_order_delivery_batches') is not null then
    select exists (
      select 1
      from public.purchase_order_delivery_batches batch
      where batch.purchase_order_id = p_po_id
        and lower(coalesce(batch.status::text, '')) = 'cancelled'
    )
      into v_has_failed;

    if v_has_failed then
      return true;
    end if;
  end if;

  if to_regclass('public.purchase_order_delivery_groups') is not null then
    select exists (
      select 1
      from public.purchase_order_delivery_groups delivery_group
      where delivery_group.purchase_order_id = p_po_id
        and lower(coalesce(delivery_group.status::text, '')) = 'cancelled'
    )
      into v_has_failed;
  end if;

  return coalesce(v_has_failed, false);
end;
$$ create or replace function app_private.project_po_has_pending_work_v1(p_po_id text)
returns boolean
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_has_pending boolean := false;
begin
  if to_regclass('public.material_request_fulfillment_batches') is not null
     and to_regclass('public.material_request_fulfillment_lines') is not null then
    select exists (
      select 1
      from public.material_request_fulfillment_lines line
      join public.material_request_fulfillment_batches batch on batch.id = line.batch_id
      left join public.transactions tx on tx.id::text = batch.transaction_id::text
      where line.po_id = p_po_id
        and lower(coalesce(batch.status::text, '')) in ('issued', 'variance_pending')
        and coalesce(tx.status, 'PENDING'::public.transaction_status) <> 'CANCELLED'::public.transaction_status
    )
      into v_has_pending;

    if v_has_pending then
      return true;
    end if;
  end if;

  if to_regclass('public.purchase_order_delivery_batches') is not null then
    select exists (
      select 1
      from public.purchase_order_delivery_batches batch
      where batch.purchase_order_id = p_po_id
        and lower(coalesce(batch.status::text, '')) = 'wms_pending'
    )
      into v_has_pending;

    if v_has_pending then
      return true;
    end if;
  end if;

  if app_private.project_po_has_failed_delivery_work_v1(p_po_id) then
    return true;
  end if;

  if to_regclass('public.purchase_order_supplier_returns') is not null then
    select exists (
      select 1
      from public.purchase_order_supplier_returns r
      where r.purchase_order_id = p_po_id
        and lower(coalesce(r.status::text, '')) not in ('completed', 'cancelled')
    )
      into v_has_pending;
  end if;

  return coalesce(v_has_pending, false);
end;
$$ create or replace function public.remove_purchase_order_delivery_batch_v1(p_delivery_batch_id uuid)
returns table(action text, id text, purchase_order_id text, po_number text)
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_delivery public.purchase_order_delivery_batches%rowtype;
  v_po public.purchase_orders%rowtype;
  v_has_permission boolean := false;
  v_batch_ids uuid[] := array[]::uuid[];
  v_transaction_ids text[] := array[]::text[];
begin
  select *
    into v_delivery
  from public.purchase_order_delivery_batches
  where public.purchase_order_delivery_batches.id = p_delivery_batch_id
  for update;

  if not found then
    raise exception 'Không tìm thấy đợt giao cần xoá.';
  end if;

  select *
    into v_po
  from public.purchase_orders
  where public.purchase_orders.id = v_delivery.purchase_order_id
  for update;

  if not found then
    raise exception 'Không tìm thấy PO của đợt giao.';
  end if;

  v_has_permission := public.is_admin()
    or nullif(v_po.created_by_id, '') = public.current_app_user_id()::text;

  if not v_has_permission then
    raise exception 'Chỉ Admin hoặc người tạo PO được xoá đợt giao này.'
      using errcode = '42501';
  end if;

  select coalesce(array_agg(distinct batch.id), array[]::uuid[]),
         coalesce(array_agg(distinct batch.transaction_id::text) filter (where batch.transaction_id is not null), array[]::text[])
    into v_batch_ids, v_transaction_ids
  from public.material_request_fulfillment_batches batch
  where batch.po_delivery_batch_id = p_delivery_batch_id;

  if coalesce(array_length(v_batch_ids, 1), 0) > 0 then
    if exists (
      select 1
      from public.material_request_fulfillment_batches batch
      where batch.id = any(v_batch_ids)
        and lower(coalesce(batch.status::text, '')) not in ('returned', 'cancelled')
    ) then
      raise exception 'Chỉ xoá được đợt giao đã bị từ chối/huỷ và không còn chờ xử lý.';
    end if;

    if exists (
      select 1
      from public.material_request_fulfillment_lines line
      where line.batch_id = any(v_batch_ids)
        and coalesce(line.received_qty, 0) > 0
    ) then
      raise exception 'Đợt giao đã phát sinh thực nhận, không thể xoá.';
    end if;
  end if;

  if coalesce(array_length(v_transaction_ids, 1), 0) > 0 then
    if exists (
      select 1
      from public.transactions tx
      where tx.id::text = any(v_transaction_ids)
        and tx.status = 'COMPLETED'::public.transaction_status
    ) then
      raise exception 'Đợt giao đã có phiếu kho hoàn tất, không thể xoá.';
    end if;

    if to_regclass('public.inventory_ledger_entries') is not null
       and exists (
         select 1
         from public.inventory_ledger_entries entry
         where entry.source_type = 'wms_transaction'
           and entry.source_id = any(v_transaction_ids)
       ) then
      raise exception 'Đợt giao đã phát sinh ledger kho, không thể xoá.';
    end if;
  end if;

  if to_regclass('public.project_document_links') is not null then
    delete from public.project_document_links link
    where (link.source_type = 'transaction' and link.source_id = any(v_transaction_ids))
       or (link.target_type = 'transaction' and link.target_id = any(v_transaction_ids));
  end if;

  if coalesce(array_length(v_batch_ids, 1), 0) > 0 then
    delete from public.material_request_fulfillment_batches batch
    where batch.id = any(v_batch_ids);
  end if;

  if coalesce(array_length(v_transaction_ids, 1), 0) > 0 then
    delete from public.transactions tx
    where tx.id::text = any(v_transaction_ids)
      and tx.status <> 'COMPLETED'::public.transaction_status
      and (
        to_regclass('public.inventory_ledger_entries') is null
        or not exists (
          select 1
          from public.inventory_ledger_entries entry
          where entry.source_type = 'wms_transaction'
            and entry.source_id = tx.id::text
        )
      )
      and not exists (
        select 1
        from public.material_request_fulfillment_batches batch
        where batch.transaction_id::text = tx.id::text
      )
      and (
        to_regclass('public.purchase_order_supplier_returns') is null
        or not exists (
          select 1
          from public.purchase_order_supplier_returns r
          where r.transaction_id::text = tx.id::text
        )
      );
  end if;

  delete from public.purchase_order_delivery_batches
  where public.purchase_order_delivery_batches.id = p_delivery_batch_id;

  action := 'deleted';
  id := p_delivery_batch_id::text;
  purchase_order_id := v_po.id::text;
  po_number := v_po.po_number::text;
  return next;
end;
$$ create or replace function public.remove_purchase_order_delivery_group_v1(p_delivery_group_id uuid)
returns table(action text, id text, purchase_order_id text, po_number text)
language plpgsql
