[create schema if not exists app_private create or replace function app_private.project_po_refresh_request_status_v1(
  p_request_ids text[]
)
returns void
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_request_id text;
  v_total_committed numeric := 0;
  v_total_active_issued numeric := 0;
  v_total_received numeric := 0;
  v_total_closed numeric := 0;
  v_open_need numeric := 0;
  v_next_status public.request_status;
  v_next_step text;
begin
  if p_request_ids is null or array_length(p_request_ids, 1) is null then
    return;
  end if;

  foreach v_request_id in array p_request_ids loop
    select coalesce(sum(
      coalesce(
        nullif(item.value ->> 'approvedQty', '')::numeric,
        nullif(item.value ->> 'requestQty', '')::numeric,
        0
      )
    ), 0)
    into v_total_committed
    from public.requests request
    cross join lateral jsonb_array_elements(coalesce(request.items, '[]'::jsonb)) item(value)
    where request.id = v_request_id;

    select
      coalesce(sum(case
        when lower(coalesce(batch.status::text, '')) not in ('draft', 'cancelled', 'returned')
          then coalesce(line.issued_qty, 0)
        else 0
      end), 0),
      coalesce(sum(case
        when lower(coalesce(batch.status::text, '')) = 'received'
          then coalesce(line.received_qty, 0)
        else 0
      end), 0)
    into v_total_active_issued, v_total_received
    from public.material_request_fulfillment_lines line
    join public.material_request_fulfillment_batches batch on batch.id = line.batch_id
    where line.material_request_id = v_request_id;

    v_total_closed := 0;
    if to_regclass('public.material_request_line_need_closures') is not null then
      select coalesce(sum(coalesce(closure.closed_qty, 0)), 0)
      into v_total_closed
      from public.material_request_line_need_closures closure
      where closure.material_request_id = v_request_id
        and lower(coalesce(closure.status::text, 'active')) = 'active';
    end if;

    v_open_need := greatest(0, v_total_committed - v_total_received - v_total_closed);
    v_next_status := case
      when v_total_committed > 0 and v_open_need <= 0 then 'COMPLETED'::public.request_status
      when v_total_active_issued > 0 or v_total_received > 0 then 'IN_TRANSIT'::public.request_status
      else 'APPROVED'::public.request_status
    end;
    v_next_step := case
      when v_next_status = 'COMPLETED'::public.request_status then 'completed'
      when v_next_status = 'IN_TRANSIT'::public.request_status then 'site_quality_check'
      else 'batch_planning'
    end;

    update public.requests
    set status = v_next_status,
        workflow_step = v_next_step,
        workflow_step_started_at = now(),
        submission_note = concat_ws(
          ' | ',
          nullif(submission_note, ''),
          'Đồng bộ lại sau khi phiếu nhập PO bị từ chối trước nhập kho.'
        )
    where id = v_request_id
      and status not in (
        'DRAFT'::public.request_status,
        'PENDING'::public.request_status,
        'REJECTED'::public.request_status
      )
      and (
        status is distinct from v_next_status
        or workflow_step is distinct from v_next_step
      );
  end loop;
end;
$$ create or replace function app_private.project_po_sync_cancelled_receipt_transaction_v1(
  p_transaction_id text,
  p_reason text default null
)
returns jsonb
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_tx public.transactions%rowtype;
  v_reason text := coalesce(nullif(trim(p_reason), ''), 'Phiếu kho nhập PO đã bị từ chối trước khi nhập kho.');
  v_batch_ids uuid[] := array[]::uuid[];
  v_delivery_batch_ids uuid[] := array[]::uuid[];
  v_delivery_group_ids uuid[] := array[]::uuid[];
  v_request_ids text[] := array[]::text[];
  v_id uuid;
begin
  if p_transaction_id is null
     or to_regclass('public.material_request_fulfillment_batches') is null
     or to_regclass('public.material_request_fulfillment_lines') is null then
    return jsonb_build_object('synced', false, 'reason', 'missing_input_or_tables');
  end if;

  select *
    into v_tx
  from public.transactions
  where id = p_transaction_id
  for update;

  if not found then
    return jsonb_build_object('synced', false, 'reason', 'transaction_not_found');
  end if;

  if v_tx.status <> 'CANCELLED'::public.transaction_status then
    return jsonb_build_object('synced', false, 'reason', 'transaction_not_cancelled');
  end if;

  if to_regclass('public.inventory_ledger_entries') is not null
     and exists (
       select 1
       from public.inventory_ledger_entries entry
       where entry.source_type = 'wms_transaction'
         and entry.source_id = v_tx.id::text
     ) then
    return jsonb_build_object('synced', false, 'reason', 'stock_ledger_exists');
  end if;

  select coalesce(array_agg(distinct batch.id), array[]::uuid[])
    into v_batch_ids
  from public.material_request_fulfillment_batches batch
  where batch.transaction_id::text = v_tx.id::text
    and lower(coalesce(batch.source_type::text, '')) = 'po_receipt'
    and lower(coalesce(batch.status::text, '')) in ('issued', 'variance_pending', 'returned')
    and not exists (
      select 1
      from public.material_request_fulfillment_lines line
      where line.batch_id = batch.id
        and coalesce(line.received_qty, 0) > 0
    );

  if coalesce(array_length(v_batch_ids, 1), 0) = 0 then
    return jsonb_build_object('synced', false, 'reason', 'no_receipt_batches_to_cancel');
  end if;

  update public.material_request_fulfillment_batches batch
  set status = 'cancelled',
      cancel_reason = coalesce(nullif(batch.cancel_reason, ''), v_reason),
      reason = coalesce(nullif(batch.reason, ''), v_reason)
  where batch.id = any(v_batch_ids);

  select coalesce(array_agg(distinct batch.po_delivery_batch_id) filter (where batch.po_delivery_batch_id is not null), array[]::uuid[]),
         coalesce(array_agg(distinct batch.po_delivery_group_id) filter (where batch.po_delivery_group_id is not null), array[]::uuid[])
    into v_delivery_batch_ids, v_delivery_group_ids
  from public.material_request_fulfillment_batches batch
  where batch.id = any(v_batch_ids);

  select coalesce(array_agg(distinct line.material_request_id) filter (where line.material_request_id is not null), array[]::text[])
    into v_request_ids
  from public.material_request_fulfillment_lines line
  where line.batch_id = any(v_batch_ids);

  foreach v_id in array v_delivery_batch_ids loop
    perform app_private.project_po_delivery_batch_refresh_status_v1(v_id);
  end loop;

  foreach v_id in array v_delivery_group_ids loop
    perform app_private.project_po_delivery_group_refresh_status_v1(v_id);
  end loop;

  perform app_private.project_po_refresh_request_status_v1(v_request_ids);

  return jsonb_build_object(
    'synced', true,
    'transactionId', v_tx.id,
    'cancelledBatchCount', coalesce(array_length(v_batch_ids, 1), 0),
    'returnedBatchCount', 0
  );
end;
$$ do $$
declare
  v_delivery_batch_ids uuid[] := array[]::uuid[];
  v_delivery_group_ids uuid[] := array[]::uuid[];
  v_request_ids text[] := array[]::text[];
  v_id uuid;
begin
  if to_regclass('public.material_request_fulfillment_batches') is null
     or to_regclass('public.material_request_fulfillment_lines') is null then
    return;
  end if;

  with repair_candidates as (
    select distinct batch.id
    from public.material_request_fulfillment_batches batch
    join public.transactions tx on tx.id::text = batch.transaction_id::text
    where tx.status = 'CANCELLED'::public.transaction_status
      and lower(coalesce(batch.source_type::text, '')) = 'po_receipt'
      and lower(coalesce(batch.status::text, '')) = 'returned'
      and not exists (
        select 1
        from public.material_request_fulfillment_lines line
        where line.batch_id = batch.id
          and coalesce(line.received_qty, 0) > 0
      )
      and (
        to_regclass('public.inventory_ledger_entries') is null
        or not exists (
          select 1
          from public.inventory_ledger_entries entry
          where entry.source_type = 'wms_transaction'
            and entry.source_id = tx.id::text
        )
      )
  ),
  updated as (
    update public.material_request_fulfillment_batches batch
    set status = 'cancelled',
        cancel_reason = coalesce(nullif(batch.cancel_reason, ''), 'Phiếu kho nhập PO đã bị từ chối trước khi nhập kho.'),
        reason = coalesce(nullif(batch.reason, ''), 'Phiếu kho nhập PO đã bị từ chối trước khi nhập kho.')
    where batch.id in (select id from repair_candidates)
    returning batch.id, batch.po_delivery_batch_id, batch.po_delivery_group_id
  )
  select coalesce(array_agg(distinct po_delivery_batch_id) filter (where po_delivery_batch_id is not null), array[]::uuid[]),
         coalesce(array_agg(distinct po_delivery_group_id) filter (where po_delivery_group_id is not null), array[]::uuid[])
  into v_delivery_batch_ids, v_delivery_group_ids
  from updated;

  select coalesce(array_agg(distinct line.material_request_id) filter (where line.material_request_id is not null), array[]::text[])
  into v_request_ids
  from public.material_request_fulfillment_lines line
  join public.material_request_fulfillment_batches batch on batch.id = line.batch_id
  join public.transactions tx on tx.id::text = batch.transaction_id::text
  where tx.status = 'CANCELLED'::public.transaction_status
    and lower(coalesce(batch.source_type::text, '')) = 'po_receipt'
    and lower(coalesce(batch.status::text, '')) = 'cancelled'
    and not exists (
      select 1
      from public.material_request_fulfillment_lines received_line
      where received_line.batch_id = batch.id
        and coalesce(received_line.received_qty, 0) > 0
    );

  foreach v_id in array v_delivery_batch_ids loop
    perform app_private.project_po_delivery_batch_refresh_status_v1(v_id);
  end loop;

  foreach v_id in array v_delivery_group_ids loop
    perform app_private.project_po_delivery_group_refresh_status_v1(v_id);
  end loop;

  perform app_private.project_po_refresh_request_status_v1(v_request_ids);
end;
$$ revoke all on function app_private.project_po_refresh_request_status_v1(text[]) from public, anon, authenticated revoke all on function app_private.project_po_sync_cancelled_receipt_transaction_v1(text, text) from public, anon, authenticated notify pgrst, 'reload schema']

[-- Allow PO creators/admins to edit a company delivery group before stock receipt.
-- Quantities and prices are kept in sync with the pending WMS transaction atomically.

create or replace function app_private.project_po_update_transaction_delivery_item_v1(
  p_item jsonb,
  p_batch_id uuid,
  p_request_line_id text,
  p_item_id text,
  p_issued_qty numeric,
  p_unit_price numeric
)
returns jsonb
language plpgsql
immutable
set search_path = ''
as $$
declare
  v_result jsonb := p_item;
  v_old_qty numeric := coalesce(nullif(p_item ->> 'quantity', '')::numeric, 0);
  v_old_accounting_qty numeric := coalesce(nullif(p_item ->> 'accountingQty', '')::numeric, 0);
  v_factor numeric := 1;
begin
  if coalesce(p_item ->> 'fulfillmentBatchId', p_item ->> 'fulfillment_batch_id', '') <> p_batch_id::text
     or coalesce(p_item ->> 'requestLineId', p_item ->> 'request_line_id', '') <> p_request_line_id
     or coalesce(p_item ->> 'itemId', p_item ->> 'item_id', '') <> p_item_id then
    return p_item;
  end if;

  if v_old_qty > 0 and v_old_accounting_qty > 0 then
    v_factor := v_old_qty / v_old_accounting_qty;
  end if;

  v_result := jsonb_set(v_result, '{quantity}', to_jsonb(p_issued_qty), true);
  v_result := jsonb_set(v_result, '{price}', to_jsonb(p_unit_price), true);

  if p_item ? 'accountingQty' then
    v_result := jsonb_set(
      v_result,
      '{accountingQty}',
      to_jsonb(round(p_issued_qty / nullif(v_factor, 0), 6)),
      true
    );
  end if;

  if p_item ? 'accountingPrice' then
    v_result := jsonb_set(
      v_result,
      '{accountingPrice}',
      to_jsonb(round(p_unit_price * v_factor, 6)),
      true
    );
  end if;

  return v_result;
end;
$$ create or replace function public.update_purchase_order_delivery_group_v1(
  p_delivery_group_id uuid,
  p_planned_date timestamptz,
  p_note text,
  p_lines jsonb
)
returns jsonb
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_delivery public.purchase_order_delivery_groups%rowtype;
  v_po public.purchase_orders%rowtype;
  v_line_row public.material_request_fulfillment_lines%rowtype;
  v_batch_row public.material_request_fulfillment_batches%rowtype;
  v_payload jsonb;
  v_payload_count integer := 0;
  v_line_count integer := 0;
  v_issued_qty numeric;
  v_unit_price numeric;
begin
  if p_planned_date is null then
    raise exception 'Ngày giao dự kiến không được để trống.';
  end if;

  if jsonb_typeof(coalesce(p_lines, '[]'::jsonb)) <> 'array' then
    raise exception 'Danh sách vật tư của đợt giao không hợp lệ.';
  end if;

  select *
    into v_delivery
  from public.purchase_order_delivery_groups delivery_group
  where delivery_group.id = p_delivery_group_id
  for update;

  if not found then
    raise exception 'Không tìm thấy đợt giao cần sửa.';
  end if;

  select *
    into v_po
  from public.purchase_orders purchase_order
  where purchase_order.id = v_delivery.purchase_order_id
  for update;

  if not found then
    raise exception 'Không tìm thấy PO của đợt giao.';
  end if;

  if not (
    public.is_admin()
    or nullif(v_po.created_by_id, '') = public.current_app_user_id()::text
  ) then
    raise exception 'Chỉ Admin hoặc người tạo PO được sửa đợt giao này.'
      using errcode = '42501';
  end if;

  if lower(coalesce(v_delivery.status, '')) not in ('draft', 'issued') then
    raise exception 'Chỉ sửa được đợt giao chưa nhập kho và chưa bị huỷ/từ chối.';
  end if;

  perform 1
  from public.material_request_fulfillment_batches batch
  where batch.po_delivery_group_id = p_delivery_group_id
  for update;

  perform 1
  from public.transactions transaction_row
  where transaction_row.id::text in (
    select batch.transaction_id::text
    from public.material_request_fulfillment_batches batch
    where batch.po_delivery_group_id = p_delivery_group_id
      and batch.transaction_id is not null
  )
  for update;

  if exists (
    select 1
    from public.material_request_fulfillment_batches batch
    where batch.po_delivery_group_id = p_delivery_group_id
      and lower(coalesce(batch.status::text, '')) not in ('draft', 'issued')
  ) then
    raise exception 'Đợt giao đã được kho xử lý hoặc đã bị từ chối, không thể sửa.';
  end if;

  if exists (
    select 1
    from public.material_request_fulfillment_batches batch
    join public.transactions transaction_row
      on transaction_row.id::text = batch.transaction_id::text
    where batch.po_delivery_group_id = p_delivery_group_id
      and transaction_row.status <> 'PENDING'::public.transaction_status
  ) then
    raise exception 'Phiếu kho của đợt giao đã được xử lý, không thể sửa.';
  end if;

  if exists (
    select 1
    from public.material_request_fulfillment_lines line
    join public.material_request_fulfillment_batches batch on batch.id = line.batch_id
    where batch.po_delivery_group_id = p_delivery_group_id
      and coalesce(line.received_qty, 0) > 0
  ) then
    raise exception 'Đợt giao đã phát sinh thực nhận, không thể sửa.';
  end if;

  if to_regclass('public.inventory_ledger_entries') is not null
     and exists (
       select 1
       from public.inventory_ledger_entries entry
       where entry.source_type = 'wms_transaction'
         and entry.source_id in (
           select batch.transaction_id::text
           from public.material_request_fulfillment_batches batch
           where batch.po_delivery_group_id = p_delivery_group_id
             and batch.transaction_id is not null
         )
     ) then
    raise exception 'Đợt giao đã phát sinh ledger kho, không thể sửa.';
  end if;

  select count(*)
    into v_line_count
  from public.material_request_fulfillment_lines line
  join public.material_request_fulfillment_batches batch on batch.id = line.batch_id
  where batch.po_delivery_group_id = p_delivery_group_id;

  select count(*)
    into v_payload_count
  from jsonb_array_elements(coalesce(p_lines, '[]'::jsonb));

  if v_payload_count <> v_line_count then
    raise exception 'Không được thêm hoặc xoá dòng vật tư khi sửa đợt giao.';
  end if;

  if (
    select count(distinct value ->> 'id')
    from jsonb_array_elements(coalesce(p_lines, '[]'::jsonb)) payload(value)
  ) <> v_payload_count then
    raise exception 'Danh sách vật tư có dòng bị trùng.';
  end if;

  if exists (
    select 1
    from jsonb_array_elements(coalesce(p_lines, '[]'::jsonb)) payload(value)
    left join public.material_request_fulfillment_lines line
      on line.id::text = payload.value ->> 'id'
    left join public.material_request_fulfillment_batches batch
      on batch.id = line.batch_id
     and batch.po_delivery_group_id = p_delivery_group_id
    where line.id is null or batch.id is null
  ) then
    raise exception 'Có dòng vật tư không thuộc đợt giao này.';
  end if;

  if exists (
    select 1
    from jsonb_array_elements(coalesce(p_lines, '[]'::jsonb)) payload(value)
    where coalesce(payload.value ->> 'issuedQty', '') !~ '^\s*[0-9]+([.][0-9]+)?\s*$'
       or coalesce(payload.value ->> 'deliveryUnitPrice', '') !~ '^\s*[0-9]+([.][0-9]+)?\s*$'
       or (payload.value ->> 'issuedQty')::numeric <= 0
       or (payload.value ->> 'deliveryUnitPrice')::numeric < 0
  ) then
    raise exception 'Số lượng phải lớn hơn 0 và đơn giá không được âm.';
  end if;

  update public.purchase_order_delivery_groups delivery_group
  set planned_date = p_planned_date,
      note = nullif(trim(coalesce(p_note, '')), '')
  where delivery_group.id = p_delivery_group_id;

  for v_payload in
    select value
    from jsonb_array_elements(coalesce(p_lines, '[]'::jsonb)) payload(value)
  loop
    v_issued_qty := (v_payload ->> 'issuedQty')::numeric;
    v_unit_price := (v_payload ->> 'deliveryUnitPrice')::numeric;

    select line.*
      into v_line_row
    from public.material_request_fulfillment_lines line
    join public.material_request_fulfillment_batches batch on batch.id = line.batch_id
    where line.id::text = v_payload ->> 'id'
      and batch.po_delivery_group_id = p_delivery_group_id
    for update of line;

    select *
      into v_batch_row
    from public.material_request_fulfillment_batches batch
    where batch.id = v_line_row.batch_id;

    if v_batch_row.transaction_id is not null and not exists (
      select 1
      from public.transactions transaction_row,
           jsonb_array_elements(coalesce(transaction_row.items, '[]'::jsonb)) transaction_item(value)
      where transaction_row.id::text = v_batch_row.transaction_id::text
        and coalesce(transaction_item.value ->> 'fulfillmentBatchId', transaction_item.value ->> 'fulfillment_batch_id', '') = v_batch_row.id::text
        and coalesce(transaction_item.value ->> 'requestLineId', transaction_item.value ->> 'request_line_id', '') = v_line_row.request_line_id
        and coalesce(transaction_item.value ->> 'itemId', transaction_item.value ->> 'item_id', '') = v_line_row.item_id
    ) then
      raise exception 'Không đồng bộ được dòng vật tư với phiếu kho liên quan.';
    end if;

    update public.material_request_fulfillment_lines line
    set issued_qty = v_issued_qty,
        committed_qty_snapshot = greatest(coalesce(line.committed_qty_snapshot, 0), v_issued_qty),
        delivery_unit_price = v_unit_price
    where line.id = v_line_row.id;

    if v_batch_row.transaction_id is not null then
      update public.transactions transaction_row
      set items = (
        select coalesce(
          jsonb_agg(
            app_private.project_po_update_transaction_delivery_item_v1(
              transaction_item.value,
              v_batch_row.id,
              v_line_row.request_line_id,
              v_line_row.item_id,
              v_issued_qty,
              v_unit_price
            )
            order by transaction_item.ordinality
          ),
          '[]'::jsonb
        )
        from jsonb_array_elements(coalesce(transaction_row.items, '[]'::jsonb))
          with ordinality as transaction_item(value, ordinality)
      )
      where transaction_row.id::text = v_batch_row.transaction_id::text;
    end if;
  end loop;

  return jsonb_build_object(
    'id', v_delivery.id,
    'purchaseOrderId', v_delivery.purchase_order_id,
    'deliveryNo', v_delivery.delivery_no,
    'lineCount', v_line_count,
    'updatedAt', now()
  );
end;
$$ revoke all on function app_private.project_po_update_transaction_delivery_item_v1(jsonb, uuid, text, text, numeric, numeric)
  from public, anon, authenticated revoke all on function public.update_purchase_order_delivery_group_v1(uuid, timestamptz, text, jsonb)
  from public, anon grant execute on function public.update_purchase_order_delivery_group_v1(uuid, timestamptz, text, jsonb)
  to authenticated notify pgrst, 'reload schema']

[-- Chat v2 group administration and message edit/delete guards.

create schema if not exists app_private revoke all on schema app_private from public grant usage on schema app_private to authenticated drop policy if exists chat_v2_participants_insert on public.chat_v2_participants create policy chat_v2_participants_insert
  on public.chat_v2_participants for insert to authenticated
  with check (
    public.is_admin()
    or app_private.chat_v2_can_manage(conversation_id, public.current_app_user_id())
    or exists (
      select 1
      from public.chat_v2_conversations c
      where c.id = chat_v2_participants.conversation_id
        and c.created_by = public.current_app_user_id()
        and c.deleted_at is null
    )
  ) drop policy if exists chat_v2_participants_update on public.chat_v2_participants create policy chat_v2_participants_update
  on public.chat_v2_participants for update to authenticated
  using (
    public.is_admin()
    or user_id = public.current_app_user_id()
    or app_private.chat_v2_can_manage(conversation_id, public.current_app_user_id())
  )
  with check (
    public.is_admin()
    or user_id = public.current_app_user_id()
    or app_private.chat_v2_can_manage(conversation_id, public.current_app_user_id())
  ) drop policy if exists chat_v2_participants_delete on public.chat_v2_participants create policy chat_v2_participants_delete
  on public.chat_v2_participants for delete to authenticated
  using (public.is_admin()) drop policy if exists chat_v2_messages_delete on public.chat_v2_messages create policy chat_v2_messages_delete
  on public.chat_v2_messages for delete to authenticated
  using (public.is_admin()) create or replace function app_private.guard_chat_v2_participant_mutation()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_conversation_id uuid := coalesce(new.conversation_id, old.conversation_id);
  v_conversation_type text;
  v_is_manager boolean;
  v_is_creator boolean;
  v_active_owner_count integer;
begin
  if v_actor is null then
    raise exception 'Không xác định được người dùng hiện tại.';
  end if;

  select c.type, c.created_by = v_actor
  into v_conversation_type, v_is_creator
  from public.chat_v2_conversations c
  where c.id = v_conversation_id
    and c.deleted_at is null;

  if v_conversation_type is null then
    raise exception 'Hội thoại không tồn tại hoặc đã bị xóa.';
  end if;

  if public.is_admin() then
    return coalesce(new, old);
  end if;

  v_is_manager := app_private.chat_v2_can_manage(v_conversation_id, v_actor);

  if tg_op = 'INSERT' then
    if not (v_is_manager or v_is_creator) then
      raise exception 'Bạn không có quyền thêm thành viên vào nhóm này.';
    end if;
    if v_conversation_type = 'direct' and not v_is_creator then
      raise exception 'Không thể thêm thành viên vào hội thoại cá nhân.';
    end if;
    if new.role = 'owner' and not v_is_creator then
      raise exception 'Không thể tự tạo quyền chủ nhóm.';
    end if;
    return new;
  end if;

  if tg_op = 'UPDATE' then
    if new.conversation_id is distinct from old.conversation_id
      or new.user_id is distinct from old.user_id
      or new.joined_at is distinct from old.joined_at then
      raise exception 'Không thể thay đổi danh tính thành viên.';
    end if;

    if old.user_id = v_actor and not v_is_manager then
      if new.role is distinct from old.role then
        raise exception 'Bạn không thể tự thay đổi quyền nhóm.';
      end if;
      if old.role = 'owner' and old.left_at is null and new.left_at is not null then
        select count(*)
        into v_active_owner_count
        from public.chat_v2_participants p
        where p.conversation_id = old.conversation_id
          and p.role = 'owner'
          and p.left_at is null
          and p.user_id <> old.user_id;
        if coalesce(v_active_owner_count, 0) = 0 then
          raise exception 'Không thể rời nhóm khi bạn là chủ nhóm cuối cùng.';
        end if;
      end if;
      return new;
    end if;

    if not v_is_manager then
      raise exception 'Bạn không có quyền quản trị thành viên nhóm này.';
    end if;

    if v_conversation_type = 'direct' and (
      new.role is distinct from old.role
      or new.left_at is distinct from old.left_at
      or new.user_id is distinct from old.user_id
    ) then
      raise exception 'Không thể quản trị thành viên trong hội thoại cá nhân.';
    end if;

    if new.role = 'owner' and old.role is distinct from 'owner' then
      raise exception 'Chỉ được gán quyền quản trị viên nhóm, không được tạo thêm chủ nhóm.';
    end if;

    if old.role = 'owner' and (
      new.role is distinct from 'owner'
      or (old.left_at is null and new.left_at is not null)
    ) then
      select count(*)
      into v_active_owner_count
      from public.chat_v2_participants p
      where p.conversation_id = old.conversation_id
        and p.role = 'owner'
        and p.left_at is null
        and p.user_id <> old.user_id;
      if coalesce(v_active_owner_count, 0) = 0 then
        raise exception 'Không thể hạ quyền hoặc loại bỏ chủ nhóm cuối cùng.';
      end if;
    end if;

    return new;
  end if;

  if tg_op = 'DELETE' then
    raise exception 'Không xóa cứng thành viên chat; hãy dùng left_at để loại khỏi nhóm.';
  end if;

  return coalesce(new, old);
end;
$$ drop trigger if exists trg_guard_chat_v2_participant_mutation on public.chat_v2_participants create trigger trg_guard_chat_v2_participant_mutation
  before insert or update or delete on public.chat_v2_participants
  for each row execute function app_private.guard_chat_v2_participant_mutation() create or replace function app_private.guard_chat_v2_message_update()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_is_manager boolean;
begin
  if v_actor is null then
    raise exception 'Không xác định được người dùng hiện tại.';
  end if;

  if public.is_admin() then
    return new;
  end if;

  if new.conversation_id is distinct from old.conversation_id
    or new.sender_id is distinct from old.sender_id
    or new.kind is distinct from old.kind
    or new.reply_to_message_id is distinct from old.reply_to_message_id
    or new.created_at is distinct from old.created_at then
    raise exception 'Không thể thay đổi dữ liệu gốc của tin nhắn.';
  end if;

  if old.deleted_at is not null and new.deleted_at is null then
    raise exception 'Không thể khôi phục tin nhắn đã xóa.';
  end if;

  v_is_manager := app_private.chat_v2_can_manage(old.conversation_id, v_actor);

  if new.body is distinct from old.body or new.edited_at is distinct from old.edited_at then
    if old.sender_id <> v_actor then
      raise exception 'Bạn chỉ có thể sửa tin nhắn của mình.';
    end if;
    if old.deleted_at is not null then
      raise exception 'Không thể sửa tin nhắn đã xóa.';
    end if;
  end if;

  if new.deleted_at is distinct from old.deleted_at or new.deleted_by is distinct from old.deleted_by then
    if old.sender_id <> v_actor and not v_is_manager then
      raise exception 'Bạn không có quyền xóa tin nhắn này.';
    end if;
    if new.deleted_at is not null and new.deleted_by is distinct from v_actor then
      raise exception 'Người xóa tin nhắn không hợp lệ.';
    end if;
  end if;

  return new;
end;
$$ drop trigger if exists trg_guard_chat_v2_message_update on public.chat_v2_messages create trigger trg_guard_chat_v2_message_update
  before update on public.chat_v2_messages
  for each row execute function app_private.guard_chat_v2_message_update() revoke all on function app_private.guard_chat_v2_participant_mutation() from public revoke all on function app_private.guard_chat_v2_message_update() from public notify pgrst, 'reload schema']

[-- Chat v2 structured messages and participant-scoped realtime inbox cache.

create schema if not exists app_private revoke all on schema app_private from public grant usage on schema app_private to authenticated alter table public.chat_v2_messages
  drop constraint if exists chat_v2_messages_kind_check alter table public.chat_v2_messages
  add constraint chat_v2_messages_kind_check
  check (kind in ('text', 'image', 'file', 'poll', 'checklist', 'quick_confirm', 'system')) alter table public.chat_v2_participants
  add column if not exists last_message_id uuid references public.chat_v2_messages(id) on delete set null,
  add column if not exists last_message_preview text,
  add column if not exists last_message_at timestamptz,
  add column if not exists last_message_sender_id uuid references public.users(id) on delete set null,
  add column if not exists unread_count integer not null default 0 alter table public.chat_v2_participants
  drop constraint if exists chat_v2_participants_unread_nonnegative alter table public.chat_v2_participants
  add constraint chat_v2_participants_unread_nonnegative
  check (unread_count >= 0) create table if not exists public.chat_v2_poll_votes (
  id uuid primary key default gen_random_uuid(),
  conversation_id uuid not null references public.chat_v2_conversations(id) on delete cascade,
  message_id uuid not null references public.chat_v2_messages(id) on delete cascade,
  option_id text not null,
  user_id uuid not null references public.users(id) on delete cascade,
  created_at timestamptz not null default now(),
  unique (message_id, option_id, user_id)
) create table if not exists public.chat_v2_checklist_items (
  id uuid primary key default gen_random_uuid(),
  conversation_id uuid not null references public.chat_v2_conversations(id) on delete cascade,
  message_id uuid not null references public.chat_v2_messages(id) on delete cascade,
  content text not null,
  sort_order integer not null default 0,
  is_done boolean not null default false,
  done_by uuid references public.users(id) on delete set null,
  done_at timestamptz,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
) create table if not exists public.chat_v2_quick_confirm_responses (
  id uuid primary key default gen_random_uuid(),
  conversation_id uuid not null references public.chat_v2_conversations(id) on delete cascade,
  message_id uuid not null references public.chat_v2_messages(id) on delete cascade,
  option_id text not null,
  user_id uuid not null references public.users(id) on delete cascade,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (message_id, user_id)
) create index if not exists idx_chat_v2_participants_user_inbox
  on public.chat_v2_participants(user_id, left_at, last_message_at desc nulls last, updated_at desc) create index if not exists idx_chat_v2_messages_conversation_created
  on public.chat_v2_messages(conversation_id, created_at desc, id desc)
  where deleted_at is null create index if not exists idx_chat_v2_poll_votes_message
  on public.chat_v2_poll_votes(message_id, option_id) create index if not exists idx_chat_v2_poll_votes_conversation
  on public.chat_v2_poll_votes(conversation_id, created_at desc) create index if not exists idx_chat_v2_checklist_items_message
  on public.chat_v2_checklist_items(message_id, sort_order, created_at) create index if not exists idx_chat_v2_checklist_items_conversation
  on public.chat_v2_checklist_items(conversation_id, updated_at desc) create index if not exists idx_chat_v2_quick_confirm_message
  on public.chat_v2_quick_confirm_responses(message_id, option_id) create index if not exists idx_chat_v2_quick_confirm_conversation
  on public.chat_v2_quick_confirm_responses(conversation_id, updated_at desc) drop trigger if exists trg_chat_v2_checklist_items_updated_at on public.chat_v2_checklist_items create trigger trg_chat_v2_checklist_items_updated_at
  before update on public.chat_v2_checklist_items
  for each row execute function public.set_updated_at() drop trigger if exists trg_chat_v2_quick_confirm_updated_at on public.chat_v2_quick_confirm_responses create trigger trg_chat_v2_quick_confirm_updated_at
  before update on public.chat_v2_quick_confirm_responses
  for each row execute function public.set_updated_at() create or replace function app_private.chat_v2_message_preview(
  p_kind text,
  p_body text,
  p_metadata jsonb
)
returns text
language sql
immutable
set search_path = ''
as $$
  select left(
    coalesce(
      nullif(trim(p_body), ''),
      case coalesce(p_kind, 'text')
        when 'image' then 'Hình ảnh'
        when 'file' then 'Tệp đính kèm'
        when 'poll' then 'Bình chọn: ' || coalesce(nullif(trim(p_metadata->>'question'), ''), nullif(trim(p_metadata->>'title'), ''), 'Chưa có tiêu đề')
        when 'checklist' then 'Checklist: ' || coalesce(nullif(trim(p_metadata->>'title'), ''), 'Chưa có tiêu đề')
        when 'quick_confirm' then 'Xác nhận: ' || coalesce(nullif(trim(p_metadata->>'title'), ''), 'Chưa có tiêu đề')
        when 'system' then 'Cập nhật hệ thống'
        else 'Tin nhắn'
      end
    ),
    240
  );
$$ revoke all on function app_private.chat_v2_message_preview(text, text, jsonb) from public grant execute on function app_private.chat_v2_message_preview(text, text, jsonb) to authenticated create or replace function app_private.chat_v2_latest_message(p_conversation_id uuid)
returns public.chat_v2_messages
language sql
stable
security definer
set search_path = ''
as $$
  select m
  from public.chat_v2_messages m
  where m.conversation_id = p_conversation_id
    and m.deleted_at is null
  order by m.created_at desc, m.id desc
  limit 1;
$$ revoke all on function app_private.chat_v2_latest_message(uuid) from public grant execute on function app_private.chat_v2_latest_message(uuid) to authenticated create or replace function app_private.chat_v2_sync_participant_inbox(
  p_conversation_id uuid,
  p_increment_unread boolean default false,
  p_sender_id uuid default null
)
returns void
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_message public.chat_v2_messages%rowtype;
  v_preview text;
begin
  select *
  into v_message
  from app_private.chat_v2_latest_message(p_conversation_id);

  if v_message.id is null then
    update public.chat_v2_conversations
    set last_message_id = null,
        last_message_at = null,
        last_message_preview = null,
        last_message_sender_id = null,
        updated_at = now()
    where id = p_conversation_id;

    update public.chat_v2_participants
    set last_message_id = null,
        last_message_at = null,
        last_message_preview = null,
        last_message_sender_id = null,
        unread_count = 0,
        updated_at = now()
    where conversation_id = p_conversation_id;
    return;
  end if;

  v_preview := app_private.chat_v2_message_preview(v_message.kind, v_message.body, v_message.metadata);

  update public.chat_v2_conversations
  set last_message_id = v_message.id,
      last_message_at = v_message.created_at,
      last_message_preview = v_preview,
      last_message_sender_id = v_message.sender_id,
      updated_at = now()
  where id = p_conversation_id;

  update public.chat_v2_participants p
  set last_message_id = v_message.id,
      last_message_at = v_message.created_at,
      last_message_preview = v_preview,
      last_message_sender_id = v_message.sender_id,
      unread_count = case
        when p_increment_unread
          and p_sender_id is not null
          and p.user_id <> p_sender_id
          and p.left_at is null
          and coalesce(p.is_muted, false) is false
        then p.unread_count + 1
        when p.last_read_at is not null and p.last_read_at >= v_message.created_at then 0
        else p.unread_count
      end,
      updated_at = now()
  where p.conversation_id = p_conversation_id;
end;
$$ revoke all on function app_private.chat_v2_sync_participant_inbox(uuid, boolean, uuid) from public grant execute on function app_private.chat_v2_sync_participant_inbox(uuid, boolean, uuid) to authenticated create or replace function app_private.guard_chat_v2_participant_mutation()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_conversation_id uuid := coalesce(new.conversation_id, old.conversation_id);
  v_conversation_type text;
  v_is_manager boolean;
  v_is_creator boolean;
  v_active_owner_count integer;
begin
  if tg_op = 'UPDATE'
    and new.conversation_id is not distinct from old.conversation_id
    and new.user_id is not distinct from old.user_id
    and new.role is not distinct from old.role
    and new.is_muted is not distinct from old.is_muted
    and new.is_pinned is not distinct from old.is_pinned
    and new.last_read_message_id is not distinct from old.last_read_message_id
    and new.last_read_at is not distinct from old.last_read_at
    and new.joined_at is not distinct from old.joined_at
    and new.left_at is not distinct from old.left_at
    and new.created_at is not distinct from old.created_at then
    return new;
  end if;

  if v_actor is null then
    raise exception 'Không xác định được người dùng hiện tại.';
  end if;

  select c.type, c.created_by = v_actor
  into v_conversation_type, v_is_creator
  from public.chat_v2_conversations c
  where c.id = v_conversation_id
    and c.deleted_at is null;

  if v_conversation_type is null then
    raise exception 'Hội thoại không tồn tại hoặc đã bị xóa.';
  end if;

  if public.is_admin() then
    return coalesce(new, old);
  end if;

  v_is_manager := app_private.chat_v2_can_manage(v_conversation_id, v_actor);

  if tg_op = 'INSERT' then
    if not (v_is_manager or v_is_creator) then
      raise exception 'Bạn không có quyền thêm thành viên vào nhóm này.';
    end if;
    if v_conversation_type = 'direct' and not v_is_creator then
      raise exception 'Không thể thêm thành viên vào hội thoại cá nhân.';
    end if;
    if new.role = 'owner' and not v_is_creator then
      raise exception 'Không thể tự tạo quyền chủ nhóm.';
    end if;
    return new;
  end if;

  if tg_op = 'UPDATE' then
    if new.conversation_id is distinct from old.conversation_id
      or new.user_id is distinct from old.user_id
      or new.joined_at is distinct from old.joined_at then
      raise exception 'Không thể thay đổi danh tính thành viên.';
    end if;

    if old.user_id = v_actor and not v_is_manager then
      if new.role is distinct from old.role then
        raise exception 'Bạn không thể tự thay đổi quyền nhóm.';
      end if;
      if old.role = 'owner' and old.left_at is null and new.left_at is not null then
        select count(*)
        into v_active_owner_count
        from public.chat_v2_participants p
        where p.conversation_id = old.conversation_id
          and p.role = 'owner'
          and p.left_at is null
          and p.user_id <> old.user_id;
        if coalesce(v_active_owner_count, 0) = 0 then
          raise exception 'Không thể rời nhóm khi bạn là chủ nhóm cuối cùng.';
        end if;
      end if;
      return new;
    end if;

    if not v_is_manager then
      raise exception 'Bạn không có quyền quản trị thành viên nhóm này.';
    end if;

    if v_conversation_type = 'direct' and (
      new.role is distinct from old.role
      or new.left_at is distinct from old.left_at
      or new.user_id is distinct from old.user_id
    ) then
      raise exception 'Không thể quản trị thành viên trong hội thoại cá nhân.';
    end if;

    if new.role = 'owner' and old.role is distinct from 'owner' then
      raise exception 'Chỉ được gán quyền quản trị viên nhóm, không được tạo thêm chủ nhóm.';
    end if;

    if old.role = 'owner' and (
      new.role is distinct from 'owner'
      or (old.left_at is null and new.left_at is not null)
    ) then
      select count(*)
      into v_active_owner_count
      from public.chat_v2_participants p
      where p.conversation_id = old.conversation_id
        and p.role = 'owner'
        and p.left_at is null
        and p.user_id <> old.user_id;
      if coalesce(v_active_owner_count, 0) = 0 then
        raise exception 'Không thể hạ quyền hoặc loại bỏ chủ nhóm cuối cùng.';
      end if;
    end if;

    return new;
  end if;

  if tg_op = 'DELETE' then
    raise exception 'Không xóa cứng thành viên chat; hãy dùng left_at để loại khỏi nhóm.';
  end if;

  return coalesce(new, old);
end;
$$ drop trigger if exists trg_guard_chat_v2_participant_mutation on public.chat_v2_participants create trigger trg_guard_chat_v2_participant_mutation
  before insert or update or delete on public.chat_v2_participants
  for each row execute function app_private.guard_chat_v2_participant_mutation() create or replace function app_private.chat_v2_touch_conversation_message()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if tg_op = 'INSERT' then
    perform app_private.chat_v2_sync_participant_inbox(new.conversation_id, true, new.sender_id);
    return new;
  end if;

  if tg_op = 'UPDATE' then
    perform app_private.chat_v2_sync_participant_inbox(new.conversation_id, false, new.sender_id);
    return new;
  end if;

  if tg_op = 'DELETE' then
    perform app_private.chat_v2_sync_participant_inbox(old.conversation_id, false, old.sender_id);
    return old;
  end if;

  return coalesce(new, old);
end;
$$ drop trigger if exists trg_chat_v2_touch_conversation_message on public.chat_v2_messages create trigger trg_chat_v2_touch_conversation_message
  after insert or update of body, kind, metadata, deleted_at or delete on public.chat_v2_messages
  for each row execute function app_private.chat_v2_touch_conversation_message() create or replace function app_private.guard_chat_v2_message_update()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_is_manager boolean;
begin
  if v_actor is null then
    raise exception 'Không xác định được người dùng hiện tại.';
  end if;

  if public.is_admin() then
    return new;
  end if;

  if new.conversation_id is distinct from old.conversation_id
    or new.sender_id is distinct from old.sender_id
    or new.kind is distinct from old.kind
    or new.reply_to_message_id is distinct from old.reply_to_message_id
    or new.created_at is distinct from old.created_at then
    raise exception 'Không thể thay đổi dữ liệu gốc của tin nhắn.';
  end if;

  if old.deleted_at is not null and new.deleted_at is null then
    raise exception 'Không thể khôi phục tin nhắn đã xóa.';
  end if;

  v_is_manager := app_private.chat_v2_can_manage(old.conversation_id, v_actor);

  if new.body is distinct from old.body
    or new.metadata is distinct from old.metadata
    or new.edited_at is distinct from old.edited_at then
    if old.sender_id <> v_actor then
      raise exception 'Bạn chỉ có thể sửa tin nhắn của mình.';
    end if;
    if old.deleted_at is not null then
      raise exception 'Không thể sửa tin nhắn đã xóa.';
    end if;
  end if;

  if new.deleted_at is distinct from old.deleted_at or new.deleted_by is distinct from old.deleted_by then
    if old.sender_id <> v_actor and not v_is_manager then
      raise exception 'Bạn không có quyền xóa tin nhắn này.';
    end if;
    if new.deleted_at is not null and new.deleted_by is distinct from v_actor then
      raise exception 'Người xóa tin nhắn không hợp lệ.';
    end if;
  end if;

  return new;
end;
$$ drop trigger if exists trg_guard_chat_v2_message_update on public.chat_v2_messages create trigger trg_guard_chat_v2_message_update
  before update on public.chat_v2_messages
  for each row execute function app_private.guard_chat_v2_message_update() create or replace function app_private.guard_chat_v2_structured_message_link()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_conversation_id uuid;
begin
  select m.conversation_id
  into v_conversation_id
  from public.chat_v2_messages m
  where m.id = coalesce(new.message_id, old.message_id);

  if v_conversation_id is null then
    raise exception 'Tin nhắn không tồn tại.';
  end if;

  if tg_op in ('INSERT', 'UPDATE') and new.conversation_id is distinct from v_conversation_id then
    raise exception 'Dữ liệu tương tác không thuộc hội thoại của tin nhắn.';
  end if;

  return coalesce(new, old);
end;
$$ drop trigger if exists trg_guard_chat_v2_poll_vote_link on public.chat_v2_poll_votes create trigger trg_guard_chat_v2_poll_vote_link
  before insert or update on public.chat_v2_poll_votes
  for each row execute function app_private.guard_chat_v2_structured_message_link() drop trigger if exists trg_guard_chat_v2_checklist_item_link on public.chat_v2_checklist_items create trigger trg_guard_chat_v2_checklist_item_link
  before insert or update on public.chat_v2_checklist_items
  for each row execute function app_private.guard_chat_v2_structured_message_link() drop trigger if exists trg_guard_chat_v2_quick_confirm_link on public.chat_v2_quick_confirm_responses create trigger trg_guard_chat_v2_quick_confirm_link
  before insert or update on public.chat_v2_quick_confirm_responses
  for each row execute function app_private.guard_chat_v2_structured_message_link() alter table public.chat_v2_poll_votes enable row level security alter table public.chat_v2_checklist_items enable row level security alter table public.chat_v2_quick_confirm_responses enable row level security drop policy if exists chat_v2_poll_votes_select on public.chat_v2_poll_votes create policy chat_v2_poll_votes_select
  on public.chat_v2_poll_votes for select to authenticated
  using (
    public.is_admin()
    or app_private.chat_v2_is_participant(conversation_id, public.current_app_user_id())
  ) drop policy if exists chat_v2_poll_votes_insert on public.chat_v2_poll_votes create policy chat_v2_poll_votes_insert
  on public.chat_v2_poll_votes for insert to authenticated
  with check (
    public.is_admin()
    or (
      user_id = public.current_app_user_id()
      and app_private.chat_v2_is_participant(conversation_id, public.current_app_user_id())
    )
  ) drop policy if exists chat_v2_poll_votes_delete on public.chat_v2_poll_votes create policy chat_v2_poll_votes_delete
  on public.chat_v2_poll_votes for delete to authenticated
  using (public.is_admin() or user_id = public.current_app_user_id()) drop policy if exists chat_v2_checklist_items_select on public.chat_v2_checklist_items create policy chat_v2_checklist_items_select
  on public.chat_v2_checklist_items for select to authenticated
  using (
    public.is_admin()
    or app_private.chat_v2_is_participant(conversation_id, public.current_app_user_id())
  ) drop policy if exists chat_v2_checklist_items_insert on public.chat_v2_checklist_items create policy chat_v2_checklist_items_insert
  on public.chat_v2_checklist_items for insert to authenticated
  with check (
    public.is_admin()
    or app_private.chat_v2_is_participant(conversation_id, public.current_app_user_id())
  ) drop policy if exists chat_v2_checklist_items_update on public.chat_v2_checklist_items create policy chat_v2_checklist_items_update
  on public.chat_v2_checklist_items for update to authenticated
  using (
    public.is_admin()
    or app_private.chat_v2_is_participant(conversation_id, public.current_app_user_id())
  )
  with check (
    public.is_admin()
    or app_private.chat_v2_is_participant(conversation_id, public.current_app_user_id())
  ) drop policy if exists chat_v2_quick_confirm_select on public.chat_v2_quick_confirm_responses create policy chat_v2_quick_confirm_select
  on public.chat_v2_quick_confirm_responses for select to authenticated
  using (
    public.is_admin()
    or app_private.chat_v2_is_participant(conversation_id, public.current_app_user_id())
  ) drop policy if exists chat_v2_quick_confirm_insert on public.chat_v2_quick_confirm_responses create policy chat_v2_quick_confirm_insert
  on public.chat_v2_quick_confirm_responses for insert to authenticated
  with check (
    public.is_admin()
    or (
      user_id = public.current_app_user_id()
      and app_private.chat_v2_is_participant(conversation_id, public.current_app_user_id())
    )
  ) drop policy if exists chat_v2_quick_confirm_update on public.chat_v2_quick_confirm_responses create policy chat_v2_quick_confirm_update
  on public.chat_v2_quick_confirm_responses for update to authenticated
  using (public.is_admin() or user_id = public.current_app_user_id())
  with check (
    public.is_admin()
    or (
      user_id = public.current_app_user_id()
      and app_private.chat_v2_is_participant(conversation_id, public.current_app_user_id())
    )
  ) grant select, insert, delete on table public.chat_v2_poll_votes to authenticated grant select, insert, update on table public.chat_v2_checklist_items to authenticated grant select, insert, update on table public.chat_v2_quick_confirm_responses to authenticated alter table public.chat_v2_poll_votes replica identity full alter table public.chat_v2_checklist_items replica identity full alter table public.chat_v2_quick_confirm_responses replica identity full do $$
declare
  v_table text;
begin
  foreach v_table in array array[
    'chat_v2_poll_votes',
    'chat_v2_checklist_items',
    'chat_v2_quick_confirm_responses'
  ]
  loop
    if exists (select 1 from pg_publication where pubname = 'supabase_realtime')
       and not exists (
         select 1
         from pg_publication_tables
         where pubname = 'supabase_realtime'
           and schemaname = 'public'
           and tablename = v_table
       ) then
      execute format('alter publication supabase_realtime add table public.%I', v_table);
    end if;
  end loop;
end $$ update public.chat_v2_participants p
set last_message_id = c.last_message_id,
    last_message_at = c.last_message_at,
    last_message_preview = c.last_message_preview,
    last_message_sender_id = c.last_message_sender_id,
    unread_count = coalesce((
      select count(*)::integer
      from public.chat_v2_messages m
      where m.conversation_id = p.conversation_id
        and m.deleted_at is null
        and m.sender_id <> p.user_id
        and (p.last_read_at is null or m.created_at > p.last_read_at)
    ), 0),
    updated_at = now()
from public.chat_v2_conversations c
where c.id = p.conversation_id notify pgrst, 'reload schema']

[-- Safety equipment document checklist
-- Reuses safety_equipment_documents as the per-equipment missing-document checklist.

alter table public.safety_equipment_documents
  add column if not exists is_done boolean not null default false,
  add column if not exists done_by text,
  add column if not exists done_at timestamptz,
  add column if not exists sort_order integer not null default 0 update public.safety_equipment_documents
set
  is_done = true,
  done_at = coalesce(done_at, updated_at, created_at)
where status in ('submitted', 'approved')
  and is_done is distinct from true create index if not exists idx_safety_equipment_documents_checklist_order
  on public.safety_equipment_documents(equipment_id, sort_order, created_at) create or replace function app_private.sync_safety_equipment_documents_status(p_equipment_id uuid)
returns void
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_total integer;
  v_done integer;
  v_next_status text;
begin
  if p_equipment_id is null then
    return;
  end if;

  select count(*), count(*) filter (where is_done)
    into v_total, v_done
  from public.safety_equipment_documents
  where equipment_id = p_equipment_id;

  v_next_status := case
    when coalesce(v_total, 0) = 0 then 'missing'
    when v_done = v_total then 'complete'
    else 'partial'
  end;

  update public.safety_equipment
  set documents_status = v_next_status,
      updated_at = now()
  where id = p_equipment_id
    and documents_status is distinct from v_next_status;
end;
$$ create or replace function app_private.normalize_safety_equipment_document_checklist()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if new.is_done then
    new.done_at := coalesce(new.done_at, now());
    new.done_by := coalesce(new.done_by, public.current_app_user_id()::text);
    if new.status = 'missing' then
      new.status := 'submitted';
    end if;
  else
    new.done_at := null;
    new.done_by := null;
    if new.status in ('submitted', 'approved') then
      new.status := 'missing';
    end if;
  end if;

  return new;
end;
$$ create or replace function app_private.touch_safety_equipment_document_checklist()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if tg_op = 'DELETE' then
    perform app_private.sync_safety_equipment_documents_status(old.equipment_id);
    return old;
  end if;

  perform app_private.sync_safety_equipment_documents_status(new.equipment_id);
  if tg_op = 'UPDATE' and old.equipment_id is distinct from new.equipment_id then
    perform app_private.sync_safety_equipment_documents_status(old.equipment_id);
  end if;
  return new;
end;
$$ drop trigger if exists trg_safety_equipment_documents_checklist_normalize on public.safety_equipment_documents create trigger trg_safety_equipment_documents_checklist_normalize
before insert or update of is_done, done_by, done_at, status on public.safety_equipment_documents
for each row execute function app_private.normalize_safety_equipment_document_checklist() drop trigger if exists trg_safety_equipment_documents_checklist_status on public.safety_equipment_documents create trigger trg_safety_equipment_documents_checklist_status
after insert or update of equipment_id, is_done, status or delete on public.safety_equipment_documents
for each row execute function app_private.touch_safety_equipment_document_checklist() do $$
declare
  v_equipment_id uuid;
begin
  for v_equipment_id in
    select id from public.safety_equipment
  loop
    perform app_private.sync_safety_equipment_documents_status(v_equipment_id);
  end loop;
end $$]

[-- Fix Safety Passport recompute trigger shared by worker profiles and certificates.

create or replace function app_private.touch_safety_worker_assignment_eligibility()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_new_worker_id uuid;
  v_old_worker_id uuid;
begin
  if tg_table_name = 'safety_worker_profiles' then
    v_new_worker_id := case when tg_op = 'DELETE' then null else new.id end;
    v_old_worker_id := case when tg_op = 'INSERT' then null else old.id end;
  else
    v_new_worker_id := case when tg_op = 'DELETE' then null else new.worker_id end;
    v_old_worker_id := case when tg_op = 'INSERT' then null else old.worker_id end;
  end if;

  if tg_op = 'DELETE' then
    perform app_private.recompute_safety_worker_assignments(v_old_worker_id);
    return old;
  end if;

  perform app_private.recompute_safety_worker_assignments(v_new_worker_id);
  if tg_op = 'UPDATE' and v_old_worker_id is distinct from v_new_worker_id then
    perform app_private.recompute_safety_worker_assignments(v_old_worker_id);
  end if;
  return new;
end;
$$]

[-- Safety Passport worker list/detail extensions.
-- Adds worker identity fields, project access fields, canonical documents,
-- and extends eligibility checks with health check + insurance documents.

alter table public.safety_worker_profiles
  add column if not exists date_of_birth date,
  add column if not exists identity_issue_place text,
  add column if not exists permanent_address text;

alter table public.safety_project_assignments
  add column if not exists site_access_card_code text,
  add column if not exists work_type text;

create unique index if not exists idx_safety_worker_documents_canonical_unique
  on public.safety_worker_documents(worker_id, document_type)
  where document_type in ('identity_front', 'identity_back', 'health_check', 'insurance', 'safety_card');

create index if not exists idx_safety_worker_documents_type_expiry
  on public.safety_worker_documents(document_type, expiry_date)
  where document_type in ('health_check', 'insurance', 'safety_card');

create index if not exists idx_safety_project_assignments_access_card
  on public.safety_project_assignments(site_access_card_code)
  where site_access_card_code is not null;

create or replace function app_private.safety_assignment_eligibility_status(p_assignment_id uuid)
returns text
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_assignment public.safety_project_assignments%rowtype;
  v_worker public.safety_worker_profiles%rowtype;
  v_required_count integer := 0;
  v_missing_count integer := 0;
  v_expired_count integer := 0;
  v_required_document_missing_count integer := 0;
begin
  select * into v_assignment
  from public.safety_project_assignments
  where id = p_assignment_id;

  if not found then
    return 'missing_profile';
  end if;

  select * into v_worker
  from public.safety_worker_profiles
  where id = v_assignment.worker_id;

  if not found then
    return 'missing_profile';
  end if;

  if v_worker.status = 'suspended' or v_assignment.is_locked then
    return 'suspended';
  end if;

  if v_worker.status <> 'active'
    or nullif(trim(v_worker.full_name), '') is null
    or nullif(trim(v_worker.worker_code), '') is null
    or v_worker.photo_attachment = 'null'::jsonb
    or nullif(trim(coalesce(v_worker.identity_number, '')), '') is null
    or jsonb_array_length(coalesce(v_worker.identity_attachments, '[]'::jsonb)) = 0
  then
    return 'missing_profile';
  end if;

  with required_documents(document_type) as (
    values ('health_check'), ('insurance')
  ),
  document_state as (
    select rd.document_type,
           swd.id,
           swd.status,
           swd.expiry_date,
           swd.attachments
    from required_documents rd
    left join lateral (
      select d.*
      from public.safety_worker_documents d
      where d.worker_id = v_worker.id
        and d.document_type = rd.document_type
        and d.status <> 'rejected'
      order by d.expiry_date desc nulls last, d.created_at desc
      limit 1
    ) swd on true
  )
  select count(*)
    into v_required_document_missing_count
  from document_state
  where id is null
    or status in ('missing', 'expired', 'rejected')
    or jsonb_array_length(coalesce(attachments, '[]'::jsonb)) = 0
    or (expiry_date is not null and expiry_date < current_date);

  if v_required_document_missing_count > 0 then
    return 'missing_profile';
  end if;

  select count(*)
    into v_required_count
  from public.safety_certificate_types sct
  where sct.is_active
    and sct.is_required_default
    and app_private.safety_required_certificate_type_applies(sct.applies_to_roles, coalesce(v_assignment.role_name, v_worker.role_name));

  if v_required_count > 0 then
    select
      count(*) filter (where swc.id is null),
      count(*) filter (where swc.id is not null and coalesce(swc.status, 'submitted') <> 'rejected' and swc.expiry_date is not null and swc.expiry_date < current_date)
      into v_missing_count, v_expired_count
    from public.safety_certificate_types sct
    left join lateral (
      select c.*
      from public.safety_worker_certificates c
      where c.worker_id = v_worker.id
        and c.certificate_type_id = sct.id
        and c.status <> 'rejected'
      order by c.expiry_date desc nulls last, c.created_at desc
      limit 1
    ) swc on true
    where sct.is_active
      and sct.is_required_default
      and app_private.safety_required_certificate_type_applies(sct.applies_to_roles, coalesce(v_assignment.role_name, v_worker.role_name));

    if v_missing_count > 0 then
      return 'missing_certificate';
    end if;
    if v_expired_count > 0 then
      return 'expired_certificate';
    end if;
  end if;

  if v_assignment.site_training_status <> 'completed'
    or v_assignment.commitment_status <> 'signed'
    or v_assignment.ppe_status <> 'complete'
    or v_assignment.toolbox_status <> 'completed'
  then
    return 'missing_site_requirement';
  end if;

  return 'eligible';
end;
$$;

drop trigger if exists trg_safety_assignment_recompute on public.safety_project_assignments;
create trigger trg_safety_assignment_recompute
after insert or update of worker_id, role_name, work_type, site_training_status, commitment_status, ppe_status, toolbox_status, is_locked
on public.safety_project_assignments
for each row execute function app_private.touch_safety_assignment_eligibility();

drop trigger if exists trg_safety_worker_profile_recompute on public.safety_worker_profiles;
create trigger trg_safety_worker_profile_recompute
after update of full_name, worker_code, photo_attachment, identity_number, identity_attachments, date_of_birth, identity_issue_place, permanent_address, status, role_name
on public.safety_worker_profiles
for each row execute function app_private.touch_safety_worker_assignment_eligibility();

drop trigger if exists trg_safety_worker_document_recompute on public.safety_worker_documents;
create trigger trg_safety_worker_document_recompute
after insert or update or delete on public.safety_worker_documents
for each row execute function app_private.touch_safety_worker_assignment_eligibility();
]

