create or replace function app_private.remove_project_staff_assignment(
  p_staff_id uuid
)
returns jsonb
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_staff public.project_staff%rowtype;
begin
  select *
  into v_staff
  from public.project_staff
  where id = p_staff_id;

  if v_staff.id is null then
    raise exception 'Project staff row does not exist: %', p_staff_id
      using errcode = 'P0002';
  end if;

  if not app_private.can_manage_project_staff_assignment(v_staff.project_id, v_staff.construction_site_id) then
    raise exception 'Not allowed to remove this project staff assignment'
      using errcode = '42501';
  end if;

  perform app_private.deactivate_project_staff_scoped_grants(v_staff);

  if v_staff.user_id ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then
    delete from public.user_permission_grants
    where user_id = v_staff.user_id::uuid
      and permission_code like 'project.%'
      and scope_type = app_private.project_staff_scope_type(v_staff.construction_site_id)
      and scope_id = app_private.project_staff_scope_id(v_staff.project_id, v_staff.construction_site_id);
  end if;

  delete from public.project_staff
  where id = p_staff_id;

  insert into public.permission_audit_events (
    actor_user_id,
    target_user_id,
    event_type,
    metadata
  )
  values (
    public.current_app_user_id(),
    case when v_staff.user_id ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then v_staff.user_id::uuid else null end,
    'remove_project_staff_assignment',
    jsonb_build_object(
      'staff_id', p_staff_id,
      'project_id', v_staff.project_id,
      'construction_site_id', v_staff.construction_site_id
    )
  );

  return to_jsonb(v_staff);
end;
$$;

revoke all on function app_private.remove_project_staff_assignment(uuid) from public;
revoke all on function app_private.remove_project_staff_assignment(uuid) from anon;
grant execute on function app_private.remove_project_staff_assignment(uuid) to authenticated;

create or replace function public.remove_project_staff_assignment(
  p_staff_id uuid
)
returns jsonb
language sql
volatile
security invoker
set search_path = ''
as $$
  select app_private.remove_project_staff_assignment(p_staff_id);
$$;

revoke all on function public.remove_project_staff_assignment(uuid) from public;
revoke all on function public.remove_project_staff_assignment(uuid) from anon;
grant execute on function public.remove_project_staff_assignment(uuid) to authenticated;

do $$
declare
  tbl text;
  policy_name text;
begin
  foreach tbl in array array['project_staff', 'project_staff_permissions']
  loop
    if to_regclass(format('public.%I', tbl)) is null then
      continue;
    end if;

    execute format('alter table public.%I enable row level security', tbl);
    execute format('revoke all privileges on table public.%I from public', tbl);
    execute format('revoke all privileges on table public.%I from anon', tbl);
    execute format('revoke all privileges on table public.%I from authenticated', tbl);
    execute format('grant select on table public.%I to authenticated', tbl);

    for policy_name in
      select policyname
      from pg_policies
      where schemaname = 'public'
        and tablename = tbl
    loop
      execute format('drop policy if exists %I on public.%I', policy_name, tbl);
    end loop;

    if tbl = 'project_staff' then
      execute format(
        'create policy %I on public.%I for select to authenticated using (
          public.is_admin()
          or public.is_module_admin(''DA'')
          or app_private.project_has_any_permission_v2(
            project_id,
            construction_site_id,
            array[''project.org.view'', ''project.org.assign_staff'', ''project.org.grant_permissions'']::text[],
            public.current_app_user_id()
          )
        )',
        tbl || '_phase3_org_select',
        tbl
      );
    else
      execute format(
        'create policy %I on public.%I for select to authenticated using (
          public.is_admin()
          or public.is_module_admin(''DA'')
          or exists (
            select 1
            from public.project_staff ps
            where ps.id = staff_id
              and app_private.project_has_any_permission_v2(
                ps.project_id,
                ps.construction_site_id,
                array[''project.org.view'', ''project.org.assign_staff'', ''project.org.grant_permissions'']::text[],
                public.current_app_user_id()
              )
          )
        )',
        tbl || '_phase3_org_select',
        tbl
      );
    end if;
  end loop;
end $$;

notify pgrst, 'reload schema';
]

[-- Phase 3.2 Daily Log namespace refactor.
-- Daily Log mutations now require explicit project.daily_log.* PBAC v2 grants.

create schema if not exists app_private;

revoke all on schema app_private from public;
revoke all on schema app_private from anon;
grant usage on schema app_private to authenticated;

create or replace function app_private.daily_log_has_action(
  p_project_id text,
  p_construction_site_id text,
  p_permission_code text,
  p_user_id uuid default public.current_app_user_id()
)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select p_permission_code like 'project.daily_log.%'
    and (
      public.is_admin()
      or public.is_module_admin('DA')
      or app_private.project_has_permission_v2(
        p_project_id,
        p_construction_site_id,
        p_permission_code,
        p_user_id
      )
    );
$$;

revoke all on function app_private.daily_log_has_action(text, text, text, uuid) from public;
revoke all on function app_private.daily_log_has_action(text, text, text, uuid) from anon;
grant execute on function app_private.daily_log_has_action(text, text, text, uuid) to authenticated;

create or replace function app_private.daily_log_has_any_action(
  p_project_id text,
  p_construction_site_id text,
  p_permission_codes text[],
  p_user_id uuid default public.current_app_user_id()
)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select exists (
    select 1
    from unnest(coalesce(p_permission_codes, '{}'::text[])) as permission_code
    where app_private.daily_log_has_action(
      p_project_id,
      p_construction_site_id,
      permission_code,
      p_user_id
    )
  );
$$;

revoke all on function app_private.daily_log_has_any_action(text, text, text[], uuid) from public;
revoke all on function app_private.daily_log_has_any_action(text, text, text[], uuid) from anon;
grant execute on function app_private.daily_log_has_any_action(text, text, text[], uuid) to authenticated;

create or replace function app_private.daily_log_is_owner(
  p_created_by_id text,
  p_submitted_by_id text,
  p_submitted_by text,
  p_created_by text,
  p_user_id uuid default public.current_app_user_id()
)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select p_user_id is not null
    and p_user_id::text in (
      coalesce(p_created_by_id, ''),
      coalesce(p_submitted_by_id, ''),
      coalesce(p_submitted_by, ''),
      coalesce(p_created_by, '')
    );
$$;

revoke all on function app_private.daily_log_is_owner(text, text, text, text, uuid) from public;
revoke all on function app_private.daily_log_is_owner(text, text, text, text, uuid) from anon;
grant execute on function app_private.daily_log_is_owner(text, text, text, text, uuid) to authenticated;

create or replace function app_private.daily_log_can_select(
  p_project_id text,
  p_construction_site_id text,
