[-- Align Project PO permissions after the Project Org permission refactor.

insert into public.permission_actions (
  module_code,
  action,
  permission_code,
  label,
  scope_modes,
  legacy_module_key,
  legacy_route,
  legacy_admin_only,
  sort_order,
  is_active
)
values (
  'project.material_po',
  'delete',
  'project.material_po.delete',
  'Xóa',
  array['global','project','construction_site']::text[],
  'DA',
  '/da/tabs/material/po',
  true,
  45,
  true
)
on conflict (permission_code) do update
set module_code = excluded.module_code,
    action = excluded.action,
    label = excluded.label,
    scope_modes = excluded.scope_modes,
    legacy_module_key = excluded.legacy_module_key,
    legacy_route = excluded.legacy_route,
    legacy_admin_only = excluded.legacy_admin_only,
    sort_order = excluded.sort_order,
    is_active = true update public.permission_actions
set scope_modes = array['global','project','construction_site']::text[],
    legacy_admin_only = true,
    sort_order = 50,
    is_active = true
where permission_code = 'project.material_po.manage' create or replace function app_private.material_has_action(
  p_project_id text,
  p_construction_site_id text,
  p_permission_code text,
  p_user_id uuid default public.current_app_user_id()
)
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select (
      p_permission_code like 'project.material%'
      or p_permission_code like 'project.custom_material.%'
    )
    and (
      public.is_admin()
      or public.is_module_admin('DA')
      or app_private.project_has_permission_v2(
        p_project_id,
        p_construction_site_id,
        p_permission_code,
        p_user_id
      )
      or (
        p_permission_code like 'project.material_po.%'
        and p_permission_code <> 'project.material_po.manage'
        and app_private.project_has_permission_v2(
          p_project_id,
          p_construction_site_id,
          'project.material_po.manage',
          p_user_id
        )
      )
    );
$$ revoke all on function app_private.material_has_action(text, text, text, uuid) from public revoke all on function app_private.material_has_action(text, text, text, uuid) from anon grant execute on function app_private.material_has_action(text, text, text, uuid) to authenticated create or replace function app_private.material_transition_context_enabled()
returns boolean
language sql
stable
security definer
set search_path = ''
as $$
  select current_setting('app.material_transition_context', true) = 'on';
$$ revoke all on function app_private.material_transition_context_enabled() from public revoke all on function app_private.material_transition_context_enabled() from anon grant execute on function app_private.material_transition_context_enabled() to authenticated create or replace function app_private.guard_purchase_order_direct_status_update()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if app_private.material_transition_context_enabled() or pg_trigger_depth() > 1 then
    return new;
  end if;

  if new.status is distinct from old.status
    or new.submitted_to_user_id is distinct from old.submitted_to_user_id
    or new.submitted_to_name is distinct from old.submitted_to_name
    or new.submitted_to_permission is distinct from old.submitted_to_permission
    or new.submission_note is distinct from old.submission_note
    or new.ever_submitted is distinct from old.ever_submitted
    or new.last_action_by is distinct from old.last_action_by
    or new.last_action_at is distinct from old.last_action_at
    or new.received_transaction_ids is distinct from old.received_transaction_ids
    or new.actual_delivery_date is distinct from old.actual_delivery_date then
    raise exception 'Purchase Order workflow fields must be changed through transition_project_purchase_order_status.'
      using errcode = '42501';
  end if;

  return new;
end;
$$ drop trigger if exists guard_purchase_order_direct_status_update on public.purchase_orders create trigger guard_purchase_order_direct_status_update
  before update on public.purchase_orders
  for each row
  execute function app_private.guard_purchase_order_direct_status_update() revoke all on function app_private.guard_purchase_order_direct_status_update() from public revoke all on function app_private.guard_purchase_order_direct_status_update() from anon create or replace function public.remove_purchase_order_v1(p_po_id text)
returns table(action text, id text, po_number text)
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_po public.purchase_orders%rowtype;
  v_has_permission boolean := false;
  v_has_stock_impact boolean := false;
  v_received_transaction_ids text[] := array[]::text[];
  v_fulfillment_transaction_ids text[] := array[]::text[];
  v_supplier_return_transaction_ids text[] := array[]::text[];
  v_supplier_return_ids uuid[] := array[]::uuid[];
  v_supplier_return_text_ids text[] := array[]::text[];
  v_cleanup_transaction_ids text[] := array[]::text[];
begin
  select *
    into v_po
  from public.purchase_orders
  where public.purchase_orders.id = p_po_id
  for update;

  if not found then
    raise exception 'Không tìm thấy PO cần xoá/lưu trữ.';
  end if;

  if v_po.archived_at is not null then
    raise exception 'PO đã được lưu trữ.';
  end if;

  v_has_permission := public.is_admin()
    or nullif(v_po.created_by_id, '') = public.current_app_user_id()::text
    or app_private.material_has_action(
      v_po.project_id::text,
      v_po.construction_site_id::text,
      'project.material_po.delete',
      public.current_app_user_id()
    );

  if not v_has_permission then
    raise exception 'Bạn cần quyền xoá PO, quyền quản trị PO, hoặc là người tạo PO để xoá/lưu trữ phiếu này.'
      using errcode = '42501';
  end if;

  if app_private.project_po_has_pending_work_v1(v_po.id::text) then
    raise exception 'PO đang có đợt giao/giao dịch chờ xử lý. Vui lòng huỷ hoặc xử lý xong trước khi xoá.';
  end if;

  v_has_stock_impact := app_private.project_po_has_stock_impact_v1(
    v_po.id::text,
    v_po.received_transaction_ids,
    v_po.items
  );

  if not v_has_stock_impact then
    select coalesce(array_agg(distinct tx_id), array[]::text[])
      into v_received_transaction_ids
    from (
      select jsonb_array_elements_text(
        case
          when jsonb_typeof(coalesce(v_po.received_transaction_ids, '[]'::jsonb)) = 'array'
            then coalesce(v_po.received_transaction_ids, '[]'::jsonb)
          else '[]'::jsonb
        end
      ) as tx_id
    ) tx
    where nullif(tx_id, '') is not null;

    if to_regclass('public.material_request_fulfillment_batches') is not null
       and to_regclass('public.material_request_fulfillment_lines') is not null then
      select coalesce(array_agg(distinct batch.transaction_id::text), array[]::text[])
        into v_fulfillment_transaction_ids
      from public.material_request_fulfillment_lines line
      join public.material_request_fulfillment_batches batch
        on batch.id = line.batch_id
      where line.po_id = v_po.id::text
        and batch.transaction_id is not null;
    end if;

    if to_regclass('public.purchase_order_supplier_returns') is not null then
      select coalesce(array_agg(distinct r.id), array[]::uuid[]),
             coalesce(array_agg(distinct r.transaction_id::text) filter (where r.transaction_id is not null), array[]::text[])
        into v_supplier_return_ids, v_supplier_return_transaction_ids
      from public.purchase_order_supplier_returns r
      where r.purchase_order_id = v_po.id::text;

      select coalesce(array_agg(ids.return_id::text), array[]::text[])
        into v_supplier_return_text_ids
      from unnest(v_supplier_return_ids) as ids(return_id);
    end if;

    select coalesce(array_agg(distinct tx_id), array[]::text[])
      into v_cleanup_transaction_ids
    from (
      select unnest(v_received_transaction_ids) as tx_id
      union
      select unnest(v_fulfillment_transaction_ids) as tx_id
      union
      select unnest(v_supplier_return_transaction_ids) as tx_id
    ) tx
    where nullif(tx_id, '') is not null;

    if to_regclass('public.project_document_links') is not null then
      delete from public.project_document_links link
      where (link.source_type = 'purchase_order' and link.source_id = v_po.id::text)
         or (link.target_type = 'purchase_order' and link.target_id = v_po.id::text)
         or (link.source_type = 'transaction' and link.source_id = any(v_cleanup_transaction_ids))
         or (link.target_type = 'transaction' and link.target_id = any(v_cleanup_transaction_ids))
         or (link.source_type = 'supplier_return' and link.source_id = any(v_supplier_return_text_ids))
         or (link.target_type = 'supplier_return' and link.target_id = any(v_supplier_return_text_ids));
    end if;

    if to_regclass('public.purchase_order_supplier_return_lines') is not null
       and coalesce(array_length(v_supplier_return_ids, 1), 0) > 0 then
      delete from public.purchase_order_supplier_return_lines line
      where line.supplier_return_id = any(v_supplier_return_ids);
    end if;

    if to_regclass('public.purchase_order_supplier_returns') is not null then
      delete from public.purchase_order_supplier_returns r
      where r.purchase_order_id = v_po.id::text;
    end if;

    if to_regclass('public.material_request_fulfillment_batches') is not null
       and to_regclass('public.material_request_fulfillment_lines') is not null then
      delete from public.material_request_fulfillment_batches batch
      where exists (
        select 1
        from public.material_request_fulfillment_lines line
        where line.batch_id = batch.id
          and line.po_id = v_po.id::text
      );
    end if;

    if coalesce(array_length(v_cleanup_transaction_ids, 1), 0) > 0 then
      delete from public.transactions t
      where t.id::text = any(v_cleanup_transaction_ids)
        and upper(coalesce(t.status::text, '')) <> 'COMPLETED'
        and not exists (
          select 1
          from public.inventory_ledger_entries entry
          where entry.source_type = 'wms_transaction'
            and entry.source_id = t.id::text
        )
        and (
          to_regclass('public.material_request_fulfillment_batches') is null
          or not exists (
            select 1
            from public.material_request_fulfillment_batches batch
            where batch.transaction_id::text = t.id::text
          )
        )
        and (
          to_regclass('public.purchase_order_supplier_returns') is null
          or not exists (
            select 1
            from public.purchase_order_supplier_returns r
            where r.transaction_id::text = t.id::text
          )
        );
    end if;

    delete from public.purchase_orders
    where public.purchase_orders.id = v_po.id;

    if to_regclass('public.project_document_links') is not null then
      delete from public.project_document_links link
      where (link.source_type = 'purchase_order' and link.source_id = v_po.id::text)
         or (link.target_type = 'purchase_order' and link.target_id = v_po.id::text);
    end if;

    action := 'deleted';
    id := v_po.id::text;
    po_number := v_po.po_number::text;
    return next;
    return;
  end if;

  if not app_private.project_po_can_archive_v1(
    v_po.id::text,
    v_po.project_id::text,
    v_po.construction_site_id::text,
    v_po.status::text,
    v_po.ever_submitted,
    v_po.received_transaction_ids,
    v_po.items
  ) then
    raise exception 'PO đã phát sinh kho và chưa đủ điều kiện lưu trữ. Vui lòng hoàn trả/đối soát đủ trước.';
  end if;

  update public.purchase_orders
  set archived_at = now(),
      archived_by = public.current_app_user_id(),
      archive_reason = 'Người dùng lưu trữ PO từ tab Cung ứng'
  where public.purchase_orders.id = v_po.id;

  action := 'archived';
  id := v_po.id::text;
  po_number := v_po.po_number::text;
  return next;
end;
$$ revoke all on function public.remove_purchase_order_v1(text) from public, anon grant execute on function public.remove_purchase_order_v1(text) to authenticated create or replace function public.create_purchase_order_supplier_return(
  p_purchase_order_id text,
  p_source_warehouse_id text,
  p_lines jsonb,
  p_reason text,
  p_note text default null
)
returns public.purchase_order_supplier_returns
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_actor uuid := public.current_app_user_id();
  v_po public.purchase_orders%rowtype;
  v_return public.purchase_order_supplier_returns%rowtype;
  v_return_id uuid := gen_random_uuid();
  v_transaction_id text := 'tx-supplier-return-' || replace(gen_random_uuid()::text, '-', '');
  v_return_no text;
  v_line jsonb;
  v_po_item jsonb;
  v_po_line_id text;
  v_item_id text;
  v_qty numeric;
  v_stock_qty numeric;
  v_received_qty numeric;
  v_returned_qty numeric;
  v_on_hand numeric;
  v_reserved numeric;
  v_purchase_unit text;
  v_stock_unit text;
  v_conversion_factor numeric;
  v_purchase_unit_price numeric;
  v_stock_unit_price numeric;
  v_is_converted boolean;
  v_transaction_items jsonb := '[]'::jsonb;
  v_return_line_rows jsonb := '[]'::jsonb;
  v_item_total record;
begin
  if v_actor is null then raise exception 'authentication required'; end if;
  if coalesce(trim(p_reason), '') = '' then
    raise exception 'Bắt buộc nhập lý do trả hàng NCC.';
  end if;
  if coalesce(p_source_warehouse_id, '') = '' then
    raise exception 'Chưa chọn kho xuất trả NCC.';
  end if;
  if jsonb_typeof(p_lines) <> 'array' or jsonb_array_length(p_lines) = 0 then
    raise exception 'Phiếu trả NCC chưa có dòng vật tư.';
  end if;

  select * into v_po
  from public.purchase_orders
  where id = p_purchase_order_id
  for update;
  if not found then raise exception 'Không tìm thấy PO cần trả hàng.'; end if;

  if not (
    public.is_admin()
    or public.is_module_admin('WMS')
    or app_private.current_user_is_global_wms_keeper()
    or app_private.material_has_action(
      v_po.project_id::text,
      v_po.construction_site_id::text,
      'project.material_po.manage',
      v_actor
    )
  ) then
    raise exception 'Bạn cần quyền quản trị PO, Admin, quản trị WMS hoặc thủ kho tổng để tạo phiếu trả hàng NCC.'
      using errcode = '42501';
  end if;

  if lower(coalesce(v_po.status::text, '')) not in ('partial', 'delivered', 'closed') then
    raise exception 'Chỉ trả NCC cho PO đã phát sinh nhận hàng và đang ở trạng thái giao một phần, hoàn thành hoặc đã đóng.';
  end if;
  if not exists (select 1 from public.warehouses w where w.id = p_source_warehouse_id) then
    raise exception 'Kho xuất trả NCC không tồn tại.';
  end if;

  v_return_no := 'SR-' || regexp_replace(coalesce(v_po.po_number, 'PO'), '[^A-Za-z0-9]+', '-', 'g')
    || '-' || upper(substr(replace(v_return_id::text, '-', ''), 1, 6));

  for v_line in
    select value from jsonb_array_elements(p_lines)
  loop
    v_po_line_id := coalesce(v_line ->> 'purchaseOrderLineId', v_line ->> 'poLineId', v_line ->> 'lineId');
    v_qty := coalesce(nullif(v_line ->> 'quantity', '')::numeric, 0);
    if coalesce(v_po_line_id, '') = '' or v_qty <= 0 then
      raise exception 'Dòng trả NCC không hợp lệ.';
    end if;

    select item.value into v_po_item
    from jsonb_array_elements(coalesce(v_po.items, '[]'::jsonb)) item(value)
    where coalesce(item.value ->> 'lineId', item.value ->> 'itemId') = v_po_line_id
    limit 1;
    if v_po_item is null then raise exception 'Dòng PO không tồn tại: %', v_po_line_id; end if;

    v_item_id := v_po_item ->> 'itemId';
    v_received_qty := coalesce(nullif(v_po_item ->> 'receivedQty', '')::numeric, 0);
    v_purchase_unit_price := coalesce(nullif(v_po_item ->> 'unitPrice', '')::numeric, 0);

    select coalesce(sum(line.return_qty), 0)
    into v_returned_qty
    from public.purchase_order_supplier_return_lines line
    join public.purchase_order_supplier_returns r on r.id = line.supplier_return_id
    where r.purchase_order_id = p_purchase_order_id
      and line.purchase_order_line_id = v_po_line_id
      and r.status in ('pending', 'completed');

    if v_qty > greatest(0, v_received_qty - v_returned_qty) then
      raise exception 'Số lượng trả của dòng % vượt khối lượng đã nhận còn có thể trả. Đã nhận %, đã/đang trả %, yêu cầu trả %.',
        v_po_line_id, v_received_qty, v_returned_qty, v_qty;
    end if;

    select
      coalesce((coalesce(i.stock_by_warehouse, '{}'::jsonb) ->> p_source_warehouse_id)::numeric, 0),
      coalesce(nullif(v_po_item ->> 'stockUnitSnapshot', ''), nullif(v_po_item ->> 'unitSnapshot', ''), i.unit, nullif(v_po_item ->> 'unit', '')),
      coalesce(nullif(v_po_item ->> 'purchaseUnitSnapshot', ''), nullif(v_po_item ->> 'unit', ''), i.purchase_unit, i.unit),
      coalesce(nullif(v_po_item ->> 'purchaseConversionFactor', '')::numeric, i.purchase_conversion_factor, 1)
    into v_on_hand, v_stock_unit, v_purchase_unit, v_conversion_factor
    from public.items i
    where i.id = v_item_id;
    if not found then raise exception 'Không tìm thấy vật tư: %', v_item_id; end if;

    v_conversion_factor := case when coalesce(v_conversion_factor, 0) > 0 then v_conversion_factor else 1 end;
    v_is_converted := coalesce(trim(v_stock_unit), '') <> ''
      and coalesce(trim(v_purchase_unit), '') <> ''
      and lower(trim(v_stock_unit)) <> lower(trim(v_purchase_unit));
    v_stock_qty := case when v_is_converted then v_qty * v_conversion_factor else v_qty end;
    v_stock_unit_price := case when v_is_converted then v_purchase_unit_price / v_conversion_factor else v_purchase_unit_price end;

    select coalesce(sum(coalesce(nullif(item.value ->> 'quantity', '')::numeric, 0)), 0)
    into v_reserved
    from public.transactions t
    cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) item(value)
    where t.source_warehouse_id = p_source_warehouse_id
      and t.status in ('PENDING'::public.transaction_status, 'APPROVED'::public.transaction_status)
      and t.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
      and item.value ->> 'itemId' = v_item_id;

    if v_stock_qty > greatest(0, v_on_hand - v_reserved) then
      raise exception 'Kho xuất trả không đủ tồn khả dụng cho vật tư %. Tồn %, đang giữ %, khả dụng %, cần trả %.',
        coalesce(v_po_item ->> 'name', v_item_id), v_on_hand, v_reserved, greatest(0, v_on_hand - v_reserved), v_stock_qty;
    end if;

    v_transaction_items := v_transaction_items || jsonb_build_array(
      jsonb_build_object(
        'itemId', v_item_id,
        'quantity', v_stock_qty,
        'price', v_stock_unit_price,
        'supplierReturnId', v_return_id::text,
        'purchaseOrderId', p_purchase_order_id,
        'purchaseOrderLineId', v_po_line_id
      )
      || case when v_is_converted then jsonb_build_object(
        'accountingQty', v_qty,
        'accountingUnit', v_purchase_unit,
        'accountingPrice', v_purchase_unit_price
      ) else '{}'::jsonb end
    );

    v_return_line_rows := v_return_line_rows || jsonb_build_array(jsonb_build_object(
      'purchaseOrderLineId', v_po_line_id,
      'itemId', v_item_id,
      'receivedQtySnapshot', v_received_qty,
      'previouslyReturnedQtySnapshot', v_returned_qty,
      'returnQty', v_qty,
      'unit', v_purchase_unit,
      'unitPrice', v_purchase_unit_price,
      'stockReturnQty', v_stock_qty,
      'stockUnit', v_stock_unit
    ));
  end loop;

  for v_item_total in
    select
      item.value ->> 'itemId' as item_id,
      sum(coalesce(nullif(item.value ->> 'quantity', '')::numeric, 0)) as quantity
    from jsonb_array_elements(v_transaction_items) item(value)
    group by item.value ->> 'itemId'
  loop
    select coalesce((coalesce(i.stock_by_warehouse, '{}'::jsonb) ->> p_source_warehouse_id)::numeric, 0)
    into v_on_hand
    from public.items i
    where i.id = v_item_total.item_id
    for update;

    select coalesce(sum(coalesce(nullif(item.value ->> 'quantity', '')::numeric, 0)), 0)
    into v_reserved
    from public.transactions t
    cross join lateral jsonb_array_elements(coalesce(t.items, '[]'::jsonb)) item(value)
    where t.source_warehouse_id = p_source_warehouse_id
      and t.status in ('PENDING'::public.transaction_status, 'APPROVED'::public.transaction_status)
      and t.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
      and item.value ->> 'itemId' = v_item_total.item_id;

    if v_item_total.quantity > greatest(0, v_on_hand - v_reserved) then
      raise exception 'Tổng số lượng trả NCC vượt tồn khả dụng của vật tư %. Tồn %, đang giữ %, khả dụng %, cần trả %.',
        v_item_total.item_id, v_on_hand, v_reserved, greatest(0, v_on_hand - v_reserved), v_item_total.quantity;
    end if;
  end loop;

  insert into public.transactions(
    id, type, date, items, source_warehouse_id, requester_id,
    status, note
  ) values (
    v_transaction_id,
    'EXPORT'::public.transaction_type,
    now(),
    v_transaction_items,
    p_source_warehouse_id,
    v_actor,
    'PENDING'::public.transaction_status,
    'Trả hàng NCC ' || v_return_no || ' theo PO ' || coalesce(v_po.po_number, p_purchase_order_id)
      || case when coalesce(v_po.vendor_name, '') <> '' then ' - ' || v_po.vendor_name else '' end
  );

  insert into public.purchase_order_supplier_returns(
    id, return_no, purchase_order_id, project_id, construction_site_id,
    vendor_id, source_warehouse_id, status, transaction_id,
    reason, note, created_by
  ) values (
    v_return_id, v_return_no, v_po.id, v_po.project_id, v_po.construction_site_id,
    v_po.vendor_id, p_source_warehouse_id, 'pending', v_transaction_id,
    trim(p_reason), nullif(trim(coalesce(p_note, '')), ''), v_actor
  )
  returning * into v_return;

  insert into public.purchase_order_supplier_return_lines(
    supplier_return_id, purchase_order_line_id, item_id,
    received_qty_snapshot, previously_returned_qty_snapshot,
    return_qty, unit, unit_price, stock_return_qty, stock_unit
  )
  select
    v_return_id,
    line.value ->> 'purchaseOrderLineId',
    line.value ->> 'itemId',
    coalesce(nullif(line.value ->> 'receivedQtySnapshot', '')::numeric, 0),
    coalesce(nullif(line.value ->> 'previouslyReturnedQtySnapshot', '')::numeric, 0),
    coalesce(nullif(line.value ->> 'returnQty', '')::numeric, 0),
    nullif(line.value ->> 'unit', ''),
    coalesce(nullif(line.value ->> 'unitPrice', '')::numeric, 0),
    coalesce(nullif(line.value ->> 'stockReturnQty', '')::numeric, 0),
    nullif(line.value ->> 'stockUnit', '')
  from jsonb_array_elements(v_return_line_rows) line(value);

  return v_return;
end;
$$ revoke all on function public.create_purchase_order_supplier_return(text, text, jsonb, text, text) from public revoke all on function public.create_purchase_order_supplier_return(text, text, jsonb, text, text) from anon grant execute on function public.create_purchase_order_supplier_return(text, text, jsonb, text, text) to authenticated notify pgrst, 'reload schema']

[create schema if not exists app_private alter table public.users
  add column if not exists account_status text,
  add column if not exists disabled_at timestamptz,
  add column if not exists disabled_by uuid references public.users(id) on delete set null,
  add column if not exists disabled_reason text,
  add column if not exists reactivated_at timestamptz,
  add column if not exists reactivated_by uuid references public.users(id) on delete set null,
  add column if not exists reactivation_reason text -- The existing profile guard requires an app actor; this one-time owner backfill
-- has no JWT. The trigger state is transactional and is restored on any error.
alter table public.users
  disable trigger trg_users_prevent_privilege_self_update update public.users
set account_status = case when coalesce(is_active, true) then 'ACTIVE' else 'DISABLED' end
where account_status is null alter table public.users
  enable trigger trg_users_prevent_privilege_self_update alter table public.users
  alter column account_status set default 'ACTIVE',
  alter column account_status set not null alter table public.users
  drop constraint if exists users_account_status_check,
  drop constraint if exists users_account_status_consistency_check alter table public.users
  add constraint users_account_status_check
    check (account_status in ('ACTIVE', 'DISABLED')),
  add constraint users_account_status_consistency_check
    check (is_active = (account_status = 'ACTIVE')) create or replace function app_private.sync_user_account_status_compat()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if tg_op = 'INSERT' then
    if session_user = 'supabase_auth_admin' then
      -- Auth user metadata is identity/profile input, never authorization input.
      new.role := 'EMPLOYEE';
      new.assigned_warehouse_id := null;
      new.allowed_modules := '{}'::text[];
      new.admin_modules := '{}'::text[];
      new.allowed_sub_modules := '{}'::jsonb;
      new.admin_sub_modules := '{}'::jsonb;
    end if;

    -- During compatibility, either explicit disabled signal must win over defaults.
    if new.account_status = 'DISABLED' or new.is_active = false then
      new.account_status := 'DISABLED';
      new.is_active := false;
    else
      new.account_status := 'ACTIVE';
      new.is_active := true;
    end if;
    return new;
  end if;

  if session_user = 'supabase_auth_admin' then
    new.role := old.role;
    new.assigned_warehouse_id := old.assigned_warehouse_id;
    new.allowed_modules := old.allowed_modules;
    new.admin_modules := old.admin_modules;
    new.allowed_sub_modules := old.allowed_sub_modules;
    new.admin_sub_modules := old.admin_sub_modules;
    new.account_status := old.account_status;
    new.is_active := old.is_active;
    return new;
  end if;

  if old.account_status is distinct from new.account_status
    or old.is_active is distinct from new.is_active
  then
    if coalesce(current_setting('app.account_lifecycle_command', true), '') <> 'on' then
      raise exception 'Account status can only be changed by the account lifecycle command'
        using errcode = '42501';
    end if;

    if old.account_status is distinct from new.account_status then
      new.is_active := new.account_status = 'ACTIVE';
    else
      new.account_status := case when new.is_active then 'ACTIVE' else 'DISABLED' end;
    end if;
  end if;

  return new;
end;
$$ revoke all on function app_private.sync_user_account_status_compat() from public, anon, authenticated drop trigger if exists trg_users_account_status_compat on public.users create trigger trg_users_account_status_compat
  before insert or update on public.users
  for each row
  execute function app_private.sync_user_account_status_compat() create or replace function app_private.guard_user_account_lifecycle_metadata()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if old.account_status is distinct from new.account_status
    or old.disabled_at is distinct from new.disabled_at
    or old.disabled_by is distinct from new.disabled_by
    or old.disabled_reason is distinct from new.disabled_reason
    or old.reactivated_at is distinct from new.reactivated_at
    or old.reactivated_by is distinct from new.reactivated_by
    or old.reactivation_reason is distinct from new.reactivation_reason
  then
    if auth.role() = 'service_role'
      and coalesce(current_setting('app.account_lifecycle_command', true), '') = 'on'
    then
      return new;
    end if;

    raise exception 'Account lifecycle metadata can only be changed by the trusted command'
      using errcode = '42501';
  end if;

  return new;
end;
$$ revoke all on function app_private.guard_user_account_lifecycle_metadata()
  from public, anon, authenticated drop trigger if exists trg_users_guard_account_lifecycle_metadata on public.users create trigger trg_users_guard_account_lifecycle_metadata
  before update on public.users
  for each row
  execute function app_private.guard_user_account_lifecycle_metadata() create or replace function public.current_app_user_id()
returns uuid
language sql
stable
security definer
set search_path = ''
as $$
  select u.id
  from public.users u
  where (
      u.auth_id = (select auth.uid())
      or (
        u.auth_id is null
        and lower(u.email) = lower(coalesce((select auth.jwt() ->> 'email'), ''))
      )
    )
    and u.is_active
    and u.account_status = 'ACTIVE'
  order by case when u.auth_id = (select auth.uid()) then 0 else 1 end
  limit 1;
$$ revoke all on function public.current_app_user_id() from public, anon grant execute on function public.current_app_user_id() to authenticated, service_role create or replace function public.enforce_active_app_actor()
returns void
language plpgsql
stable
security definer
set search_path = ''
as $$
begin
  if (select auth.role()) = 'authenticated'
    and public.current_app_user_id() is null
  then
    raise exception 'Active application account required'
      using errcode = '42501';
  end if;
end;
$$ revoke all on function public.enforce_active_app_actor() from public grant execute on function public.enforce_active_app_actor() to anon, authenticated, service_role alter role authenticator
  set pgrst.db_pre_request = 'public.enforce_active_app_actor' -- Backfill every currently RLS-protected application table. Storage is a
-- Supabase-managed schema, so its supported RLS surface is handled separately.
do $$
declare
  target record;
  policy_name text;
begin
  for target in
    select n.nspname as schema_name, c.relname as table_name
    from pg_class c
    join pg_namespace n on n.oid = c.relnamespace
    where c.relkind in ('r', 'p')
      and c.relrowsecurity
      and n.nspname = 'public'
  loop
    policy_name := left(target.table_name || '_active_actor_gate', 63);
    execute format(
      'drop policy if exists %I on %I.%I',
      policy_name,
      target.schema_name,
      target.table_name
    );
    execute format(
      'create policy %I on %I.%I as restrictive for all to authenticated using ((select public.current_app_user_id()) is not null) with check ((select public.current_app_user_id()) is not null)',
      policy_name,
      target.schema_name,
      target.table_name
    );
  end loop;

  if to_regclass('storage.objects') is not null then
    drop policy if exists storage_objects_active_actor_gate on storage.objects;
    create policy storage_objects_active_actor_gate
      on storage.objects
      as restrictive
      for all
      to authenticated
      using ((select public.current_app_user_id()) is not null)
      with check ((select public.current_app_user_id()) is not null);
  end if;
end;
$$ drop policy if exists users_delete on public.users revoke delete on public.users from authenticated notify pgrst, 'reload config' notify pgrst, 'reload schema']

[-- Phase 2 governed Business Role, assignment, rollout and direct-grant commands.

create or replace function app_private.assert_authorization_permission(
  p_permission_code text
)
returns uuid
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_actor_user_id uuid := public.current_app_user_id();
begin
  if v_actor_user_id is null
    or not app_private.has_permission(
      v_actor_user_id,
      p_permission_code,
      'global',
      '*'
    )
  then
    raise exception 'Authorization administration permission required'
      using errcode = '42501';
  end if;

  return v_actor_user_id;
end;
$$ create or replace function app_private.assert_and_record_sod_warnings(
  p_decision jsonb,
  p_acceptances jsonb,
  p_command_type text,
  p_command_id uuid,
  p_actor_user_id uuid,
  p_target_user_id uuid
)
returns void
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_hard_denies jsonb := coalesce(p_decision -> 'hardDenies', '[]'::jsonb);
  v_warnings jsonb := coalesce(p_decision -> 'warnings', '[]'::jsonb);
  v_acceptances jsonb := coalesce(p_acceptances, '[]'::jsonb);
  v_warning jsonb;
  v_acceptance jsonb;
  v_owner_id uuid;
  v_expires_at timestamptz;
begin
  if p_actor_user_id is distinct from public.current_app_user_id()
    or not app_private.has_any_permission(
      public.current_app_user_id(),
      array[
        'system.authorization.manage_roles',
        'system.authorization.manage_grants'
      ],
      'global',
      '*'
    )
  then
    raise exception 'Authorization administration permission required'
      using errcode = '42501';
  end if;

  if jsonb_typeof(v_hard_denies) <> 'array'
    or jsonb_typeof(v_warnings) <> 'array'
    or jsonb_typeof(v_acceptances) <> 'array'
  then
    raise exception 'Invalid SoD decision or warning acceptances'
      using errcode = '22023';
  end if;

  if jsonb_array_length(v_hard_denies) > 0 then
    raise exception 'Authorization change violates a hard SoD rule'
      using errcode = '42501';
  end if;

  if exists (
    select 1
    from jsonb_array_elements(v_acceptances) supplied
    group by
      supplied.value ->> 'ruleCode',
      supplied.value ->> 'scopeType',
      supplied.value ->> 'scopeId'
    having count(*) > 1
  ) then
    raise exception 'Duplicate SoD warning acknowledgement'
      using errcode = '22023';
  end if;

  for v_warning in
    select value
    from jsonb_array_elements(v_warnings)
  loop
    select value
    into v_acceptance
    from jsonb_array_elements(v_acceptances)
    where value ->> 'ruleCode' = v_warning ->> 'ruleCode'
      and value ->> 'scopeType' = v_warning ->> 'scopeType'
      and value ->> 'scopeId' = v_warning ->> 'scopeId'
    limit 1;

    if v_acceptance is null then
      raise exception 'SoD warning acknowledgement required'
        using errcode = '22023';
    end if;

    begin
      v_owner_id := nullif(v_acceptance ->> 'controlOwnerUserId', '')::uuid;
      v_expires_at := nullif(v_acceptance ->> 'expiresAt', '')::timestamptz;
    exception
      when invalid_text_representation or datetime_field_overflow then
        raise exception 'Invalid SoD warning control evidence'
          using errcode = '22023';
    end;

    if char_length(btrim(coalesce(v_acceptance ->> 'reason', ''))) < 10
      or char_length(btrim(coalesce(v_acceptance ->> 'compensatingControls', ''))) < 10
      or v_expires_at is null
      or v_expires_at <= now()
      or v_owner_id is null
      or v_owner_id = p_actor_user_id
      or v_owner_id = p_target_user_id
      or not exists (
        select 1
        from public.users owner_row
        where owner_row.id = v_owner_id
          and owner_row.is_active
          and owner_row.account_status = 'ACTIVE'
          and app_private.has_permission(
            owner_row.id,
            'system.authorization.audit',
            'global',
            '*'
          )
      )
    then
      raise exception 'Invalid SoD warning control evidence'
        using errcode = '22023';
    end if;

    insert into public.authorization_sod_warning_acceptances (
      rule_code,
      command_type,
      command_id,
      actor_user_id,
      target_user_id,
      scope_type,
      scope_id,
      reason,
      control_owner_user_id,
      compensating_controls,
      expires_at
    )
    values (
      v_warning ->> 'ruleCode',
      p_command_type,
      p_command_id,
      p_actor_user_id,
      p_target_user_id,
      v_warning ->> 'scopeType',
      v_warning ->> 'scopeId',
      btrim(v_acceptance ->> 'reason'),
      v_owner_id,
      btrim(v_acceptance ->> 'compensatingControls'),
      v_expires_at
    );
  end loop;

  if exists (
    select 1
    from jsonb_array_elements(v_acceptances) supplied
    where not exists (
      select 1
      from jsonb_array_elements(v_warnings) expected
      where expected ->> 'ruleCode' = supplied.value ->> 'ruleCode'
        and expected ->> 'scopeType' = supplied.value ->> 'scopeType'
        and expected ->> 'scopeId' = supplied.value ->> 'scopeId'
    )
  ) then
    raise exception 'Unexpected SoD warning acknowledgement'
      using errcode = '22023';
  end if;
end;
$$ revoke all on function app_private.assert_authorization_permission(text)
  from public, anon, authenticated revoke all on function app_private.assert_and_record_sod_warnings(
  jsonb,jsonb,text,uuid,uuid,uuid
) from public, anon, authenticated create or replace function app_private.preview_business_role_change_impl(
  p_role_template_id uuid,
  p_items jsonb
)
returns jsonb
language plpgsql
stable
security definer
set search_path = ''
as $$
declare
  v_actor_user_id uuid;
  v_before_items jsonb := '[]'::jsonb;
  v_after_items jsonb := '[]'::jsonb;
  v_added_keys jsonb := '[]'::jsonb;
  v_removed_keys jsonb := '[]'::jsonb;
  v_affected_principal_count integer := 0;
  v_affected_scope_count integer := 0;
begin
  v_actor_user_id := app_private.assert_authorization_permission(
    'system.authorization.manage_roles'
  );

  if jsonb_typeof(coalesce(p_items, '[]'::jsonb)) <> 'array' then
    raise exception 'Business Role items must be an array'
      using errcode = '22023';
  end if;

  if p_role_template_id is not null
    and not exists (
      select 1
      from public.role_permission_templates role_row
      where role_row.id = p_role_template_id
    )
  then
    raise exception 'Business Role does not exist'
      using errcode = '23503';
  end if;

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'permissionCode', item.permission_code,
        'scopeType', item.scope_type,
        'scopeId', item.scope_id,
        'sortOrder', item.sort_order
      )
      order by item.permission_code, item.scope_type, item.scope_id
    ),
    '[]'::jsonb
  )
  into v_before_items
  from public.role_permission_template_items item
  where item.template_id = p_role_template_id;

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'permissionCode', normalized.permission_code,
        'scopeType', normalized.scope_type,
        'scopeId', normalized.scope_id,
        'sortOrder', normalized.sort_order
      )
      order by normalized.permission_code, normalized.scope_type, normalized.scope_id
    ),
    '[]'::jsonb
  )
  into v_after_items
  from (
    select distinct
      item.permission_code,
      coalesce(nullif(item.scope_type, ''), 'global') as scope_type,
      coalesce(nullif(item.scope_id, ''), '*') as scope_id,
      coalesce(item.sort_order, 0) as sort_order
    from jsonb_to_recordset(coalesce(p_items, '[]'::jsonb)) item(
      permission_code text,
      scope_type text,
      scope_id text,
      sort_order integer
    )
  ) normalized;

  select count(*), count(distinct assignment_row.scope_type || ':' || assignment_row.scope_id)
  into v_affected_principal_count, v_affected_scope_count
  from public.principal_role_assignments assignment_row
  where assignment_row.role_template_id = p_role_template_id;

  select coalesce(jsonb_agg(key_value order by key_value), '[]'::jsonb)
  into v_added_keys
  from (
    select (item.value ->> 'permissionCode')
      || '::' || (item.value ->> 'scopeType')
      || '::' || (item.value ->> 'scopeId') as key_value
    from jsonb_array_elements(v_after_items) item
    except
    select (item.value ->> 'permissionCode')
      || '::' || (item.value ->> 'scopeType')
      || '::' || (item.value ->> 'scopeId')
    from jsonb_array_elements(v_before_items) item
  ) added;

  select coalesce(jsonb_agg(key_value order by key_value), '[]'::jsonb)
  into v_removed_keys
  from (
    select (item.value ->> 'permissionCode')
      || '::' || (item.value ->> 'scopeType')
      || '::' || (item.value ->> 'scopeId') as key_value
    from jsonb_array_elements(v_before_items) item
    except
    select (item.value ->> 'permissionCode')
      || '::' || (item.value ->> 'scopeType')
      || '::' || (item.value ->> 'scopeId')
    from jsonb_array_elements(v_after_items) item
  ) removed;

  return jsonb_build_object(
    'affectedPrincipalCount', v_affected_principal_count,
    'affectedScopeCount', v_affected_scope_count,
    'addedPermissionKeys', v_added_keys,
    'removedPermissionKeys', v_removed_keys
  );
end;
