begin
  v_actor_user_id := app_private.assert_authorization_permission(
    'system.authorization.manage_roles'
  );

  return app_private.evaluate_business_role_assignment_impl(
    v_actor_user_id,
    p_target_user_id,
    p_role_template_id,
