[create or replace function public.transition_project_material_request_status(
  p_request_id text,
  p_status text,
  p_action text,
  p_actor_user_id text,
  p_target_user_id text default null,
  p_target_permission text default null,
  p_note text default null,
  p_patch jsonb default '{}'::jsonb
)
returns public.requests
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_request public.requests%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_required_permission text;
  v_previous_guard text;
begin
  if v_user_id is null or p_actor_user_id is distinct from v_user_id::text then
    raise exception 'Không xác định được người dùng chuyển bước phiếu vật tư.'
      using errcode = '42501';
  end if;

  select *
  into v_request
  from public.requests
  where id = p_request_id
    and coalesce(request_origin, 'wms') = 'project'
  for update;

  if not found then
    raise exception 'Không tìm thấy phiếu vật tư dự án.';
  end if;

  v_required_permission := case
    when upper(coalesce(p_action, '')) in ('SUBMITTED', 'RESUBMITTED') then 'project.material_request.submit'
    when upper(coalesce(p_action, '')) in ('RETURNED', 'REJECTED') then 'project.material_request.return'
    when upper(coalesce(p_action, '')) in ('FULFILLED', 'CONFIRMED', 'CONFIRM_FULFILLMENT') then 'project.material_request.confirm_fulfillment'
    when coalesce(p_patch->>'workflow_step', '') in ('site_quality_check', 'completed')
      or upper(coalesce(p_status, '')) in ('COMPLETED', 'IN_TRANSIT') then 'project.material_request.confirm_fulfillment'
    else 'project.material_request.approve'
  end;

  if v_required_permission = 'project.material_request.approve'
    and (
      v_request.status is distinct from 'PENDING'::public.request_status
      or upper(coalesce(p_status, '')) <> 'APPROVED'
      or upper(coalesce(p_action, '')) <> 'APPROVED'
    )
  then
    raise exception 'Chỉ phiếu đang chờ duyệt mới được duyệt.'
      using errcode = '23514';
  end if;

  if v_required_permission = 'project.material_request.submit' then
    if coalesce(v_request.status::text, 'DRAFT') not in ('DRAFT', 'REJECTED') then
      raise exception 'Chỉ phiếu nháp hoặc bị trả lại mới được gửi duyệt.';
    end if;
    if not (public.is_admin() or public.is_module_admin('DA')) and v_request.requester_id is distinct from v_user_id then
      raise exception 'Chỉ người tạo phiếu mới được gửi duyệt.'
        using errcode = '42501';
    end if;
  elsif not (public.is_admin() or public.is_module_admin('DA')) then
    if v_request.submitted_to_user_id is not null
      and v_request.submitted_to_user_id <> v_user_id::text then
      raise exception 'Bạn không phải người đang được giao xử lý phiếu vật tư này.'
        using errcode = '42501';
    end if;
  end if;

  if not app_private.material_has_action(v_request.project_id, v_request.construction_site_id, v_required_permission, v_user_id) then
    raise exception 'Bạn cần quyền % để chuyển bước phiếu vật tư.', v_required_permission
      using errcode = '42501';
  end if;

  if nullif(p_target_user_id, '') is not null and nullif(p_target_permission, '') is not null then
    if not app_private.material_has_action(
      v_request.project_id,
      v_request.construction_site_id,
      p_target_permission,
      p_target_user_id::uuid
    ) then
      raise exception 'Người được chọn chưa có quyền % trong Tổ chức dự án.', p_target_permission
        using errcode = '42501';
    end if;
  end if;

  v_previous_guard := current_setting('app.material_transition_context', true);
  perform set_config('app.material_transition_context', 'on', true);

  update public.requests
  set
    status = coalesce(nullif(p_status, '')::public.request_status, status),
    logs = case when p_patch ? 'logs' then p_patch->'logs' else logs end,
    ever_submitted = case when p_patch ? 'ever_submitted' then coalesce((p_patch->>'ever_submitted')::boolean, ever_submitted) else ever_submitted end,
    last_action_by = case when p_patch ? 'last_action_by' then nullif(p_patch->>'last_action_by', '') else last_action_by end,
    last_action_at = case when p_patch ? 'last_action_at' then nullif(p_patch->>'last_action_at', '')::timestamptz else last_action_at end,
    workflow_step = case when p_patch ? 'workflow_step' then nullif(p_patch->>'workflow_step', '') else workflow_step end,
    workflow_step_started_at = case when p_patch ? 'workflow_step_started_at' then nullif(p_patch->>'workflow_step_started_at', '')::timestamptz else workflow_step_started_at end,
    workflow_step_due_at = case when p_patch ? 'workflow_step_due_at' then nullif(p_patch->>'workflow_step_due_at', '')::timestamptz else workflow_step_due_at end,
    workflow_step_sla_hours = case when p_patch ? 'workflow_step_sla_hours' then nullif(p_patch->>'workflow_step_sla_hours', '')::integer else workflow_step_sla_hours end,
    workflow_step_actor_user_id = case when p_patch ? 'workflow_step_actor_user_id' then nullif(p_patch->>'workflow_step_actor_user_id', '') else workflow_step_actor_user_id end,
    submitted_to_user_id = case when p_patch ? 'submitted_to_user_id' then nullif(p_patch->>'submitted_to_user_id', '') else submitted_to_user_id end,
    submitted_to_name = case when p_patch ? 'submitted_to_name' then nullif(p_patch->>'submitted_to_name', '') else submitted_to_name end,
    submitted_to_permission = case when p_patch ? 'submitted_to_permission' then nullif(p_patch->>'submitted_to_permission', '') else submitted_to_permission end,
    submission_note = case when p_patch ? 'submission_note' then nullif(p_patch->>'submission_note', '') else submission_note end
  where id = p_request_id
  returning * into v_request;

  perform set_config('app.material_transition_context', coalesce(v_previous_guard, ''), true);
  return v_request;
end;
$$ revoke all on function public.transition_project_material_request_status(text, text, text, text, text, text, text, jsonb) from public revoke all on function public.transition_project_material_request_status(text, text, text, text, text, text, text, jsonb) from anon grant execute on function public.transition_project_material_request_status(text, text, text, text, text, text, text, jsonb) to authenticated]

[create or replace function public.transition_project_purchase_order_status(
  p_po_id text,
  p_status text,
  p_patch jsonb default '{}'::jsonb
)
returns void
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_po public.purchase_orders%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_required_permission text;
  v_previous_guard text;
begin
  if v_user_id is null then
    raise exception 'Không xác định được người dùng chuyển trạng thái PO.'
      using errcode = '42501';
  end if;

  select *
  into v_po
  from public.purchase_orders
  where id = p_po_id
  for update;

  if not found then
    raise exception 'Không tìm thấy PO.';
  end if;

  if coalesce(p_status, '') = 'cancelled' then
    raise exception 'PO không được hủy qua luồng duyệt; dùng luồng Quy trình hoặc Yêu cầu.'
      using errcode = '23514';
  end if;

  v_required_permission := case
    when coalesce(p_status, '') in ('in_transit', 'partial', 'delivered', 'closed')
      or p_patch ? 'received_transaction_ids'
      or p_patch ? 'actual_delivery_date' then 'project.material_po.receive'
    when coalesce(p_status, '') = 'sent' then 'project.material_po.create'
    when coalesce(p_status, '') in ('confirmed', 'returned') then 'project.material_po.approve'
    else 'project.material_po.create'
  end;

  if v_required_permission = 'project.material_po.approve'
    and (
      lower(coalesce(v_po.status, '')) <> 'sent'
      or lower(coalesce(p_status, '')) not in ('confirmed', 'returned')
    )
  then
    raise exception 'Chỉ PO đang chờ duyệt mới được duyệt hoặc trả lại.'
      using errcode = '23514';
  end if;

  if coalesce(p_status, '') = 'sent'
    and lower(coalesce(v_po.status, '')) not in ('draft', 'returned')
  then
    raise exception 'Chỉ PO nháp hoặc bị trả lại mới được gửi duyệt.'
      using errcode = '23514';
  end if;

  if not (
    public.is_admin()
    or public.is_module_admin('DA')
    or (v_po.source_mode = 'company_consolidated' and app_private.company_procurement_can_manage())
    or (
      v_required_permission = 'project.material_po.receive'
      and (
        app_private.current_user_is_global_wms_keeper()
        or app_private.current_user_is_wms_keeper_for(v_po.target_warehouse_id)
      )
    )
    or app_private.material_has_action(v_po.project_id, v_po.construction_site_id, v_required_permission, v_user_id)
  ) then
    raise exception 'Bạn cần quyền % để chuyển trạng thái PO.', v_required_permission
      using errcode = '42501';
  end if;

  v_previous_guard := current_setting('app.material_transition_context', true);
  perform set_config('app.material_transition_context', 'on', true);

  update public.purchase_orders
  set
    status = coalesce(nullif(p_status, ''), status),
    submitted_to_user_id = case when p_patch ? 'submitted_to_user_id' then nullif(p_patch->>'submitted_to_user_id', '') else submitted_to_user_id end,
    submitted_to_name = case when p_patch ? 'submitted_to_name' then nullif(p_patch->>'submitted_to_name', '') else submitted_to_name end,
    submitted_to_permission = case when p_patch ? 'submitted_to_permission' then nullif(p_patch->>'submitted_to_permission', '') else submitted_to_permission end,
    submission_note = case when p_patch ? 'submission_note' then nullif(p_patch->>'submission_note', '') else submission_note end,
    ever_submitted = case when p_patch ? 'ever_submitted' then coalesce((p_patch->>'ever_submitted')::boolean, ever_submitted) else ever_submitted end,
    last_action_by = case when p_patch ? 'last_action_by' then nullif(p_patch->>'last_action_by', '') else last_action_by end,
    last_action_at = case when p_patch ? 'last_action_at' then nullif(p_patch->>'last_action_at', '')::timestamptz else last_action_at end,
    received_transaction_ids = case when p_patch ? 'received_transaction_ids' then coalesce(p_patch->'received_transaction_ids', '[]'::jsonb) else received_transaction_ids end,
    actual_delivery_date = case when p_patch ? 'actual_delivery_date' then nullif(p_patch->>'actual_delivery_date', '') else actual_delivery_date end
  where id = p_po_id;

  perform set_config('app.material_transition_context', coalesce(v_previous_guard, ''), true);
end;
$$ revoke all on function public.transition_project_purchase_order_status(text, text, jsonb) from public revoke all on function public.transition_project_purchase_order_status(text, text, jsonb) from anon grant execute on function public.transition_project_purchase_order_status(text, text, jsonb) to authenticated]

[create or replace function app_private.guard_payment_certificate_direct_workflow_update()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if tg_op = 'INSERT' then
    if coalesce(new.status, 'draft') <> 'draft' then
      raise exception 'Payment Certificate workflow must start in draft.'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if current_setting('app.project_document_transition_context', true) is distinct from 'on'
    and (
      old.status is distinct from new.status
      or old.submitted_by is distinct from new.submitted_by
      or old.submitted_at is distinct from new.submitted_at
      or old.approved_by is distinct from new.approved_by
      or old.approved_at is distinct from new.approved_at
      or old.paid_at is distinct from new.paid_at
      or old.returned_by is distinct from new.returned_by
      or old.returned_at is distinct from new.returned_at
      or old.return_reason is distinct from new.return_reason
      or old.submitted_to_user_id is distinct from new.submitted_to_user_id
      or old.submitted_to_name is distinct from new.submitted_to_name
      or old.submitted_to_permission is distinct from new.submitted_to_permission
      or old.submission_note is distinct from new.submission_note
    )
  then
    raise exception 'Payment Certificate workflow fields must be changed through transition_project_payment_certificate_status.'
      using errcode = '42501';
  end if;

  return new;
end;
$$ drop trigger if exists guard_payment_certificate_direct_workflow_update on public.payment_certificates create trigger guard_payment_certificate_direct_workflow_update
  before insert or update on public.payment_certificates
  for each row execute function app_private.guard_payment_certificate_direct_workflow_update() create or replace function app_private.guard_quantity_acceptance_direct_workflow_update()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  if tg_op = 'INSERT' then
    if coalesce(new.status, 'draft') <> 'draft' then
      raise exception 'Quantity Acceptance workflow must start in draft.'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if current_setting('app.project_document_transition_context', true) is distinct from 'on'
    and (
      old.status is distinct from new.status
      or old.submitted_by is distinct from new.submitted_by
      or old.submitted_at is distinct from new.submitted_at
      or old.approved_by is distinct from new.approved_by
      or old.approved_at is distinct from new.approved_at
      or old.returned_by is distinct from new.returned_by
      or old.returned_at is distinct from new.returned_at
      or old.return_reason is distinct from new.return_reason
      or old.submitted_to_user_id is distinct from new.submitted_to_user_id
      or old.submitted_to_name is distinct from new.submitted_to_name
      or old.submitted_to_permission is distinct from new.submitted_to_permission
      or old.submission_note is distinct from new.submission_note
    )
  then
    raise exception 'Quantity Acceptance workflow fields must be changed through transition_project_quantity_acceptance_status.'
      using errcode = '42501';
  end if;

  return new;
end;
$$ drop trigger if exists guard_quantity_acceptance_direct_workflow_update on public.quantity_acceptances create trigger guard_quantity_acceptance_direct_workflow_update
  before insert or update on public.quantity_acceptances
  for each row execute function app_private.guard_quantity_acceptance_direct_workflow_update() revoke all on function app_private.guard_payment_certificate_direct_workflow_update() from public, anon, authenticated revoke all on function app_private.guard_quantity_acceptance_direct_workflow_update() from public, anon, authenticated create or replace function public.transition_project_payment_certificate_status(
  p_certificate_id uuid,
  p_status text,
  p_actor_user_id uuid,
  p_reason text default null,
  p_target_user_id text default null,
  p_target_name text default null,
  p_target_permission text default null,
  p_submission_note text default null
)
returns public.payment_certificates
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_certificate public.payment_certificates%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_required_permission text;
  v_previous_guard text;
  v_expected_target_permission text;
begin
  if v_user_id is null or p_actor_user_id is distinct from v_user_id then
    raise exception 'Không xác định được người dùng chuyển trạng thái chứng từ thanh toán.'
      using errcode = '42501';
  end if;

  select *
  into v_certificate
  from public.payment_certificates
  where id = p_certificate_id
  for update;

  if not found then
    raise exception 'Không tìm thấy chứng từ thanh toán.';
  end if;

  v_required_permission := case p_status
    when 'submitted' then 'project.payment.submit'
    when 'returned' then 'project.payment.verify'
    when 'approved' then 'project.payment.approve'
    when 'cancelled' then 'project.payment.approve'
    when 'paid' then 'project.payment.confirm'
    else null
  end;

  if v_required_permission is null then
    raise exception 'Trạng thái chứng từ thanh toán không hợp lệ: %', p_status
      using errcode = '23514';
  end if;

  if (p_status = 'submitted' and coalesce(v_certificate.status, 'draft') not in ('draft', 'returned'))
    or (p_status in ('returned', 'approved') and v_certificate.status is distinct from 'submitted')
    or (p_status = 'paid' and v_certificate.status is distinct from 'approved')
    or (p_status = 'cancelled' and coalesce(v_certificate.status, 'draft') not in ('approved', 'paid'))
  then
    raise exception 'Chuyển trạng thái chứng từ thanh toán không hợp lệ: % -> %.', v_certificate.status, p_status
      using errcode = '23514';
  end if;

  if p_status in ('returned', 'cancelled') and nullif(btrim(coalesce(p_reason, '')), '') is null then
    raise exception 'Cần nêu lý do trả lại hoặc hủy chứng từ thanh toán.'
      using errcode = '23514';
  end if;

  if p_status in ('submitted', 'approved', 'paid')
    and coalesce(jsonb_array_length(v_certificate.items), 0) = 0
    and not exists (
      select 1
      from public.payment_certificate_items item_row
      where item_row.payment_certificate_id = p_certificate_id
    )
  then
    raise exception 'Chứng từ thanh toán chưa có hạng mục.'
      using errcode = '23514';
  end if;

  if p_status = 'approved' and v_certificate.acceptance_id is not null and not exists (
    select 1
    from public.quantity_acceptances acceptance_row
    where acceptance_row.id = v_certificate.acceptance_id
      and acceptance_row.status = 'approved'
  ) then
    raise exception 'Phải duyệt nghiệm thu liên kết trước khi duyệt chứng từ thanh toán.'
      using errcode = '23514';
  end if;

  if not public.is_admin()
    and v_certificate.submitted_to_user_id is not null
    and p_status in ('returned', 'approved', 'paid')
    and v_certificate.submitted_to_user_id <> v_user_id::text
  then
    raise exception 'Bạn không phải người đang được giao xử lý chứng từ thanh toán.'
      using errcode = '42501';
  end if;

  if not app_private.project_has_permission_v2(
    v_certificate.project_id::text,
    v_certificate.construction_site_id::text,
    v_required_permission,
    v_user_id
  ) then
    raise exception 'Bạn cần quyền % để chuyển trạng thái chứng từ thanh toán.', v_required_permission
      using errcode = '42501';
  end if;

  v_expected_target_permission := case p_status
    when 'submitted' then 'project.payment.approve'
    when 'approved' then 'project.payment.confirm'
    else null
  end;

  if v_expected_target_permission is not null then
    if nullif(p_target_user_id, '') is null or p_target_permission is distinct from v_expected_target_permission then
      raise exception 'Cần chọn người nhận có quyền %.', v_expected_target_permission
        using errcode = '23514';
    end if;
    if not app_private.project_has_permission_v2(
      v_certificate.project_id::text,
      v_certificate.construction_site_id::text,
      p_target_permission,
      p_target_user_id::uuid
    ) then
      raise exception 'Người được chọn chưa có quyền % trong phạm vi dự án.', p_target_permission
        using errcode = '42501';
    end if;
  end if;

  v_previous_guard := current_setting('app.project_document_transition_context', true);
  perform set_config('app.project_document_transition_context', 'on', true);

  update public.payment_certificates
  set
    status = p_status,
    submitted_by = case when p_status = 'submitted' then v_user_id::text else submitted_by end,
    submitted_at = case when p_status = 'submitted' then now() else submitted_at end,
    returned_by = case when p_status = 'returned' then v_user_id::text else returned_by end,
    returned_at = case when p_status = 'returned' then now() else returned_at end,
    return_reason = case when p_status = 'returned' then p_reason else return_reason end,
    approved_by = case when p_status = 'approved' then v_user_id::text else approved_by end,
    approved_at = case when p_status = 'approved' then now() else approved_at end,
    paid_at = case when p_status = 'paid' then now() else paid_at end,
    submitted_to_user_id = case
      when p_status in ('submitted', 'approved') then p_target_user_id
      when p_status = 'returned' then v_certificate.submitted_by
      when p_status in ('paid', 'cancelled') then null
      else submitted_to_user_id
    end,
    submitted_to_name = case
      when p_status in ('submitted', 'approved') then p_target_name
      when p_status = 'returned' then null
      when p_status in ('paid', 'cancelled') then null
      else submitted_to_name
    end,
    submitted_to_permission = case
      when p_status in ('submitted', 'approved') then p_target_permission
      when p_status = 'returned' then 'edit'
      when p_status in ('paid', 'cancelled') then null
      else submitted_to_permission
    end,
    submission_note = case
      when p_status in ('submitted', 'approved') then p_submission_note
      when p_status in ('returned', 'paid', 'cancelled') then p_reason
      else submission_note
    end,
    updated_at = now()
  where id = p_certificate_id
  returning * into v_certificate;

  perform set_config('app.project_document_transition_context', coalesce(v_previous_guard, ''), true);
  return v_certificate;
end;
$$ create or replace function public.transition_project_quantity_acceptance_status(
  p_acceptance_id uuid,
  p_status text,
  p_actor_user_id uuid,
  p_reason text default null,
  p_target_user_id text default null,
  p_target_name text default null,
  p_target_permission text default null,
  p_submission_note text default null
)
returns public.quantity_acceptances
language plpgsql
security definer
set search_path = ''
as $$
declare
  v_acceptance public.quantity_acceptances%rowtype;
  v_user_id uuid := public.current_app_user_id();
  v_required_permission text;
  v_previous_guard text;
begin
  if v_user_id is null or p_actor_user_id is distinct from v_user_id then
    raise exception 'Không xác định được người dùng chuyển trạng thái nghiệm thu.'
      using errcode = '42501';
  end if;

  select *
  into v_acceptance
  from public.quantity_acceptances
  where id = p_acceptance_id
  for update;

  if not found then
    raise exception 'Không tìm thấy nghiệm thu.';
  end if;

  v_required_permission := case p_status
    when 'submitted' then 'project.quantity_acceptance.submit'
    when 'returned' then 'project.quantity_acceptance.verify'
    when 'approved' then 'project.quantity_acceptance.approve'
    when 'cancelled' then 'project.quantity_acceptance.approve'
    else null
  end;

  if v_required_permission is null then
    raise exception 'Trạng thái nghiệm thu không hợp lệ: %', p_status
      using errcode = '23514';
  end if;

  if (p_status = 'submitted' and coalesce(v_acceptance.status, 'draft') not in ('draft', 'returned'))
    or (p_status in ('returned', 'approved') and v_acceptance.status is distinct from 'submitted')
    or (p_status = 'cancelled' and v_acceptance.status is distinct from 'approved')
  then
    raise exception 'Chuyển trạng thái nghiệm thu không hợp lệ: % -> %.', v_acceptance.status, p_status
      using errcode = '23514';
  end if;

  if p_status in ('returned', 'cancelled') and nullif(btrim(coalesce(p_reason, '')), '') is null then
    raise exception 'Cần nêu lý do trả lại hoặc hủy nghiệm thu.'
      using errcode = '23514';
  end if;

  if p_status in ('submitted', 'approved') and not exists (
    select 1
    from public.quantity_acceptance_items item_row
    where item_row.acceptance_id = p_acceptance_id
  ) then
    raise exception 'Nghiệm thu chưa có hạng mục.'
      using errcode = '23514';
  end if;

  if p_status = 'cancelled' and exists (
    select 1
    from public.payment_certificates certificate_row
    where certificate_row.acceptance_id = p_acceptance_id
  ) then
    raise exception 'Không thể hủy nghiệm thu vì đã có chứng từ thanh toán liên kết.'
      using errcode = '23514';
  end if;

  if not public.is_admin()
    and v_acceptance.submitted_to_user_id is not null
    and p_status in ('returned', 'approved')
    and v_acceptance.submitted_to_user_id <> v_user_id::text
  then
    raise exception 'Bạn không phải người đang được giao xử lý nghiệm thu.'
      using errcode = '42501';
  end if;

  if not app_private.project_has_permission_v2(
    v_acceptance.project_id::text,
    v_acceptance.construction_site_id::text,
    v_required_permission,
    v_user_id
  ) then
    raise exception 'Bạn cần quyền % để chuyển trạng thái nghiệm thu.', v_required_permission
      using errcode = '42501';
  end if;

  if p_status = 'submitted' then
    if nullif(p_target_user_id, '') is null or p_target_permission is distinct from 'project.quantity_acceptance.approve' then
      raise exception 'Cần chọn người nhận có quyền project.quantity_acceptance.approve.'
        using errcode = '23514';
    end if;
    if not app_private.project_has_permission_v2(
      v_acceptance.project_id::text,
      v_acceptance.construction_site_id::text,
      p_target_permission,
      p_target_user_id::uuid
    ) then
      raise exception 'Người được chọn chưa có quyền % trong phạm vi dự án.', p_target_permission
        using errcode = '42501';
    end if;
  end if;

  v_previous_guard := current_setting('app.project_document_transition_context', true);
  perform set_config('app.project_document_transition_context', 'on', true);

  update public.quantity_acceptances
  set
    status = p_status,
    submitted_by = case when p_status = 'submitted' then v_user_id::text else submitted_by end,
    submitted_at = case when p_status = 'submitted' then now() else submitted_at end,
    returned_by = case when p_status = 'returned' then v_user_id::text else returned_by end,
    returned_at = case when p_status = 'returned' then now() else returned_at end,
    return_reason = case when p_status = 'returned' then p_reason else return_reason end,
    approved_by = case when p_status = 'approved' then v_user_id::text else approved_by end,
    approved_at = case when p_status = 'approved' then now() else approved_at end,
    submitted_to_user_id = case
      when p_status = 'submitted' then p_target_user_id
      when p_status = 'returned' then v_acceptance.submitted_by
      when p_status in ('approved', 'cancelled') then null
      else submitted_to_user_id
    end,
    submitted_to_name = case
      when p_status = 'submitted' then p_target_name
      when p_status = 'returned' then null
      when p_status in ('approved', 'cancelled') then null
      else submitted_to_name
    end,
    submitted_to_permission = case
      when p_status = 'submitted' then p_target_permission
      when p_status = 'returned' then 'edit'
      when p_status in ('approved', 'cancelled') then null
      else submitted_to_permission
    end,
    submission_note = case
      when p_status = 'submitted' then p_submission_note
      when p_status in ('returned', 'cancelled') then p_reason
      else submission_note
    end,
    updated_at = now()
  where id = p_acceptance_id
  returning * into v_acceptance;

  perform set_config('app.project_document_transition_context', coalesce(v_previous_guard, ''), true);
  return v_acceptance;
end;
$$ revoke all on function public.transition_project_payment_certificate_status(uuid, text, uuid, text, text, text, text, text) from public revoke all on function public.transition_project_payment_certificate_status(uuid, text, uuid, text, text, text, text, text) from anon grant execute on function public.transition_project_payment_certificate_status(uuid, text, uuid, text, text, text, text, text) to authenticated revoke all on function public.transition_project_quantity_acceptance_status(uuid, text, uuid, text, text, text, text, text) from public revoke all on function public.transition_project_quantity_acceptance_status(uuid, text, uuid, text, text, text, text, text) from anon grant execute on function public.transition_project_quantity_acceptance_status(uuid, text, uuid, text, text, text, text, text) to authenticated]

[do $$
declare
  v_codes text[] := array[
    'project.payment.verify',
    'project.payment.approve',
    'project.payment.confirm',
    'project.quantity_acceptance.verify',
    'project.quantity_acceptance.approve'
  ];
begin
  if (
    select count(*)
    from public.permission_actions
    where permission_code = any(v_codes)
      and is_active
      and grant_readiness = 'declared'
  ) <> cardinality(v_codes) then
    raise exception 'Payment/Quantity readiness promotion requires five active declared actions.';
  end if;

  update public.permission_actions
  set grant_readiness = 'verified',
      updated_at = now()
  where permission_code = any(v_codes)
    and is_active
    and grant_readiness = 'declared';

  if (
    select count(*)
    from public.permission_actions
    where permission_code = any(v_codes)
      and is_active
      and grant_readiness = 'verified'
  ) <> cardinality(v_codes) then
    raise exception 'Payment/Quantity readiness promotion failed.';
  end if;
end;
$$]

[do $$
declare
  v_codes text[] := array[
    'project.material_request.approve',
    'project.material_po.approve',
    'project.custom_material.approve'
  ];
begin
  if (
    select count(*)
    from public.permission_actions
    where permission_code = any(v_codes)
      and is_active
      and grant_readiness = 'declared'
  ) <> cardinality(v_codes) then
    raise exception 'Material approval readiness promotion requires three active declared actions.';
  end if;

  update public.permission_actions
  set grant_readiness = 'verified',
      updated_at = now()
  where permission_code = any(v_codes)
    and is_active
    and grant_readiness = 'declared';

  if (
    select count(*)
    from public.permission_actions
    where permission_code = any(v_codes)
      and is_active
      and grant_readiness = 'verified'
  ) <> cardinality(v_codes) then
    raise exception 'Material approval readiness promotion failed.';
  end if;
end;
$$]
